{"Content":"","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Funding","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"AcceptedOffers","ResourceKey":"B2B","Script":"AcceptedOffers = {
