	init: async function (app, container) {
		app = app || session.app;
		container = container || $("[name=AcceptInvite]");

        var userId = getQueryParameter('user');
        var email = getQueryParameter('e');
        var token = getQueryParameter('t');

        if(userId == '' || email == '' || token == '') {
            $("[name=accept-form]", container).toggleClass('d-none');
            $("[name=error-text]", container).html("[resource_displayname[clickinvitelinkandtryagain]]");
            $("[name=error]", container).toggleClass('d-none');
        }

        $("input[name=userId]", container).val(userId);
        $("input[name=email]", container).val(email);

		$("[name=accept-invite]", container).on("click", async () => {
			await AcceptInvite.acceptInvite(app, container, userId, email, token);
		});
	},

    acceptInvite: async function(app, container, userId, email, token) {
        var displayName = $("[name=displayname]", container).val();
        var password = $("[name=password]", container).val();
        var confirmPassword = $("[name=confirm-password]", container).val();

        if(password !== confirmPassword || password == '') {
            notification.error("[resource_displayname[passwordsdonotmatch]]");
            return;
        }

        if(displayName == '') {
            notification.error("[resource_displayname[pickadisplayname]]");
            return;
        }

        try {
            await api.post(`Security/SSOUser/AcceptInvite?userId=${encodeURIComponent(userId)}&inviteToken=${token}`, {
                "displayName": displayName,
                "email": email,
                "password": password,
                "culture": app.DefaultCultureId,
                "phoneNumber": null,
                "appId": app.Id
            });
        } catch(e) {
            notification.error(e.error);
            return;
        }

        notification.success('[resource_displayname[inviteaccepted]]');

        await api.login(userId, password, true);

        var roles = (await api.get(`Core/User?$filter=Id eq '${encodeURIComponent(userId)}'&$expand=Roles($expand=Role)`)).value;
        var invitedRole = roles.filter(r => r?.Role?.Name == 'Invited Users')[0];

        if(invitedRole != null) {
            await api.destroy(`Core/UserRole(RoleId=${invitedRole.Id},UserId='${userId}')`);
        }

        location.href = '/';
    }
}"}

