<div name="acceptedOffersComponentContainer" class="hidden"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"AcceptOffers","ResourceKey":"B2B","Script":"AcceptOffers = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=AcceptOffers]");
        
        AcceptOffers.initNavTabIds(app, container);
        await AcceptOffers.addClickListenerForComponents(app, container);
        
        var proposedComponent = await loadComponent($('[name=proposedOffersComponentContainer]', container), 'ProposedOffers');
        await proposedComponent.init(app, $('[name=proposed]', container));

        AcceptOffers.activateTabFromHash(app, container);
    },

    initNavTabIds: function(app, container) {
        var id = Guid();
        var template = $('script[name=accepted-offers-tabs]', container).html();
        template = template.replaceAll('{ID}', id);
        container.append(template);
    },

    addClickListenerForComponents: async function(app, container) {
        var buttons = $('button[role=tab]', container);

        buttons.each((button) => {
            var button = $(buttons[button], container);
            var target = $(button.attr('data-component-container'));
            var component = button.attr('data-component');

            if (component != null) {
                button.on('click', async () => {
                    await AcceptOffers.loadTabContent(button, app, container);
                });

                // Update URL when tab is clicked
                button.on('click', function () {
                    let newUrl = window.location.pathname + button.attr("data-bs-target");
                    history.pushState(null, "", newUrl);
                });
            }
        });
    },

    activateTabFromHash: async function(app, container) {
        let hash = window.location.hash;
        if (hash) {
            let tab = container.find(`[data-bs-target="${hash}"]`);
            if (tab.length) {
                new bootstrap.Tab(tab[0]).show();
                await AcceptOffers.loadTabContent(tab, app, container);
            }
        }
    },

    loadTabContent: async function(tab, app, container) {
        let target = $(tab.attr('data-component-container'));
        let component = tab.attr('data-component');

        if (component && target.length > 0) {
            let existing = $(`.k-grid`, $(tab.attr('data-bs-target'), container));
            if (existing.length === 0) {
                await loadComponent($(target, container), component, async (c) => {
                    await c.init(app, $(tab.attr('data-bs-target'), container));
                });
            }
        }
    }
};
"}

{"Content":"<h3 class="chartTitle">[resource_displayname[ActiveCompanies]]</h3>
<div class="chart" name="chart"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Charts","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"ActiveCompanies","ResourceKey":"B2B","Script":"ActiveCompanies = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=ActiveCompanies]");

		var data = await this.getData(app);
		var chart = this.initChart(container, data);
		chart.init();

		$(window).resize(function () {
			chart.kendoObject.refresh();
		});
	},

	initChart: function (container, data) {
		var args = {
			showLegend: true,
			valueTemplate: "#: kendo.toString(value, type.number)#",
			tooltipTemplate: "#= series.name #: #= kendo.toString(value, type.number) #",
			series: [{
				name: `[resource_displayname[suppliercount]]`,
				data: data.counts
			}],
			categories: data.months,
			max: Math.max(...data.counts),
			type: "line",
			style: "smooth"
		};

		return (new Chart($("[name=chart]", container), args));
	},

	getData: async function(app) {
		var results = [];
		var sourceSystem = app.Config.B2B.SourceSystem;
		var data = [];

		var suppliers = (await api.get(`B2B/Bucket/ClientRollout()?system=${sourceSystem}&perspectiveKey=Creditor&$top=12`)).value;

		suppliers = suppliers
			.map(s => {
				var split = s.Name.split('-');
				var year = split[0];
				var month = split[1].padStart(2, '0');
				s.month = new Date(`${year}-${month}-01`);
				s.formatted = kendo.toString(s.month, 'MM-yyyy');
				return s;
			})
			.sort((a, b) => a.month - b.month);

		var categories = [... new Set(suppliers.map(t => t.formatted))];

		return {
			months: categories,
			counts: categories.map(m => suppliers
				.filter(s => s.formatted == m)
				.map(s => s.Count)
				.reduce((accumulator, current) => accumulator + current, 0))
		};
	}
}"}

{"Content":"","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"ActiveTransactions","ResourceKey":"B2B","Script":"ActiveTransactions = {
    invoiceTypes: [
        { id: 1, name: "[resource_displayname[SalesInvoice]]" },
        { id: 2, name: "[resource_displayname[CopyInvoice]]" },
        { id: 3, name: "[resource_displayname[Replacement]]" },
        { id: 4, name: "[resource_displayname[SelfBillingInvoice]]" },
        { id: 5, name: "[resource_displayname[ProFormaInv]]" }
    ],
    creditTypes: [
        { id: 1, name: "[resource_displayname[CreditNote]]" },
        { id: 2, name: "[resource_displayname[Replacement]]" },
        { id: 3, name: "[resource_displayname[DebitNote]]" },
        { id: 4, name: "[resource_displayname[SelfBillingCredit]]" }
    ],

    transactionStates: [script[TransactionStates]],
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=ActiveTransactions]");

        api.addToMetaCache([{
            "Name": "B2B",
            "Types": [
                [meta[B2B/ActiveTransaction]]
            ]
        }]);

        var config = {
            endpoint: "B2B/ActiveTransaction",
            odataAppend: "/FromSystem(SystemId='" + app.Config.B2B.TransactionSource + "')",
        };
        if (getQueryParameter("fundable")) {
            config.odataAppend = "/Fundable(SystemId='" + app.Config.B2B.TransactionSource + "')?$expand=Buckets($expand=Bucket($expand=FundingDetails))"
            var calendarId = app.Config.Calendars.primary;
            var cutoffEventName = app.Config.Calendars.CutoffEventName;
            var paymentEventName = app.Config.Calendars.PaymentEventName;
            var today = (new Date()).toISOString().split("T")[0];

            var nextCutoff = (await api.get("Core/CalendarEvent?$filter=CalendarId eq " + calendarId + " and Name eq '" + cutoffEventName + "' and Start ge " + today + "&$top=1&$orderby=Start asc&$select=Start")).value;
            if (nextCutoff.length === 0) {
                error("[resource_displayname[cutoffdatamissing]]");
            }
            nextCutoff = nextCutoff[0];

            var cutoffDate = (new Date(nextCutoff.Start)).toISOString().split("T")[0];
            var nextPaymentRun = (await api.get("Core/CalendarEvent?$filter=CalendarId eq " + calendarId + " and Name eq '" + paymentEventName + "' and Start ge " + cutoffDate + "&$top=1&$orderby=Start asc&$select=Start")).value;
            var funderPaymentDate = new Date(nextPaymentRun[0].Start);
            ActiveTransactions.FunderPaymentDate = funderPaymentDate;
        }

        var dataSource = await model.getDatasource(config);
        var widget = await ActiveTransactions.build({
            element: container,
            dataSource: dataSource,
            sourceSystem: app.Config.B2B.TransactionSource,
            app: app
        });

        if (getQueryParameter("fundable")) {
            widget.columns = widget.columns.concat([
                { field: "DaysEarly", title: "[resource_shortdisplayname[discountdays]]", template: "#=ActiveTransactions.getDays(data)#", filterable: false, sortable: false },
                { field: "DiscountAmount", title: "[resource_shortdisplayname[discountamount]]", template: "#=ActiveTransactions.evaluateFormula(data)#", filterable: false, sortable: false },
                { field: "Formula", title: "[resource_shortdisplayname[formula]]", template: "#=ActiveTransactions.getFormula(data)#", filterable: false, sortable: false }
            ]);
            widget.toolbar = widget.toolbar.concat([
                {
                    template: "<label>[resource_displayname[funderpaymentdate]]</label>: " + ActiveTransactions.FunderPaymentDate.toISOString().split("T")[0]
                }
            ]);
        }
        await widget.init();

        $("a[title*='filter column settings']").on("click", function () {
            $("input[type=checkbox]").addClass("k-checkbox k-checkbox-md k-rounded-md");
        });
    },

    getDays(activeTransaction) {
        return Math.ceil(Math.abs(new Date(activeTransaction.DebtorPaymentDate) - ActiveTransactions.FunderPaymentDate) / (1000 * 60 * 60 * 24));
    },

    getFormula(activeTransaction) {
        var detail = ActiveTransactions.fundingDetailFor(activeTransaction.toJSON());
        if (!detail)
            return "";

        var fundingFormula = detail.Formula.toLowerCase().replaceAll("m", "");
        fundingFormula = fundingFormula.replaceAll("fundablevalue", activeTransaction.FundableValue);
        fundingFormula = fundingFormula.replaceAll("facevalue", activeTransaction.Value);
        fundingFormula = fundingFormula.replaceAll("days", ActiveTransactions.getDays(activeTransaction));
        return fundingFormula;
    },

    evaluateFormula(activeTransaction) {
        var detail = ActiveTransactions.fundingDetailFor(activeTransaction.toJSON());
        if (!detail)
            return 0;

        var fundingFormula = detail.Formula.toLowerCase().replaceAll("m", "");
        fundingFormula = fundingFormula.replaceAll("fundablevalue", activeTransaction.FundableValue);
        fundingFormula = fundingFormula.replaceAll("facevalue", activeTransaction.Value);
        fundingFormula = fundingFormula.replaceAll("days", ActiveTransactions.getDays(activeTransaction));
        return kendo.toString(eval(fundingFormula), type.moneyFormat);
    },

    fundingDetailFor: function (activeTransaction) {
        var details = activeTransaction.Buckets.map(b => b.Bucket).map(s => s.FundingDetails).flat();

        var result = details.filter(d => d.CurrencyId == activeTransaction.CurrencyId && d.BuyerReferenceId === activeTransaction.DebtorReference);
        if (result.length > 0)
            return result[0];

        result = details.filter(d => d.CurrencyId == activeTransaction.CurrencyId && d.BuyerReferenceId === null);
        if (result.length > 0)
            return result[0];

        return null;
    },

    build: async function (vars) {
        var g = new GridWidget(vars.element, vars.dataSource);
        g.searchable = true;
        g.search = {
            fields: ["SourceSystemId", "TransactionType", "DebtorName", "DebtorReference", "CreditorName", "CreditorReference", "Number", "FunderReference", "Comment"]
        };
        g.filterable = true;
        g.editable = false;
        g.scrollable = true;
        g.exports = true;
        g.columns = [
            {
                field: "SourceSystemId",
                title: "[resource_shortdisplayname[sourcesystemid]]",
                description: "[resource_description[sourcesystemid]]",
                groupable: false,
                sortable: true
            },
            {
                field: "TransactionType",
                title: "[resource_shortdisplayname[TypeId]]",
                description: "[resource_description[TypeId]]",
                template: "#=(TransactionType == 'Invoice') ? ActiveTransactions.invoiceTypes[0].name : ActiveTransactions.creditTypes[0].name #",
                filterable: {
                    search: false,
                },
                groupable: false,
                sortable: true,
                values: [
                    { id: "Invoice", name: ActiveTransactions.invoiceTypes[0].name },
                    { id: "Credit", name: ActiveTransactions.creditTypes[0].name }
                ]
            },
            {
                field: "DebtorName",
                title: "[resource_shortdisplayname[DebtorName]]",
                description: "[resource_description[DebtorName]]",
                filterable: { multi: true, search: true }
            },
            {
                field: "DebtorReference",
                title: "[resource_shortdisplayname[DebtorReference]]",
                description: "[resource_description[DebtorReference]]"
            },
            {
                field: "DebtorState",
                template: "#= B2B.transactionStates[DebtorState || 'None'] #",
                title: "[resource_shortdisplayname[DebtorState]]",
                description: "[resource_description[DebtorState]]",
                filterable: true,
                sortable: true,
                values: Object.keys(B2B.transactionStates).map(c => ({
                    id: c,
                    name: B2B.transactionStates[c]
                })),
            },
            {
                field: "CreditorName",
                title: "[resource_shortdisplayname[CreditorName]]",
                description: "[resource_description[CreditorName]]",
                filterable: {
                    multi: true,
                    search: true
                }
            },
            {
                field: "CreditorReference",
                title: "[resource_shortdisplayname[CreditorReference]]",
                description: "[resource_description[CreditorReference]]"
            },
            {
                field: "CreditorState",
                template: "#= B2B.transactionStates[CreditorState || 'None'] #",
                title: "[resource_shortdisplayname[CreditorState]]",
                description: "[resource_description[CreditorState]]",
                filterable: true,
                sortable: true,
                values: Object.keys(B2B.transactionStates).map(c => ({
                    id: c,
                    name: B2B.transactionStates[c]
                })),
            },
            {
                field: "Number",
                title: "[resource_shortdisplayname[Number]]",
                description: "[resource_description[Number]]"
            },
            {
                field: "TaxPoint",
                format: "{0:" + type.dateFormat + "}",
                title: "[resource_shortdisplayname[TaxPoint]]",
                description: "[resource_description[TaxPoint]]",
                type: "date",
                width: "[theme[columns.date]]"
            },
            {
                field: "Value",
                format: "{0:" + type.moneyFormat + "}",
                title: "[resource_shortdisplayname[Value]]",
                description: "[resource_description[Value]]",
                attributes: { style: "text-align:right;" }
            },
            {
                field: "OfferValue",
                format: "{0:" + type.moneyFormat + "}",
                title: "[resource_shortdisplayname[OfferValue]]",
                description: "[resource_description[OfferValue]]",
                attributes: { style: "text-align:right;" }
            },
            {
                field: "CurrencyId",
                title: "[resource_shortdisplayname[CurrencyId]]",
                description: "[resource_description[CurrencyId]]",
                filterable: {
                    multi: true,
                    search: true,
                    dataSource: vars.app.Config.B2B.Currencies.map(c => ({ id: c, name: c }))
                },
                values: vars.app.Config.B2B.Currencies.map(c => ({ id: c, name: c }))
            },
            {
                field: "DueDate",
                format: "{0:" + type.dateFormat + "}",
                title: "[resource_shortdisplayname[DueDate]]",
                description: "[resource_description[DueDate]]",
                type: "date",
                width: "[theme[columns.date]]"
            },
            {
                field: "AgreedDiscountPaymentDate",
                format: "{0:" + type.dateFormat + "}",
                title: "[resource_shortdisplayname[earlypaymentdate]]",
                description: "[resource_description[earlypaymentdate]]",
                type: "date",
                width: "[theme[columns.date]]"
            },
            {
                field: "DebtorPaymentDate",
                format: "{0:" + type.dateFormat + "}",
                title: "[resource_shortdisplayname[BuyerPaymentDate]]",
                description: "[resource_description[BuyerPaymentDate]]",
                type: "date",
                width: "[theme[columns.date]]"
            },
            {
                field: "FunderReference",
                title: "[resource_shortdisplayname[FunderReference]]",
                description: "[resource_description[FunderReference]]"
            },

            {
                field: "Comment",
                title: "[resource_shortdisplayname[Comment]]",
                description: "[resource_description[Comment]]"
            }
        ];

        // Set up widths.
        // g = ActiveTransactions.setUpWidths(vars.element, g);

        //TODO: Revisit
        g.dataBound = function (e) {
            var rows = $("tr", this.tbody);
            var now = new Date();

            rows.each(i => {
                var row = rows[i];
                var item = g.dataItem(row);
                if (item.DueDate < now) {
                    $(row).addClass("overdue");
                }
            });
        }

        var funderReferenceApplicable = (await api.get(`B2B/ActiveTransaction/FromSystem(SystemId='${vars.sourceSystem}')?$apply=groupby((FunderReference))`)).filter(r => r.FunderReference);

        if (funderReferenceApplicable.length <= 1) {
            var index = g.columns.findIndex(r => r.field == "FunderReference");
            g.columns.splice(index, 1);
        }

        var creditorStateApplicable = (await api.get(`B2B/ActiveTransaction/FromSystem(SystemId='${vars.sourceSystem}')?$apply=groupby((FunderReference))`)).filter(r => r.FunderReference);

        if (creditorStateApplicable.length <= 1) {
            var index = g.columns.findIndex(r => r.field == "CreditorState");
            g.columns.splice(index, 1);
        }

        if (session.app.Config.B2B.SourceSystem.indexOf(",") === -1) {
            g.columns.splice(0, 1);
        };

        if (g.viewCommand) {
            g.commands.push({
                name: "view",
                icon: "k-i-share",
                text: "[resource_shortdisplayname[View]]",
                href: "/Transactions/#:TransactionType#?Id=#:TransactionId#"
            });
        }
        if (g.expandView) {
            g.detailTemplate = "<div name='container'></div>";
            g.detailExpand = function (e) {
                var transaction = this.dataItem(e.masterRow);
                var transactionType = transaction.TransactionType;
                var transactionId = transaction.TransactionId;
                var container = $(e.detailRow).find("div[name=container]");
                container.html("");
                loadComponent(container[0], transactionType, (component) => {
                    component.id = transactionId;
                    component.backButton = false;
                    component.init(session.app, container[0]);
                    container.find("button").hide();
                });
            };
        }
        if (g.viewDialogCommand) {
            g.commands.push({
                name: "viewDialog",
                icon: "k-i-share",
                text: "[resource_shortdisplayname[ViewDialog]]",
                click: function (e, item, grid, widget) {
                    var transactionType = item.TransactionType,
                        transactionId = item.TransactionId,
                        d = new Dialog();
                    d.title = "[resource_shortdisplayname[TransactionDetails]]";
                    d.width = 1630;
                    d.height = 800;
                    d.init(() => {
                        loadComponent(d.element, transactionType, (component) => {
                            component.id = transactionId;
                            component.backButton = false;
                            component.init(session.app, d.element);
                            $(d.element).find("button").hide();
                        });
                    });
                }
            });
        }

        return g;
    },

    setUpWidths: function (container, grid) {
        var totalLength = 0;
        var gridWidth = $(grid.element).width;

        grid.columns.map(c => {
            totalLength += c.title.length;
        });

        for (var i = 0; i < grid.columns.length; i++) {
            var width = Math.round((grid.columns[i].title.length / totalLength) * gridWidth);
            grid.columns[i].width = width;
        }

        return grid;
    }
};"}

