</div>","Script":"ActivityEditor = {
	init: function (app, container, activity, callback) {
		app = app || session.app;
		container = container || $(".component[name=ActivityEditor]");
		$("[name=\\$type]", container).val(activity.model['$type']);
		$("input[name=Ref]", container).val(activity.model.Ref);
		$("[name=metaType]", container).val(activity.meta.ServerType);

		for (var i in activity.model) {
			var meta = activity.meta.Properties.filter(p => p.Name === i)[0];
			$('[name=properties]', container).append(ActivityEditor.editorFor(i, activity.model[i], meta));
		}
		$('[name=submit]', container).on('click', (e) => ActivityEditor.save(e, container, activity, callback));
	},

	editorFor: function (key, value, meta) {
		if (meta && meta.Type !== "object" && meta.Type !== "array" && key !== "AssignCode") {
			return `
        <div class="input-group input-group-sm mb-2">
            <span class="input-group-text">${key}</span>
            <input class="form-control" name="${key}" type="text" value="${value || ''}">
        </div>`;
		}
		return '';
	},

	save: async function (e, container, activity, callback) {
		e.preventDefault();

		var values = $('input', container).get();
		var newRef = $("input[name=Ref]", container).val();
		if (newRef !== activity.model.Ref) {
			// confirm uniqueness
			if (!activity.flow.Activities.every(a => a.model.Ref !== newRef)) {
				notification.error("Ref must be unique for the flow.");
				return;
			}

			activity.flow.Links = activity.flow.Links.map(l => {
				if (l.model.Source === activity.model.Ref) { l.model.Source = newRef; }
				if (l.model.Destination === activity.model.Ref) { l.model.Destination = newRef; }
				return l;
			});
			activity.model.Ref = newRef;
		}

		values.map((e, i) => {
			var prop = $(e).attr('name');
			activity.model[prop] = $(e).val() || null;
		});

		callback(activity);
	},

	validateActivity: async function (activity) {
		var activityString = JSON.stringify(activity.model);
		var result = "";
		for (let i = 0; i < activityString.length; i++) {
			if (activityString[i] === "\"") {
				result += "\"\"";
			} else {
				result += activityString[i];
			}
		}
		var code = `var k = @"${result}"; Core.Objects.Data.ParseJson(k); return "";`
		return await api.sendRaw("POST", "ExecuteScript", code);
	}
}","Name":"ActivityEditor","Description":null,"Key":"Workflow"}

