    toolbar: true,

    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=AppManagement]")[0];
        app = await api.get("Core/App(" + app.Id + ")");
        app.Config = JSON.parse(app.ConfigJson);
        if (AppManagement.toolbar) {
            $("[name=appToolbar]").kendoToolBar({
                items: [
                    {
                        text: "[resource_displayname[save]]",
                        type: "button",
                        template: `
                            <div class="btn-group btn-group-sm">
                                <button class="btn btn-primary" name="appSave">
                                    <span class='k-icon k-i-save'></span> [resource_displayname[Save]]
                                </button>
                                <button class="btn btn-primary" name="appMigrate" data-bs-toggle="modal" data-bs-target="#app-migrator-model">
                                    <span class='k-icon k-i-arrow-up'></span> [resource_displayname[Migrate]]
                                </button>
                            </div>`
                    }
                ]
            });
        } else {
            $("[name=appToolbar]", container).remove();
        }

        this.initNavTabIds(app, container);
        await this.addClickListenerForComponents(app, container);

        if ($(".tab-pane[name=config] > div[name=editor]", container)[0].childElementCount === 0) {
            var configEditor = new MonacoEditor($(".tab-pane[name=config] > div[name=editor]", container)[0], {
                code: app.ConfigJson,
                language: "json",
                automaticLayout: true
            });
            configEditor.onChange = () => app.ConfigJson = configEditor.getValue();
            configEditor.init();
            $(".tab-pane[name=config] > div[name=editor]", container).data("configEditor", configEditor);
            $("[name=appSave]", container).click(() => AppManagement.save(app, configEditor));
            $("[name=appMigrate]", container).click(() => AppManagement.migrate(app, container));
        }
    },

    initNavTabIds: function(app, container) {
        var nav = $('#app-management-nav-tab', container);
        nav.attr('id', `${nav.attr('id')}-${app.Id}`);
        var content = $('#app-management-nav-tabContent', container);
        content.attr('id', `${content.attr('id')}-${app.Id}`);

        var buttons = $('button[role=tab]', nav);
        buttons.each((button) => {
            var button = $(buttons[button], container);
            button.attr('data-bs-target', `${button.attr('data-bs-target')}-${app.Id}`);
        });

        var tabs = $('.tab-pane', content);
        tabs.each((tab) => {
            var tab = $(tabs[tab], container);
            tab.attr('id', `${tab.attr('id')}-${app.Id}`);
        });
    },

    addClickListenerForComponents: async function(app, container) {
        var buttons = $('button[role=tab]', container);
        buttons.each((button) => {
            var button = $(buttons[button], container);
            var target = $(button.attr('data-bs-target'));
            var component = target.attr('data-component');

            if(component != null) {
                button.click(async () => {
                    console.log(`Loading component: ${component}`);

                    var existing = $(`.component[name=${component}]`, $(target, container));

                    if(existing.length == 0) {
                        await loadComponent($(target, container), component, async (c) => {
                            await c.init(app, $(`.component[name=${component}]`, $(target, container)));
                        });
                    }
                });
            }
        });
    },

    migrate: async function (app, container) {
        // var d = new Dialog({ title: "[resource_displayname[migrate]]", width: 620, height: "auto" });
        // d.template = $("[name=appMigratorComponent]").first().html();
        var element = $("[name=AppMigrator]", container);
        await AppMigrator.init(app, element, app);
    },

    save: async function (app, configEditor) {
        var newApp = {
            ConfigJson: configEditor.getValue(),
            Cultures: app.Cultures,
            DefaultCultureId: app.DefaultCultureId,
            DefaultTheme: app.DefaultTheme,
            Domain: app.Domain,
            Id: app.Id,
            Name: app.Name,
            TenantId: app.TenantId
        };
        try {
            JSON.parse(newApp.ConfigJson);
        } catch(err) {
            error("[resource_displayname[AppConfigParsingError]]");
            return;
        }
        notification.info("[resource_displayname[saving]]");
        await api.update("Core/App(" + app.Id + ")", newApp).then(() => {
            notification.success("[resource_displayname[saved]]")
        }).catch((err) => error(err));
    }
};"}

