    init: async function (app, container, appToMigrate, dialog) {
        app = app || session.app;
        container = container || $(".component[name=AppMigrator]");
        if(!appToMigrate)
            return;

        var environments = JSON.parse(appToMigrate.ConfigJson).Deployment.Targets;
        var apiSelect = $('[name=api]', container);

        if($('option', apiSelect).length == 1) {
            environments.forEach((env) => {
                apiSelect.append('<option value="' + env.Api + '">' + env.EnvironmentName + '</option>');
            });

            var packages = await api.get("Core/App(" + appToMigrate.Id + ")/Export()");
            packages.value.push({ Name: "DMS" });
            var packageGrid = new GridWidget($("[name=selectPackagesGrid]", container), {
                data: packages.value,
                sort: {
                    field: "Name",
                    dir: "asc"
                }
            });
            packageGrid.groupable = false;
            packageGrid.pageable = false;
            packageGrid.editable = false;
            packageGrid.columns = [
                {
                    selectable: true,
                    width: 50
                },
                {
                    field: "Name"
                }
            ];
            packageGrid.init(() => {
                packageGrid.kendoObject.select(packageGrid.kendoObject.tbody.find(">tr"));
            });
            $("button[name=migrate]", container).off().on("click", async function (e) {
                if(dialog)
                    dialog.events.close();
                
                await AppMigrator.migrate(app, container, appToMigrate, packageGrid);
            });
        }
    },

    migrate: async function (app, container, sourceApp, packageGrid) {
        var packagesSelected = [];
        packageGrid.kendoObject.select().each(function () {
            packagesSelected.push(packageGrid.kendoObject.dataItem(this).Name);
        });
        var functions = {
            [script[MigrateApp]]
        };
        var vars = {
            Domain: JSON.parse(sourceApp.ConfigJson).Deployment.Targets.filter(
                r => r.Api == $("[name=api]", container).val()
            )[0].Domain,
            RemoteAuth: {
                User: session.user,
                Pass: $("[name=pass]", container).val(),
                Api: JSON.parse(sourceApp.ConfigJson).Deployment.Targets.filter(
                    r => r.Api == $("[name=api]", container).val()
                )[0].Api,
            },
            SelectedPackageNames: packagesSelected,
            SourceApp: sourceApp,
            ForceUpdate: $('[name=force-update]', container).is(':checked')
        };
        if(packagesSelected.filter(r => r == "DMS").length > 0) {
            vars.DMSPaths = JSON.parse(sourceApp.ConfigJson).Deployment.DMS;
        }
        var d = new Dialog({
            width: 800,
            height: 500,
            title: "[resource_displayname[migrating]]"
        });
        d.init(async () => {
            await loadComponent($(d.element), "ScriptRunner", (scriptRunner) =>
                scriptRunner.init(app, $(".component[name=ScriptRunner]", d.element), vars, functions, d));
        });
    }
}"}

