    init: async function(app, container) {
        app = app || session.app;
        container = container || $(".component[name=AppThemeList]");
        var appKeys = Object.keys(app.Config.Themes);
        var appThemes = appKeys.map(k => ({
            name: k,
            theme: app.Config.Themes[k]
        }));
        var themeGrid = new GridWidget(container, appThemes);
        themeGrid.toolbar = [
			{
				template: `<div class="btn-group btn-group-sm">
                    <button class="btn btn-primary" name="add">
                        <span class="k-icon k-i-plus"></span>[resource_displayname[new]]
                    </button>
                </div>`
			}
		];
        themeGrid.groupable = false;
        themeGrid.pageable = false;
        themeGrid.sortable = true;
        themeGrid.columns = [{ field: "name", title: "[resource_displayname[name]]" }];
        themeGrid.commands.push({ name: "edit", icon: "k-i-pencil", text: "[resource_displayname[edit]]" });
        themeGrid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });
        themeGrid.dataBound = function () {
            $("[name=edit]", themeGrid.gridElement).on("click", (e) => AppThemeList.editTheme(e, app, themeGrid));
            $("[name=delete]", themeGrid.gridElement).on("click", (e) => AppThemeList.removeTheme(e, app, themeGrid));
        };
        await themeGrid.init();
        $("button[name=add]", themeGrid.gridElement).on("click", () => AppThemeList.addTheme(app, themeGrid));
    },

    editTheme: async function(e, app, themeGrid) {
        e.preventDefault();
        var item = themeGrid.dataItem($(e.currentTarget).closest("tr"));
        var d = new Dialog({
            title: "[resource_displayname[edittheme]]",
            width: 1000,
            height: 600,
        });
        d.template = $("[name=editThemeTemplate]").html();
        d.init(async () => {
            var c = await loadComponent($("[name=themeContent]", d.element), "ThemeBuilder");
            c.init(app, $(".component[name=ThemeBuilder]", d.element), item.theme);
            $("[name=save]", d.element).on("click",  async function(e) {
                item.theme = ThemeBuilder.build($(".component[name=ThemeBuilder]", d.element));
                await AppThemeList.save(app, themeGrid);
            });
        });
    },

    save: async function(app, themeGrid) {
        var themes = themeGrid.dataSource().data();
        var dictionary = {};
        for(let i = 0; i < themes.length; i++) {
            dictionary[themes[i].name] = themes[i].theme;
        }
        var app = await api.get("Core/App(" + app.Id + ")");
        var config = JSON.parse(app.ConfigJson);
        config.Themes = dictionary;
        app.ConfigJson = JSON.stringify(config, null, 4);
        await api.put("Core/App(" + app.Id + ")", app).then(() => {
            notification.success("[resource_displayname[saved]]");
            var appKeys = Object.keys(config.Themes);
            var appThemes = appKeys.map(k => ({name: k, theme: config.Themes[k]}));
            themeGrid.kendoObject.setDataSource({data: appThemes});
        }).catch((err) => error(err));
    },

    addTheme: function (app, themeGrid) {
        var model = kendo.observable({ name: "", theme: JSON.parse(JSON.stringify(app.Config.Themes.Default)) });
        var addThemeDialog = new Dialog({ title: "[resource_displayname[addtheme]]" });
        addThemeDialog.template = $("[name=addThemeDialog]").html();
        addThemeDialog.events.confirm = async function () {
            themeGrid.dataSource().insert(0, model);
            await AppThemeList.save(app, themeGrid);
            addThemeDialog.events.close();
        };
        addThemeDialog.init(() => {  
            kendo.bind(addThemeDialog.element, model);  
        });
    },

    removeTheme: async function (e, app, themeGrid) {
        e.preventDefault();

		var d = new ConfirmDialog({
			title: "[resource_displayname[areyousure]]",
			confirm: "[resource_displayname[confirm]]",
			close: "[resource_displayname[close]]"
		});

		d.events.confirm = async function () {
			var item = themeGrid.dataItem($(e.currentTarget).closest("tr"));
            themeGrid.dataSource().remove(item);
            await AppThemeList.save(app, themeGrid);
			d.events.close();
		};

		d.init();
    }
}"}

