    init: async function(app, container) {
        app = app || session.app;
        container = container || $(".component[name=AppTheming]");

        var themeListContainer = $('[name=app-theme-list]', container);
        await loadComponent(themeListContainer, 'AppThemeList', async (c) => {
            await c.init(app, $(`.component[name=AppThemeList]`, themeListContainer));
        });

        AppTheming.wireUpEvents(container);
    },

    wireUpEvents: function(container) {
        AppTheming.wireUpFileUploading(
            $('input[name=brand-logo]', container),
            $('img[name=brand-logo-preview]', container),
            'Content/CompanyLogo.png');

        AppTheming.wireUpFileUploading(
            $('input[name=project-logo]', container),
            $('img[name=project-logo-preview]', container),
            'Content/CompanyLogo2.png');

        AppTheming.wireUpFileUploading(
            $('input[name=animation]', container),
            $('img[name=animation-preview]', container),
            'Content/background.gif');
    },

    wireUpFileUploading: function(element, preview, path) { 
        element.on('change', (e) => AppTheming.handleFileUploadEvent(e, preview, path));
        element.on('dragend',(e) => AppTheming.handleFileUploadEvent(e, preview, path));
    },

    handleFileUploadEvent: async function(event, element, path) {
        if(event.target.files.length > 1) {
            notification.error('[resource_displayname[onlyonefile]]');
            return;
        }

        var file = event.target.files[0] || null;
        if(file == null)
            return;

        AppTheming.handleFileUploadPreview(file, element);
        await api.file.upload(path, file);
    },

    handleFileUploadPreview: function(file, element) {
        var preview = URL.createObjectURL(file);
        element.attr('src', preview);
    }
};"}

