    init: async function(app, container) {
        app = app || session.app;
        app = await api.get("Core/App(" + app.Id + ")");
        app.Config = JSON.parse(app.ConfigJson);
        container = container || $(".component[name=B2BAdmin]");

        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Bucket]]
                ]
            }
        ]);
        var rootBucketId = await B2BAdmin.getRootBucket(app);
        await B2BAdmin.checkSystemExists(rootBucketId, app);
        await B2BAdmin.initialiseConfig(app);
        await B2BAdmin.setupTabs(app, container, rootBucketId);
    },

    checkSystemExists: async function(rootBucketId, app) {
        if(!app.Config.B2B.SourceSystem) {
            app.Config.B2B.SourceSystem = app.Name;
            app.ConfigJson = JSON.stringify(app.Config, null, 2);
            var copy = JSON.parse(JSON.stringify(app));
            delete copy.Cultures;
            delete copy.Config;
            await api.update("Core/App(" + app.Id + ")", copy)
                .catch((err) => error(err));
        }
        var systemExists = await api.get("B2B/System?$filter=Id in (" + app.Config.B2B.SourceSystem.split(",").map(r => "'" + r + "'").join() + ")");
        if(systemExists.value.length === 0) {
            // await api.post("B2B/System",
            //     {
            //         Id: app.Config.B2B.SourceSystem,
            //         Name: app.Config.B2B.SourceSystem,
            //         Description: app.Config.B2B.SourceSystem,
            //         Buckets: [
            //             { BucketId: rootBucketId, SystemId: app.Config.B2B.SourceSystem }
            //         ]
            //     }
            // );
        }
        var systemsInRootBucket = (await api.get("B2B/BucketSystem?$filter=BucketId eq " + rootBucketId)).value;
        if(systemsInRootBucket.length === 0) {
            var systemsToAdd = app.Config.B2B.SourceSystem.split(",");
            for(let i = 0; i < systemsToAdd.length; i++) {
                // await api.post("B2B/BucketSystem", { BucketId: rootBucketId, SystemId: systemsToAdd[i] });
            }
        }
    },

    getRootBucket: async function(app) {
        // if (!app.Config.B2B) {
        //     app.Config.B2B = {
        //         SourceSystem: app.Name,
        //         TransactionSource: app.Name,
        //         ExpiryTime: "23:59",
        //         Currencies: [ "EUR" ],
        //         DefaultCurrency: "EUR",
        //         RootBucket: (await api.post("B2B/Bucket/CreateStructure")).Id
        //     };
        //     app.ConfigJson = JSON.stringify(app.Config, null, 2);
        //     var copy = JSON.parse(JSON.stringify(app));
        //     delete copy.Cultures;
        //     delete copy.Config;
        //     await api.update("Core/App(" + app.Id + ")", copy)
        //         .catch((err) => error(err));
        // } else if(!app.Config.B2B.RootBucket)  {
        //     app.Config.B2B.RootBucket = (await api.post("B2B/Bucket/CreateStructure")).Id;
        //     app.ConfigJson = JSON.stringify(app.Config, null, 2);
        //     var copy = JSON.parse(JSON.stringify(app));
        //     delete copy.Cultures;
        //     delete copy.Config;
        //     await api.update("Core/App(" + app.Id + ")", copy)
        //         .catch((err) => error(err));
        // }
        return app.Config.B2B.RootBucket;
    },

    initialiseConfig: async function(app) {
        var app = await api.get("Core/App(" + app.Id + ")");
        var config = JSON.parse(app.ConfigJson);
        var modified = false;
        if(!config.B2B.ExpiryTime) {
            config.B2B.ExpriyTime = "23:59";
            modified = true;
        }
        if(!config.B2B.DefaultCurrency) {
            config.B2B.DefaultCurrency = "EUR";
            modified = true;
        }
        if(!config.B2B.Currencies) {
            config.B2B.Currencies = ["EUR"];
            modified = true;
        }
        if(!config.Calendars.PaymentEventName) {
            config.Calendars.PaymentEventName = "Payment";
            modified = true;
        }
        if(!config.Calendars.CutoffEventName) {
            config.Calendars.CutoffEventName = "Cutoff";
            modified = true;
        }
        if(!config.Deployment.TenantId) {
            config.Deployment.TenantId = app.TenantId;
            modified = true;
        }
        if(modified) {
            app.ConfigJson = JSON.stringify(config, null, 4);
            await api.update("Core/App(" + app.Id + ")", app);
        }
    },

    setupTabs: async function(app, container, rootBucket) {
        $("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });
        var bucket = await api.get("B2B/Bucket(" + rootBucket + ")?$expand=Buckets");
        var funderBucket = null;
        if(bucket.Buckets.filter(b => b.Key == "FunderGroup").length > 0) {
            funderBucket = bucket.Buckets.filter(b => b.Key == "FunderGroup")[0].Id;
        }
        if(bucket.Buckets.filter(b => b.Key == "DebtorGroup").length > 0) {
            B2BAdminCompany.init(app, $(".component[name=B2BAdminCompany]", $("[name=debtors]", container) ), bucket.Buckets.filter(b => b.Key == "DebtorGroup")[0].Id, funderBucket);
        }
        if(bucket.Buckets.filter(b => b.Key == "CreditorGroup").length > 0) {
