        }
        if(bucket.Buckets.filter(b => b.Key == "FunderGroup").length > 0) {
            B2BAdminFunderCompany.init(app, $(".component[name=B2BAdminFunderCompany]", $("[name=funders]", container) ), bucket.Buckets.filter(b => b.Key == "FunderGroup")[0].Id, funderBucket);
        }
        BucketedRoleManagement.init(app, $(".component[name=BucketedRoleManagement]", $("[name=security]", container)), bucket);
    }
}"}

{"Name":"B2BAdminBucketManagement","ResourceKey":"B2B","Content":"<script name="bucketDetails" type="template">
<div class='component' name='bucketDetails'>
