<style>
   .k-grid-content { height: auto !important; max-height: 800px; }
</style>","Script":"B2BAdminBucketManagement = {
    init: async function (app, container, rootBucket) {
        app = app || session.app;
        container = container || $(".component[name=B2BAdminBucketManagement]");
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Bucket]]
                ]
            }
        ]);
        if (!rootBucket) {
            if (!app.Config.B2B) {
                app.Config.B2B = {};
            }
            rootBucket = app.Config.B2B.RootBucket;
            await B2BAdminBucketManagement.setupGrid(app, container, rootBucket);
        } else {
            await B2BAdminBucketManagement.setupGrid(app, container, rootBucket);
        }
    },

    createRootBucket: async function (app, callback) {
        var functions = {
            [script[CreateBucketStructure]]
        };
        var vars = {
            App: app
        };
        var d = new Dialog({
            width: 800,
            height: 500
        });
        d.init(() => {
            loadComponent(d.element, "ScriptRunner", (c) => {
                ScriptRunner.init(app, d.element, vars, functions, d);
            });
        });
    },

    setupGrid: async function (app, container, rootBucket) {
        var ds = rootBucket ? await model.getDatasource({ endpoint: "B2B/Bucket", odataAppend: "?$filter=ParentId eq " + rootBucket + "&$expand=Roles" }) : { data: [] };
        var toolbar = "<button name='create'><span class='k-icon k-i-plus'></span>[resource_displayname[new]]</button>";
        if (!rootBucket) { toolbar += "<button name='createRootBucket'>[resource_displayname[createrootbucket]]</button>"; }
        var grid = new GridWidget(container, ds);
        grid.groupable = false;
        grid.filterable = true;
        grid.toolbar = toolbar;
        grid.columns = [
            { field: "Name", title: "[resource_shortdisplayname[Name]]" }, 
        ];
        grid.commands.push({name: "save", icon: "k-i-save", text: "[resource_displayname[save]]"});
        grid.commands.push({name: "destroy", icon: "k-i-delete", text: "[resource_displayname[delete]]"});
        grid.detailTemplate = $("script[name=bucketDetails]").first().html();
        grid.detailExpand = (e) => B2BAdminBucketManagement.expand(app, $(e.detailRow), grid.dataItem(e.masterRow), container);
        grid.dataBound = function (e) {
            $("a[name=save]", grid.gridElement).on("click", (e) => B2BAdminBucketManagement.save(e, container, grid));
            $("a[name=destroy]", grid.gridElement).on("click", (e) => B2BAdminBucketManagement.destroy(e, container, grid));
        };
        await grid.init();
        kendo.resize($("body"));
        $("button[name=createRootBucket]", grid.gridElement).on("click", (e) => B2BAdminBucketManagement.createRootBucket(app,  () => window.location.reload()));
        $("button[name=create]", grid.gridElement).on("click", (e) => B2BAdminBucketManagement.newBucket(e, container, rootBucket, grid));
    },

    expand: async function (app, container, bucket, rootContainer) {
        if (!$("[name=tabs", container).hasClass("k-tabstrip")) {
            $("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });
            var B2BAdminBucketManagement = await loadComponent($("[name=buckets]", container), "B2BAdminBucketManagement");
            await B2BAdminBucketManagement.init(app, $(".component[name=B2BAdminBucketManagement]", container), bucket.Id);
            var systemsManagement = await loadComponent($("[name=systems]", container), "BucketedSystemsManagement");
            await systemsManagement.init(app, $(".component[name=BucketedSystemsManagement]", container), bucket);
            var companyManagement = await loadComponent($("[name=companies]", container), "BucketedCompanyManagement");
            await companyManagement.init(app, $(".component[name=BucketedCompanyManagement]", container), bucket);
            var roleManagement = await loadComponent($("[name=roles]", container), "BucketedRoleManagement");
            await roleManagement.init(app, $(".component[name=BucketedRoleManagement]", container), bucket);
        }

    },

    save: function (e, container, grid) {
        e.preventDefault();
        var bucket = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
        bucket.save(e, function () {
            notification.success("[resource_displayname[BucketSaved]]");
        });
    },

    destroy: function (e, container, grid) {
        e.preventDefault();
        var d = new ConfirmDialog({
            title: "[resource_displayname[areyousure]]",
