","Script":"B2BAdminBuyerCompany = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=B2BAdminBuyerCompany]");

        api.addToMetaCache([
            { "Name": "B2B", "Types": [[meta[B2B/Company]]] }
        ]);

        if (container.length === 0) {
            console.error("B2BAdminBuyerCompany container not found!");
            return;
        }

        var rootBucket = await api.get(`B2B/Bucket(${app.Config.B2B.RootBucket})?$expand=Buckets`);
        var buyerBucketId = rootBucket.Buckets.find(b => b.Key === "DebtorGroup")?.Id;
        if (!buyerBucketId) {
            console.warn("DebtorGroup bucket not found");
            return;
        }

        var companyData = await model.getDatasource({
            endpoint: "B2B/Company",
            odataAppend: `?$filter=Buckets/any(b: b/Bucket/ParentId eq ${buyerBucketId})&$expand=Address,References,Buckets($expand=Bucket)`,
            sort: { field: "Name", dir: "asc" }
        });

        if (!companyData) {
            console.warn("No buyer company data returned");
            return;
        }

        var companyGrid = new GridWidget(container, companyData);
        companyGrid.groupable = false;
        companyGrid.filterable = true;
        companyGrid.editable = true;

        // Fix: replace {ID} before Kendo compilation
        companyGrid.detailTemplate = function() {
            var id = Guid();
            return $("[name=buyerCompanyDetails]").first().html().replace(/{ID}/g, id);
        };

        companyGrid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" });
        companyGrid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });

        companyGrid.dataBound = function () {
            $("[name=save]", companyGrid.gridElement).off("click").on("click", (e) => B2BAdminBuyerCompany.save(e, companyGrid));
            $("[name=delete]", companyGrid.gridElement).off("click").on("click", (e) => B2BAdminBuyerCompany.removeCompany(e, companyGrid, buyerBucketId));
        };

        companyGrid.pageable.responsive = false;

        companyGrid.detailExpand = async (e) => {
            var $detailRow = $(e.detailRow);
            if ($(".tab-control", $detailRow).attr('tabs-initialised')) return;

            $('.tab-control', $detailRow).attr('tabs-initialised', true);

            var company = companyGrid.dataItem($(e.masterRow).closest("tr"));
            var matchedBucket = company.Buckets.filter(b => b.Bucket.ParentId === buyerBucketId)[0].Bucket;

            loadComponent($("[name=security]", $detailRow), "BucketedRoleManagement", (c) => c.init(app, $(".component[name=BucketedRoleManagement]", $detailRow), matchedBucket));
            loadComponent($("[name=details]", $detailRow), "CompanyDetails", (c) => c.init(app, $(".component[name=CompanyDetails]", $detailRow), company));
        };

        companyGrid.columns = [
            { field: "Name", title: "[resource_displayname[name]]" }
        ];

        await companyGrid.init();
    },

    save: async function (e, companyGrid) {
        e.preventDefault();
        var item = companyGrid.dataItem($(e.currentTarget).closest("tr"));
        await api.update("B2B/Company(" + item.Id + ")", item)
            .then(() => { notification.success("[resource_displayname[saved]]"); companyGrid.refresh(); })
            .catch((err) => error(err));
    },

    removeCompany: async function (e, companyGrid, groupBucketId) {
        e.preventDefault();
        var item = companyGrid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
        var matchedBucket = item.Buckets.map(b => b.Bucket).filter(r => r.ParentId === groupBucketId)[0];
        await api.destroy("B2B/BucketCompany(BucketId=" + matchedBucket.Id + ",CompanyId=" + item.Id + ")")
            .then(() => { notification.success("[resource_displayname[deleted]]"); companyGrid.refresh(); })
            .catch((err) => error(err));
    }
};
