</script>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"B2BAdminCompany","ResourceKey":"B2B","Script":"B2BAdminCompany = {
	init: async function(app, container, groupBucket) {
		app = app || session.app;
		container = container || $(".component[name=B2BAdminCompany]");
		if(!groupBucket)
			return;

		var companyData = await model.getDatasource({
			endpoint: "B2B/Company",
			odataAppend: "?$filter=Buckets/any(b: b/Bucket/ParentId eq " + groupBucket + ")&$expand=Address,References,Buckets($expand=Bucket)",
			sort: { field: "Name", dir: "asc"}
		});
		var companyGrid = new GridWidget(container, companyData);
		companyGrid.groupable = false;
		companyGrid.filterable = true;
		companyGrid.editable = true;
		companyGrid.detailTemplate = $("[name=companyDetails]", container).first().html();
		companyGrid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" });
		companyGrid.commands.push({ name: "remove", icon: "k-i-trash", text: "[resource_displayname[delete]]" });
		companyGrid.dataBound = function (e) {
			$("[name=save]", companyGrid.gridElement).off("click").on("click", (e) => B2BAdminCompany.save(e, companyGrid));
			$("[name=remove]", companyGrid.gridElement).off("click").on("click", (e) => B2BAdminCompany.removeCompany(e, companyGrid, groupBucket));
			$("[name=exportByFundingType]", companyGrid.gridElement).on("click", (e) => B2BAdminCompany.exportCompaniesByFundingType(e, app, companyGrid, groupBucket));
		};
		companyGrid.pageable.responsive = false;

		companyGrid.detailExpand = async (e) => {
			if($(".tab-control", $(e.detailRow)).attr('tabs-initialised')) {
				return;
			}

			var id = Guid();

			$(e.detailRow).html($(e.detailRow).html().replace(new RegExp('\{ID\}', 'g'), id));
			$('.tab-control', $(e.detailRow)).attr('tabs-initialised', true);

			var company = companyGrid.dataItem($(e.masterRow).closest("tr"));
			var matchedBucket = company.Buckets.filter(b => b.Bucket.ParentId === groupBucket)[0].Bucket;

			loadComponent($("[name=security]", $(e.detailRow)), "BucketedRoleManagement", (c) => c.init(app,$(".component[name=BucketedRoleManagement]", $(e.detailRow)), matchedBucket));
			loadComponent($("[name=details]", $(e.detailRow)), "CompanyDetails", (c) => c.init(app,$(".component[name=CompanyDetails]", $(e.detailRow)), company));
		};
		companyGrid.columns = [
			{ field: "Name", title: "[resource_displayname[name]]" },
		];

		var bucket = await api.get(`B2B/Bucket(${groupBucket})`);

		if(bucket.Key == 'CreditorGroup') {
			companyGrid.toolbar = [{
				template: `<button class="btn btn-sm btn-primary" name="exportByFundingType">[resource_displayname[exportFundableCompanies]]</button>`
			}];
		}

		await companyGrid.init();
	},

	initBsTabs: function(container) {
		var id = Guid();

		var tabs = $('.nav.nav-tabs', container);
		var detailsButton = $('#b2b-admin-company-details-tab', tabs);
		var securityButton = $('#b2b-admin-company-security-tab', tabs);
		var detailsPane = $('#b2b-admin-company-details', tabs);
		var securityPane = $('#b2b-admin-company-security', tabs);

		tabs.attr('bs-id', id);
		detailsButton.attr('id', `${detailsButton.attr('id')}-${id}`);
		securityButton.attr('id', `${securityButton.attr('id')}-${id}`);
		detailsPane.attr('id', `${detailsPane.attr('id')}-${id}`);
		securityPane.attr('id', `${securityPane.attr('id')}-${id}`);

		detailsButton.attr('data-bs-target', `#${detailsPane.attr('id')}`);
		securityButton.attr('data-bs-target', `#${securityPane.attr('id')}`);

		detailsButton.attr('aria-controls', detailsPane.attr('id'));
		securityButton.attr('aria-controls', securityPane.attr('id'));

		detailsPane.attr('aria-labelledby', detailsButton.attr('id'));
		securityPane.attr('aria-labelledby', securityButton.attr('id'));
	},

	save: async function (e, companyGrid) {
		e.preventDefault();
		var item = companyGrid.dataItem($(e.currentTarget).closest("tr"));
		await api.update("B2B/Company(" + item.Id + ")", item).then(() => {
			notification.success("[resource_displayname[saved]]");
			companyGrid.refresh();
		}).catch((err) => error(err));
	},

	removeCompany: async function (e, companyGrid, groupBucketId) {
		e.preventDefault();
		var item = companyGrid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
		var matchedBucket = item.Buckets.map(b => b.Bucket).filter(r => r.ParentId === groupBucketId)[0];
		console.log(item, matchedBucket);
		await api.destroy("B2B/BucketCompany(BucketId=" + matchedBucket.Id + ",CompanyId=" + item.Id + ")").then(() => {
			notification.success("[resource_displayname[deleted]]");
			companyGrid.refresh();
		}).catch((err) => error(err));
	},

	exportCompaniesByFundingType: async function(e, app, companyGrid, groupBucketId) {
		var fundingBuckets = (await api.get(`B2B/Bucket?filter=Key eq 'FundingType' and startswith(Path,'${app.TenantId}')&$expand=Companies($expand=Company($expand=Address,References))&$select=Name,companies`))
			.value;

		var fundedCompanies = [{
			FundingType: '[resource_displayname[fundingType]]',
			Name: '[resource_displayname[name]]',
			GlobalTaxRef: '[resource_displayname[globalTaxReference]]',
			SystemRef: '[resource_displayname[systemReference]]'
		}];

		fundingBuckets.map(b => { 
			var companies = [];

			for(var c in b.Companies) {
				var company = b.Companies[c].Company;
				company.FundingType = b.Name;

				var globalTaxRef = company.References.filter(r => r.SystemId == "GlobalTax")[0]?.Value;
				var systemRef = company.References.filter(r => r.SystemId == app.Config.B2B.SourceSystem)[0]?.Value;

				var result = {
					FundingType: b.Name,
					Name: company.Name,
					GlobalTaxRef: globalTaxRef ?? '',
					SystemRef: systemRef ?? ''
				};

				companies.push(result);
			}

			return companies; 
		}).map(c => fundedCompanies.push(c));

		var finalSet = fundedCompanies
			.flat()
			.map(c => `${c.FundingType},${c.Name},${c.GlobalTaxRef},${c.SystemRef}`)
			.join("\n");

		var csvContent = 'data:text/csv;charset=utf-8,' + finalSet;
		var encodedUri = encodeURI(csvContent);
		var link = document.createElement("a");
		link.setAttribute("href", encodedUri);
		link.setAttribute("download", 'companies-by-funding-type.csv');
		document.body.appendChild(link);
		link.click();
	}
}"}

