    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=B2BAdminFunderCompany]");
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Company]],
                    [meta[B2B/Bucket]]
                ]
            }
        ]);

        var rootBucket = await api.get(`B2B/Bucket(${app.Config.B2B.RootBucket})?$expand=Buckets`);
        var funderBucket = rootBucket.Buckets.find(b => b.Key === "FunderGroup");
        if (!funderBucket) {
            console.warn("FunderGroup bucket not found");
            return;
        }

        var groupBucketId = funderBucket.Id;

        var companies = await model.getDatasource({
            endpoint: "B2B/Company",
            odataAppend: `?$filter=Buckets/any(b: b/Bucket/ParentId eq ${groupBucketId})&$expand=Address,References,Buckets($expand=Bucket)`,
            sort: { field: "Name", dir: "asc" }
        });

        if (!companies) {
            console.warn("No companies found in FunderGroup bucket");
            return;
        }

        // Initialize grid
        var companyGrid = new GridWidget(container, companies);
        companyGrid.groupable = false;
        companyGrid.filterable = true;
        companyGrid.editable = true;
        companyGrid.detailTemplate = "<div class='funder-company-detail-container'></div>";
        companyGrid.columns = [{ field: "Name", title: "[resource_displayname[name]]" }];
        companyGrid.pageable.responsive = false;

        companyGrid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" });
        companyGrid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });

        companyGrid.dataBound = function () {
            $("[name=save]", companyGrid.gridElement).off("click").on("click", (e) => B2BAdminFunderCompany.save(e, companyGrid));
            $("[name=delete]", companyGrid.gridElement).off("click").on("click", (e) => B2BAdminFunderCompany.destroy(e, companyGrid, groupBucketId));
        };

        companyGrid.detailExpand = async function (e) {
            var $detailContainer = $(e.detailRow).find(".funder-company-detail-container");
            var company = companyGrid.dataItem($(e.masterRow).closest("tr"));
            var matchedBucket = company.Buckets.filter(b => b.Bucket.ParentId === groupBucketId)[0].Bucket;

            // Load tabs template
            var html = $("[name=funderCompanyDetailsTemplate]").html().replace(/{ID}/g, company.Id);
            $detailContainer.html(html);

            loadComponent($("[name=details]", $detailContainer), "CompanyDetails", (c) => c.init(app, $(".component[name=CompanyDetails]", $detailContainer), company));
            loadComponent($("[name=security]", $detailContainer), "BucketedRoleManagement", (c) => c.init(app, $(".component[name=BucketedRoleManagement]", $detailContainer), matchedBucket));
            loadComponent($("[name=fundingtypes]", $detailContainer), "B2BAdminFundingTypes", (c) => c.init(app, $(".component[name=B2BAdminFundingTypes]", $detailContainer), matchedBucket.Id));
        };

        await companyGrid.init();
    },

    save: async function (e, companyGrid) {
        e.preventDefault();
        var item = companyGrid.dataItem($(e.currentTarget).closest("tr"));
        await api.update(`B2B/Company(${item.Id})`, item)
            .then(() => { notification.success("[resource_displayname[saved]]"); companyGrid.refresh(); })
            .catch(err => error(err));
    },

    destroy: async function (e, companyGrid, groupBucketId) {
        e.preventDefault();
        var item = companyGrid.dataItem($(e.currentTarget).closest("tr"));
        var matchedBucket = item.Buckets.filter(r => r.Bucket.ParentId === groupBucketId && r.Bucket.Key === "Funder")[0];
        if (!matchedBucket) return;

        await api.destroy(`B2B/Bucket(${matchedBucket.Bucket.Id})`)
            .then(() => { notification.success("[resource_displayname[deleted]]"); companyGrid.refresh(); })
            .catch(err => error(err));
    }
};"}

