            odataAppend: "?$filter=Key eq 'FundingType' and ParentId eq " + funderBucketId
        });

        var fundingTypeGrid = new GridWidget(container, dataSource);

        fundingTypeGrid.toolbar =
            "<button class='btn btn-sm btn-primary float-end' name='add'>" +
            "<span class='k-icon k-i-plus'></span>[resource_displayname[add]] </button> " +
            "<button class='btn btn-sm btn-primary float-end' name='fundingDetails'>" +
            "<span class='k-icon k-i-chart-area-stacked'></span>[resource_displayname[fundingsummary]] </button>";

        fundingTypeGrid.groupable = false;
        fundingTypeGrid.filterable = false;
        fundingTypeGrid.pageable = false;
        fundingTypeGrid.commandWidth = 110;
        fundingTypeGrid.editable = true;

        fundingTypeGrid.detailTemplate = function () {
            return $("[name=TypeDetails]").html();
        };

        fundingTypeGrid.detailExpand = async function (e) {
            var bucket = fundingTypeGrid.dataItem($(e.masterRow));
            var container = $(e.detailRow);

            if ($(".tab-control", container).attr("tabs-initialised")) {
                return;
            }

            var id = Guid();
            $(container).html($(container).html().replace(new RegExp("{ID}", "g"), id));
            $(".tab-control", container).attr("tabs-initialised", true);

            $("[name=companies]", container).html(
                $("[name=bucketedCompanyManagementComponent]").first().html()
            );

            $("[name=fundingdetails]", container).html(
                $("[name=fundingDetailsComponent]").first().html()
            );

            BucketedCompanyManagement.init(
                app,
                $(".component[name=BucketedCompanyManagement]", container),
                bucket
            );

            FundingDetails.init(
                app,
                $(".component[name=FundingDetails]", container),
                bucket.Id
            );
        };

        fundingTypeGrid.columns = [
            { field: "Name", title: "[resource_shortdisplayname[name]]" },
            { field: "Description", title: "[resource_shortdisplayname[description]]" }
        ];

        fundingTypeGrid.dataBound = () => {
            $("[name=save]", fundingTypeGrid.gridElement).on(
                "click",
                async (e) => await B2BAdminFundingTypes.save(e, fundingTypeGrid)
            );

            $("[name=delete]", fundingTypeGrid.gridElement).on(
                "click",
                async (e) => await B2BAdminFundingTypes.destroy(e, fundingTypeGrid)
            );
        };

        fundingTypeGrid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_shortdisplayname[save]]" });
        fundingTypeGrid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_shortdisplayname[delete]]" });

        await fundingTypeGrid.init();

        $("[name=add]", fundingTypeGrid.gridElement).on(
            "click",
            async (e) => await B2BAdminFundingTypes.create(e, fundingTypeGrid, funderBucketId)
        );

        $("[name=fundingDetails]", fundingTypeGrid.gridElement).on("click", async (e) => {
            e.preventDefault();

            var d = new Dialog({ title: "[resource_displayname[fundingsummary]]", width: 1200, height: 600 });
            d.init(async () => {
                var dataSource = await model.getDatasource({
                    endpoint: "B2B/Bucket",
                    odataAppend: "(" + funderBucketId + ")/FundingSummaryOverview()"
                });

                var g = new GridWidget(d.element, dataSource);
                g.groupable = false;
                g.columns = [
                    { field: "Scheme", title: "[resource_displayname[scheme]]", width: 150 },
                    { field: "Description", title: "[resource_displayname[description]]", width: 200 },
                    { field: "Formula", title: "[resource_displayname[formula]]" },
                    {
                        field: "IsSystematic",
                        type: "boolean",
                        title: "[resource_shortdisplayname[issystematic]]",
                        width: 80,
                        template: "<input type='checkbox' disabled class='k-checkbox k-checkbox-md k-rounded-md' name='isSystematic' #=(IsSystematic) ? 'checked' : ''# />"
                    }
                ];
                g.init();
            });
        });
    },

    create: async function (e, grid, parentBucketId) {
        e.preventDefault();

        var model = kendo.observable({
            Id: "00000000-0000-0000-0000-000000000000",
            ParentId: parentBucketId,
            Key: "FundingType",
            Name: "",
            Description: ""
        });

        var createDialog = new Dialog({ title: "[resource_displayname[addfundingtypebucket]]" });
        createDialog.template = $("[name=addFundingType]").first().html();

        createDialog.events.create = async function () {
            await api.add("B2B/Bucket", model.toJSON())
                .then(() => {
                    notification.success("[resource_displayname[fundingtypecreated]]");
                    grid.refresh();
                    createDialog.events.close();
                })
                .catch((err) => error(err));
        };

        createDialog.init(() => {
            kendo.bind(createDialog.element, model);
        });
    },

    destroy: async function (e, grid) {
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        var bucket = await api.get("B2B/Bucket(" + item.Id + ")");
        await api.destroy("B2B/Bucket(" + bucket.Id + ")", bucket)
            .then(() => {
                notification.success("[resource_displayname[deleted]]");
                grid.refresh();
            })
            .catch((e) => error(e));
    },

    save: async function (e, grid) {
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        var bucket = await api.get("B2B/Bucket(" + item.Id + ")");
        bucket.Name = item.Name;
        await api.update("B2B/Bucket(" + bucket.Id + ")", bucket).catch((e) => error(e));
        notification.success("[resource_displayname[saved]]");
        grid.refresh();
    }
};
"}

