    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=B2BAdminTools]");
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/System]],
                    [meta[B2B/Company]],
                    [meta[B2B/Currency]]
                ]
            }
        ]);

        $("[name=importCompaniesFromData]", container).on("click", async (e) => await B2BAdminTools.importCompanyData(e, app));
        $("[name=clearCompanies]", container).off("click").on("click", async (e) => await B2BAdminTools.clearCompanies(e, app));
        $("[name=migrateFunderData]", container).on("click", async (e) => await B2BAdminTools.migrateFunderData(e,app));

        $("[name=importTransactionsFromData]", container).on("click", async (e) => await B2BAdminTools.importTransactionData(e,app));
        $("[name=clearTransactions]", container).on("click", async (e) => await B2BAdminTools.clearTransactions(e, app));

        var folder = await api.get("Core/Folder?$filter=Path eq 'data' and AppId eq " + app.Id);
        if(folder.value.length === 0) {
            $("[name=createDMSStructure]", container).on("click", async (e) => await B2BAdminTools.createDMSStructure(e));
        } else {
            $("[name=dmsComponent]", container).hide();
        }

        var task = await api.get("Core/ScheduledTask?$filter=AppId eq " + app.Id + "and contains(Name, 'offer')")
        if(task.value.length > 0 ){
            $("[name=generateOffers]", container).on("click", async (e) => await B2BAdminTools.generateOffers(e,app));
        } else {
            $("[name=fundingComponent]", container).hide();
        }

        $("[name=createBuyerAdminAccount]", container).on("click", (e) => B2BAdminTools.createBuyerAdminAccount(e, app));
    },

    createDMSStructure: async function(e) {
        e.preventDefault();
        await api.post("DMS/data/transactions/received", null);
        await api.post("DMS/data/transactions/transformed", null);
        await api.post("DMS/data/transactions/processed", null);
        await api.post("DMS/data/masterdata/received", null);
        await api.post("DMS/data/masterdata/transformed", null);
        await api.post("DMS/data/masterdata/processed", null);
        notification.success("[resource_displayname[built]]");
    },

    importCompanyData: async function (e, app) {
        e.preventDefault();
        var newCompanyDataDialog = new Dialog({
            width: 1200,
            height: 500,
            title: "[resource_displayname[importCompanyData]]"
        });
        newCompanyDataDialog.component = "CSVMasterdataLineCreator";
        newCompanyDataDialog.init(() => CSVMasterdataLineCreator.init(app, $(".component[name=CSVMasterdataLineCreator]", newCompanyDataDialog.element)));
    },

    clearCompanies: async function(e, app) {
        e.preventDefault();

        var d = new ConfirmDialog({
            title: "[resource_displayname[areyousure]]",
            question: "[resource_displayname[cannotbeundone]]",
            confirm: "[resource_displayname[confirm]]"
        });

        d.events.confirm = async function () {
            var consoleDialog = new ConsoleDialog();
            consoleDialog.title = "[resource_displayname[clearcompanies]]";
            consoleDialog.init();

            var rootBucketId = app.Config.B2B.RootBucket;
            consoleDialog.log("info", "[resource_displayname[deletingbuckets]]");
            await api.post('B2B/Bucket/ClearDown?rootBucketId=' + rootBucketId);

            consoleDialog.log("success", "[resource_displayname[cleared]]");
            consoleDialog.events.close();
        };

        d.init();
    },

    migrateFunderData: async function(e, app) {
        e.preventDefault();
        var dialog = new Dialog({ width: 600, height: 250, title: "[resource_displayname[migrateFunderData]]" });
        dialog.component = "MigrateFunderData";
        dialog.init(() => MigrateFunderData.init(app, $(".component[name=MigrateFunderData]", dialog.element), dialog));
    },

    importTransactionData: async function (e, app) {
        e.preventDefault();
        var newTransactionDataDialog = new Dialog({ width: 1450, height: 320, title: "[resource_displayname[importTransactionData]]" });
        newTransactionDataDialog.component = "CSVTransactionLineCreator";
        newTransactionDataDialog.init(() => CSVTransactionLineCreator.init(app, $(".component[name=CSVTransactionLineCreator]", newTransactionDataDialog.element)));
    },

    clearTransactions: async function(e, app) {
        e.preventDefault();
        var sourceSystem = app.Config.B2B.SourceSystem;
        var d = new ConfirmDialog({
            title: "[resource_displayname[areyousure]]",
            question: "[resource_displayname[cannotbeundone]]",
            close: "[resource_displayname[close]]",
            confirm: "[resource_displayname[confirm]]"
        });
        d.events.confirm = async function () {
            var consoleDialog = new ConsoleDialog();
            consoleDialog.title = "[resource_displayname[cleardowntransactions]]";
            consoleDialog.init();

            await api.destroy("B2B/Transactions/ClearDown?sourceSystemId=" + sourceSystem).catch((e) => {
                consoleDialog.log("error", JSON.stringify(e));
                error(e);
            });
            consoleDialog.log("success", "[resource_displayname[cleared]]");
            consoleDialog.events.close();
        };
        d.init();
    }
}"}

