<div name="splitter">
	<div class="panel left">
		<div name="treeRoot"></div>
	</div>
	<div class="panel right" name="workspace"></div>
</div>
<style>
    .component[name=B2BManagement], 
    .component[name=B2BManagement]>[name=splitter] { margin: 0; border: none; box-shadow: none; width: 100%;  height: 100%; }
	.component[name=B2BManagement]>[name=splitter]>.panel { height: 100%; }
    .component[name=B2BManagement]  [name=treeRoot] { padding: 10px; }
   .component[name=B2BManagement] [name=workspace] { overflow: visible; right: 0; }
</style>","Script":"var B2BManagement = {
	init: function (app, container) {
		app = app || session.app;
		container = container || $('.component[name=B2BManagement]');
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/App]],
				]
			}
		]);
		$(window).on("resize", function (e) { B2BManagement.resize(container); });
		B2BManagement.resize(container);
		var workspace = $("workspace", container);
		var treeRoot = $("[name=treeRoot]", container);
		treeRoot.on("contextmenu", ".k-in", function (e) { B2BManagement.tree.rightClick(e, app, container); });
		$("[name=splitter]", container).kendoSplitter({
			scrollable: false,
			panes: [
				{ collapsible: false, size: "320px" },
				{ collapsible: false, scrollable: false }
			]
		});
		// initialize the tree
		var tree = treeRoot.kendoTreeView({
			dataSource: new kendo.data.HierarchicalDataSource({
				data: [{
					text: app.Name,
					spriteCssClass: "root",
					type: "Root",
					data: null,
					expanded: false,
					hasChildren: true
				}]
			}),

			// events
			expand: function (e) { B2BManagement.tree.expandNode(e, app, container); },
			collapse: B2BManagement.tree.collapseNode,
		})
			.data("kendoTreeView");

		if (!app.Config.B2B.RootBucket) {
			B2BManagement.createRootBucket(app, function (newRoot) {
				tree.expand(".k-item:first");
			});
		} else {
			tree.expand(".k-item:first");
		}
	},

	resize: function (container) {
		var headerHeight = $("body > header").height();
		var footerHeight = $("body > footer").height();
		var bodyHeight = $("body").height();
		container.height(bodyHeight - (headerHeight + footerHeight) - 3);
		container.width("100%");
	},

	tree: {
		dragStart: function (e) {
			var nodeData = this.dataItem(e.sourceNode);
			if (nodeData.data == null) {
				e.preventDefault();
				$(e.element).addClass("k-denied");
			}
		},

		drop: async function (e) {
			e.preventDefault();
			var dropNode = this.dataItem($(e.dropTarget).closest(".k-in"));
			var dragNode = this.dataItem($(e.sourceNode));
			var newNode = {
				text: dragNode.text,
				//type: "Page",
				//spriteCssClass: "page",
				expanded: false,
				hasChildren: true,
				data: dragNode,
				//draggable: true,
				//droppable: ["Page"]
			};
			// apply move
			var index = this.dataItem($(e.sourceNode).parent()).items.indexOf(dragNode);
			this.dataItem($(e.sourceNode).parent()).items.splice(index, 1);
			if (dropNode.type != "Root") {
				dropNode.items.push(dragNode);
				dragNode.data.ParentId = dropNode.data.Id;
			}
			else {
				dropNode.items.push(dragNode);
				dragNode.data.ParentId = null;
			}

			// update the server
			await api.update("Core/Page(" + dragNode.data.Id + ")", dragNode.data);
			notification.success("[resource_displayname[PageMoved]]");
		},

		rightClick: function (e, app, container) {
			$("[name=contextMenu]").remove();
			e.preventDefault();
			var tree = $("[name=treeRoot]", container).data("kendoTreeView");
			var bucket = tree.dataItem(e.target).data || { Id: app.Config.B2B.RootBucket };
			// if we dont have nodedata.data then we have a root level page
			container.append("<div name='contextMenu' class='contextMenu'></div>");
			var menu = $("[name=contextMenu]");
			menu.css({
				display: "block",
				position: "absolute",
				left: e.pageX - 3,
				top: e.pageY - 3
			})

			loadComponent(menu, "BucketContextMenu", function (comp) {
				BucketContextMenu.init(app, bucket, function (operation) {
					menu.remove();
					var node = operation === "delete"
						? tree.parent(e.target)
						: e.target;

					tree.collapse(node);
					setTimeout(function () { tree.expand(node); }, 400);
				});
			});
		},

		collapseNode: function (e) {
			var nodeData = this.dataItem(e.node);
			$(nodeData).children('.k-group').remove();
			if (nodeData.data != null) {
				nodeData.loaded(false);
				e.node.loaded = false;
			}
		},

		expandNode: async function (e, app, container) {
			var tree = $("[name=treeRoot]", container).data("kendoTreeView");
			var nodeData = tree.dataItem(e.node);
			var bucket = nodeData.data;

			if (!bucket) { bucket = { Id: app.Config.B2B.RootBucket }; }

			var items = nodeData.children.data();
			for (var i = 0, max = items.length; i < max; i++) {
				var item = tree.findByUid(items[0].uid);
				tree.remove(item);
			}
			var children = await api.get("B2B/Bucket?$filter=ParentId eq " + bucket.Id);
			var newNodes = children.value.map(function (c) {
				return {
					text: c.Name,
					type: c.Key,
					spriteCssClass: "page",
					expanded: false,
					hasChildren: true,
					data: c,
					//draggable: true,
					//droppable: ["Page"]
				};
			});

			for (var i = 0; i < newNodes.length; i++) { nodeData.items.push(newNodes[i]); }
		}
	},

	createRootBucket: async function (app, callback) {
		var newBucket = {
			Name: app.Name + " Root",
			Key: "AppRoot",
			Description: "Root bucket for application @ " + app.Domain
		};
		var res = await api.add("B2B/Bucket", newBucket);
		app.Config.B2B.RootBucket = res.Id;
		callback(res);
		var a = {
			Id: app.Id,
			DefaultCultureId: app.DefaultCultureId,
			Name: app.Name,
			Domain: app.Domain,
			DefaultTheme: app.DefaultTheme,
			ConfigJson: JSON.stringify(app.Config, null, "\t")
		};
		var meta = await api.getType("Core/App");
		model.prepareItem(a, meta);
		a.save(null, function () {
			//drop the cached copy form the front end
			$.ajax({
				type: "DELETE",
				url: "../app",
				beforeSend: api.beforeSend
			});
			notification.success("[resource_displayname[AppSaved]]");
		});
	}
};


