{"Content":"","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B Admin","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"B2BRolePrivManagement","ResourceKey":"B2B","Script":"B2BRolePrivManagement = {
    init: async function(app, container, role) {
        app = app || session.app;
        container = container || $(".component[name=B2BRolePrivManagement]");
        if(!role) { return; }
        var privs = (await api.get("B2B/B2BPrivilege")).value;
        privs.forEach(p => p.Has = (role.Privs.indexOf(p.Id) !== -1));
        var rolePrivGrid = new GridWidget(container, {data: privs});
        rolePrivGrid.columns=[
            {field: "Has", title: " ", template: "<input class='k-select-checkbox k-checkbox k-checkbox-md k-rounded-md' type='checkbox' #= (Has == true) ? checked ='checked' : '' # class='chkbx k-checkbox'/>", width: 40},
            {field: "Type", title: "[resource_displayname[Type]]" },
            {field: "Operation", title: "[resource_displayname[Operation]]"},
            {field: "Description", title: "[resource_displayname[PrivExplanation]]"}
        ];
        rolePrivGrid.groupable = false;
        rolePrivGrid.editable = false;
        rolePrivGrid.pageable = false;
        rolePrivGrid.filterable = false;
        rolePrivGrid.sortable = false;
        rolePrivGrid.dataBound = () => B2BRolePrivManagement.onGridDataBound(role, rolePrivGrid);
        await rolePrivGrid.init();
        rolePrivGrid.kendoObject.dataSource.group({field: "Type"});
    },

    onGridDataBound: function(role, rolePrivGrid) {
        $("input[type=checkbox]", rolePrivGrid.gridElement)
            .off("click")
            .on("click", e => B2BRolePrivManagement.onPrivClick(e, role, rolePrivGrid));
    },

    onPrivClick: async function(e, role, rolePrivGrid) {
            e.preventDefault();
            var dataItem = rolePrivGrid.kendoObject.dataItem($(e.target).closest("tr"));
            dataItem.set("Has", e.target.checked);

            role.Privs = rolePrivGrid.kendoObject.dataSource
                .data()
                .filter(p => p.Has)
                .map(p => p.Id)
                .join(',');
        
            await role.save()
                .then(() => { notification.success("[resource_displayname[rolesaved]]"); })
                .catch((err) => { error(err); });
        }
}"}

