    init: async function (app, container, role) {
        app = app || session.app;
        container = container || $(".component[name=B2BRoleUserManagement]");
        if(!role) { return; }
        api.addToMetaCache([
        {
            Name: "Core",
            Types: [
                [meta[Core/User]]
            ]
        },
        {
            Name: "B2B",
            Types: [
                [meta[B2B/B2BUserRole]]
            ]
        }]);
        var dataSource = await model.getDatasource({ endpoint: "B2B/B2BUserRole", odataAppend: "?$filter=RoleId eq " + role.Id + "&$expand=User" });
        var usersGrid = new GridWidget(container, dataSource);
        usersGrid.commandWidth = 100;
        usersGrid.columns = [
            { field: "UserId", title: "[resource_displayname[userid]]" },
            { field: "User.EmailAddress", title: "[resource_displayname[email]]" }
        ];
        usersGrid.pageable = false;
        usersGrid.editable = false;
        usersGrid.toolbar = [
            {
                template: `<div class="btn-group btn-group-sm">
                    <button class="btn btn-primary" name="addUser">
                        <span class="k-icon k-i-plus"></span>[resource_displayname[adduserbyid]]
                    </button>
                    <button class="btn btn-primary" name="addUsers">
                        <span class="k-icon k-i-plus"></span>[resource_displayname[selectusers]]
                    </button>
                </div>`
            }
        ];
        usersGrid.groupable = false;
        usersGrid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });
        usersGrid.dataBound = function() { 
            $("[name=delete]", usersGrid.gridElement).on("click", async function(e) {
		        var item = usersGrid.dataItem($(e.currentTarget).closest("tr"));
                await B2BRoleUserManagement.deleteUser(item);
            });
        };
        await usersGrid.init();
        $("[name=addUser]", usersGrid.gridElement).on("click", async (e) => await B2BRoleUserManagement.addUser(e, container, role, usersGrid));
        $("[name=addUsers]", usersGrid.gridElement).on("click", async (e) => await B2BRoleUserManagement.addUsers(e, container, app, usersGrid, role));
    },

    deleteUser: async function(roleUser) {
        await api.destroy("B2B/B2BUserRole(RoleId=" + roleUser.RoleId + ",UserId='" + roleUser.UserId + "')").then(() => {
            notification.success("[resource_displayname[userdeleted]]");
        }).catch((err) => error(err));
    },

	addUsers: async function(e, container, app, grid, role) {
        e.preventDefault();
        var userGrid = null;
        var userDialog = new Dialog({
            title: "[resource_displayname[selectusers]]",
            width: 800,
        });
        userDialog.template = $("[name=selectUsersDialog]", container).first().html();
        userDialog.events.select = async function(e) {
            e.preventDefault();
			var selected = userGrid.select();
            for(let i = 0; i < selected.length; i++) {
				await api.post("B2B/B2BUserRole", {RoleId: role.Id, UserId: selected[i].Id}).then(() => {
					grid.refresh();
				}).catch((e) => error(e));
			}
			userDialog.events.close();
        };
        userDialog.init(async () => {
            var userData = await model.getDatasource({endpoint: "Core/User", odataAppend: "?$filter=Roles/any(r: r/Role/AppId eq " + app.Id + ") and IsActive eq true"});
            userGrid = new GridWidget($("[name=selectUsersGrid]", userDialog.element), userData);
			userGrid.filterable = true;
			userGrid.groupable = false;
            userGrid.editable = false;
            userGrid.columns = [
                {selectable: true, width: 50},
                { field: "Id", title: "[resource_displayname[id]]" },
                { field: "DisplayName", title: "[resource_displayname[displayname]]" },
                { field: "Email", title: "[resource_displayname[email]]" }
            ];
            userGrid.init();
        });
    },

    addUser: async function (e, container, role, usersGrid) {
        e.preventDefault();
        var addUserDialog = new Dialog({
            title: "[resource_displayname[AddUser]]",
            width: 450
        });
        addUserDialog.template = $("[name=addUserDialog]", container).html();
        addUserDialog.events.confirm = async function (e) {
            var model = {
                RoleId: role.Id,
                UserId: $("[name=UserId]", addUserDialog.element).val()
            };
            await api.add("B2B/B2BUserRole", model).then(() => {
                notification.success("[resource_displayname[AddedUserToRole]]");
                usersGrid.refresh();
                addUserDialog.events.close();
            }).catch((err) => error(err));
        };
        addUserDialog.init();
    }
}"}

