</style>","Script":"B2BUserInfo = {
    init: async function(app, container, userId) {
        app = app || session.app;
        container = container || $(".component[name=B2BUserInfo]");
        if(!userId && !getQueryParameter("userId")) {
            return;
         }
        api.addToMetaCache([
        {
            "Name": "B2B",
            "Types": [
                [meta[B2B/B2BRole]]
            ]
        }]);
         var userId = userId || getQueryParameter("userId");
         var b2bUser = await api.get("B2B/B2BUser('" + userId + "')");
         B2BUserInfo.setupUserInfoDetails($("[name=userDetails]", container), b2bUser);
         B2BUserInfo.setupRoleGrid($("[name=roles]", container), b2bUser);
    },

    setupUserInfoDetails: function(container, userInfo) {
        var detailView = new ReadOnlyDetailView(container);
        detailView.title = "#=Id# [resource_displayname[details]]";
        detailView.fields = [
            { field: "DisplayName", title: "[resource_displayname[displayname]]", description: "[resource_description[displayname]]" },
            { field: "EmailAddress", title: "[resource_displayname[emailaddress]]", description: "[resource_description[emailaddress]] "},
            { field: "Id", title: "[resource_displayname[id]]", description: "[resource_description[id]]" },
            { field: "IsActive", title: "[resource_displayname[isactive]]", description: "[resource_description[isactive]]" },
            { field: "MobilePhone", title: "[resource_displayname[mobilephone]]", description: "[resource_displayname[mobilephone]]" },
            { field: "WorkPhone", title: "[resource_displayname[workphone]]", description: "[resource_description[workphone]]" }
        ];
        detailView.init(userInfo);
    },

    setupRoleGrid: async function(container, userInfo) {
        var roleInfo = (await api.get("B2B/B2BRole?$filter=Users/any(u: u/UserId eq '" + userInfo.Id +"')&$expand=Buckets")).value;
        for(let i = 0; i < roleInfo.length; i++) {
            roleInfo[i].App = "";
        }

        var rootBuckets = await B2BUserInfo.getRootBucketDatabase();
        for(let i = 0; i < roleInfo.length; i++) {
            var buckets = [...new Set(roleInfo[i].Buckets.map(l => l.BucketId.toLowerCase()))];
            var rootBucketMatchesInApp = rootBuckets.filter(r => buckets.includes(r.RootBucket.toLowerCase()));
            if(rootBucketMatchesInApp.length === 0) {
                if(roleInfo[i].Buckets.length > 0) {
                    var rootBucketInfo = await api.post("B2B/Bucket/DetermineRootBuckets", { value: [roleInfo[i].Buckets[0].BucketId] });
                    var rootBucketId = rootBucketInfo.value[0].Details;
                    rootBucketMatchesInApp = rootBuckets.filter(r => rootBucketId === r.RootBucket.toLowerCase());
                }
            }
            roleInfo[i].App = rootBucketMatchesInApp.map(l => l.Name).join();
        }
        var roleGrid = new GridWidget(container, { data: roleInfo, pageSize: 20 });
        roleGrid.groupable = false;
        roleGrid.editable = false;
        roleGrid.columns = [
            { field: "Id", title: "[resource_displayname[id]]"},
            { field: "Name", title: "[resource_displayname[name]]" },
            { field: "Description", title: "[resource_displayname[description]]" },
            { field: "CreatedOn", title: "[resource_displayname[createdon]]", type: "date", format: "{0:"+ type.dateFormat + "}", width: 100},
            { field: "LastUpdated", title: "[resource_displayname[lastupdated]]", type: "date", format: "{0:"+ type.dateFormat + "}", width: 100},
            { field: "UsersArePortalAdmins", title: "[resource_displayname[usersareportaladmins]]", template: "#=(UsersArePortalAdmins) ? '<span class=\"k-icon k-i-check\"></span>' : ''#", width: 80 },
            { field: "App", title: "[resource_displayname[App]]" }
        ];
        await roleGrid.init();
    },

    getRootBucketDatabase: async function() {
        return (await api.get("Core/App")).value.map((a) => {
            var config = JSON.parse(a.ConfigJson);
            if(config && config.B2B && config.B2B.RootBucket) {
                return { Name: a.Name, Domain: a.Domain, RootBucket: config.B2B.RootBucket };
            }
        }).filter(r => r);
    }
}","CreatedOn":"2022-05-17T12:23:26.186Z","LastUpdated":"2022-05-17T12:23:26.186Z"}

{"Key":"Content Mangaement","Name":"BackgroundJobs","ResourceKey":"CMS","Content":"<style scoped>
   .component [name=BackgroundJobs] { flex: none !important; height: 100%; }
   .component[name=BackgroundJobs] > [name=BackgroundJobsGrid] { flex: none !important; height: 100%; }
    </style>","Script":"BackgroundJobs = {
    states: {
        "Queued": "[resource_displayname[queued]]",
        "Running": "[resource_displayname[running]]",
        "Failed": "[resource_displayname[failed]]"
    },

    init: async function(app, container) {
        app = app || session.app;
        container = container || $(".component[name=BackgroundJobs]");
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/BackgroundJob]]
				]
			}
		]);
        await BackgroundJobs.setupGrid(app, container);
    },

    setupGrid: async function(app, container) {
        var dataSource = await model.getDatasource({
            endpoint: "Core/BackgroundJob",
            odataAppend: "?$filter=AppId eq " + app.Id
        });
        var grid = new GridWidget(container, dataSource);
        grid.filterable = true;
        grid.groupable = false;
        grid.columns = [
            {field: "CreatedBy", title: "[resource_displayname[createdby]]"},
            {
                field: "State", 
                title: "[resource_displayname[state]]", 
                template: "#=BackgroundJobs.states[State]#",
                editor: function(container, options) {
                    var input = $("<input/>");
                    input.attr("name", options.field);
                    if(options.model.State === "Running") {
                        input.attr("disabled", "");
                    }
                    input.appendTo(container);
                    input.kendoDropDownList({
                        dataTextField: "name",
                        dataValueField: "name",
                        dataSource: [
                            { name: "Queued" },
                            { name: "Failed" }
                        ]
                    });
                }
            },
            {field: "CreatedOn", title: "[resource_displayname[createdon]]", type: "date", format: "{0:" + type.dateFormat + " hh:mm" + "}"},
            {field: "LastUpdated", title: "[resource_displayname[lastupdated]]", type: "date", format: "{0:" + type.dateFormat + " hh:mm" +  "}"}
        ];
        grid.commands.push({name: "save", icon: "k-i-save", text: "[resource_displayname[save]]"});
        grid.dataBound = function() {
            $("[name=save]", grid.gridElement).on("click", (e) => BackgroundJobs.save(e, grid));
        };
        await grid.init();
    },

    save: async function(e, grid) {
        e.preventDefault();
        var item = grid.dataItem($(e.currentTarget).closest("tr")).toJSON();
        delete item.type;
        await api.update("Core/BackgroundJob(" + item.Id + ")", item).then(() => {
            notification.success("[resource_displayname[saved]]");
            grid.refresh();
        }).catch((err) => error(err));
    }
}","CreatedOn":"2022-04-11T11:08:26.731Z","LastUpdated":"2022-04-11T11:08:26.731Z"}

