    init: async function (app, container, observable) {
        app = app || session.app;
        container = container || $(".component[name=Border]");
        if(!observable)
            return;

        $("[name=borderStyleDropdown]", container).kendoDropDownList({
            dataTextField: "text",
            dataValueField: "name",
            change: function(e) {
                e.preventDefault();
                var existingBorderValue = observable.get("border.style");
                var parts = existingBorderValue.split(" ");
                parts[0] = this.value();
                observable.set("border.style", parts.join(" "));
            },
            dataSource: {
                data: [
                    { name: "dotted", text: "[resource_displayname[dotted]]" },
                    { name: "dashed", text: "[resource_displayname[dashed]]" },
                    { name: "solid", text: "[resource_displayname[solid]]" },
                    { name: "double", text: "[resource_displayname[double]]" },
                    { name: "groove", text: "[resource_displayname[groove]]" },
                    { name: "ridge", text: "[resource_displayname[ridge]]" },
                    { name: "inset", text: "[resource_displayname[inset]]" },
                    { name: "outset", text: "[resource_displayname[outset]]" },
                    { name: "none", text: "[resource_displayname[none]]" },
                    { name: "hidden", text: "[resource_displayname[hidden]]" }
                ]
            }
        });

        $("[name=borderColorPicker]", container).kendoColorPicker({
            buttons: false,
            value: observable.get("border.style").split(" ")[2],
            change: function(e) {
                e.preventDefault();
                var existingBorderValue = observable.get("border.style");
                var parts = existingBorderValue.split(" ");
                parts[2] = this.value();
                observable.set("border.style", parts.join(" "));
            }
        });

        await Border.initSliders(container, observable);
    },

    initSliders: async function(container, observable) {
        $("[name=borderWidthSlider]", container).kendoSlider({ 
            min: 0, 
            max: 20, 
            smallStep: 1, 
            largeStep: 2, 
            value: parseFloat(observable.get("border.style").split(" ")[1].replaceAll("px", "")),
            change: function(e) {
                e.preventDefault();
                var existingBorderValue = (observable.get("border.style") || "solid 0px");
                var parts = existingBorderValue.split(" ");
                parts[1] = this.value() + "px";
                observable.set("border.style", parts.join(" "));
                observable.set("border.width", this.value() + "px");
            }
        });

        $("[name=borderRadiusSlider]", container).kendoSlider({ 
            min: 0, 
            max: 20, 
            smallStep: 1, 
            largeStep: 2, 
            value: parseFloat((observable.get("border.radius") || "0px").replaceAll("px", "")),
            change: function(e) {
                e.preventDefault();
                var existingBorderValue = (observable.get("border.radius") || "0px");
                var parts = existingBorderValue.split(" ");
                parts[1] = this.value() + "px";
                observable.set("border.radius", this.value() + "px");
            }
        });
    }
}"}

