   .toolbar > .itemGroup > li .k-icon { color: #1c7add; }
   .lanes { margin: 5px; border-collapse: collapse; }
   .lanes th { text-align: left; width: 300px; border-left: solid 2px #EEE; border-right: solid 2px #EEE; background: #DDD; padding: 10px; }
   .lanes th span[name=laneName] { font-size: 120%; }
