   .artifact > button { position: relative; float: right; vertical-align: top; top: -28px; right: -25px; padding-left: 4px; padding-right: 1px; width: 10px; height: 15px; }
   .artifact > button > .k-icon { font-size: 9px; }

   .artifact > span.k-icon { position: absolute; }
