</style>","Script":"BPEditor = {
	init: async function (app, container) {
		if (!app) { app = session.app; }
		if (!container) { container = $(".component[name=BPEditor]"); }
		var meta = [
			{
				"Name": "Core",
				"Types": [
					[meta[Core/BusinessProcess]]
				]
			}
		];

		$(window).on("resize", function (e) { BPEditor.resize(); });
		BPEditor.resize();

		$("[name=splitter]", container).kendoSplitter({
			orientation: "horizontal",
			panes: [
				{ collapsible: false, resizable: false, size: "271px" },
				{ collapsible: false, resizable: false }
			]
		});

		var url = window.location.search.replace('?', '').split('&');
		var idParam = url.filter(u => u.indexOf('id=') >= 0)[0];
		var id = idParam.replace('id=', '');
		var bp = await api.get("Core/BusinessProcess(" + id + ")");
		await api.getType("Core/BusinessProcess").then((meta) => {
			model.prepareItem(bp, meta);
		});
		var def = JSON.parse(bp.DefinitionJson);
		if (!def) {
			def = {
				Lanes: [
					{ Id: 0, Name: "Source" },
					{ Id: 1, Name: "Portal (CLX)" },
					{ Id: 2, Name: "Destination" },
				],
				Links: [
					{ From: 0, To: 1 },
					{ From: 1, To: 2 },
					{ From: 2, To: 3 }
				],
				Artifacts: [
					{ Id: 0, Lane: 0, Row: 1, Type: "External", Text: "Data Sent to DMS", DataKey: null },
					{ Id: 1, Lane: 1, Row: 1, Type: "Core/Folder", Text: "Data Import Folder (DMS)", DataKey: "Data/Import" },
					{ Id: 2, Lane: 1, Row: 2, Type: "Core/FlowDefinition", Text: "Process Received Data", DataKey: "Import" },
					{ Id: 3, Lane: 1, Row: 3, Type: "B2B/Bucket", Text: "Add Invoices to Bucket", DataKey: "New Invoices" }
				]
			};
		}

		BPEditor.setup(container, def);
		$(".toolbar > .itemGroup > li").kendoDraggable({ hint: function (e) { return e.clone(); } });
		$(".toolbar button[name=showDef]", container).on('click', function (e) { BPEditor.showDefinition(e, def, function (d) { def = d; BPEditor.setup(container, def); }); });
		$(".toolbar button[name=save]", container).on('click', function (e) { BPEditor.save(e, bp, def); });
	},

	showDefinition: function (e, def, updateCallback) {
		$("body").append("<div name='definitionDialog' style='overflow: hidden;'></div>");
		var dialog = $("[name=definitionDialog]").kendoWindow({
			title: "Artifact Details",
			width: 600,
			height: 360,
			closable: true,
			modal: false,
			close: function (e) { this.destroy(); $("[name=definitionDialog]").remove(); }
		});
		dialog.append(
			"<textarea name='definition'>" + JSON.stringify(def, null, "\t") + "</textarea>" +
			"<hr/>" +
			"<button name='update' style='float: right; margin-right: 10px;'><span class='k-icon k-i-save'></span>Update Diagram</button>"
		);
		dialog.data("kendoWindow").center().open();
		var editor = CodeMirror.fromTextArea($("textarea", dialog)[0], { tabsize: 4, indentUnit: 4, mode: "javascript", lineWrapping: false });

		$("button[name=update]", dialog).on('click', function (e) {
			updateCallback(JSON.parse(editor.getValue()));
		});
	},

	setup: function (container, def) {
		var lanes = $("table[name=lanes]", container);
		lanes.empty();
		lanes.append(BPEditor.buildLanes(lanes, def));
		lanes.append(BPEditor.buildRows(lanes, def));
		BPEditor.buildLinks(lanes, def);
		var cells = $(".lanes td", container);
		cells.kendoDropTarget({
			//dragenter: droptargetOnDragEnter,
			//dragleave: droptargetOnDragLeave,
			drop: function (e) { if (BPEditor.drop(e, def)) { BPEditor.setup(container, def); }; }
		});
		$(".artifact", lanes).kendoDraggable({ hint: function (e) { return e.clone(); } });
		$(".artifact > .details", lanes).on("click", function (e) { BPEditor.showDetails(e, container, def); });
		$(".artifact > button[name=drop]", lanes).on("click", function (e) { BPEditor.removeArtifact(e, def); BPEditor.setup(container, def); });
	},

	removeArtifact: function (e, def) {
		e.preventDefault();
		var cellPos = BPEditor.getCellPos($(e.target).closest("td"));
		var victim = def.Artifacts.filter(function (a) { return a.Lane == cellPos.Lane && a.Row == cellPos.Row; })[0];
		def.Artifacts = def.Artifacts.filter(function (a) { return !(a.Lane == cellPos.Lane && a.Row == cellPos.Row); });
		def.Links = def.Links.filter(function (a) { return !(a.From == victim.Id || a.To == victim.Id); });
	},

	showDetails: function (e, container, def) {
		var cellPos = BPEditor.getCellPos($(e.target).closest("td"));
		var artifact = def.Artifacts.filter(function (a) { return a.Lane == cellPos.Lane && a.Row == cellPos.Row; })[0];
		$("body").append("<div name='artifactDetailsDialog'></div>");
		var links = "";
		var link = function (direction) { return "<button name='" + direction + "'><span class='k-icon k-i-arrow-chevron-" + direction + "'></span></button>"; }
		if (def.Artifacts.filter(function (a) { return a.Lane == cellPos.Lane && a.Row == cellPos.Row - 1; }).length > 0) { links += link("up"); }
		if (def.Artifacts.filter(function (a) { return a.Lane == cellPos.Lane && a.Row == cellPos.Row + 1; }).length > 0) { links += link("down"); }
		if (def.Artifacts.filter(function (a) { return a.Lane == cellPos.Lane - 1 && a.Row == cellPos.Row; }).length > 0) { links += link("left"); }
		if (def.Artifacts.filter(function (a) { return a.Lane == cellPos.Lane + 1 && a.Row == cellPos.Row; }).length > 0) { links += link("right"); }

		var template = kendo.template($("[name=artifactDetails]").html().replace("[LINKS]", links));

		var dialog = $("[name=artifactDetailsDialog]").kendoWindow({
			width: "450px",
			title: "Artifact Details",
			closable: true,
			modal: false,
			close: function (e) { this.destroy(); $("[name=artifactDetailsDialog]").remove(); }
		});
		dialog.append(template(artifact));
		dialog.data("kendoWindow").center().open();

		$("button", dialog).on('click', function (e) {
			var direction = $(e.currentTarget).attr("name");
			var filter = BPEditor.artifactFilter(direction, artifact);
			var other = def.Artifacts.filter(filter)[0];
			BPEditor.toggleLink(def, artifact.Id, other.Id);
			BPEditor.setup(container, def);
		});
	},

	artifactFilter: function (direction, source) {
		if (direction === "up") { return function (a) { return a.Lane == source.Lane && a.Row == source.Row - 1; }; }
		if (direction === "down") { return function (a) { return a.Lane == source.Lane && a.Row == source.Row + 1; }; }
		if (direction === "left") { return function (a) { return a.Lane == source.Lane - 1 && a.Row == source.Row; }; }
		if (direction === "right") { return function (a) { return a.Lane == source.Lane + 1 && a.Row == source.Row; }; }
	},

	toggleLink: function (def, from, to) {
		var existingLink = def.Links.filter(function (link) { return (link.From == from && link.To == to) || (link.From == to && link.To == from); });
		if (existingLink.length > 0) { def.Links = def.Links.filter(function (link) { return !((link.From == from && link.To == to) || (link.From == to && link.To == from)); }); }
		else { def.Links.push({ From: from, To: to }); }
	},

	buildLanes: function (lanes, def) {
		var header = "<thead><tr>";
		$.each(def.Lanes, function (i, lane) {
			header += "<th data-lane-id='" + lane.Id + "'><button style='left: -8px;' name='addLaneBefore'>+</button><span name='laneName'>" + lane.Name + "</span><button style='float: right;' name='addLaneAfter'>+</button><button style='float: right;' name='removeLane'>-</button></th>";
		});
		header += "</tr><thead>";
		return header;
	},

	buildRows: function (lanes, def) {
		var rowsNeeded = Math.max.apply(null, def.Artifacts.map(function (i) { return i.Row; }));
		rowsNeeded += 10;
		var append = "<tbody>";
		for (var i = 1; i < rowsNeeded; i++) {
			append += BPEditor.buildRow(lanes, i, def) + "</tr>";
		}
		append += "</tbody>";
		return append;
	},

	buildRow: function (lanes, rowIndex, def) {
		var row = "<tr data-row-id='" + rowIndex + "'>";
		for (var i = 0; i < def.Lanes.length; i++) {
			row += "<td data-index='" + i + "-" + rowIndex + "'>";
			var a = def.Artifacts.filter(function (artifact) { return artifact.Lane == i && artifact.Row == rowIndex; });
			if (a.length > 0) { row += BPEditor.buildArtifact(a[0]); }
			row += "</td>";
		}
		row += "</tr>";
		return row;
	},

	buildArtifact: function (artifact, container) {
		var menuItem = $(".toolbar li[data-type=" + artifact.Type.replace("/", "_") + "]", container);
		var artifactTypeIcon = "<span class='typeIcon " + $("span.k-icon", menuItem).attr("class") + "'></span>";
		var remove = "<button name='drop'><span class='k-icon k-i-close'></span></button>";
		return "<div class='artifact' >" + remove + "<div class='details'>" + artifactTypeIcon + artifact.Text + "</div></div>";
	},

	buildLinks: function (lanes, def) {
		$.each(def.Links, function (i, link) {
			var fromArtifact = def.Artifacts.filter(function (a) { return a.Id == link.From; })[0];
			var toArtifact = def.Artifacts.filter(function (a) { return a.Id == link.To; })[0];
			BPEditor.drawConnector(fromArtifact, toArtifact, lanes);
		});
	},

	drawConnector: function (from, to, lanes) {
		// identify their hosting cells
		var container = $("td[data-index=" + from.Lane + "-" + from.Row + "] > .artifact", lanes);

		var diff = { Lane: to.Lane - from.Lane, Row: to.Row - from.Row };
		if (diff.Row > 0) { container.append("<span class='k-icon k-i-arrow-seek-down'></span>"); }
		if (diff.Row < 0) { container.append("<span class='k-icon k-i-arrow-seek-up'></span>"); }
		if (diff.Lane > 0) { container.append("<span class='k-icon k-i-arrow-seek-right'></span>"); }
		if (diff.Lane < 0) { container.append("<span class='k-icon k-i-arrow-seek-left'></span>"); }
	},

	getRelativeCell: function (lanes, cell, x, y) {
		var index = $(cell).data("index").split("-");
		return $("td[data-index=" + (parseInt(index[0]) + x) + "-" + (parseInt(index[1]) + y) + "]", lanes);
	},

	resize: function () {
		var root = $('[name=BPEditor].component');
		var headerHeight = $("body > header").height();
		var footerHeight = $("body > footer").height();
		var bodyHeight = $("body").height();
		root.height(bodyHeight - (headerHeight + footerHeight) - 3);
		root.width("100%");
	},

	dragStart: function (e) {
		ev.dataTransfer.setData("text", ev.target.outerHtml);

	},

	drag: function (e) {
		e.originalEvent.dataTransfer.setData("source", e.target.outerHtml);
		var canDrop = $(e.target).closest(".lanes").length > 0 && $(e.target).find(".artifact").length == 0;
		if (canDrop) { e.preventDefault(); }
	},

	drop: function (e, def) {
		e.preventDefault();
		e.draggable.dropped = true;
		var source = $(e.draggable.currentTarget);
		var cell = BPEditor.getCellPos(e.dropTarget);
		// new artifact was dropped on to the diagram
		if (source[0].nodeName === "LI") {
			def.Artifacts.push({ Id: def.Artifacts.length, Type: source.data("type"), Lane: cell.Lane, Row: cell.Row, Text: source.text(), DataKey: null });
		}

		// artifact was moved
		if (source.hasClass("artifact")) {
			var sourceCell = source.closest("td");
			var sourceIndex = BPEditor.getCellPos(sourceCell);
			var artifact = def.Artifacts.filter(function (a) { return a.Lane == sourceIndex.Lane && a.Row == sourceIndex.Row })[0];
			artifact.Lane = cell.Lane;
			artifact.Row = cell.Row;
			def.Links = def.Links.filter(function (link) { return !(link.From == artifact.Id || link.To == artifact.Id); });
		}
		return true;
	},

	getCellPos: function (cell) { return { Lane: parseInt(cell.data("index").split("-")[0]), Row: parseInt(cell.data("index").split("-")[1]) }; },

	save: function (e, bp, def) {
		bp.DefinitionJson = JSON.stringify(def);
		bp.save(e, function () {
			notification.success("[resource_displayname[BusinessProcessSaved]]");
		});
	}
};

lineTool = {
	createLineElement: function (x, y, length, angle) {
		var line = document.createElement("div");
		var styles = 'border: 1px solid black; '
			+ 'width: ' + length + 'px; '
			+ 'height: 0px; '
			+ '-moz-transform: rotate(' + angle + 'rad); '
			+ '-webkit-transform: rotate(' + angle + 'rad); '
			+ '-o-transform: rotate(' + angle + 'rad); '
			+ '-ms-transform: rotate(' + angle + 'rad); '
			+ 'position: relative; '
			+ 'top: ' + y + 'px; '
			+ 'left: ' + x + 'px;';
		line.setAttribute('style', styles);
		line.setAttribute("role", "connector");
		return line;
	},

	createLine: function (x1, y1, x2, y2) {
		var a = x1 - x2, b = y1 - y2, c = Math.sqrt(a * a + b * b);
		var sx = (x1 + x2) / 2, sy = (y1 + y2) / 2;
		var x = sx - c / 2, y = sy;
		var alpha = Math.PI - Math.atan2(-b, a);
		return lineTool.createLineElement(x, y, c, alpha);
	}
};

