	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=BPM]");
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/BusinessProcess]]
				]
			}
		]);
		if(!window.knownTypes) {
            window.knownTypes = await api.get('GetMetadata');
        }
		await BPM.setupGrid(app, container);
	},

	setupGrid: async function (app, container) {
		var processes = await model.getDatasource({
            endpoint: "Core/BusinessProcess",
            odataAppend: "?$filter=AppId eq " + app.Id
        });
		var grid = new GridWidget(container, processes);
		grid.groupable = false;
		grid.pageable = false;
		grid.toolbar = "<button class='btn btn-sm btn-primary' name='create'><span class='k-icon k-i-plusIcon'></span>[resource_displayname[new]]</button>";
		grid.columns = [
			{ field: "Category", width: 100, title: "[resource_displayname[category]]" }, 
			{ field: "ReportingComponentName", width: 200, title: "[resource_displayname[reportingcomponentname]]" }, 
			{ field: "Name", width: 200, title: "[resource_displayname[name]]" }, 
			{ field: "CreatedBy", width: 130, editable: false, title: "[resource_displayname[createdby]]" },
			{ field: "Created", width: 100, editable: false, title: "[resource_displayname[created]]", format: "{0:" + type.dateFormat + "}" }, 
			{ field: "LastUpdatedBy", editable: false, width: 130, title: "[resource_displayname[lastupdatedby]]" }, 
			{ field: "LastUpdated", editable: false, width: 100, title: "[resource_displayname[lastupdated]]", format: "{0:" + type.dateFormat + "}" }, 
			{ field: "Description", title: "[resource_displayname[description]]" }
		];
		grid.commands.push({
            name: "edit",
            icon: "k-i-edit",
            href: "../Admin/BusinessProcesses/Editor?id=#:Id#",
            text: "[resource_displayname[edit]]"
        });
		grid.commands.push({
            name: "save",
            icon: "k-i-save",
            text: "[resource_displayname[save]]"
        });
		grid.commands.push({
            name: "destroy",
            icon: "k-i-trash",
            text: "[resource_displayname[delete]]"
        });
		grid.dataBound = function() {
			$("[name=run]", grid.gridElement).on("click", (e) => BPM.run(e, grid));
			$("[name=destroy]", grid.gridElement).on("click", (e) => BPM.destroy(e, grid));
			$("[name=save]", grid.gridElement).on("click", (e) => BPM.save(e, grid));
		};
		grid.detailTemplate = kendo.template($("[name=processDetails]", container).html());
		grid.detailExpand = async function(e) {
			if ($("[name=flows]", $(e.detailRow))[0].childElementCount === 0) {
				var process = grid.dataItem(e.masterRow);

				$("[name=flows]", $(e.detailRow)).html($("[name=workflowManagementComponent]").first().html());
				WorkflowManagement.init(app, $(".component[name=WorkflowManagement]", $(e.detailRow)), process);
			}
		}
		await grid.init();
		$("[name=create]", grid.gridElement).on("click", (e) => BPM.create(e, app, grid));
		$("[name=migrate]", grid.gridElement).on("click", (e) => BPM.migrate(e, app));
	},

	migrate: function (e, app) {
		e.preventDefault();
		var d = new Dialog({ width: 620, height: "auto", title: "[resource_displayname[migratebp]]" });
		d.template = $("[name=bpMigrationComponent]").first().html();
		d.init(() => BPMigration.init(app, $(".component[name=BPMigration]", d.element), d));
	},

	create: async function (e, app, grid) {
		e.preventDefault();
		var today = new Date().toISOString().slice(0, 10);
		var newBP = kendo.observable({
			Name: "",
			Description: "",
			Category: "New",
			AppId: app.Id,
			LastUpdated: today,
			CreatedOn: today
		});
		var createDialog = new Dialog({
			title: "[resource_displayname[new]]", width: 400, height: 250
		})
		createDialog.template = $("[name=createBP]").html();
		createDialog.events.create = async function() {
			await api.add("Core/BusinessProcess", newBP.toJSON()).then(() => {
				grid.refresh();
				notification.success("[resource_description[created]]");
				createDialog.events.close();
			}).catch((err) => { error(err); });
		};
		createDialog.init(() => {
			kendo.bind(createDialog.element, newBP);
		});
	},

	destroy: async function (e, grid) {
		e.preventDefault();
		var bp = grid.dataItem($(e.currentTarget).closest("tr"));
		await bp.destroy(e).then(() => {
			grid.refresh();
			notification.success("[resource_description[businessprocessdeleted]]");
		}).catch((err) => error(err));
	},

	save: async function (e, grid) {
		e.preventDefault();
		var process = grid.dataItem($(e.currentTarget).closest("tr"));
		await process.save();
		notification.success("[resource_displayname[saved]]");;
		grid.refresh();
	}
}"}

{"AppId":11,"ResourceKey":"CMS","Content":"<ul class="fieldList">
