</style>","Script":"BPMigration = {
    init: async function (app, container, dialog) {
        app = app || session.app;
        container = container || $(".component[name=BPMigration]");
        if(!dialog) { return; } 
        api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/App]]
				]
			}
		]);
        let ds = await model.getDatasource({ endpoint: "Core/App" });
        $("[name=app]", container).kendoDropDownList({ autoBind: false, optionLabel: "[resource_displayname[selectapp]]", dataTextField: "Name", dataValueField: "Id", dataSource: ds });

        // Init environments list for migration dialog.
        var targets = app.Config.Deployment.Targets;
        $("[name=environment]", container).kendoDropDownList(
            { autoBind: false, optionLabel: "[resource_displayname[selectenvironment]]", dataTextField: "EnvironmentName", dataValueField: "EnvironmentName", dataSource: targets }
        );

        var businessProcesses = (await api.get("Core/BusinessProcess?$filter=AppId eq " + app.Id + "&$select=Name")).value;
        var g = new GridWidget($("[name=selectBpGrid]", container), businessProcesses);
        g.columns = [
            { selectable: true, width: 40 },
            { field: "Name" }
        ];
        g.groupable = false;
        await g.init();
        g.kendoObject.dataSource.sort({ field: "Name", dir: "asc" });
        g.kendoObject.select(g.kendoObject.tbody.find(">tr"));
        $("[name=migrate]", container).on("click", async function (e) {
            var packages = await BPMigration.getPackages($("[name=bpGrid]", container), app, g);
            var appId = session.app.Id;
            var targetSelected = $("[name=environment]", container).val();

            var targetApi = app.Config.Deployment.Targets.filter(r => r.EnvironmentName == targetSelected)[0].Api;
            var newApi = new Api({ apiRoot: targetApi });
            var userLogin = {
                User: session.user,
                Pass: $("[name=password]", container).val()
            };

            await newApi.login(userLogin.User, userLogin.Pass, true);
            await newApi.post("Core/Package/ImportThis?appId=" + appId, packages).then(() => {
                notification.success("[resource_displayname[migrated]]");
            }).catch((err) => error(err));
        });
    },

    getPackages: async function (container, app, businessProcessGrid) {
        var grid = businessProcessGrid.kendoObject;
        var businessProcesses = [];
        grid.select().each(function () {
            businessProcesses.push(grid.dataItem(this).Name);
        });
        var query = "";
        for (var i = 0; i < businessProcesses.length; i = i + 1) {
            query += "'" + businessProcesses[i] + "',";
        }
        query = query.substring(0, query.length - 1);
        var businessData = (await api.get("Core/BusinessProcess?$filter=AppId eq " + app.Id + " and Name in (" + query + ")")).value;
        var flows = [];
        for (var i = 0; i < businessData.length; i = i + 1) {
            var flowData = (await api.get("Core/FlowDefinition?$filter=AppId eq " + app.Id + " and ProcessId eq " + businessData[i].Id)).value;
            for (var j = 0; j < flowData.length; j = j + 1) {
                flowData[j].ProcessName = businessData[i].Name;
                flows.push(flowData[j]);
            }
        }
        var packages = [{
            Id: "00000000-0000-0000-0000-000000000000",
            Name: "Business Processes",
            Description: "Generated by BPMigration",
            Category: "Dynamic",
            SourceApi: session.apiRoot,
            Items: [
                {
                    Id: "00000000-0000-0000-0000-000000000000",
                    PackageId: "00000000-0000-0000-0000-000000000000",
                    Type: "Core/BusinessProcess",
                    Data: JSON.stringify(businessData.map(c => ({ Name: c.Name, ReportingComponentName: c.ReportingComponentName, Description: c.Description, Category: c.Category, LastUpdated: c.LastUpdated})))
                },
                {
                    Id: "00000000-0000-0000-0000-000000000000",
                    PackageId: "00000000-0000-0000-0000-000000000000",
                    Type: "Core/FlowDefinition",
                    Data: JSON.stringify(flows)
                }
            ]
        }];
        return packages;
    },

    getPackage: async function (container) {
        error("Unsupported for this component, due to multiple package export of both FlowDefinition and BusinessProcess.");
    }
};","Name":"BPMigration","Description":null,"Key":"Content Management"}

