    init: function (app, bucket, callback) {
        if (!app) { app = session.app; }
        var root = $(".component[name=BucketContextMenu]");
        if ((!bucket || bucket.Id === app.Config.B2B.RootBucket)) { $("[name=delete]", root).remove(); }

        $("[name=newChild]", root).on("click", function (f) {
            $(document).off("click");
            BucketContextMenu.newChild(app, bucket, callback);
        });

        $("[name=delete]", root).on("click", function (f) {
            $(document).off("click");
            BucketContextMenu.destroy(app, bucket, callback);
        });

        if (callback) $(document).on("click", callback);
    },

    newChild: function (app, bucket, callback) {
        $("body").append("<div name='newBucketDialog'>" + $("script[name=newBucket]").html() + "</div>");
        var dialog = $("[name=newBucketDialog]");
        var d = dialog.kendoWindow({
            visible: false,
            modal: true,
            resizable: false,
            width: 510,
            title: "New Bucket",
            deactivate: function (e) {
                this.destroy();
                if (callback) { callback("create"); }
            },
        }).data("kendoWindow");
        d.center();
        d.open();
        var key = $("select[name=Key]").val();
        var model = new kendo.data.ObservableObject({
            ParentId: bucket.Id,
            Key: key,
            Name: "",
            Description: ""
        });
        kendo.bind(dialog, model);
        $("button[name=submit]", dialog).click(async function (e) {
            delete model.uid;
            await api.add("B2B/Bucket", model).then((e) => {
                notification.success('[resource_description[SuccesfullyAddedNewPage]]'); d.close();
            }).catch((e) => {
                notification.error(e.responseJSON.error.message); d.close();
            });
        });
    },

    destroy: function (app, bucket, callback) {
        if (confirm('[resource_description[AreYouSure]]')) {
            api.destroy("B2B/Bucket(" + bucket.Id + ")").then((e) => {
                notification.success("[resource_description[BucketDeleted]]");
            }).catch((e) => {
                notification.error("[resource_description[BucketDeleteFailed]]");
            });
        }
        if (callback) { callback("delete"); }
    }
