	init: function (app, container, bucket) {
		app = app || session.app;
		container = container || $(".component[Name=BucketedCompanyManagement]");
		if (!bucket) { return; }
		api.addToMetaCache([
			{
				"Name": "B2B",
				"Types": [
					[meta[B2B/Company]]
				]
			}
		]);
		BucketedCompanyManagement.setupGrid(app, container, bucket);
	},

	setupGrid: async function (app, container, bucket) {
		var ds = await model.getDatasource({ endpoint: "B2B/Company",  odataAppend: "?$filter=Buckets/any(b:b/BucketId eq " + bucket.Id + ")&$expand=References"  });
		var grid = new GridWidget(container, ds);
		var systems = app.Config.B2B.SourceSystem.split(',');

		grid.toolbar = `<div class="btn-group btn-group-sm">
											<button name='add' <button class="btn btn-primary"><span class='k-icon k-i-plus'></span>[resource_displayname[addbyreference]]</button>
											<button name='selectcompanytoadd' class="btn btn-primary"'><span class='k-icon k-i-plus'></span>[resource_displayname[addcompanies]]</button>
											</div>`;
		grid.groupable = false;
		grid.editable = false;
		grid.columns = [
			{ field: "Name", title: "[resource_shortdisplayname[Name]]", width: 250 },
			{ field: "ContactEmailAddress", title: "[resource_shortdisplayname[ContactEmailAddress]]", width: 250 },
			{ field: "ContactPhoneNumber", title: "[resource_shortdisplayname[ContactPhoneNumber]]", width: 60 },
			{ field: "WebsiteUrl", title: "[resource_shortdisplayname[WebsiteUrl]]", width: 250 },
			{ field: "DateTradingEnabled", type: "date", title: "[resource_shortdisplayname[DateTradingEnabled]]", format: "{0:" + type.dateFormat + "}", width: 80 },
			{ field: "Reference", template: "#= References.map(c => c.Id).filter(c => c == 'GlobalTax' || BucketedCompanyManagement.systems().includes(c)).join(',') #" },
		];
		grid.commands.push({name:"remove", icon: "k-i-trash", text:"[resource_displayname[Delete]]"});
		grid.dataBound = function () {
			$("button[name=remove]", grid.gridElement).off("click").on("click",  (e) => BucketedCompanyManagement.remove(e, grid, bucket));
		};
		await grid.init();
		$("button[name=add]", grid.gridElement).off("click").on("click",  (e) =>  BucketedCompanyManagement.add(e, grid, bucket));
		$("button[name=selectcompanytoadd]", grid.gridElement).off("click").on("click",  (e) =>  BucketedCompanyManagement.selectCompanyToAdd(e, app, grid, bucket.Id));
	},

	selectCompanyToAdd: async function(e, app, grid, bucketId) {
        e.preventDefault();
        var sourceSystems = app.Config.B2B.SourceSystem;
        var companyGrid = null;
        var companyDialog = new Dialog({title: "[resource_displayname[selectcompanies]]", width: 800, height: 600});
        companyDialog.template = $("[name=selectcompaniesdialog]").first().html();
        companyDialog.events.select = async function(e) {
            e.preventDefault();
			var selected = companyGrid.select();
            for(let i = 0; i < selected.length; i++) {
				await api.post("B2B/BucketCompany", {BucketId: bucketId, CompanyId: selected[i].Id}).then(() => {
					grid.refresh();
					companyDialog.events.close();
					notification.success("[resource_displayname[CompanyAdded]]");
				}).catch((e) => error(e));
			}
			companyDialog.events.close();
        };
        companyDialog.init(async () => {
            var companyData = await model.getDatasource({endpoint: "B2B/Company", odataAppend: "/FromSystem(SystemId='" + sourceSystems + "')"});
            companyGrid = new GridWidget($("[name=selectCompaniesGrid]", companyDialog.element), companyData);
			companyGrid.filterable = true;
			companyGrid.groupable = false;
            companyGrid.columns = [
                {selectable: true, width: 50},
                { field: "Name", title: "[resource_displayname[name]]" }
            ];
            companyGrid.init();
        });
    },
	

	add: function (e, grid, bucket) {
		e.preventDefault();
		var d = new Dialog({
			title: "[resource_displayname[addbyreference]]",
			height: 200
		});
		d.template = $("[name=addCompanyDialog]").html();
		d.events.create = async function() {
			var reference = $("[name=name]", d.element).val();
			var matchedCompanies = await api.get("B2B/Company?$filter=References/any(r: r/Id eq '" + reference + "')&$expand=References");
			if(matchedCompanies.value.length > 0) {
				var matchedCompany = matchedCompanies.value[0];
				await api.post("B2B/BucketCompany", {BucketId: bucket.Id, CompanyId: matchedCompany.Id}).then(() => {
					grid.refresh();
					d.events.close();
					notification.success("[resource_displayname[CompanyAdded]]");
				}).catch((e) => { notification.error(e); });
			} else {
				notification.error("[resource_displayname[ReferenceNotFound]]");
			}
		};
		d.init();
	},

	remove: async function (e, grid, bucket) {
		e.preventDefault();
		var tr = $(e.currentTarget).closest("tr");
		var company = grid.dataItem(tr);
		await api.destroy("B2B/BucketCompany(BucketId="+bucket.Id +",CompanyId=" + company.Id + ")").then(()=>{
			notification.success("[resource_displayname[companyRemoved]]");
			grid.refresh();
		}).catch((err)=>error(err));
	},

	systems: function()  { 
		return session.app.Config.B2B.SourceSystem.split(',');
	}
}"}

