<div name="B2BRolePrivManagementComponent" style="display:none;">[component[B2BRolePrivManagement]]</div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"BucketedRoleManagement","ResourceKey":"B2B","Script":"BucketedRoleManagement = {
	init: async function (app, container, bucket) {
		app = app || session.app;
		container = container || $(".component[name=BucketedRoleManagement]");

		if (!bucket) {
			try {
				app = await api.get("Core/App(" + app.Id + ")");
				app.Config = JSON.parse(app.ConfigJson || "{}");

				const rootBucketId = app.Config?.B2B?.RootBucket;
				if (!rootBucketId) {
					error("No RootBucket found in app configuration. Please initialize B2B first.");
					return;
				}

				bucket = await api.get("B2B/Bucket(" + rootBucketId + ")?$expand=Buckets");
			} catch (err) {
				error(err);
				return;
			}
		}

		this.bucket = bucket;

        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/B2BRole]],
                ]
            }
        ]);
		await BucketedRoleManagement.setupRoleGrid(container, app, bucket);
	},

	setupRoleGrid: async function (container, app, bucket) {
		var config = { 
			endpoint: "B2B/B2BRole", 
			odataAppend: "?$filter=Buckets/any(r:r/BucketId eq " + bucket.Id + ")&$orderby=Name asc" 
		};
		var ds = await model.getDatasource(config);
		var roleGrid = new GridWidget(container, ds);
		roleGrid.groupable = false;
		roleGrid.editable = false;
		roleGrid.toolbar = [
			{
				template: `<div class="btn-group btn-group-sm">
					<button class="btn btn-primary" name="createRole">
						<span class="k-icon k-i-plus"></span>[resource_displayname[new]]
					</button>
				</div>`
			}
		];
		roleGrid.columns = [{ field: "Name", title: "[resource_shortdisplayname[Name]]" }];
		roleGrid.commands.push({ name: "save", icon: 'k-i-save', text: "[resource_displayname[save]]" });
		roleGrid.commands.push({ name: "delete", icon: 'k-i-trash', text: "[resource_displayname[delete]]" });

		roleGrid.detailTemplate = function () {
			return $("[name=roleDetails]").html();
		};

		roleGrid.detailExpand = function (e) { 
			BucketedRoleManagement.expandRole(e, app, roleGrid.kendoObject, bucket); 
		};
		roleGrid.dataBound = function () {
			$("[name=save]", roleGrid.gridElement).on("click", async (e) => 
				await BucketedRoleManagement.save(e, roleGrid.kendoObject)
			);
			$("[name=delete]", roleGrid.gridElement)
				.off("click")
				.on("click", async (e) => 
					await BucketedRoleManagement.destroy(e, roleGrid.kendoObject, bucket)
				);
		};

		await roleGrid.init();
		$("button[name=createRole]", roleGrid.gridElement)
			.off("click")
			.on("click", (e) => BucketedRoleManagement.createRole(bucket, roleGrid));
	},

	save: async function (e, grid) {
		e.preventDefault();
		var role = grid.dataItem($(e.currentTarget).closest("tr"));
		await role.save()
			.then(() => {
				notification.success("[resource_displayname[saved]]");
				grid.refresh();
			})
			.catch((err) => { error(err); });
	},

	destroy: async function (e, grid, bucket) {
		e.preventDefault();
		var row = $(e.currentTarget).closest("tr");
		var role = grid.dataItem(row);
		grid.dataSource.remove(role);
		await api.destroy("B2B/BucketRole(BucketId=" + bucket.Id + ",RoleId=" + role.Id + ")")
			.then(() => {
				notification.success("[resource_displayname[deleted]]");
				grid.refresh();
			})
			.catch((err) => { error(err); });
	},

	expandRole: async function (e, app, grid, bucket) {
		var role = grid.dataItem(e.masterRow);
		var container = $(e.detailRow);

		if ($(".tab-control", container).attr('tabs-initialised')) {
			return;
		}

		var id = Guid();
		$(container).html($(container).html().replace(new RegExp('{ID}', 'g'), id));
		$(".tab-control", container).attr('tabs-initialised', true);

		$("[name=users]", container).html($("[name=B2BRoleUserManagementComponent]").first().html());
		$("[name=privs]", container).html($("[name=B2BRolePrivManagementComponent]").first().html());

		B2BRoleUserManagement.init(app, $(".component[name=B2BRoleUserManagement]", container), role);
		B2BRolePrivManagement.init(app, $(".component[name=B2BRolePrivManagement]", container), role);
	},

	createRole: function (bucket, grid) {
		var newRole = {
			Id: "00000000-0000-0000-0000-000000000000",
			Name: "",
			Description: "",
			Buckets: [{ BucketId: bucket.Id }],
			CreatedOn: (new Date()).toISOString(),
			LastUpdated: (new Date()).toISOString(),
			UsersArePortalAdmins: false,
			Privs: ""
		};

		var addRoleDialog = new Dialog({
			title: "[resource_displayname[newRole]]",
			width: 450
		});

		addRoleDialog.template = $("[name=addRoleDialog]").html();

		addRoleDialog.events.confirm = async function () {
			newRole.Name = $("[data-bind='value: Name']", addRoleDialog.element).val();
			newRole.Description = $("[data-bind='value: Description']", addRoleDialog.element).val();

			await api.add("B2B/B2BRole", newRole)
				.then(() => {
					notification.success("[resource_displayname[rolecreated]]");
					grid.refresh();
					addRoleDialog.events.close();
				})
				.catch((err) => error(err));
		};

		addRoleDialog.init();
	}
}
"}

