        ]);
        await BucketedSystemsManagement.setupGrid(container, bucket);
    },

    setupGrid: async function (container, bucket) {
        var ds = await model.getDatasource({ endpoint: "B2B/System", odataAppend: "?$filter=Buckets/Any(b: b/BucketId eq " + bucket.Id + ")" });
        var grid = new GridWidget(container, ds);
        grid.sortable = true;
        grid.groupable = false;
        grid.filterable = true;
        grid.confirmation = false;
        grid.scrollable = true;
        grid.pageable = { refresh: true, pageSizes: true, buttonCount: 5 };
        grid.toolbar = kendo.template("<button name='add'><span class='k-icon k-i-plus'></span>[resource_displayname[AddSystem]]</button>");
        grid.columns = [
            { field: "Id", title: "[resource_shortdisplayname[Id]]", width: 120 }, 
            { field: "Name", title: "[resource_shortdisplayname[Name]]", width: 120 }, 
            { field: "Description", title: "[resource_shortdisplayname[Description]]" },
            { width: 100, template: "<a name='remove'><span class='k-icon k-i-delete'></span>[resource_displayname[Remove]]</a>" }
        ];
        grid.dataBound = function () {
            $("a[name=remove]", grid.gridElement).off().on("click", async function (e) { await BucketedSystemsManagement.remove(e, grid, bucket); });
        };
        await grid.init();
        $("button[name=add]", grid.gridElement).on("click", function (e) { BucketedSystemsManagement.addNew(e, grid, bucket); });
    },

    addNew: function (e, grid, bucket) {
        var model = kendo.observable({SystemId: null});
        var d = new Dialog({title: "[resource_displayname[AddNewSystem]]", width: 450, height: 130});
        d.template = $("[name=addSystemDialog]").html();
        d.init(() => {
            kendo.bind(d.element, model);
            $("button[name=submit]", d.element).on("click", async function(e) {
                await api.get("B2B/System('" + model.SystemId + "')").then(async (system) => {
                    await api.post("B2B/BucketSystem", { BucketId: bucket.Id, SystemId: system.Id }).then(() => {
                        notification.success("[resource_displayname[SystemAdded]]");
                        grid.refresh();
                        d.events.close();
                    }).catch((err) => error(err));
                }).catch(() => { notification.error("[resource_displayname[SystemNotFound]]"); });
            });
        });
    },

    remove: async function (e, grid, bucket) {
        e.preventDefault();
        var dataItem = grid.dataItem($(e.currentTarget).closest("tr"));
        await api.destroy("B2B/BucketSystem(BucketId=" + bucket.Id + ",SystemId='" + dataItem.Id + "')").then(() => {
            notification.success("[resource_displayname[SystemRemoved]]");
            grid.refresh();
        }).catch((err) => error(err));
    }
}
