   </style>","Script":"BucketManagement = {

    init: async function (app, container, rootBucket) {
        app = app || session.app;
        container = container || $(".component[name=BucketManagement]");
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Bucket]]
                ]
            }
        ]);
        if (!rootBucket) {
            if (!app.Config.B2B) {
                app.Config.B2B = {};
            }
            rootBucket = app.Config.B2B.RootBucket;
            await BucketManagement.setupGrid(app, container, rootBucket);
        } else {
            await BucketManagement.setupGrid(app, container, rootBucket);
        }
    },

    createRootBucket: async function (app, callback) {
        var functions = {
            [script[CreateBucketStructure]]
        };
        var vars = {
            App: app
        };
        var d = new Dialog({
            width: 800,
            height: 500
        });
        d.init(() => {
            loadComponent(d.element, "ScriptRunner", (c) => {
                ScriptRunner.init(app, d.element, vars, functions, d);
            });
        });
    },

    setupGrid: async function (app, container, rootBucket) {
        var ds = rootBucket ? await model.getDatasource({ endpoint: "B2B/Bucket", odataAppend: "?$filter=ParentId eq " + rootBucket + "&$expand=Roles" }) : { data: [] };
        var toolbar = "<button name='create'><span class='k-icon k-i-plus'></span>[resource_displayname[new]]</button>";
        if (!rootBucket) { toolbar += "<button name='createRootBucket'>[resource_displayname[createrootbucket]]</button>"; }
        var grid = new GridWidget(container, ds);
        grid.groupable = false;
        grid.filterable = true;
        grid.toolbar = toolbar;
        grid.columns = [
            { field: "Id", title: "[resource_displayname[Id]]", editor: function(element, options) { element.text(options.model.Id) }, width: 240 }, 
            { field: "Key", title: "[resource_shortdisplayname[Key]]" }, 
            { field: "Name", title: "[resource_shortdisplayname[Name]]" }, 
            { field: "Description", title: "[resource_shortdisplayname[Description]]" }
        ];
        grid.commands.push({name: "save", icon: "k-i-save", text: "[resource_displayname[save]]"});
        grid.commands.push({name: "destroy", icon: "k-i-delete", text: "[resource_displayname[delete]]"});
        grid.detailTemplate = $("script[name=bucketDetails]").first().html();
        grid.detailExpand = (e) => BucketManagement.expand(app, $(e.detailRow), grid.dataItem(e.masterRow));
        grid.dataBound = function (e) {
            $("a[name=save]", grid.gridElement).on("click", (e) => BucketManagement.save(e, grid));
            $("a[name=destroy]", grid.gridElement).on("click", (e) => BucketManagement.destroy(e, container, grid));
        };
        await grid.init();
        kendo.resize($("body"));
        $("button[name=createRootBucket]", grid.gridElement).on("click", (e) => BucketManagement.createRootBucket(app,  () => window.location.reload()));
        $("button[name=create]", grid.gridElement).on("click", (e) => BucketManagement.newBucket(e, container, rootBucket, grid));
    },

    expand: async function (app, container, bucket) {
        if (!$("[name=tabs", container).hasClass("k-tabstrip")) {
            $("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });
            await loadComponent($("[name=buckets]", container), "BucketManagement");
            BucketManagement.init(app, $(".component[name=BucketManagement]", container), bucket.Id);

            $("[name=systems]", container).html($("[name=bucketedSystemsManagementComponent]").first().html());
            $("[name=companies]", container).html($("[name=bucketedCompanyManagementComponent]").first().html());
            $("[name=roles]", container).html($("[name=bucketedRoleManagementComponent]").first().html());

            BucketedSystemsManagement.init(app, $(".component[name=BucketedSystemsManagement]", container), bucket);
            BucketedCompanyManagement.init(app, $(".component[name=BucketedCompanyManagement]", container), bucket);
            BucketedRoleManagement.init(app, $(".component[name=BucketedRoleManagement]", container), bucket);
        }

    },

    save: function (e, grid) {
        e.preventDefault();
        var bucket = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
        bucket.save(e, function () {
            notification.success("[resource_displayname[BucketSaved]]");
        });
    },

    destroy: function (e, container, grid) {
        e.preventDefault();
        var d = new ConfirmDialog({
            title: "[resource_displayname[areyousure]]",
            confirm: "[resource_displayname[confirm]]",
            close: "[resource_displayname[close]]",
            question: "[resource_displayname[areyousure]]"
        });
        d.events.confirm = function () {
            var bucket = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
            bucket.destroy(e, function () {
                notification.success("[resource_description[BucketDeleted]]");
                grid.kendoObject.dataSource.read();
                grid.kendoObject.refresh();
                d.events.close();
            }, (err) => error(err));
        };
        d.init();
    },

    newBucket: async function (e, container, parentId, grid) {
        e.preventDefault();
        var newBucket = {
            ParentId: parentId,
            Name: "",
            Key: "new",
            Description: ""
        };
        var args = {
            fields: [{ field: "Name", title: "[resource_displayname[name]]" }, { field: "Description", title: "[resource_displayname[description]]" }],
            title: "[resource_displayname[newbucket]]",
            data: newBucket,
            close: "[resource_displayname[close]]",
            confirm: "[resource_displayname[confirm]]"
        };
        var resources = api.getType("B2B/Bucket").Properties.map(c => ({Name: c.Name, Description: c.Description, ShortDisplayName: c.ShortDisplayName, DisplayName: c.DisplayName}));
        var addBucketDialog = new EditorDialog(args);
        addBucketDialog.events.confirm = async function () {
            newBucket = addBucketDialog.data.toJSON();//Remove all the kendo observable properties.
            await api.add("B2B/Bucket", newBucket).then((res) => {
                addBucketDialog.events.close();
                notification.success("[resource_description[BucketCreated]]");
                grid.kendoObject.dataSource.read();
                grid.kendoObject.refresh();
            }).catch((err) => error(err));
        };
        addBucketDialog.init(null, resources);
    }
};
