	days: {
		0: '[resource_displayname[sunday]]',
		1: '[resource_displayname[monday]]',
		2: '[resource_displayname[tuesday]]',
		3: '[resource_displayname[wednesday]]',
		4: '[resource_displayname[thursday]]',
		5: '[resource_displayname[friday]]',
		6: '[resource_displayname[saturday]]'
	},
	months: {
		1: "[resource_displayname[month-1]]",
		2: "[resource_displayname[month-2]]",
		3: "[resource_displayname[month-3]]",
		4: "[resource_displayname[month-4]]",
		5: "[resource_displayname[month-5]]",
		6: "[resource_displayname[month-6]]",
		7: "[resource_displayname[month-7]]",
		8: "[resource_displayname[month-8]]",
		9: "[resource_displayname[month-9]]",
		10: "[resource_displayname[month-10]]",
		11: "[resource_displayname[month-11]]",
		12: "[resource_displayname[month-12]]"
	},

	repeats: {
		"never": "[resource_displayname[never]]",
		"weekly": "[resource_displayname[weekly]]"
	},

	init: async function (app, container, args) {
		app = app || session.app;
		container = container || $(".component[name=CalendarManagement]");

		if (args && args.fromDate && args.toDate) {
			if (args.toDate < args.fromDate) {
				let copy = new Date(toDate.getTime());
				args.toDate = args.fromDate;
				args.fromDate = copy;
			}
		}

		var currentMonth = new Date().getMonth() + 1;
		var monthData = [];
		for (const [key, value] of Object.entries(CalendarManagement.months)) {
			monthData.push({
				Name: value,
				Number: key
			});
		}
		var yearData = [];
		var currentYear = new Date().getFullYear();
		for (var i = currentYear - 10; i < currentYear + 10; i++) {
			yearData.push(i);
		}

		var defaultArgs = {
			calendarId: app.Config.Calendars.primary,
			month: parseInt($("[name=month]", container).val()) - 1,
			year: parseInt($("[name=year]", container).val()),
			readOnly: (args && args.readOnly) ? true : false,
			eventSource: (args && args.eventSource) ? args.eventSource : null,
			fromDate: (args && args.fromDate) ? args.fromDate : null,
			toDate: (args && args.toDate) ? args.toDate : null,
			agendaView: (args && args.agendaView) ? true : false
		};

		var monthDropdown = $("[name=month]", container).kendoDropDownList({
			dataTextField: "Name",
			dataValueField: "Number",
			value: currentMonth,
			dataSource: monthData,
			change: async function () {
				await CalendarManagement.buildCalendar(container, defaultArgs);
			}
		}).data("kendoDropDownList");

		var yearDropdown = $("[name=year]", container).kendoDropDownList({
			dataSource: yearData,
			value: currentYear,
			change: async function () {
				await CalendarManagement.buildCalendar(container, defaultArgs);
			}
		}).data("kendoDropDownList");

		if (args && args.fromDate != null) {
			monthDropdown.value(args.fromDate.getMonth());
			yearDropdown.value(args.fromDate.getFullYear());
		}

		// await CalendarManagement.initCalendar(container, defaultArgs());
		$("[name=newcalendar]", container).on("click", (e) => CalendarManagement.newCalendar(e, app));
		$("[name=setprimary]", container).on("click", (e) => CalendarManagement.setPrimary(e, app, container));
		$("[name=deletecalendar]", container).on("click", (e) => CalendarManagement.deleteCalendar(e, container));

		if (args && args.readOnly)
			$("[name=toolbar]", container).remove();

		await CalendarManagement.buildCalendar(container, defaultArgs);
	},

	initialiseCalendarGrid: function(container) {
		var calendar = $('[name=calendar]', container);
		var calendarContent = '';
		var week = `
		<div class="row">
			<div class="col-calendar" name="{WEEK}-0" data-date="{FULLDATE}">
                <button class="btn btn-primary btn-sm float-end mt-1 me-1" name="add-event" data-date="{FULLDATE}"><span class="k-icon k-i-plus"></span>[resource_displayname[newevent]]</button>
				<div class="calendar-bar w-100"><p name="day">{DATE} [resource_displayname[sunday]]</p></div>
				<div class="events w-100"></div>
			</div>
			<div class="col-calendar" name="{WEEK}-1" data-date="{FULLDATE}">
                <button class="btn btn-primary btn-sm float-end mt-1 me-1" name="add-event" data-date="{FULLDATE}"><span class="k-icon k-i-plus"></span>[resource_displayname[newevent]]</button>
				<div class="calendar-bar w-100"><p name="day">{DATE} [resource_displayname[monday]]</p></div>
				<div class="events w-100"></div>
			</div>
			<div class="col-calendar" name="{WEEK}-2" data-date="{FULLDATE}">
                <button class="btn btn-primary btn-sm float-end mt-1 me-1" name="add-event" data-date="{FULLDATE}"><span class="k-icon k-i-plus"></span>[resource_displayname[newevent]]</button>
				<div class="calendar-bar w-100"><p name="day">{DATE} [resource_displayname[tuesday]]</p></div>
				<div class="events w-100"></div>
			</div>
			<div class="col-calendar" name="{WEEK}-3" data-date="{FULLDATE}">
                <button class="btn btn-primary btn-sm float-end mt-1 me-1" name="add-event" data-date="{FULLDATE}"><span class="k-icon k-i-plus"></span>[resource_displayname[newevent]]</button>
				<div class="calendar-bar w-100"><p name="day">{DATE} [resource_displayname[wednesday]]</p></div>
				<div class="events w-100"></div>
			</div>
			<div class="col-calendar" name="{WEEK}-4" data-date="{FULLDATE}">
                <button class="btn btn-primary btn-sm float-end mt-1 me-1" name="add-event" data-date="{FULLDATE}"><span class="k-icon k-i-plus"></span>[resource_displayname[newevent]]</button>
				<div class="calendar-bar w-100"><p name="day">{DATE} [resource_displayname[thursday]]</p></div>
				<div class="events w-100"></div>
			</div>
			<div class="col-calendar" name="{WEEK}-5" data-date="{FULLDATE}">
                <button class="btn btn-primary btn-sm float-end mt-1 me-1" name="add-event" data-date="{FULLDATE}"><span class="k-icon k-i-plus"></span>[resource_displayname[newevent]]</button>
				<div class="calendar-bar w-100"><p name="day">{DATE} [resource_displayname[friday]]</p></div>
				<div class="events w-100"></div>
			</div>
			<div class="col-calendar" name="{WEEK}-6" data-date="{FULLDATE}">
                <button class="btn btn-primary btn-sm float-end mt-1 me-1" name="add-event" data-date="{FULLDATE}"><span class="k-icon k-i-plus"></span>[resource_displayname[newevent]]</button>
				<div class="calendar-bar w-100"><p name="day">{DATE} [resource_displayname[saturday]]</p></div>
				<div class="events w-100"></div>
			</div>
		</div>`;

		for(var w = 0; w < 6; w++) {
			var temp = week;
			calendarContent += temp.replaceAll('{WEEK}', w);
		}

		calendar.html(calendarContent);
	},

	sunday: 0,

	populateCalendarDates: function(container, startDate, endDate) {
		var current = new Date(startDate.toISOString()); // Create a copy of the start date
		var end = endDate
			? new Date(endDate)
			: null;

		if(end == null) {
			end = new Date(CalendarManagement.formatDateToYMD(startDate));
			end.setMonth(end.getMonth() + 1);
			end.setDate(0);
		}

		var week = 0;

		// Step 1: Fill week 0 correctly (even if the month doesn't start on Sunday)
		while (current <= end) {
			var dayOfWeek = current.getDay();
			if (current.getDate() === 1 && dayOfWeek !== CalendarManagement.sunday) {
				// Ensure the first week is filled even if the month doesn't start on Sunday
				for (var emptyDay = 0; emptyDay < dayOfWeek; emptyDay++) {
					var placeholderDate = $(`[name=${week}-${emptyDay}]`, container);
					placeholderDate.html('{DATE}');
				}
			}

			// Step 2: Fill the current date in the grid
			var calendarDate = $(`[name=${week}-${dayOfWeek}]`, container);
			calendarDate.html(calendarDate.html().replaceAll('{DATE}', current.getDate()));

			// Set the correct data-date for the element
			var fullDate = CalendarManagement.formatDateToYMD(current);
			calendarDate.attr('data-date', fullDate);
			$('button[name=add-event]', calendarDate).attr('data-date', fullDate);

			// Step 3: Move to the next day
			current.setDate(current.getDate() + 1);

			// Step 4: Increment the week counter if the day is Sunday (end of week)
			if (dayOfWeek === 6 && current <= end) {
				week++;
			}
		}

		// Step 5: Clear out any remaining placeholders (those that still contain '{DATE}')
		var invalid = $(container).find('.col-calendar:contains({DATE})');
		invalid.each(function() {
			$(this).html(''); // Clear the placeholders
		});

		// Step 6: Clear out any fully invalid rows
		var rows = $(container).find('.row');
		rows.each(function() {
			var dates = $(this).find('.col-calendar');

			var rowIsEmpty = true;
			for(var date of dates) {
				if($(date).html() != '')
					rowIsEmpty = false;
			}

			if(rowIsEmpty)
				$(this).remove();
		});
	},

	populateCalendarEvents: function(container, events) {
		console.log("Events:", events);
		for(var event of events) {
			var eventDate = new Date(event.Start.split('T')[0]).toISOString().split('T');

			var eventCode = `<div class="calendarEvent">
				<button class="btn btn-sm btn-primary float-end" name="delete-event" data-eventid="${event.Id}">
					<span class="k-icon k-i-trash"></span>
				</button>
				<span class="k-icon k-i-calendar"></span>
				<label>${event.Name}</label>
			</div>`;

			var dateBlock = $(`.col-calendar[data-date=${eventDate[0]}] > .events`, container);
			dateBlock.append(eventCode);
		}
	},

	buildCalendar: async function(container, args) {
		// Reset the calendar state.
		CalendarManagement.initialiseCalendarGrid(container);

		var selectedYear = $('[name=year]', container).val();
		var selectedMonth = $('[name=month]', container).val().padStart(2, '0');
		var selectedCalendar = args.calendarId;

		var start = (args && args.fromDate)
			? new Date(args.fromDate)
			: new Date(selectedYear, selectedMonth - 1, 1);

		var end = (args && args.toDate) 
			? new Date(args.toDate) 
			: new Date(start.getFullYear(), start.getMonth() + 1, 0);

		CalendarManagement.populateCalendarDates($('[name=calendar]', container), start, end);

		var events;
		if (args && args.eventSource) {
			events = args.eventSource;
		} else {
			events = (await api.get(`Core/CalendarEvent?$filter=CalendarId eq ${selectedCalendar} and Start ge ${CalendarManagement.formatDateToYMD(start)} and Start le ${CalendarManagement.formatDateToYMD(end)}`)).value;
		}

		await CalendarManagement.populateCalendarEvents(container, events);
		CalendarManagement.wireUpClickEvents(container, args);
	},

	wireUpClickEvents: async function(container, args) {
		$('[name=add-event]', container).on('click', async (e) => {
			var selectedCalendar = $('[name=calendars]', container).val();
			var eventDate = $(e.target).attr('data-date');
			await CalendarManagement.newCalendarEvent(e, selectedCalendar, eventDate, container, args);
		});

		$('[name=delete-event]', container).on('click', async (e) => {
			var eventId = $(e.target).attr('data-eventid');
			await CalendarManagement.deleteCalendarEvent(e, eventId, container, args);
		});

		if(args && args.readOnly) {
			$('[name=add-event]', container).remove();
			$('[name=delete-event]', container).remove();
		}
	},

	setPrimary: async function (e, app, container) {
		e.preventDefault();
		var serverApp = await api.get("Core/App(" + app.Id + ")");
		var config = JSON.parse(serverApp.ConfigJson);
		config.Calendars.primary = $("[name=calendars]", container).val();
		serverApp.ConfigJson = JSON.stringify(config, null, 4);
		await api.update("Core/App(" + serverApp.Id + ")", serverApp)
			.then(() => notification.success("[resource_displayname[saved]]"))
			.catch((err) => error(err));
	},

	deleteCalendar: async function (e, container) {
		e.preventDefault();
		var calendar = $("[name=calendars]", container).val();
		await api.destroy("Core/Calendar(" + calendar + ")")
			.catch((err) => error(err));

		window.location.reload();
	},

	newCalendar: async function (e, app) {
		e.preventDefault();
		var calendar = {
			Id: 0,
			AppId: app.Id,
			Name: "",
		};
		var args = {
			fields: [
				{ field: "Name", title: "[resource_displayname[name]]", description: "[resource_description[name]]" },
			],
			title: "[resource_displayname[newcalendar]]",
			data: calendar,
			confirm: "[resource_displayname[confirm]]",
			close: "[resource_displayname[close]]"
		};
		var addCalendarDialog = new EditorDialog(args);
		addCalendarDialog.events.confirm = async function () {
			calendar = addCalendarDialog.data.toJSON();//Remove all the kendo observable properties.
			await api.add("Core/Calendar", calendar).then(async (calendarCreated) => {
				addCalendarDialog.events.close();
				var currentApp = await api.get("Core/App(" + app.Id + ")");
				var config = JSON.parse(currentApp.ConfigJson);
				config.Calendars[calendarCreated.Name] = calendarCreated.Id;
				currentApp.ConfigJson = JSON.stringify(config, null, 4);
				await api.put("Core/App(" + currentApp.Id + ")", currentApp).then(() => {
					notification.success("[resource_displayname[created]]");
					window.location.reload();
				}).catch((err) => error(err));
			}).catch((err) => error(err));
		};
		addCalendarDialog.init();
	},

	newCalendarEvent: async function (e, calendarId, start, container, args) {
		e.preventDefault();
		var startInformation = new Date(start);
		var trueStart = new Date(Date.UTC(startInformation.getUTCFullYear(), startInformation.getUTCMonth(), startInformation.getUTCDate()));
		var calendarEvent = kendo.observable({
			Id: 0,
			CalendarId: args.calendarId,
			Name: "",
			Start: trueStart.toISOString(),
			DurationInTicks: 1000000 * 24 * 60 * 60
		});

		var addCalendarEventDialog = new Dialog({ title: "[resource_displayname[neweventfor]] " + CalendarManagement.days[new Date(start).getDay()] });
		addCalendarEventDialog.template = $("[name=newCalendarEventDialog]", container).first().html();
		addCalendarEventDialog.events.confirm = async function () {
			calendarEvent = calendarEvent.toJSON();
			var repeatsEvery = $("[name=repeatsEvery]", addCalendarEventDialog.element).val();

			if (repeatsEvery == "never") {
				await api.add("Core/CalendarEvent", calendarEvent)
					.then(async () => {
						addCalendarEventDialog.events.close();
						notification.success("[resource_displayname[created]]");
						await CalendarManagement.buildCalendar(container, args);
					})
					.catch((err) => error(err));
			} else if (repeatsEvery == "weekly") {
				var start = new Date(trueStart);
				var untilDate = $("[name=until]", addCalendarEventDialog.element).data("kendoDatePicker").value();
				var events = [];
				while (start < untilDate) {
					events.push({
						Id: calendarEvent.Id,
						CalendarId: calendarEvent.CalendarId,
						Name: calendarEvent.Name,
						Start: start.toISOString(),
						DurationInTicks: calendarEvent.DurationInTicks
					});
					start.setDate(start.getDate() + 7);
				}
				notification.info("[resource_displayname[adding]]");

				// Post all events to "Core/CalendarEvent" individually
				for (let i = 0; i < events.length; i++) {
					await api.add("Core/CalendarEvent", events[i])
						.catch((err) => error(err));
				}

				addCalendarEventDialog.events.close();
				notification.success("[resource_displayname[created]]");
				await CalendarManagement.buildCalendar(container, args);
			}
		};

		addCalendarEventDialog.init(() => {
			kendo.bind(addCalendarEventDialog.element, calendarEvent);
			$("[name=repeatsEvery]", addCalendarEventDialog.element).kendoDropDownList({
				dataSource: Object.keys(CalendarManagement.repeats).map(r => ({
					Text: CalendarManagement.repeats[r],
					Value: r
				})),
				dataTextField: "Text",
				dataValueField: "Value"
			});
			$("[name=until]", addCalendarEventDialog.element).kendoDatePicker({
				autoBind: false,
				value: new Date(),
				dateInput: true,
				format: type.dateFormat
			});
		});
	},


	deleteCalendarEvent: async function (e, eventId, container, args) {
		e.preventDefault();
		await api.destroy("Core/CalendarEvent(" + eventId + ")").then(async () => {
			notification.success("[resource_displayname[deleted]]");
			await CalendarManagement.buildCalendar(container, args);
		}).catch((err) => error(err));
	},

	formatDateToYMD: function(date) {
		return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')}`;
	}
}"}

