<div name="grid"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"CapitalEarnings","ResourceKey":"B2B","Script":"CapitalEarnings = {
    init: async function (app, container) {
        await CapitalEarnings.setupFilters(app, container);
        await CapitalEarnings.onFilterChanged(app, container);
    },

    setupFilters: async function(app, container) {
        var defaultCurrency = app.Config.B2B.DefaultCurrency 
            ? app.Config.B2B.DefaultCurrency 
            : "EUR";
            
        var currencies = app.Config.B2B.Currencies 
            ? app.Config.B2B.Currencies 
            : ["USD", "EUR", "GBP"];

        $("[name=currency]", container).kendoDropDownList({
            dataSource: currencies,
            index: currencies.indexOf(defaultCurrency),
            change: (e) => CapitalEarnings.onFilterChanged(app, container)
        }).data("kendoDropDownList");

        var years = (await api.get(`B2B/Offer/FromSystem(SystemId='${app.Config.B2B.SourceSystem}')?$apply=groupby((DueDate))`))
            .map(i => new Date(i.DueDate).getFullYear());
        
        var today = new Date();

        $("select[name=fromYear]", container).kendoDropDownList({ 
            dataSource: [...new Set([...years, today.getFullYear()])], 
            change: (e) => CapitalEarnings.onFilterChanged(app, container) 
        });

        $("select[name=toYear]", container).kendoDropDownList({ 
            dataSource: [...new Set([...years, today.getFullYear()])], 
            change: (e) => CapitalEarnings.onFilterChanged(app, container) 
        });

        $("select[name=fromMonth]", container)
            .kendoDropDownList({ change: (e) => CapitalEarnings.onFilterChanged(app, container) });

        $("select[name=toMonth]", container)
            .kendoDropDownList({ change: (e) => CapitalEarnings.onFilterChanged(app, container) });

        $('select[name=fromYear]', container).data('kendoDropDownList').select(0);
        $('select[name=toYear]', container).data('kendoDropDownList').select(0);
        $('select[name=fromMonth]', container).data('kendoDropDownList').select(today.getMonth());
        $('select[name=toMonth]', container).data('kendoDropDownList').select(today.getMonth());
    },

    onFilterChanged: async function(app, container) {
        var reportParams = CapitalEarnings.getParams(app, container);
        await CapitalEarnings.buildReport(reportParams, app, container);
    },

    getParams: function(app, container) {
        var to = new Date(`${$("select[name=toYear]", container).val()}-${$("select[name=toMonth]", container).val()}-01`);
        to.setMonth(to.getMonth() + 1);
        to.setDate(0);
        return {
            currency: $("select[name=currency]", container).val(),
            from: `${$("select[name=fromYear]", container).val()}-${$("select[name=fromMonth]", container).val()}-01`,
            to: to.toISOString().split('T')[0],
            source: app.Config.B2B.SourceSystem
        };
    },

    buildReport: async function(reportParams, app, container) {
        var gridElement = $("[name=grid]", container);
        gridElement.empty();

        gridElement.kendoGrid({
            dataSource: {
                data: await CapitalEarnings.getReportData(reportParams),
                scrollable: true,
                sortable: true,
                filterable: true,
                pageable: true,
                schema: {
                    model: {
                        fields: {
                            supplierName: { type: "string" },
                            offers: { type: "number" },
                            totalDaysDiscounted: { type: "number" },
                            transactionTotal: { type: "number" },
                            totalOfferValue: { type: "number" },
                            totalDiscountingCost: { type: "number" },
                            averageDaysDiscounted: { type: "number" },
                            averageOfferValue: { type: "number" },
                            averageDiscountingCost: { type: "number" },
                            effectiveSavingsRate: { type: "number" }
                        }
                    }
                }
            },
            columns: [
                { field: "supplierName", title: "Supplier Name",  width: "300px" },
                { field: "offers", title: "Offers", format: "{0:n0}",  width: "100px" },
                { field: "transactionTotal", title: "Transaction Total (sum)", format: "{0:" + type.aggregateMoneyFormat + "}" },
                { field: "totalOfferValue", title: "Offer Value (sum)", format: "{0:" + type.aggregateMoneyFormat + "}" },
                { field: "totalDiscountingCost", title: "Discount Cost (sum)", format: "{0:" + type.aggregateMoneyFormat + "}" },
                { field: "averageDaysDiscounted", title: "Days Dis (avg)", format: "{0:n}" },
                { field: "averageOfferValue", title: "Offer Value (avg)", format: "{0:" + type.moneyFormat + "}" },
                { field: "averageDiscountingCost", title: "Cost (avg)", format: "{0:" + type.moneyFormat + "}" },
                { field: "possibleSavings", title: "Potential Savings %", format: "{0:n2}%" },
                { field: "realisedSavings", title: "Actual Savings %", format: "{0:n2}%" }
            ],
            detailInit: async (e) => CapitalEarnings.loadDetails(app, e.detailCell, "CapitalEarningsDetail", e.data)
        });
    },

    loadDetails: async function(app, detailCell, childComponentName, parentData) {
        var detailContainer = $(detailCell);
        await loadComponent(detailContainer, childComponentName, async (detailComponent) => {
            await detailComponent.init(app, $("section[name=" + childComponentName + "]", detailContainer), parentData);
        });
    },

    getReportData: async function(reportParams) {
        // build our query and pull data from the api
        var filter = `CurrencyId eq '${reportParams.currency}' and DebtorPaymentDate ge ${reportParams.from} and DebtorPaymentDate lt ${reportParams.to}`;
        var select = `CreditorName,TransactionValue,Value,Cost,DebtorPaymentDate,DueDate,DebtorState,CreditorState,FunderState,DebtorAcceptanceRule`;
        var expand = `Companies($filter=Perspective eq 'Creditor' and startswith(CompanyReferenceId, '${reportParams.source}'))`;
        var apiData = (await api.get(`B2B/Offer/FromSystem(SystemId='${reportParams.source}')?$filter=${filter}&$select=${select}&$expand=${expand}`)).value;

        // group our result set form the api by supplier
        var supplierOfferGroups = apiData.reduce((acc, item) => {
            var groupKey = `${item.CreditorName}_${item.Companies[0].CompanyReferenceId}`;

            // If the group doesn't exist in the accumulator, create an empty array
            if (!acc[groupKey]) {
                acc[groupKey] = [];
            }

            // Push the current item into its group
            acc[groupKey].push(item);
            
            return acc;
        }, {});

        var results = [];

        for(var key in supplierOfferGroups)
        {
            results.push(CapitalEarnings.mapSupplierOfferGroup(key, supplierOfferGroups[key], reportParams));
        }

        // build the grid dataset
        return results;
    },

    mapSupplierOfferGroup: function(groupKey, offerGroup, reportParams) {
        // compute our sums
        var totalOfferValue = offerGroup.reduce((total, item) => total + item.Value, 0);
        var totalDiscountingCost = offerGroup.reduce((total, item) => total + item.Cost, 0);
        var totalDays = offerGroup.reduce((total, item) => total + Math.ceil(Math.abs(new Date(item.DebtorPaymentDate) - new Date(item.DueDate)) / (1000 * 60 * 60 * 24)), 0);

        // compute our averages
        var averageOfferValue = totalOfferValue / offerGroup.length;
        var averageDiscountingCost = totalDiscountingCost / offerGroup.length;
        var averageDays = totalDays / offerGroup.length;
        var possibleSavings = (totalDiscountingCost / totalOfferValue) * 100;
        var realisedSavings = (offerGroup
            .filter(i => i.FunderState == 'FundingAccepted' || i.FunderState == 'Paid' || i.CreditorState == 'FundingAccepted')
            .reduce((total, item) => total + item.Cost, 0) / totalOfferValue) * 100;

        // build our result for this supplier
        return {
            // basic information
            supplierRef: groupKey.split('_')[1],
            supplierName: groupKey.split('_')[0],
            offers: offerGroup.length,

            // totals
            transactionTotal: offerGroup.reduce((total, item) => total + item.TransactionValue, 0),
            totalOfferValue: totalOfferValue,
            totalDiscountingCost: totalDiscountingCost,

            // averages
            averageDaysDiscounted: averageDays,
            averageOfferValue: averageOfferValue,
            averageDiscountingCost: averageDiscountingCost,

            possibleSavings: possibleSavings,
            realisedSavings: realisedSavings,

            reportParams: reportParams
        };
    }
}"}

