    init: async function (app, container, capitalEarningsItem) {

        await CapitalEarningsDetail.loadCompanyDetails(app, container, capitalEarningsItem.supplierRef);
        var chartData = await CapitalEarningsDetail.getData(capitalEarningsItem);
        var colours = app.Config.Themes['[theme[name]]']?.colours.charts || ['red', 'green', 'yellow', 'blue', 'white'];

        CapitalEarningsDetail.buildCharts(container, chartData, colours);
    },

    loadCompanyDetails : async function(app, container, reference) {
        var company = (await api.get(`B2B/Company?$filter=References/any(r:r/Id eq '${reference}')&$expand=Address,References`)).value[0];
        var systems = app.Config.B2B.SourceSystem.split(',');
        var references = company.References.filter(c => c.SystemId == 'GlobalTax' || systems.includes(c.SystemId));

        var config = {
            element: $("div[name=references]",container), 
            dataSource: references 
        };
        
        await (await [script[CompanyReferencesGrid]](config)).init();
    },

    getData: async function(capitalEarningsItem) {
        var reportParams = capitalEarningsItem.reportParams;

        // build our query and pull data from the api
        var filter = `CurrencyId eq '${reportParams.currency}' and DebtorPaymentDate ge ${reportParams.from} and DebtorPaymentDate lt ${reportParams.to} and Companies/any(c:c/CompanyReferenceId eq '${capitalEarningsItem.supplierRef}')`;
        var select = `Value,DebtorPaymentDate,DueDate,FundingState`;
        var invoiceData = (await api.get(`B2B/Invoice/FromSystem(SystemId='${reportParams.source}')?$filter=${filter}&$select=${select}&$expand=References($expand=OfferLines)`)).value; 

        return CapitalEarningsDetail.mapData(invoiceData);
    },

    mapData: function(invoiceData) {
        var fundedInvoices = invoiceData
            .filter(i => (i.FundingState == 'FundingAccepted' || i.FundingState == 'Paid') && (i.References.map(r => r.OfferLines).length > 0));

        var proposedInvoices = invoiceData
            .filter(i => (i.FundingState == 'Proposed' && !(i.CreditorState == 'FundingAccepted')) && i.References.map(r => r.OfferLines).length > 0);

        var paidUnfunded = invoiceData
            .filter(i => (i.DebtorState == 'Paid' || i.FundingState == 'Paid') && i.References.map(r => r.OfferLines).length == 0);

        var savings = fundedInvoices
            .map(i => i.References)
            .flat()
            .map(r => r.OfferLines)
            .flat()
            .map(l => l.Cost)
            .reduce((sum, cost) => sum + cost, 0);

        var potentialSavings = proposedInvoices
            .map(i => i.References)
            .flat()
            .map(r => r.OfferLines)
            .flat()
            .map(l => l.Cost)
            .reduce((sum, cost) => sum + cost, 0);

        return {
            active: invoiceData.map(l => l.Value).reduce((sum, cost) => sum + cost, 0) - paidUnfunded.map(l => l.Value).reduce((sum, cost) => sum + cost, 0) - fundedInvoices.map(l => l.Value).reduce((sum, cost) => sum + cost, 0),
            paidUnfunded: paidUnfunded.map(l => l.Value).reduce((sum, cost) => sum + cost, 0),
            paidFunded: fundedInvoices.map(l => l.Value).reduce((sum, cost) => sum + cost, 0),

            costs: invoiceData
                .map(i => i.Value)
                .reduce((sum, cost) => sum + cost, 0) - savings - potentialSavings,
            savings: savings,
            potentialSavings: potentialSavings
        };
    },

    buildCharts: function(container, data, colours) {
        var states = [
            { 
                category: "[resource_shortdisplayname[active]]",
                value: data.active,
                color: colours[0]
            }, {
                category: "[resource_shortdisplayname[paidnormally]]",
                value: data.paidUnfunded,
                color: colours[1] 
            }, {
                category: "[resource_shortdisplayname[funded]]",
                value: data.paidFunded,
                color: colours[2]
            }, {
                category: "[resource_shortdisplayname[total]]: " + kendo.toString((data.active + data.paidUnfunded + data.paidFunded), type.moneyFormat),
                value: 0,
                color: colours[0],
                visible: false
            }
        ];

        var statesChart = new PieChart($("[name=transactionStates]", container), states);
        statesChart.init();

        var savings = [
            {
                category: "[resource_shortdisplayname[costs]]",
                value: data.costs,
                color: colours[0]
            },{
                category: "[resource_shortdisplayname[saved]]",
                value: data.savings,
                color: colours[1]
            },{
                category: "[resource_shortdisplayname[potentiallysaved]]",
                value: data.potentialSavings,
                color: colours[2]
            }, {
                category: "[resource_shortdisplayname[total]]: " + kendo.toString((data.costs + data.savings + data.potentialSavings), type.moneyFormat),
                value: 0,
                color: colours[0],
                visible: false
            }
        ];

        var savingsChart = new PieChart($("[name=transactionSavings]", container), savings);
        savingsChart.init();
    }
}"}

