	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=CMS]");

		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/Page]],
					[meta[Core/Layout]]
				]
			}]);

		var treeElement = $('[name=tree]', container);

		CMS.initSplitter(container);
		var tree = await CMS.initDataTreeView(app, container, treeElement);
		CMS.initPageTreeContextMenu(app, container, tree);
		CMS.initPageTreeVisibilityToggler(app, container, tree);
	},

	initSplitter: function(container) {
		$("[name=splitter]").kendoSplitter({
			scrollable: false,
			panes: [
				{ collapsible: false, size: 300 },
				{ collapsible: false, scrollable: false }
			]
		});
	},

	initDataTreeView: async function(app, container, treeElement) {
		var tree = new DataTreeViewWidget(treeElement, {
			dataSource: await CMS.getDataForPagesTree(app),
			template: '<span class="k-icon k-i-file-config"></span> <span name="showOnMenu" class="k-icon k-i-#: item.showOnMenus ? "eye" : "eye-slash" #"></span> #: item.text #',
			dragAndDrop: true,
		});

		tree.onSelect = async (e) => {
			await CMS.pageTreeOnSelect(e, app, container, tree);
		};

		tree.onDrop = async (e) => {
			await CMS.pageTreeOnDrop(e, app, tree);
		};

		tree.dataBound = async (e) => {
			await CMS.pageTreeVisibilityToggle(e, tree);
		};

		tree.init();

		return tree;
	},

	initPageTreeContextMenu: async function(app, container, tree) {
		$('.left', container).append($('[name=context-menu-template]', container).html());

		$('[name=context-menu]', container).kendoContextMenu({
			target: ".k-treeview-item",
			select: async function (e) {
				var item = $(e.target);
				var node = tree.kendoObject.dataItem(item);
				var action = $(e.item).attr('data-action');

				switch(action) {
					case 'new-page':
						await CMS.openNewPageDialog(app, container, tree, node);
						break;
					case 'delete-page':
						await CMS.openDeletePageDialog(app, container, tree, node);
						break;
					case 'page-properties':
						await CMS.openPagePropertiesDialog(app, container, node);
						break;
					default:
						console.log(`Unknown action: ${action}`);

				}
			}
		});
	},

	initPageTreeVisibilityToggler: async function(app, container, tree) {
		tree.treeElement.off('click', 'span[name=showOnMenu]');
		tree.treeElement.on('click', 'span[name=showOnMenu]', async function(e) {
			e.preventDefault();  
			e.stopPropagation();

			var page = tree.kendoObject.dataItem($(e.target));
			await CMS.togglePageVisibility(page);
			await CMS.reloadPageTree(app, tree, page.id);
		});
	},

	getDataForPagesTree: async function(app) {
		var pages = (await api.get(`Core/Page?$filter=AppId eq ${app.Id}&$orderBy=Order asc`)).value;

		var linkedPages = CMS.linkPagesToParents(pages);

		return [{
			id: null,
			items: CMS.buildTreeDataSource(linkedPages),
			path: null,
			parentId: null,
			text: session.app.Domain,
			expanded: true,
			page: null
		}];
	},

	linkPagesToParents: function(pages) {
		var rootPages = pages.filter(p => p.ParentId == null);

		for(var rootPage of rootPages)
			CMS.linkChildPages(rootPage, pages);

		return rootPages;
	},

	linkChildPages: function(page, pages) {
		page.Pages = pages.filter(p => p.ParentId == page.Id);

		for(var childPage of page.Pages)
			CMS.linkChildPages(childPage, pages);
	},

	buildTreeDataSource: function(pages) {
		return pages.map(p => {
			return {
				id: p.Id,
				text: CMS.getCulturedPageTitle(p),
				items: CMS.buildTreeDataSource(p.Pages),
				path: p.Path,
				parentId: p.ParentId,
				order: p.Order,
				showOnMenus: p.ShowOnMenus,
				page: p
			};
		});
	},

	getCulturedPageTitle: function(page) {
		return page.Name;
	},

	pageTreeOnSelect: async function(e, app, container, tree) {
		var page = tree.kendoObject.dataItem(e.node);
		var port = location.port != ''
			? ':' + location.port
			: '';

		$("[name=workspace]", container).html(`<iframe src="https://${app.Domain}${port}/${page.page.Path}?edit=true"></iframe>`);
	},

	pageTreeOnDrop: async function(e, app, tree) {
		var source = tree.kendoObject.dataItem($(e.sourceNode));
		var target = tree.kendoObject.dataItem($(e.destinationNode));
		var sourceParent = tree.kendoObject.dataItem($(e.sourceNode).parent());
		var targetParent = tree.kendoObject.dataItem($(e.destinationNode).parent());

		if(e.dropPosition == 'over') {
			if(source.id == target.id) {
				e.setValid(false);
			} else if(source.parentId != null && targetParent == null) { // Make the page a root page.
				await CMS.reparentPage(app, source, target);
				await CMS.reloadPageTree(app, tree, source.id);
			} else if(source.parentId != target.id) {
				await CMS.reparentPage(app, source, target);
				await CMS.updatePageOrders(targetParent);
				await CMS.reloadPageTree(app, tree, source.id);
			} else {
				e.setValid(false);
			}
		} else if(e.dropPosition == 'before' || e.dropPosition == 'after') {
			// Update order of child pages of parent.
			if(sourceParent.id != targetParent.id)
				await CMS.reparentPage(app, source, targetParent);

			await CMS.updatePageOrders(targetParent);
			await CMS.reloadPageTree(app, tree, source.id);
		} else {
			e.setValid(false);
		}
	},

	togglePageVisibility: async function(page) {
		page.page.ShowOnMenus = !page.showOnMenus;
		await api.put(`Core/Page(${page.id})`, page.page);
	},

	reparentPage: async function(app, page, newParent) {
		await api.put(`Core/Page(${page.id})`, {
			Id: page.id,
			ParentId: newParent.id,
			AppId: app.Id,
			Order: page.order,
			ShowOnMenus: page.showOnMenus,
			Name: page.page.Name,
			ResourceKey: page.page.ResourceKey,
			Layout: page.page.Layout
		});

		page.parentId = newParent.id;
		page.page.ParentId = newParent.id;

		notification.success('[resource_displayname[changedParentPage]]');
	},

	updatePageOrders: async function(page) {
		var i = 0;
		for(var thisPage of page.items) {
			thisPage.page.Order = i;
			await api.put(`Core/Page(${thisPage.id})`, thisPage.page);
			i++;
		}

		notification.success('[resource_displayname[pageOrdersUpdated]]');
	},

	reloadPageTree: async function(app, tree, pageId = null) {
		tree.kendoObject.setDataSource((await CMS.getDataForPagesTree(app)));

		if(pageId)
			tree.kendoObject.expandTo(pageId);

		CMS.initPageTreeContextMenu(app, $(tree.element), tree);
	},

	openNewPageDialog: async function(app, container, tree, parentPage) {
		var dialog = new Dialog();
		dialog.template = $('[name=newChildPageTemplate]', container).html();
		dialog.title = '[resource_displayname[newChildPage]]';
		dialog.events.create = async () => {
			var name = $('[name=name]', dialog.element).val();
			var showOnMenus = $('[name=show-on-menus]', dialog.element).is(':checked');
			var layout = $('[name=layout]', dialog.element).val();
			var title = $('[name=title]', dialog.element).val();
			var keywords = $('[name=keywords]', dialog.element).val();
			var description = $('[name=description]', dialog.element).val();
			var page = {
				Name: name,
				ParentId: (parentPage != null) ? parentPage.id : null,
				AppId: app.Id,
				ShowOnMenus: showOnMenus,
				Layout: layout,
				Order: parentPage == null ? 0 : parentPage.items.length,
				PageInfo: [
					{
						CultureId: "",
						Title: title,
						Description: description,
						Keywords: keywords
					}
				],
				Contents: [
					{
						CultureId: "",
						Html: "",
						Name: "body"
					}
				]
			};

			var newPage = await api.post('Core/Page', page);
			notification.success('[resource_displayname[childPageAdded]]');
			dialog.events.close();
			await CMS.reloadPageTree(app, tree, newPage.Id);
		};
		dialog.init(async () => {
			var layouts = (await api.get(`Core/Layout?$filter=AppId eq ${app.Id}`)).value;
			$('[name=layout]', dialog.element).kendoDropDownList({
				dataSource: layouts,
				dataTextField: "Name",
				dataValueField: "Name",
			});
		});
	},

	openDeletePageDialog: async function(app, container, tree, page) {
		var dialog = new ConfirmDialog({
			title: `[resource_description[deletePage]] ${page.page.Path}?`,
			question: '[resource_displayname[thisCannotBeUndone]]',
			confirm: "[resource_displayname[confirm]]",
			close: "[resource_displayname[close]]"
		});

		dialog.events.confirm = async (e) => {
			await api.destroy(`Core/Page(${page.id})`);
			notification.success("[resource_description[pageDeleted]]");
			dialog.events.close();
			await CMS.reloadPageTree(app, tree, page.parentId);
		};
		dialog.init();
	},

	openPagePropertiesDialog: async function(app, container, page) {
		var dialog = new Dialog();
		dialog.title = `[resource_displayname[pageProperties]]: ${page.path}`;
		dialog.component = 'PageProperties';
		dialog.init(() => {
			PageProperties.init(app, $(".component[name=PageProperties]", $(dialog.element)), page.page, async (e) => {
				await api.put(`Core/Page(${page.id})`, page.page);
				notification.success('[resource_displayname[pageUpdated]]');
			});
		});
	}
};"}

