    init: async function (app, container, company) {
        app = app || session.app;
        container = container || $(".component[name=CompanyDetails]");
        if(!company && !getQueryParameter("Id")) { return; }

        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Company]],
                    [meta[B2B/Address]]
                ]
            }
        ]);

        if (!company) {
          var company = await api.get("B2B/Company(" + getQueryParameter("Id") + ")?$expand=Address,References");
        }
        
        var details = [script[CompanyDetails]]({element: $("[name=companyDetails]", container),company: company});
        if (!this.backButton) {
            details.toolbar = "";
        }
        await details.init(company);

        var systems = app.Config.B2B.SourceSystem.split(',');
        var references = company.References.filter(c => c.SystemId == 'GlobalTax' || systems.includes(c.SystemId));
        var config = {
            element: $("div[name=referencesGrid]",container), 
            dataSource: references 
        };
        await (await [script[CompanyReferencesGrid]](config)).init();
    }
}"}

{"Key":"B2B","Name":"CompanyImportCSVLines","ResourceKey":"Import","Content":"","Script":"CompanyImportCSVLines = {
