            endpoint: "B2B/CompanyCSVLine",
            odataAppend: "?$filter=SourceSystemId eq '" + app.Config.B2B.SourceSystem + "'"
        }; 

        var dataSource = await model.getDatasource(config);
        var widget = await CompanyImportCSVLines.build({ element: container, dataSource: dataSource }, app);
        await widget.init();
