            }
        ];

        g.commands.push({ name: "reimport", icon: "k-i-redo", text: "[resource_displayname[reimport]]" });
        
        g.dataBound = function (e) {
            $("[name=reimport]", g.gridElement).off("click").on("click", (e) => CompanyImportCSVLines.reimport(e, g));
