			},
			{
				field: "LastUpdatedBy",
				title: "[resource_displayname[lastupdated]]",
				width: "[theme[columns.small]]"
			}
		];
		grid.commands.push({
			name: "save",
			icon: "k-i-save",
			text: "[resource_displayname[save]]"
		});
		grid.commands.push({
			name: "delete",
			icon: "k-i-trash",
			text: "[resource_displayname[delete]]"
		});
		grid.detailTemplate = kendo.template($("[name=componentDetails]", container).html()),
			grid.groupable = false;
		grid.searchable = true;
		grid.filterable = true;
		grid.detailExpand = async function (e) {
			if ($(e.detailRow).find(".monaco-editor").length === 0) {
				var component = this.dataItem(e.masterRow);

				var expandContainer = $(e.detailRow);
				var replaced = expandContainer.html().replaceAll('{ID}', Guid());

				expandContainer.html(replaced);

				var contentEditor = $(e.detailRow).find("div[name=content] > div[name=editorContainer]", expandContainer);
				var scriptEditor = $(e.detailRow).find("div[name=script] > div[name=editorContainer]", expandContainer);
				var html = new HTMLMonacoEditor(contentEditor[0], {
					code: component.Content
				});
				var script = new JavaScriptMonacoEditor(scriptEditor[0], {
					code: component.Script
				});
				html.onChange = (e) => {
					component.Content = html.getValue();
				};
				script.onChange = (e) => {
					component.Script = script.getValue();
				};
				html.init();
				script.init();

				$('[name=body-tab-button]', expandContainer).on('click', () => {
