				$('[name=script-tab-button]', expandContainer).on('click', () => {
					script.editor.layout();
				});
			}
		};
		grid.detailCollapse = function (e) {
			$(e.detailRow).find(".monaco-editor").css("visbility", "hidden");
		};
		grid.dataBound = function () {
			$("button[name=save]", grid.gridElement).on("click", (e) => ComponentManagement.save(e, grid));
			$("button[name=delete]", grid.gridElement).on("click", (e) => ComponentManagement.destroy(e, grid));
		};
		await grid.init();
		$("button[name=create]", grid.gridElement).off("click").on("click", (e) => ComponentManagement.newComponent(e, grid, app));
		$("button[name=migrate]", grid.gridElement).off("click").on("click", (e) => ComponentManagement.migrate(e, app));

		await loadComponent($('[name=componentMigrationComponent', container), 'ComponentMigration', async (c) => {
			await c.init(app, $('[name=componentMigrationComponent', container));
		});
	},

	migrate: function (e, app) {
		e.preventDefault();
		var d = new Dialog({
			width: 1100,
			height: 370,
			title: "[resource_displayname[migrateComponents]]"
		});
		d.template = $("[name=componentMigrationComponent]").first().html();
		// d.init(() => ComponentMigration.init(app, $(".component[name=ComponentMigration]", d.element)));
		d.init();

		ComponentMigration.initDropdown($(".component[name=ComponentMigration]", d.element));
	},

	newComponent: async function (e, grid, app) {
		e.preventDefault();

		var newComponent = {
			Id: 0,
			AppId: app.Id,
			Name: "",
			Key: "",
			ResourceKey: "",
			Content: "",
			Script: ""
		};

		var d = new Dialog({
			title: "[resource_displayname[CreateNewComponent]]"
		});
		d.template = $("[name=newComponentDialog]").html();

		d.events.create = async function (e) {
			e.preventDefault();

			newComponent.Name = $("input[name=Name]", d.element).val();
			newComponent.Key = $("input[name=Key]", d.element).val();
			newComponent.ResourceKey = $("input[name=ResourceKey]", d.element).val();

			await api.add("Core/Component", newComponent)
				.then(() => {
					notification.success("[resource_displayname[componentcreated]]");
					d.events.close();
					grid.refresh();
				})
				.catch(err => error(err));
		};

		d.init(() => {
			$("[name=create]", d.element).off("click").on("click", d.events.create);
			$("[name=close]", d.element).off("click").on("click", d.events.close);
		});

	},


	delay: function (callback, ms) {
		var timer = 0;
		return function () {
			var context = this, args = arguments;
			clearTimeout(timer);
			timer = setTimeout(function () {
				callback.apply(context, args);
			}, ms || 0);
		};
	},

	save: async function (e, grid) {
		e.preventDefault();
		var component = grid.dataItem($(e.currentTarget).closest("tr"));
		await component.save(e);
		notification.success("Component Saved");
	},

	destroy: function (e, grid) {
		e.preventDefault();
		var d = new ConfirmDialog({
			title: "[resource_displayname[areyousure]]",
			question: "[resource_displayname[areyousure]]",
			confirm: "[resource_displayname[confirm]]",
			close: "[resource_displayname[close]]"
		});
		d.events.confirm = function () {
			var component = grid.dataItem($(e.currentTarget).closest("tr"));
			component.destroy(e);
			notification.success("[resource_displayname[componentdeleted]]");
			grid.refresh();
			d.events.close();
		};
		d.init();
	}
};"}

