</button>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"CMS","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"ComponentMigration","ResourceKey":"CMS","Script":"ComponentMigration = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=ComponentMigration]");
        api.addToMetaCache([
        {
            "Name": "Core",
            "Types": [
                [meta[Core/App]]
            ]
        }]);
        let ds = await model.getDatasource({ endpoint: "Core/App" });
        $("[name=app]", container).kendoDropDownList({
            autoBind: false,
            optionLabel: "[resource_displayname[selectapp]]",
            dataTextField: "Name",
            dataValueField: "Id",
            dataSource: ds
        });
        var componentCategories = await api.get("Core/Component?$filter=AppId eq " + app.Id + "&$select=Key");
        var list = [...new Set(componentCategories.value.map(item => item.Key))].map(x => ({ Key: x }))
        var g = new GridWidget($("[name=componentGrid]", container), list);
        g.columns = [
            { selectable: true, width: 40 },
            { field: "Key" }
        ];
        g.groupable = false;
        g.init(() => {
            g.kendoObject.dataSource.sort({ field: "Key", dir: "asc" });
            g.kendoObject.select(g.kendoObject.tbody.find(">tr"));
        });
        $("[name=migrate]", container).on("click", async function (e) {
            var packages = await ComponentMigration.getPackages($("[name=componentGrid]", container), app);
            var appId = $("[name=app]", container).val();
            await api.add("Core/Package/ImportThis?appId=" + appId, packages);
            notification.success("[resource_displayname[migrated]]");
        });
    },

    initDropdown: async function(container) {
        let ds = await model.getDatasource({
            endpoint: "Core/App"
        });

        $("[name=app]", container).kendoDropDownList({
            optionLabel: "[resource_displayname[selectapp]]",
            dataTextField: "Name",
            dataValueField: "Id",
            dataSource: ds
        });
    },

    getPackages: async function (container, app) {
        var packages = [{
            Id: "00000000-0000-0000-0000-000000000000",
            Name: "Components",
            Description: "Generated by ComponentManagement",
            Category: "Dynamic",
            SourceApi: session.apiRoot,
            Items: [
                await ComponentMigration.getPackage(container, app)
            ]
        }];
        return packages;
    },

    getPackage: async function (container, app) {
        var grid = $(container).find(".k-grid").data("kendoGrid");
        var categories = [];
        grid.select().each(function () {
            categories.push(grid.dataItem(this).Key);
        });
        var query = "";
        for (var i = 0; i < categories.length; i = i + 1) {
            query += "'" + categories[i] + "',";
        }
        query = query.substring(0, query.length - 1);
        var data = await api.get("Core/Component?$filter=AppId eq " + app.Id + " and Key in (" + query + ")");
        for (var i = 0; i < data.value.length; i = i + 1) {
            delete data.value[i].Id;
        }
        return {
            Id: "00000000-0000-0000-0000-000000000000",
            PackageId: "00000000-0000-0000-0000-000000000000",
            Type: "Core/Component",
            Data: JSON.stringify(data.value)
        };
    }
};"}

