                          detailTemplate: kendo.template($("script[name=contractDetails]").html()),
                		  detailExpand: function(e) { ContractManagement.expand(app, $(e.detailRow), this.dataItem(e.masterRow)); },
                          dataBound: function () {
                              $("a[name=save]", grid).on("click", function(e) { ContractManagement.save(e, container); });
                              $("a[name=destroy]", grid).on("click", function(e) { ContractManagement.destroy(e, container); });
