</style>","Script":"Credit = {
    //TODO: populate this from the server
    types: [
        { id: 1, name: "[resource_displayname[CreditNote]]" },
        { id: 2, name: "[resource_displayname[Replacement]]" },
        { id: 3, name: "[resource_displayname[DebitNote]]" },
        { id: 4, name: "[resource_displayname[SelfBillingCredit]]" }
    ],
    id: null,
    backButton: true,
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=Credit]");
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Credit]],
                    [meta[B2B/CreditLine]],
                    [meta[B2B/Company]]
                ]
            }
        ]);
        $(".component[name=Credit]").addClass("details");

        if (this.id === null) {
            this.id = getQueryParameter("Id");
        }

        var creditDetailsInit = [script[CreditDetails]];
        var vars = {
            element: $("[name=creditDetails", container)
        };
        creditDetailsInit(vars);
        var details = vars.CreditDetails;
        if (!this.backButton) {
            details.toolbar = "";
        }
        details.config.odataAppend = "(" + this.id + ")?$expand=InvoiceReference($expand=Invoice),References($expand=OfferLines($expand=Offer),RemittanceAdviceLines),AuditTrail,Companies";
        await details.init();
        var credit = details.data;

        var referenceGridInit = [script[ReferenceGrid]];
        var referenceVariables = {
            element: $("[name=referencesGrid]", container),
            references: credit.References
        };
        referenceGridInit(referenceVariables);
        referenceVariables.ReferenceGrid.init();
        await (await [script[CreditLineGrid]]({
            element: $("[name=linesGrid]", container),
            creditId: credit.Id
        })).init();
        var offers = [];
        for (var i = 0; i < credit.References.length; i = i + 1) {
            for (var j = 0; j < credit.References[i].OfferLines.length; j++) {
                credit.References[i].OfferLines[i].Offer.EarliestRelatedTaxPoint = new Date(credit.References[i].OfferLines[i].Offer.EarliestRelatedTaxPoint);
                offers.push(credit.References[i].OfferLines[j]);
            }
        }
        var payments = [];
        for (var i = 0; i < credit.References.length; i = i + 1) {
            for (var j = 0; j < credit.References[i].RemittanceAdviceLines.length; j++) {
                payments.push(credit.References[i].RemittanceAdviceLines[j]);
            }
        }
        var invoices = [];

        if (credit.InvoiceReference && credit.InvoiceReference.Invoice) {
            invoices.push(credit.InvoiceReference.Invoice);
            var relatedInvoicesGridInit = [script[RelatedInvoicesGrid]];
            var relatedInvoicesVariables = {
                element: $("[name=invoices]", container),
                invoices: invoices
            };
            relatedInvoicesGridInit(relatedInvoicesVariables);
            relatedInvoicesVariables.RelatedInvoicesGrid.init();
        }
        else { $("[name=invoice]", container).remove(); }

        if (payments.length > 0) {
            var relatedPaymentGridInit = [script[RelatedPaymentsGrid]];
            var relatedPaymentGridVariables = {
                element: $("[name=paymentsGrid]", container),
                payments: payments
            };
            relatedPaymentGridInit(relatedPaymentGridVariables);
            relatedPaymentGridVariables.RelatedPaymentsGrid.init();
        }
        else { $("[name=payments]", container).remove(); }

        if (offers.length > 0) {
            var relatedOffersGridInit = [script[RelatedOffersGrid]];
            var relatedOffersGridVariables = {
                element: $("[name=offersGrid]", container),
                offers: offers
            };
            relatedOffersGridInit(relatedOffersGridVariables);
            relatedOffersGridVariables.RelatedOffersGrid.init();
        }
        else { $("[name=offers]", container).remove(); }
        var audit = [];
        for (var i = 0; i < credit.AuditTrail.length; i = i + 1) {
            audit.push(credit.AuditTrail[i]);
        }
        if (credit.AuditTrail.length > 0) {
            var historyGrid = [script[HistoryGrid]];
            var variables = {
                element: $("[name=historyGrid]", container),
                history: audit
            };
            historyGrid(variables);
            var h = variables.HistoryGrid;
            h.init(() => {
                h.kendoObject.dataSource.sort({ field: "CreatedOn", dir: "asc" });
            });
        } else { $("[name=history]", container).remove(); }
        var companyInfo = (await api.get("B2B/Company?$filter=References/any(r: r/CreditReferences/any(j: j/CreditId eq " + this.id + "))&$expand=References,Address")).value;
        var transactionCompanyInfo = [];
        var transactionSourceSystem = credit.SourceSystemId;
        for (let i = 0; i < credit.Companies.length; i++) {
            var transactionCompany = credit.Companies[i];
            var matchedCompanyInfo = companyInfo.filter(ci => ci.References.filter(cir => cir.Id == transactionCompany.CompanyReferenceId).length > 0)[0];
            transactionCompany.Name = matchedCompanyInfo.Name;
            transactionCompany.DebtorReference = matchedCompanyInfo.References.filter(r => r.SystemId !== "GlobalTax").map(r => r.Value).join();
            transactionCompany.DebtorVATReference = (matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax").length > 0 ? matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax")[0].Value : "N/A");
            transactionCompany.Id = matchedCompanyInfo.Id;
            if (transactionCompanyInfo.filter(r => r.Perspective == transactionCompany.Perspective && r.DebtorReference == transactionCompany.DebtorReference).length === 0) {
                transactionCompanyInfo.push(transactionCompany);
            }
        }
        var companyGridInit = [script[CompanyGrid]];
        (await companyGridInit({
            element: $("[name=companyDetails]", container),
            dataSource: transactionCompanyInfo
        })).init();
    }
