<div class="creditValueDisplay"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"CreditYearToDate","ResourceKey":"B2B","Script":"CreditYearToDate = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=CreditYearToDate]");

        const defaultCurrency = app.Config.B2B.DefaultCurrency || "EUR";

        const currencyDropdown = $("[name=currencyDropdown]", container).kendoDropDownList({
            dataSource: app.Config.B2B.Currencies || ["USD", "EUR", "GBP"],
            change: async function () {
                const selectedCurrency = this.value();
                await CreditYearToDate.updateCreditData(app, container, selectedCurrency);
            }
        }).data("kendoDropDownList");

        currencyDropdown.value(defaultCurrency);
        await CreditYearToDate.updateCreditData(app, container, defaultCurrency);

        $(".comparison-icon").kendoTooltip({
            content: function (e) {
                return "[resource_displayname[comparisontext]]"
            },
            position: "right"
        });
    },

    updateCreditData: async function (app, container, currency) {
        const { total, creditCount, totalComparisonResult, countComparisonResult } = await CreditYearToDate.getData(app, currency);
        CreditYearToDate.displayTotalCredit(total, creditCount, totalComparisonResult, countComparisonResult, container);
    },

    getData: async function (app, currency) {
        const sourceSystem = app.Config.B2B.SourceSystem;
        const creditQuery = `B2B/Credit?$filter=SourceSystemId eq '${sourceSystem}' and CurrencyId eq '${currency}'`;

        const credits = (await api.get(creditQuery)).value;

        const currentDate = new Date();
        const currentYear = currentDate.getFullYear().toString();
        const previousYear = (currentDate.getFullYear() - 1).toString();
        const currentMonth = currentDate.getMonth() + 1; // numeric month

        const filterCreditsYearToDate = (year) =>
            credits.filter(({ TaxPoint }) => {
                const [creditYear, creditMonth] = TaxPoint.split("-");
                return (
                    creditYear === year &&
                    parseInt(creditMonth, 10) <= currentMonth
                );
            });

        const currentYearCredits = filterCreditsYearToDate(currentYear);
        const previousYearCredits = filterCreditsYearToDate(previousYear);

        const calculateTotal = (creditList) =>
            creditList.reduce((sum, { Value }) => sum + Value, 0);

        const totalForCurrentYear = calculateTotal(currentYearCredits);
        const totalForPreviousYear = calculateTotal(previousYearCredits);

        const compare = (current, previous) =>
            current > previous ? "up" : current < previous ? "down" : "same";

        return {
            total: totalForCurrentYear,
            creditCount: currentYearCredits.length,
            totalComparisonResult: compare(totalForCurrentYear, totalForPreviousYear),
            countComparisonResult: compare(currentYearCredits.length, previousYearCredits.length)
        };
    },

    displayTotalCredit: function (total, creditCount, totalComparisonResult, countComparisonResult, container) {
        const creditValueDisplay = $("div.creditValueDisplay", container);

        const getComparisonIcon = (result) => ({
            up: '<span class="comparison-icon up-arrow">↑</span>',
            down: '<span class="comparison-icon down-arrow">↓</span>',
            same: '<span class="comparison-icon same-icon">→</span>'
        })[result];

        const countComparisonIcon = getComparisonIcon(countComparisonResult);
        const valueComparisonIcon = getComparisonIcon(totalComparisonResult);

        creditValueDisplay.html(`
            <h4>[resource_displayname[totalcreditcountthisyear]]</h4>
            <h2 class="yearToDate">${creditCount} ${countComparisonIcon}</h2>
            <h4>[resource_displayname[totalcreditvaluethisyear]]</h4>
            <h2 class="yearToDate">${kendo.toString(total, type.moneyFormat)} ${valueComparisonIcon}</h2>
        `);
    }
};
"}

