","Script":"CreditYearToDateStats = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=CreditYearToDateStats]");
        container.addClass("small");
        const currentDate = new Date();
        const offset = currentDate.getTimezoneOffset();
        const firstDay = new Date((new Date(currentDate.getFullYear(), 0, 1)).getTime() - (offset * 60 * 1000)).toISOString().split("T")[0];
        const lastDay = new Date((new Date(currentDate.getFullYear(), 11, 31)).getTime() - (offset * 60 * 1000)).toISOString().split("T")[0];
        var creditData = await api.get(`B2B/Credit/FromSystem(SystemId='${app.Config.B2B.SourceSystem}')?$apply=filter(TaxPoint ge ${firstDay} and TaxPoint le ${lastDay})/groupby((CurrencyId), aggregate(Value with sum as Total, Id with countdistinct as Count))`);
        CreditYearToDateStats.setupCreditGrid(creditData, $(".creditGrid", container));
    },

    setupCreditGrid: async function (creditData, container) {
        var dataSource = creditData;
        var creditGrid = new GridWidget(container, dataSource);
        creditGrid.pageable = false;
        creditGrid.groupable = false;
        creditGrid.scrollable = true;
        creditGrid.editable=false;
        creditGrid.columns = [
            { field: "CurrencyId", title: "[resource_displayname[currency]]" },
            { field: "Total", title: "[resource_displayname[value]]", format: "{0:" + type.moneyFormat + "}", width: 100 },
            { field: "Count", title: "[resource_displayname[count]]" },
        ];
        await creditGrid.init();
    },

}","CreatedOn":"2023-08-17T21:23:49.279Z","LastUpdated":"2023-08-17T21:23:49.279Z"}

