    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=CSVMasterdataLineCreator]");

        CSVMasterdataLineCreator.initMasterdataGrid(container);

        $('[name=add-company-by-form]', container).on('click', () => CSVMasterdataLineCreator.addCompany(app, container));
        $('[name=import]', container).on('click', () => CSVMasterdataLineCreator.importCompanies(app, container));
    },

    initMasterdataGrid: function(container) {
        var masterdataGridContainer = $('[name=masterdata-grid]', container);
        var masterdataGrid = new GridWidget(masterdataGridContainer, []);
        masterdataGrid.columns = [
            {
                field: 'Name',
                title: '[resource_displayname[companyname]]',
                encoded: true
            },
            {
                field: 'Perspective',
                title: '[resource_displayname[perspective]]',
                encoded: true
            },
            {
                field: 'Address.Line1',
                title: '[resource_displayname[addressline1]]',
                encoded: true
            },
            {
                field: 'Address.Line2',
                title: '[resource_displayname[addressline2]]',
                encoded: true
            },
            {
                field: 'Address.City',
                title: '[resource_displayname[city]]',
                encoded: true
            },
            {
                field: 'Address.Region',
                title: '[resource_displayname[region]]',
                encoded: true
            },
            {
                field: 'Address.Country',
                title: '[resource_displayname[country]]',
                encoded: true
            },
            {
                field: 'Address.PostCode',
                title: '[resource_displayname[postcode]]',
                encoded: true
            },
            {
                field: 'GlobalTax',
                title: '[resource_displayname[globaltax]]',
                encoded: true
            },
            {
                field: 'Reference',
                title: '[resource_displayname[reference]]',
                encoded: true
            }
        ];
        masterdataGrid.groupable = false;
        masterdataGrid.pageable = false;
        masterdataGrid.init();
    },

    addCompany: async function(app, container) {
        var dialog = new Dialog({
            name: "add-company",
            title: "[resource_displayname[addcompany]]",
            template: $('[name=new-company-form]', container).html(),
            width: 1200,
            height: 'auto'
        });

        dialog.events['add-company-to-grid'] = async function() {
            var dialogContainer = $(dialog.element);
            var referencesGrid = $('[name=references-gridGrid]', dialogContainer).data('widget');

            var item = {
                Name: $('[name=company-name]', dialogContainer).val(),
                Perspective: $('[name=company-perspective]', dialogContainer).val(),
                Address: {
                    Line1: $('[name=address-line-1]', dialogContainer).val(),
                    Line2: $('[name=address-line-2]', dialogContainer).val(),
                    City: $('[name=address-city]', dialogContainer).val(),
                    Region: $('[name=address-region]', dialogContainer).val(),
                    Country: $('[name=address-country]', dialogContainer).val(),
                    PostCode: $('[name=address-postcode]', dialogContainer).val(),
                },
                Reference: referencesGrid
                    .dataSource()
                    .data()
                    .map(r => {
                        return r.Value == ''
                            ? ''
                            : `${r.SystemId}|${r.Value}`
                    })
                    .filter(r => r != '')
                    .join(','),
                GlobalTax: $('[name=globaltax]', dialogContainer).val()
            };

            if(item.Name == '' || item.Perspective == '') {
                notification.warning('[resource_displayname[nameandperspectiverequired]]');
                return;
            }

            $('[name=masterdata-gridGrid', container).data('widget').dataSource().add(item);

            dialog.kendoObject.destroy();
        };

        dialog.init(async () => {
            var dialogContainer = $(dialog.element);
            $('[name=company-perspective]', dialogContainer).kendoDropDownList();

            var systems = await api.get(`B2B/System?$filter=Buckets/any(b:b/BucketId eq ${app.Config.B2B.RootBucket})&$select=Id`);
            var referencesGridContainer = $('[name=references-grid]', dialogContainer);
            var referencesGrid = new GridWidget(referencesGridContainer, systems.value.map(s => {
                return {
                    SystemId: s.Id,
                    Value: null
                }
            }));

            referencesGrid.columns = [
                {
                    field: "SystemId",
                    title: "[resource_displayname[sourcesystem]]",
                    description: "[resource_displayname[sourcesystem]]"
                },
                {
                    field: "Value",
                    title: "[resource_displayname[reference]]",
                    description: "[resource_displayname[reference]]",
                    encoded: true
                }
            ];
            referencesGrid.groupable = false;
            referencesGrid.pageable = false;
            referencesGrid.init();
        });
    },

    importCompanies: async function(app, container) {
        var masterdataGrid = $('[name=masterdata-gridGrid]', container).data('widget');
        var items = masterdataGrid
            .dataSource()
            .data();

        if(items.length == 0) {
            notification.warning('[resource_displayname[addcompaniesbeforeimporting]]');
            return;
        }

        var header = 'Name;Perspective;Address.Line1;Address.Line2;Address.City;Address.Region;Address.Country;Address.PostCode;GlobalTax;Reference';

        var csv = items.map(i => {
            return `${i.Name};${i.Perspective};${i.Address.Line1};${i.Address.Line2};${i.Address.City};${i.Address.Region};${i.Address.Country};${i.Address.PostCode};${i.GlobalTax};${i.Reference}`;
        });

        var csvData = header + '\n' + csv.join('\n');

        /*
        rootBucketId
        sourceSystemId
        fileName
        */

        await api.sendRaw('POST', `B2B/Import/Companies?rootBucketId=${app.Config.B2B.RootBucket}&sourceSystemId=${app.Config.B2B.SourceSystem}&fileName=ui-b2b-admin-import.csv`, csvData);

        notification.success('[resource_displayname[companiesposted]]');

        masterdataGrid.kendoObject.setDataSource([]);
    }
}"}

