<style scoped>
   .component[name=CultureFlags] { border: none; box-shadow: none; margin: 0; min-width: 110px; background: transparent; }
   .flags > a.culture { opacity: 0.2; margin-left: 10px; float: right; text-transform: uppercase; font-weight: bold; font-size: 120%; color: [theme[colours.secondary]]; }
   .flags > a.culture.active { opacity: 1; border-bottom: 3px [theme[colours.primary]] solid; }
   .flags > a { text-decoration: none; cursor: pointer; }
</style>
","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Account","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"CultureFlags","ResourceKey":"Account","Script":"CultureFlags = {
   init: async function (app, container) {
      app = app || session.app;
      container = container || $(".component[name=CultureFlags]");

      var layout = CultureFlags.getCultureFlagLayout(app);

      //Retrieve app with culture info since this isn't loaded by default
      var appCultures = (await api.get("Core/AppCulture?$filter=AppId eq " + app.Id + " and CultureId ne ''&$expand=Culture($select=Name)&$select=CultureId,Culture")).value;

      var cultures = appCultures.map(function (cul) {
         var activeClass = "";
         var hasCulture = appCultures.filter(c => c.CultureId == session.culture).length > 0;
         if(!hasCulture && cul == appCultures[0] || cul.CultureId == session.culture) {
            activeClass += "active";
         }
         var imagePath = api.apiRoot + "DMS/Content/Flags/" + cul.CultureId + ".png";
         var cultureText = (layout == "text") 
            ? cul.CultureId.split("-")[0].toUpperCase()
            : "<img src=\"" + imagePath + "\" class='flag " + cul.CultureId.split('-')[0] + " " + activeClass + "'>"

         return "<a data-culture='" + cul.CultureId + "' title='" + cul.Culture.Name + "' class=\"culture " + activeClass + "\">" + cultureText + "</a>";
      });
      $("[name=flags]", container).append(cultures.join(" "));
      $("a[data-culture]", container).on("click", function (e) { CultureFlags.setCulture(e, $(this).attr("data-culture")) });
   },

   setCulture: function(e, culture) {
      e.preventDefault();
      setQueryParameter("culture", culture);
   },

   getCultureFlagLayout(app) {
      var cultureFlagLayout = "text";
      if(app.Config.Themes.hasOwnProperty(session.theme)) 
      {
         var themeInfo = app.Config.Themes[session.theme];
         if(themeInfo.cultureFlagLayout && themeInfo.cultureFlagLayout !== "text") {
            cultureFlagLayout = themeInfo.cultureFlagLayout;
         }
      }
      return cultureFlagLayout;
   }
}
"}

{"AppId":11,"ResourceKey":"CMS","Content":"","Script":"CultureManagement = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=CultureManagement]");
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/Culture]]
				]
			}
		]);

		var linkedCultureIds = (await api.get("Core/AppCulture?$filter=AppId eq " + app.Id)).value.map(r => r.CultureId);

        var cultures = (await api.get("Core/Culture")).value;
        cultures.forEach(p => p.Has = (linkedCultureIds.indexOf(p.Id) !== -1));	

		var grid = new GridWidget(container, { data: cultures, pageSize: 20 });
		grid.pageable = false;
		grid.columns = [
            {field: "Has", title: " ", template: "<input type='checkbox' #= (Has == true) ? checked ='checked' : '' # class='chkbx k-checkbox'/>", width: 40},
			{ field: "Id", title: '[resource_displayname[Id]]', width: 70 },
			{ field: "Name", title: '[resource_displayname[Name]]' }
		];
		grid.groupable = false;
        grid.editable = false;
        grid.pageable = false;
        grid.filterable = false;
        grid.sortable = false;
        grid.dataBound = function() {
            $("input[type=checkbox]", grid.gridElement).off("click").on("click", async function(e) {
                e.preventDefault();
                var dataItem = grid.dataItem($(e.target).closest("tr"));
                dataItem.set("Has", this.checked);
				if(this.checked) {
					await api.post("Core/AppCulture", { AppId : app.Id, CultureId: dataItem.Id }).then(() => notification.success("[resource_displayname[added]]"))
						.catch((err) => error(err));
				} else {
					await api.destroy("Core/AppCulture(AppId=" + app.Id + ",CultureId='" + dataItem.Id + "')").then(() => notification.success("[resource_displayname[deleted]]"))
						.catch((err) => error(err));
				}
            });
        };
        await grid.init();
	},

}","Name":"CultureManagement","Description":null,"Key":"Content Management"}

