    </style>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Home","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"DebtorStatePieChart","ResourceKey":"B2B","Script":"DebtorStatePieChart = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=DebtorStatePieChart]");

		var defaultCurrency = app.Config.B2B.DefaultCurrency
			? app.Config.B2B.DefaultCurrency
			: "EUR";

		$("[name=currencyDropdown]", container).kendoDropDownList({
			dataSource: app.Config.B2B.Currencies
				? app.Config.B2B.Currencies
				: ["USD", "EUR", "GBP"],
			change: async function (e) {
				var value = this.value();
				var data = await DebtorStatePieChart.getData(app, value);

				chart.kendoObject.options.series[0].name = `[resource_displayname[netvalue]] (${value})`;
				chart.kendoObject.options.series[0].data = data;
				chart.kendoObject.refresh();

				if(data.flat().filter(d => d.value != 0).length == 0) {
					$('[name=nodata]', container).show();
					$('[name=chart]', container).hide();
				} else {
					$('[name=nodata]', container).hide();
					$('[name=chart]', container).show();
				}
			}
		});

		$("[name=currencyDropdown]", container).data("kendoDropDownList").value(defaultCurrency);

		var data = await this.getData(app, defaultCurrency);
		var chart = this.initChart(container, data);
		chart.init();

		if(data.flat().filter(d => d.value != 0).length == 0) {
			$('[name=nodata]', container).show();
			$('[name=chart]', container).hide();
		} else {
			$('[name=nodata]', container).hide();
			$('[name=chart]', container).show();
		}

		$(window).resize(function () {
			chart.kendoObject.refresh();
		});
	},

	initChart: function (container, data) {
		return (new PieChart($("[name=chart]", container), data));
	},

	getData: async function(app, currency) {
		var sourceSystem = app.Config.B2B.SourceSystem;
		var colours = app.Config.Themes['[theme[name]]']?.colours.charts || ['red', 'green', 'yellow', 'blue', 'white'];

		var filter = `filter(CurrencyId eq '${currency}')`;
		var transactionQuery = `B2B/ActiveTransaction/FromSystem(SystemId='${sourceSystem}')?$apply=${filter}/groupby((DebtorState), aggregate(Value with sum as Sum))`;

		var transactions = (await api.get(transactionQuery));

		return transactions.sort((a, b) => b.Sum - a.Sum).map((item, index) => {
			return {
				category: B2B.transactionStates[item.DebtorState],
				value: item.Sum,
				color: colours[index]			
			};
		});
	}
}"}

{"AppId":11,"ResourceKey":"Nav","Content":"","Script":"DetailedNav = {
