		const row = $("<div class='row g-3 p-2'></div>");
		container.append(row);

		var query = "core/Page?$filter=AppId eq " + session.app.Id + " and ParentId eq " + session.page.PageId + "&$expand=PageInfo,Pages($expand=PageInfo,Pages($expand=PageInfo))";

		await api.get(query).then(function (pages) {
			const sortedPages = pages.value.sort((a, b) => a.Order - b.Order);
			for (const page of sortedPages) {
				if (page.ShowOnMenus) {
					DetailedNav.createItem(page, row);
				}
			}
		});
	},

	createItem: function (page, parentElement) {
		if (page.Path === null) { page.Path = ""; }

		const col = $("<div class='col-md-4 p-1'></div>");
		const card = $(`
		<div class="card h-100 d-flex flex-column">
			<div class="card-body d-flex flex-column">
				<div>
				<h3 class="card-title">
				${DetailedNav.titleOf(page)}
				</h3>
					<p class="card-text">${DetailedNav.descriptionOf(page)}</p>
				</div>
				<div class="mt-auto text-end">
					<a href='/${page.Path}' class='btn btn-primary'>[resource_displayname[go]]</a>
				</div>
			</div>
		</div>
	`);

		col.append(card);
		parentElement.append(col);
	},


	itemClass: function (page) {
		if (session.page.PageId == page.Id) return "item current";
		return "item";
	},

	titleOf: function (page) {
		const culture = $("html").attr("lang");
		for (const info of page.PageInfo) {
			if (info.CultureId === culture) return info.Title;
		}
		for (const info of page.PageInfo) {
			if (info.CultureId === "") return info.Title;
		}
		return "unknown";
	},

	descriptionOf: function (page) {
		const culture = $("html").attr("lang");
		for (const info of page.PageInfo) {
			if (info.CultureId === culture) return info.Description;
		}
		for (const info of page.PageInfo) {
			if (info.CultureId === "") return info.Description;
		}
		return "unknown";
	}
};
