</style>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Document Management","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"DMS","ResourceKey":"DMS","Script":"DMS = {
    init: async function (app, container) {
        app = app || session.app;
        app = await api.get("Core/App(" + app.Id + ")");
        container = container || $('.component[name=DMS]');

        api.addToMetaCache([
            {
                "Name": "Core",
                "Types": [
                    [meta[Core/Folder]]
                ]
            }]);

        var tree = new ODataTree(new ODataTreeOptions()
            .setElement($("[name=treeRoot]", container))
            .setEndpoint("Core/Folder")
            .setODataAppend("?$expand=Files,SubFolders($top=1)&$filter=AppId eq " + app.Id + "&$orderby=Name")
        );
        let typeInfo = await api.getType("Core/Folder");

        tree.prepareData = (data) => {
            model.prepareItem(data, typeInfo);
            return { text: data.Name, spriteCssClass: "folder", type: "Folder", data: data, expanded: false, hasChildren: data.SubFolders.length > 0 };
        };

        tree.select = (e) => DMS.selectNode(e, tree, app, $(".component[name=FolderManagement]", container));
        tree.init();

        $("[name=treeRoot]", container).on("contextmenu", (e) => DMS.rightClick(e, app, tree, container));
    },

    resize: function (container) {
        var headerHeight = $("body > header").height();
        var footerHeight = $("body > footer").height();
        var bodyHeight = $("body").height();
        container.height(bodyHeight - (headerHeight + footerHeight) - 3);
        container.width("100%");
    },

    selectNode: function (e, tree, app, listingContainer) {
        if(!e || !e.node) { return; }
        var folder = tree.dataItem(e.node).data;
        tree.selectNode(e.node);
        FolderManagement.init(app, listingContainer, folder, false);
    },

    rightClick: function (e, app, tree, container) {
        e.preventDefault();

        tree.selectNode(e.target);
        var node = $(e.target).parents().filter("li").first();
        var nodeData = tree.dataItem(e.target);

        var contextMenu = new ContextMenuWidget(container);
        contextMenu.commands.push({name: "newChild", icon:"k-i-folderAddIcon", text: "[resource_displayname[newfolder]]"});
        if (nodeData) {
            contextMenu.commands.push({name: "delete", icon: "k-i-trashIcon", text: "[resource_displayname[delete]]"});
        }
        contextMenu.commands.push({template:"<li name='unpack'><span class='k-icon k-i-fileZipIcon'></span>[resource_displayname[unpackzipto]]</li>"});
        contextMenu.commands.push({name: "rename", icon: "k-i-textboxIcon", text: "[resource_displayname[rename]]"});
        contextMenu.commands.push({name: "downloadFolder", icon: "k-i-download", text: "[resource_displayname[download]]"});
        contextMenu.commands.push({name: "folderProperties", icon: "k-i-folder-more", text: "[resource_displayname[properties]]"});

        contextMenu.init(e.pageX, e.pageY);

        $("[name=newChild]", contextMenu.contextMenuElement).on("click", (e) => DMS.addNewFolder(e, app, tree, node));
        $("[name=delete]", contextMenu.contextMenuElement).on("click", (e) => DMS.removeFolder(e, tree, node));
        $("[name=rename]", contextMenu.contextMenuElement).on("click", (e) => DMS.renameFolder(e, tree, node));
        $("[name=folderProperties]", contextMenu.contextMenuElement).on("click", async (e) => await DMS.showFolderProperties(e, app, nodeData.data));
        $("[name=downloadFolder]", contextMenu.contextMenuElement).on("click", async (e) => await DMS.downloadFolder(e, nodeData.data));

        $("[name=unpack]", contextMenu.contextMenuElement).on("click",(e) => DMS.unpackFolder(e, tree, node, container));
    },

    unpackFolder: async function(e, tree, node, container) {
      e.stopPropagation();
      var folder = tree.dataItem(node).data;
      var inputElement = $("<input id = 'file' type='file' style='visibility: hidden; position: absolute'/>").appendTo(container);
      $(inputElement).change(async (e) => {
        api.file.upload(folder.Path + "?unpack",$(inputElement)[0].files[0], () => {
            notification.success("[resource_displayname[unpacked]]");
        });

      });
      document.getElementById("file").click();
    },

    renameFolder: async function (e, tree, node) {
        e.preventDefault();
        var dataItem = tree.dataItem(node);
        if (!dataItem) {
            console.error("Invalid node:", node);
            return;
        }
        var editorDialog = new EditorDialog({
            title: "[resource_displayname[renamefolder]]",
            fields: [{ field: "Name", title: "[resource_displayname[name]]" }],
            confirm: "[resource_displayname[update]]",
            data: dataItem.data
        });
        editorDialog.events.confirm = (e) => {
            editorDialog.data.save(e);
            notification.success('[resource_description[folderrenamedsuccessfully]]');
            dataItem.set("text", dataItem.data.Name);
            editorDialog.events.close();
        };

        await editorDialog.init();
    },


    addNewFolder: async function (e, app, tree, node) {
        e.preventDefault();

        var folder = await model.item.createInstance("Core/Folder");
        folder.AppId = app.Id;

        var hasParent = node.length > 0 && !$(node).hasClass("k-treeview");

        if(hasParent) {
            var item = tree.dataItem(node).data;
            folder.ParentId = item.Id;
        }

        var editorDialog = new EditorDialog({
            title: "[resource_displayname[newfolder]]",
            confirm: "<span class='k-icon k-i-plus'></span> [resource_displayname[create]]",
            fields: [
                { field: "Name", title: "[resource_displayname[name]]" }
            ],
            data: folder
        });

        editorDialog.events.confirm = async (e) => {
            await editorDialog.data.save(e);
            if(hasParent) {
                var item = tree.dataItem(node);
                if(item.expanded) {
                    tree.collapseNode(node);
                    tree.expandNode(node);
                 }
            } else {
                await tree.refresh();
            }
            editorDialog.events.close();
        };

        editorDialog.init();
    },

    removeFolder: async function (e, tree, node) {
        var data = tree.dataItem(node).data;

        var c = new ConfirmDialog({
            title: "[resource_displayname[DeleteFolderTitle]]: " + data.Path,
            question: "[resource_displayname[deleteconfirmation]]",
            confirm: "[resource_displayname[confirm]]",
            close: "[resource_displayname[close]]"
        });

        c.events.confirm = async function () {
            await data.destroy(e);
            notification.success('[resource_description[FolderDeletedSuccesfully]]');
            tree.removeNode(node);
            c.events.close();
        };
        c.init();
    },

    showFolderProperties: async function (e, app, folder) {
        e.preventDefault();
        var d = new Dialog({
            title: "[resource_displayname[folderproperties]]: " + folder.Path,
            height: 500,
            width: 1000,
            component: "FolderProperties"
        });
        d.init(async function (c) {
            await FolderProperties.init(app, $(".component[name=FolderProperties]", d.element), folder);
        });
    },

    downloadFolder: async function(e, folder) {
        e.preventDefault();
        var link = window.location.protocol + "//" + window.location.hostname + "/Api/DMS/" + folder.Path;
        window.location.href = link;
    }
}"}

