</style>","Script":"ExpressionBuilder = {
   init: function (app, container, config, callback) {
      if (!config) { config = {}; }
      if (!config.expression) { config.expression = '' }
      ExpressionBuilder.build(container, config, callback);
   },

   getMetaFor: function (serverTypeName) {
      return window.knownTypes.map(ctx => ctx.Types).reduce((a, b) => a.concat(b))
         .filter(t => t.ServerTypeName === serverTypeName)[0];
   },

   build: function (container, config, callback) {
      if (config.args) {
         var meta = $("[name=meta]", container);
         var args = new Array();
         for (var i in config.args) {
            var meta = ExpressionBuilder.getMetaFor(config.args[i]);
            args.push(
               "<div class='metaType tip'>" + html.encode(meta.ServerTypeName) +
               "<ul class='fieldList metaList tooltiptext'>" +
               ExpressionBuilder.getProps(meta) +
               ExpressionBuilder.getMethods(meta) +
               "</ul>" +
               "</div> " + i);
         }
      }
      var editor = new CSharpMonacoEditor($("[name=code")[0], {
         fixedOverflowWidgets: true,
         code: config.expression.trim() + "\n\n"
      });
      editor.init();
      $("[name=code").css("height", "500px", "width", "800px");
      $("[name=in]", container).html("(" + args.join(", ") + ") => ");
      $('[name=submit]', container).off('click').on('click', function (e) {
         callback(editor.getValue());
      });
   },

   getProps: function (meta) {
      var props = meta.Properties.map(function (p) {
         var typeInfo = p.ServerTypeName.split(".");

         return "<li class='meta'><span class='k-icon k-i-arrow-60-right'></span>" +
            "<div class='metaType'>" + html.encode(typeInfo[typeInfo.length - 1]) + "</div> " + p.Name + "</li>";
      });
      return props.join("");
   },

   getMethods: function (meta) {
      var props = meta.Methods.map(function (m) {
         var typeInfo = m.Returns.ServerTypeName.split(".");
         return "<li class='meta'><span class='k-icon k-i-drag-and-drop'></span>" +
            "<div class='metaType'>" + html.encode(typeInfo) + "</div> " + m.Name + "(" +
            ExpressionBuilder.getParams(m) + ")</li>";
      });
      return props.join("");
   },

   getParams(method) {
      return method.Parameters
         .map(p => "<span class='paramType'>" + html.encode(p.ServerTypeName) + "</span> " + p.name)
         .join(", ");
   }
}","Name":"ExpressionBuilder","Description":null,"Key":"Workflow"}

