</style>","Script":"FileContextMenu = {
    init: async function(app, container, files, readOnly, callback) {
        app = app || session.app;
        container = container || $(".component[name=FileContextMenu]");
        if(!files) { return; }

        $(container).focus();
        $(document).off().on('click', () => {
            $("[name=contextMenu]").remove();
        });
        $("[name=download]", container).on("click", (e) => FileContextMenu.downloadFiles(e, files, callback));
        if(!readOnly) {
            $("[name=rename]", container).on("click", (e) => FileContextMenu.renameFiles(e, files, callback));
            $("[name=delete]", container).on("click", (e) => FileContextMenu.deleteFiles(e, files, callback));
        } else {
            $("[name=rename]", container).remove();
            $("[name=delete]", container).remove();
        }
        
    },

    downloadFiles: async function(e, files, callback) {
        e.preventDefault();
        if(files.length === 1) {
            window.location.href = session.apiRoot + "DMS/" + files[0].Path + "?download";
        } else {
            window.location.href = session.apiRoot + "DMS/?downloadPaths=" + files.map(f => f.Path).join();
        }
        callback()
    },

    renameFiles: async function(e, files, callback) {
        e.preventDefault();
        var renameDialog = new Dialog({title: "[resource_displayname[rename]]"});
        renameDialog.template = $("[name=renameDialog]").first().html();
        renameDialog.events.rename = async function() {
            var newName = $("[name=newName]", renameDialog.element).val();
            if(files.length === 1) {
                var folderPath = files[0].Path.substring(0, files[0].Path.lastIndexOf("/")+1);
                if(newName.indexOf(".") !== -1) {
                    await api.post("DMS/" + files[0].Path + "?moveTo=" + folderPath + newName).then(() => callback()).catch((err) => error(err));
                } else {
                    var extension = files[0].Name.substring(files[0].Name.lastIndexOf("."));
                    await api.post("DMS/" + files[0].Path + "?moveTo=" + folderPath + newName + extension).then(() => callback()).catch((err) => error(err));
                }
                callback();
            } else {
                if(newName.indexOf(".") !== -1) {
                    error("[resource_displayname[batchextensionrenameunsupported]]");
                } else {
                    for(let i = 0; i < files.length; i++) {
                        var folderPath = files[i].Path.substring(0, files[i].Path.lastIndexOf("/")+1);
                        var extension = files[i].Name.substring(files[i].Name.lastIndexOf("."));
                        await api.post("DMS/" + files[i].Path + "?moveTo=" + folderPath + newName + "-" + (i+1).toString() + extension).catch((err) => error(err));
                    }
                    callback();
                }
            }
        };
        renameDialog.init(() => $("[name=newName]").val(files[0].Name));
    },

    deleteFiles: async function(e, files, callback) {
        e.preventDefault();
        for(let i = 0; i < files.length; i++) {
            await api.file.destroy(files[i].Path).catch((err) => error(err));
        }
        $("[name=contextMenu]").remove();
        callback();
    }
}","CreatedOn":"2022-04-27T12:34:11.970Z","LastUpdated":"2022-04-27T12:34:11.970Z"}

{"Content":"","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"DMS","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"FileVersionGrid","ResourceKey":"DMS","Script":"FileVersionGrid = {
