				width: 100,
				title: '[resource_shortdisplayname[download]]',
				template: `<a href="${api.apiRoot}DMS/${file.Path}?version=#= Version #&t=${session.token}&download"><span class="k-icon k-i-download"></span> [resource_displayname[download]]</a>`
			}
		];

		grid.dataBound = () => {
			$("[name=delete]", container).on("click", async (e) => await FileVersionGrid.deleteFileVersion(e, grid, file));
		};

		await grid.init();
	},

	deleteFileVersion: async function(e, grid, file) {
		e.preventDefault();

		let fileVersion = grid.dataItem($(e.currentTarget).closest("tr"));

		let confirmDialog = new ConfirmDialog({
			title: '[resource_displayname[areYouSure]]',
			question: '[resource_displayname[cannotBeUndone]]',
			close: '[resource_displayname[close]]',
			confirm: '<span class="k-icon k-i-check"></span>[resource_displayname[confirm]]'
		});

		confirmDialog.events.confirm = () => FileVersionGrid.deleteFileVersionApiCall(grid, file, fileVersion.Version, confirmDialog);

		confirmDialog.init();
	},

	deleteFileVersionApiCall: async function(grid, file, version, confirmDialog) {
		await api.file.destroy(file.Path + "?version=" + version).then(async () => {
			grid.refresh();
			confirmDialog.events.close();
			notification.success("[resource_displayname[fileversiondeleted]]");
		}).catch((err) => { error(err); });
	}
}"}

