<p name="nodata" class="alert alert-warning text-center m-2">[resource_displayname[nodatatodisplay]]</p>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Charts","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"FinancialForecast","ResourceKey":"B2B","Script":"FinancialForecast = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=FinancialForecast]");

		var defaultCurrency = app.Config.B2B.DefaultCurrency
			? app.Config.B2B.DefaultCurrency
			: "EUR";

		var data = await this.getData(app, defaultCurrency);

		var chart = this.initChart(container, data, defaultCurrency);
		chart.init();

		var flatData = data.length == 0
			? []
			: [data.series[0], data.series[1]].flat().filter(d => d != 0);

		if(flatData.length == 0) {
			$('[name=nodata]', container).show();
			$('[name=chart]', container).hide();
		} else {
			$('[name=nodata]', container).hide();
			$('[name=chart]', container).show();
		}

		$(window).resize(function () {
			chart.kendoObject.refresh();
		});

		$("[name=currencyDropdown]", container).kendoDropDownList({
			dataSource: app.Config.B2B.Currencies
				? app.Config.B2B.Currencies
				: ["USD", "EUR", "GBP"],
			change: async function (e) {
				var value = this.value();
				var newData = JSON.parse(JSON.stringify(await FinancialForecast.getData(app, value)));

				var flatData = newData.length == 0
					? []
					: [newData.series[0], newData.series[1]].flat().filter(d => d != 0);

				if(flatData.length == 0) {
					$('[name=nodata]', container).show();
					$('[name=chart]', container).hide();
				} else {
					var kendoChart = chart.kendoObject;

					kendoChart.options.series[0].data = newData.series[0].data;
					kendoChart.options.series[0].name = "[resource_displayname[cashforecastpermonth]] (" + value + ")";
					kendoChart.options.series[1].data = newData.series[1].data;
					kendoChart.options.series[1].name = "[resource_displayname[accumulativeforecast]] (" + value + ")";

					kendoChart.options.max = newData.max * 1.1;
					chart.kendoObject.options.categoryAxis.categories = newData.categories;
					chart.kendoObject.options.valueAxis.max = Math.max(...newData.series[1].data, 10) * 1.1;

					chart.kendoObject.refresh();

					$('[name=nodata]', container).hide();
					$('[name=chart]', container).show();
				}
			}
		});

		$("[name=currencyDropdown]", container).data("kendoDropDownList").value(defaultCurrency);
	},

	initChart: function (container, data, currency) {
		if(data.length == 0) {
			data = {
				series: [
					{
						data: [0],
						name: "[resource_displayname[cashforecastpermonth]] (" + currency + ")"
					},
					{
						data: [0],
						name: "[resource_displayname[accumulativeforecast]] (" + currency + ")"
					}
				],
				categories: [
					kendo.toString(new Date(), 'dd-MM-yyyy')
				],
				max: 10
			};
		}

		var args = {
			showLegend: true,
			valueTemplate: "#: kendo.toString(value, type.aggregateMoneyFormat)#",
			tooltipTemplate: "#= series.name #: #= kendo.toString(value, type.aggregateMoneyFormat) #",
			series: data.series,
			categories: data.categories,
			max: data.max * 1.1,
			type: "column"
		};

		return (new Chart($("[name=chart]", container), args));
	},

	getData: async function(app, currency) {
		var results = [];
		var sourceSystem = app.Config.B2B.SourceSystem;
		var primaryCalendarId = app.Config.Calendars.primary;
		var paymentEventName = app.Config.Calendars.PaymentEventName;
		var startDate = kendo.toString(new Date(), "yyyy-MM-dd");

		var maxActiveTransaction = (await api.get("B2B/ActiveTransaction/FromSystem(SystemId='" + app.Config.B2B.SourceSystem + "')?$orderby=DebtorPaymentDate desc&$top=1")).value;
		if(maxActiveTransaction.length === 0) {
			console.log("Financial forecast chart: no transactions");
			return [];
		}

		var maxPaymentDate = maxActiveTransaction[0].DebtorPaymentDate.split("T")[0];
		var maxQuery =  `Core/CalendarEvent?$filter=CalendarId eq ${primaryCalendarId} and Name eq '${paymentEventName}' and date(Start) ge ${maxPaymentDate}&$orderby=Start desc&$top=1`;
		var maxCalendarEvent = (await api.get(maxQuery)).value;

		if(maxCalendarEvent.length === 0) {
			console.log("Financial forecast chart: no payment events after " + maxPaymentDate);
			return [];
		}

		var endDate = maxCalendarEvent[0].Start.split("T")[0];

		var calendarQuery = `Core/CalendarEvent?$filter=CalendarId eq ${primaryCalendarId} and Name eq '${paymentEventName}' and date(Start) ge ${startDate} and date(Start) le ${endDate}&$orderby=Start asc`;
		var events = (await api.get(calendarQuery)).value;
		var earliestEventStartDate = events[0].Start.split("T")[0];

		var endpoint = `B2B/ActiveTransaction/FromSystem(SystemId='${sourceSystem}')`;
		var filter = `$filter=DebtorState ne 'Held' and date(DebtorPaymentDate) ge ${earliestEventStartDate} and CurrencyId eq '${currency}'&$select=DebtorPaymentDate,Value,CurrencyId`;
		var chartData = await api.get(`${endpoint}?${filter}`);

		// Make the DebtorPaymentDate a Date object.
		chartData = chartData.value.map(d => {
			d.DebtorPaymentDate = new Date(d.DebtorPaymentDate.split("T")[0]);
			return d;
		});

		// Sort chart data into ascending order.
		chartData.sort((a, b) => a.DebtorPaymentDate - b.DebtorPaymentDate);

		return this.buildSeriesDataset(chartData, currency);
	},

	buildSeriesDataset: function (data, currency) {
		// Convert the dates to the desired format MM-YYYY
		data = data.map(d => {
			let date = new Date(d.DebtorPaymentDate);
			let month = (date.getMonth() + 1).toString().padStart(2, '0'); // Ensure two digits for month
			d.month = `${month}-${date.getFullYear()}`; // Format as MM-YYYY
			return d;
		});

		var months = [...new Set(data.map(d => d.month))];
		var monthlyDataset = FinancialForecast.perMonthDataset(data, months);
		var accumulativeDataset = FinancialForecast.accumulativeDataset(monthlyDataset, months);
		var max = accumulativeDataset.toReversed()[0].Value;

		var ret = {
			series: [
				{
					name: "[resource_displayname[cashforecastpermonth]] (" + currency + ")",
					data: monthlyDataset.map(m => m.Value)
				}, {
					name: "[resource_displayname[accumulativeforecast]] (" + currency + ")",
					data: accumulativeDataset.map(m => m.Value)
				}
			],
			categories: months,
			max: max
		};

		return ret;
	},

	perMonthDataset: function(data, months) {
		var chartData = [];

		for(var i = 0; i < months.length; i++) {
			var month = months[i];

			chartData.push({
				Value: data.filter(d => d.month == month).reduce((accumulator, current) => accumulator + current.Value, 0),
				Month: month
			});
		}

		return chartData;
	},

	accumulativeDataset: function(monthlyData, months) {
		var accumulative = [];

		var currentValue = 0;

		for(var i = 0; i < months.length; i++) {
			var month = months[i];
			var monthValue = monthlyData.filter(d => d.Month == month)[0].Value;
			currentValue += monthValue;

			accumulative.push({
				Value: currentValue,
				Month: month
			});
		}

		return accumulative;
	}
}"}

