        grid.detailTemplate = "";
        grid.detailExpand = async function (e) {
            var instance = grid.dataItem(e.masterRow);
            var detailElement = $('.k-detail-cell', e.detailRow);
            console.log(detailElement);

            if (detailElement[0].childElementCount === 0) {
                await loadComponent(detailElement, 'FlowInstanceDetails', async(c) => {
                    FlowInstanceDetails.init(app, detailElement, instance, reportComponentName);
                });
            }
        };
        grid.groupable = false;
        await grid.init();
        grid.kendoObject.dataSource.sort({field: "Start", dir: "desc"});
        $("[name=deleteAll]", grid.gridElement).on("click", async (e) => FlowInstanceManagement.deleteAll(e, definitionId, grid));
