<script name="console" type="template">
<div class='execConsole' name='execConsole'>
   <style>
      [name=flowConsole] { padding: 5px; }
      [name=flowConsole] > .message { }
      [name=flowConsole] > .message > * { vertical-align: top; }
      [name=flowConsole] > .message > .message { display: inline-block; border: none; max-width: 90%; word-wrap: break-word; }
      [name=flowConsole] > .message .time { margin-right: 10px; }
      [name=flowConsole] > .message.success > .message { color: green; }
      [name=flowConsole] > .message.info > .message { color: green; }
      [name=flowConsole] > .message.debug > .message { color: blue; }
      [name=flowConsole] > .message.warning > .message { color: #D8A700; }
      [name=flowConsole] > .message.error > .message { color: red; }
      [name=flowConsole] > .message.fatal > .message { color: red; }
   </style>
   <div name='flowConsole'></div>
</div>
</script>","Script":"var FlowRunner = {
   init: function (app, container, flow, executeCallback, completeCallback) {
      app = app || session.app;
      container = container || $(".component[name=FlowRunner]");
      $(container).css("overflow", "hidden");
      $("button[name=executeFlow]", container).off().on("click", async function (e) {
         await FlowRunner.execute(app, container, flow, null, null, completeCallback);
         executeCallback(e);
      });
   },

   connectToHub:async function(app, console, flow, callback, completeCallback) {
      var connection = new signalR.HubConnectionBuilder().withUrl(session.apiRoot + "Hubs/Workflow").build();
      var refFlow = flow;
      connection.on("ConsoleReceive", async function (level, message, instance) {
         var d = new Date();
         var time = d.getHours() + ":" + d.getMinutes() + ":" + d.getSeconds();
         $("[name=flowConsole]", console).append(
            $("<div class='message " + level + "'>" +
               "<span class='time'>" + time + "</span>" +
               "<pre class='message'>" + html.encode(message) + "</pre>" +
               "</div>")
         );
         $("[name=flowConsole]", console).parent()[0].scrollTop = $("[name=flowConsole]", console).parent()[0].scrollHeight;

         if (level == "info" && message == "Done!") {
            connection.invoke("leave", instance);
            notification.info("Disconnected from workflow hub.");
            var startsChildActivity = JSON.parse(refFlow.DefinitionJson).Activities.filter(r => r.$type.indexOf("ExecuteFlow") !== -1);
            if(startsChildActivity.length > 0 & !$(".error", console).length) {
               var childFlow = startsChildActivity[0];
               var newestChildFlowData = await api.get("Core/FlowInstanceData?$select=Id&$expand=FlowDefinition&$top=1&$orderby=Start desc&$filter=FlowDefinition/Name eq '" + childFlow.Name + "' and FlowDefinition/AppId eq " + app.Id + " and FlowDefinition/Process/Name eq '" + childFlow.ProcessName + "'");
               if(newestChildFlowData.value.length > 0 && !$(".error", console).length && !$(".fatal", console).length) {
                  var flowDefId = newestChildFlowData.value[0].Id;
                  connection.invoke("join", flowDefId);
                  connection.invoke("ConsoleSend", "info", "Client Connected to instance " +flowDefId, flowDefId);
                  refFlow = newestChildFlowData.value[0].FlowDefinition;
               } else {
                  error("Cannot find child flow instance, has it executed?");
               }
            } else {
               if (completeCallback) { completeCallback(instance, console); }
            }
         }
      });

      connection.start()
         .then(function () { notification.info("Connected to workflow hub."); callback(connection); })
         .catch(function (err) { error(err.toString()); });
   },

   setupConsoleForInstance: function () {
      var execNum = $(".execConsole").length + 1;
      $("body").append($("script[name=console]").html());
      var dialog = $("div[name=execConsole]");
      dialog.kendoWindow({
         title: "Console",
         modal: false,
         visible: false,
         close: function () { this.destroy(); },
         resizable: true,
         width: '70%',
         height: 500
      });

      return dialog;
   },

   onConnect: async function (container, dialog, flow, instance, bookmark, connection) {
      dialog.data("connection", connection);
      dialog.data("flow", flow);
      dialog.data("instance", instance);
      var requestJson = $("textarea[name=data]", container).val();
      var request = requestJson.length > 0 ? JSON.parse(requestJson) : null;
      var r = await api.post("Core/FlowDefinition(" + flow.Id + ")/Execute", request);
      connection.invoke("join", r.value);
      connection.invoke("ConsoleSend", "info", "Client Connected to instance " + r.value, r.value);

      dialog.data("kendoWindow").wrapper.css({ top: 140, left: '20%' });
      dialog.data("kendoWindow").open();
   },

   execute: async function (app, container, flow, instance, bookmark, completeCallback) {
      var dialog = FlowRunner.setupConsoleForInstance();
      var connection = await FlowRunner.connectToHub(app, dialog,flow, function (c) { FlowRunner.onConnect(container, dialog, flow, instance, bookmark, c); }, completeCallback);
   }
}","Name":"FlowRunner","Description":null,"Key":"Workflow"}

