{"Key":"Document Management","Name":"FolderEventManager","ResourceKey":"DMS","Content":"<style scoped>
    .k-tabstrip-content, .k-tabstrip>.k-content {overflow: hidden !important; }
    </style>","Script":"FolderEventManager = {
    init: async function (app, container, folder) {
        app = app || session.app;
        container = container || $(".component[name=FolderEventManager]");
        if(!folder) { return; }
        api.addToMetaCache([
            {
                "Name": "Core",
                "Types": [
                    [meta[Core/FlowDefinition]],
                    [meta[Core/User]],
                    [meta[Core/WorkflowEvent]]
                ]
            }]);
        await FolderEventManager.setupGrid(app, container, folder);
    },

    setupGrid: async function(app, container, folder) {
		var flowDefinitions = await model.getDatasource({ endpoint: "Core/FlowDefinition", odataAppend: "?$filter=AppId eq " + app.Id});

		var users = await model.getDatasource({endpoint: "Core/User", odataAppend: "?$filter=Roles/any(r: r/Role/AppId eq " + app.Id + ")", pageSize: 1000});
        var events = await model.getDatasource({endpoint: "Core/WorkflowEvent", odataAppend: "?$filter=startswith(EventContext,'App(" + app.Id + ")/DMS(File_') and Type eq 'Core/File' and endswith(EventContext,'" + folder.Path.toLowerCase() + "')&$expand=Flow" });

        var eventGrid = new GridWidget(container, events);
        eventGrid.pageable = false;
        eventGrid.scrollable = false;
        eventGrid.filterable = false;
        eventGrid.groupable = false;
        eventGrid.toolbar = "<button name='addevent'><span class='k-icon k-i-plus'></span>[resource_displayname[newevent]]</button>";
		eventGrid.commands.push({name: "save", text: "[resource_displayname[save]]", icon: "k-i-save"});
		eventGrid.commands.push({name: "destroy", text: "[resource_displayname[delete]]" , icon: "k-i-delete"});
        eventGrid.columns = [
            { 
                field: "EventContext", 
                title: "[resource_displayname[eventtype]]", 
                template: "#=FolderEventManager.getEventType(EventContext)#",
				editor: function(container, options) {
					$('<input required name="' + options.field + '"/>').appendTo(container).kendoDropDownList({ autoBind: false, dataTextField: "text", dataValueField: "value", dataSource: { data: FolderEventManager.getEventContexts(folder) } });
                }
            },
			{ 
				field: "ExecuteAs", 
				title: "[resource_shortdisplayname[executeas]]", 
				width: 120,
				editor: function(container, options) {
					$('<input required name="' + options.field + '"/>').appendTo(container).kendoDropDownList({ autoBind: false, dataTextField: "Id", dataValueField: "Id", dataSource: users });
                }
            },
			{
				field: "FlowId",
				title: "[resource_shortdisplayname[Flow]]",
				template: "#=(Flow) ? Flow.Name : ''#",
				editor: function (container, options) {
					$('<input required name="' + options.field + '"/>').appendTo(container).kendoDropDownList({ autoBind: false, dataTextField: "Name", dataValueField: "Id", dataSource: flowDefinitions });
				}
			},
        ];

        eventGrid.dataBound = function() {
            $("[name=save]", eventGrid.gridElement).off("click").on("click", (e) => FolderEventManager.save(e, eventGrid));
            $("[name=destroy]", eventGrid.gridElement).off("click").on("click", (e) => FolderEventManager.destroy(e, eventGrid));
            $("[name=addevent]", eventGrid.gridElement).off("click").on("click", (e) => FolderEventManager.createEvent(e, eventGrid, folder));
        };

        eventGrid.init();
    },

    createEvent: async  function(e, grid, folder) {
        e.preventDefault();
        var eventModel = {
            Id: "new",
            Type: "Core/File",
            CreatedOn: (new Date()).toISOString(),
            EventContext: FolderEventManager.getEventContexts(folder)[0].value,
            FlowId: "00000000-0000-0000-0000-000000000000",
            Flow: null,
            ExecuteAs: session.user
        };

        var meta = await api.getType("Core/WorkflowEvent");

        model.prepareItem(eventModel, meta);

        grid.dataSource().insert(eventModel);
    },

	save: async function (e, grid) {
		e.preventDefault();
		var task = grid.dataItem($(e.currentTarget).closest("tr"));
        var copy =   task.toJSON();
        delete  copy.Flow;
        delete copy.type;
        delete copy.ExecuteAs_input;
        copy.CreatedOn = copy.CreatedOn.toISOString();
        if(copy.Id === "new") {
            delete copy.Id;
            await api.add("Core/WorkflowEvent", copy).then(() => {
                notification.success("[resource_displayname[saved]]");
            }).catch((err) => error(err));
        } else {
            await api.update("Core/WorkflowEvent(" + copy.Id + ")", copy).then(() => {
                notification.success("[resource_displayname[saved]]");
            }).catch((err) => error(err));
        }
        grid.refresh();
    },

	destroy: async function (e, grid) {
		var task = grid.dataItem($(e.currentTarget).closest("tr"));
        task.destroy(e).then(() => notification.success("[resource_displayname[deleted]]"));
        grid.refresh();
    },

    getEventContexts: function (folder) {
        return [
            {value: "App(" + folder.AppId + ")/DMS(File_Created)/" + folder.Path.toLowerCase(), text: "[resource_displayname[filecreated]]"},
            {value: "App(" + folder.AppId + ")/DMS(File_Updated)/" + folder.Path.toLowerCase(), text: "[resource_displayname[fileupdated]]"},
            {value: "App(" + folder.AppId + ")/DMS(File_Deleted)/" + folder.Path.toLowerCase(), text: "[resource_displayname[filedeleted]]"},
        ];
    },

    getEventType: function(eventContext) {
        if(eventContext.indexOf("DMS(File_Created)") !== -1) { return "[resource_displayname[filecreated]]"; };
        if(eventContext.indexOf("DMS(File_Updated)") !== -1) { return "[resource_displayname[fileupdated]]"; };
        if(eventContext.indexOf("DMS(File_Deleted)") !== -1) { return "[resource_displayname[filedeleted]]"; };
        return "Unknown";
    }

}","CreatedOn":"2022-03-30T14:11:15.762Z","LastUpdated":"2022-03-30T14:11:15.762Z"}

