","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Document Management","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"FolderManagement","ResourceKey":"DMS","Script":"var FolderManagement = {
    init: async function (app, container, folder, readOnly, disablePaging = false) {
        app = app || session.app;
        container = container || $(".component[name=FolderManagement]");

        if (!folder)
            return;

        readOnly = readOnly || false;
        api.addToMetaCache([
            {
                "Name": "Core",
                "Types": [
                    [meta[Core/Folder]],
                    [meta[Core/File]],
                    [meta[Core/FileContent]]
                ]
            }]);
        $("h3", container).text(folder.Name);
        $("div", container).remove();

        await FolderManagement.buildWidget($(container), folder, readOnly, app, disablePaging);
    },

    dragContainsFiles: (event) => (event.dataTransfer.types) ? event.dataTransfer.types.filter(r => r === "Files").length > 0 : false,

    buildWidget: async function (element, folder, readOnly, app, disablePaging = false) {
        var shiftPressed = false;
        var ctrlPressed = false;
        $(window).keydown((evt) => {
            if (evt.which === 16) { shiftPressed = true; }
            if (evt.which === 17) { ctrlPressed = true; }
        }).keyup((evt) => {
            if (evt.which === 16) { shiftPressed = false; }
            if (evt.which === 17) { ctrlPressed = false; }
        });

        var config = {
            endpoint: "Core/File",
            odataAppend: "?$filter=FolderId eq " + folder.Id + "&$expand=Contents($select=CreatedOn;$orderBy=CreatedOn desc;$top=1)"
        };
        var ds = await model.getDatasource(config);

        var folderGrid = new GridWidget(element, ds);
        folderGrid.filterable = true;
        folderGrid.groupable = false;
        folderGrid.editable = false;
        folderGrid.scrollable = true;
        if (disablePaging) {
            folderGrid.pageable = false;
            folderGrid.filterable = false;
        }
        folderGrid.columns = [
            {
                title: '',
                width: 30,
                template: '<img src="/icons/#:Name.split(".")[Name.split(".").length-1]#.svg" style="height: 25px;"></img>'
            },
            {
                field: "Name",
                title: "[resource_shortdisplayname[name]]"
            },
            {
                field: 'Size',
                width: 80,
                title: "[resource_shortdisplayname[size]]"
            },
            {
                field: 'CreatedBy',
                title: "[resource_shortdisplayname[createdby]]",
                editable: false,
                width: "[theme[columns.small]]"
            },
            {
                field: 'CreatedOn',
                title: "[resource_shortdisplayname[createdon]]",
                editable: false,
                format: "{0:" + type.dateFormat + " HH:mm:ss}",
                width: "[theme[columns.small]]"
            },
            {
                field: 'Contents[0].CreatedOn',
                title: "[resource_shortdisplayname[lastupdated]]",
                editable: false,
                template: `#: kendo.toString(new Date(Contents[0].CreatedOn), '${type.dateFormat} HH:mm:ss') #`,
                width: "[theme[columns.small]]"
            }
        ];
        folderGrid.columns.splice(0, 0, { selectable: true, width: 30 });
        folderGrid.dataBound = function () {
            $("[name=save]", folderGrid.gridElement).on("click", (e) => FolderManagement.saveFile(e, folderGrid));
            folderGrid.gridElement.on("click", "tr.k-master-row", (e) => {
                if (shiftPressed) { FolderManagement.shiftClick(e, folderGrid); }
                if (ctrlPressed) { FolderManagement.ctrlClick(e, folderGrid); }
            });
        };

        var fileDropContainerWidget = new FileDropContainerWidget(folderGrid.gridElement);
        fileDropContainerWidget.events.drop = (e) => FolderManagement.fileDrop(e, folderGrid, folder);
        fileDropContainerWidget.init();

        folderGrid.detailTemplate = kendo.template("<div name='fileVersionGrid'></div>");
        folderGrid.detailExpand = async (e) => await FolderManagement.expand(e, app, folderGrid, readOnly);
        await folderGrid.init();

        folderGrid.gridElement.on("contextmenu", "tr.k-master-row", (e) => FolderManagement.rightClick(e, folderGrid, readOnly));
        folderGrid.gridElement.on("click", (e) => {
            if (e.target.tagName.toLowerCase() === "div") {
                FolderManagement.clearSelection(e, folderGrid);
            }
        });
    },

    clearSelection: function (e, grid) {
        e.preventDefault();
        grid.clearSelection();
    },

    ctrlClick: function (e, grid) {
        var rowSelected = $(e.currentTarget).closest("tr");
        grid.kendoObject.select(rowSelected);
    },

    shiftClick: async function (e, grid) {
        var rowSelected = $("tr.k-state-selected", grid.gridElement).length > 0;
        if (rowSelected) {
            var rowSelectedIndex = $("tr.k-state-selected", grid.gridElement).index();
            var currentRowIndex = $(e.currentTarget).closest("tr").index();
            var children = $("tr.k-state-selected", grid.gridElement).parent().children();
            grid.kendoObject.clearSelection();
            if (currentRowIndex > rowSelectedIndex) {
                for (let i = rowSelectedIndex; i <= currentRowIndex; i++) {
                    grid.kendoObject.select(children[i]);
                }
            } else {
                for (let i = currentRowIndex; i <= rowSelectedIndex; i++) {
                    grid.kendoObject.select(children[i]);
                }
            }
        }
    },

    rightClick: async function (e, grid, readOnly) {
        e.preventDefault();
        var item = $(e.currentTarget).closest("tr");
        grid.kendoObject.select(item);
        var contextMenu = new ContextMenuWidget(grid.gridElement);

        contextMenu.commands.push({ name: "download", icon: "k-i-download", text: "[resource_displayname[download]]" });
        if (!readOnly) {
            contextMenu.commands.push({ name: "rename", icon: "k-i-edit-tools", text: "[resource_displayname[rename]]" });
            contextMenu.commands.push({ name: "delete", icon: "k-i-trashIcon", text: "[resource_displayname[delete]]" });
        }

        contextMenu.init(e.clientX, e.clientY);
        $("[name=download]", contextMenu.contextMenuElement).on("click", (e) => FolderManagement.downloadFiles(e, grid));
        $("[name=rename]", contextMenu.contextMenuElement).on("click", (e) => FolderManagement.renameFiles(e, grid));
        $("[name=delete]", contextMenu.contextMenuElement).on("click", (e) => FolderManagement.deleteFiles(e, grid));
    },

    downloadFiles: async function (e, grid) {
        e.preventDefault();
        var files = grid.select();
        if (files.length === 1) {
            window.location.href = session.apiRoot + "DMS/" + files[0].Path + "?download";
        } else {
            window.location.href = session.apiRoot + "DMS/?downloadPaths=" + files.map(f => f.Path).join();
        }
    },

    renameFiles: async function (e, grid) {
        e.preventDefault();
        var files = grid.select();
        var renameDialog = new Dialog({ title: "[resource_displayname[rename]]", height: "auto" });
        renameDialog.template = $("[name=renameDialog]").first().html();
        renameDialog.events.rename = async function () {
            var newName = $("[name=newName]", renameDialog.element).val();
            if (files.length === 1) {
                var folderPath = files[0].Path.substring(0, files[0].Path.lastIndexOf("/") + 1);
                if (newName.indexOf(".") !== -1) {
                    await api.post("DMS/" + files[0].Path + "?moveTo=" + folderPath + newName).then(() => {
                        notification.success("[resource_displayname[saved]]");
                        grid.refresh();
                        renameDialog.events.close();
                    }).catch((err) => error(err));
                } else {
                    var extension = files[0].Name.substring(files[0].Name.lastIndexOf("."));
                    await api.post("DMS/" + files[0].Path + "?moveTo=" + folderPath + newName + extension)
                        .then(() => {
                            notification.success("[resource_displayname[saved]]");
                            grid.refresh();
                            renameDialog.events.close();
                        })
                        .catch((err) => error(err));
                }
                grid.refresh();
            } else {
                if (newName.indexOf(".") !== -1) {
                    error("[resource_displayname[batchextensionrenameunsupported]]");
                } else {
                    for (let i = 0; i < files.length; i++) {
                        var folderPath = files[i].Path.substring(0, files[i].Path.lastIndexOf("/") + 1);
                        var extension = files[i].Name.substring(files[i].Name.lastIndexOf("."));
                        await api.post("DMS/" + files[i].Path + "?moveTo=" + folderPath + newName + "-" + (i + 1).toString() + extension).catch((err) => error(err));
                    }
                    notification.success("[resource_displayname[saved]]");
                    grid.refresh();
                    renameDialog.events.close();
                }
            }
        };
        renameDialog.init(() => $("[name=newName]").val(files[0].Name));
    },

    deleteFiles: async function (e, grid) {
        e.preventDefault();
        var files = grid.select();
        for (let i = 0; i < files.length; i++) {
            await api.file.destroy(files[i].Path).catch((err) => error(err));
        }
        grid.refresh();
    },

    expand: async function (e, app, grid, readOnly) {
        e.preventDefault();
        const container = $(e.detailRow).find('[name=fileVersionGrid]');

        if (!container.data("initialized")) {
            const file = grid.dataItem(e.masterRow);

            await loadComponent(container, 'FileVersionGrid', async (c) => {
                await c.init(app, container, file, readOnly);
                container.data("initialized", true); // mark as initialized
            });
        }
    },

    saveFileVersion: async function (e, grid) {
        e.preventDefault();
        var fileVersion = grid.dataItem($(e.currentTarget).closest("tr"));
        await fileVersion.save().then(() => { notification.success("[resource_displayname[saved]]"); })
            .catch((err) => { error(err); });
    },

    saveFile: async function (e, grid) {
        var file = grid.dataItem($(e.currentTarget).closest("tr"));
        var oldPath = file.Path;
        var newPath = oldPath.substring(0, oldPath.lastIndexOf("/") + 1) + file.Name;
        await api.post("DMS/" + oldPath + "?moveTo=" + newPath).then(() => {
            notification.success("[resource_displayname[FileSaved]]");
            grid.refresh();
        }).catch((err) => error(err));
    },

    deleteFileVersion: async function (e, grid, file) {
        e.preventDefault();
        var fileVersion = grid.dataItem($(e.currentTarget).closest("tr"));
        var d = new ConfirmDialog({
            title: "[resource_displayname[areyousure]]",
            question: "[resource_displayname[areyousure]]",
            close: "[resource_displayname[close]]",
            confirm: "[resource_displayname[confirm]]"
        });
        d.events.confirm = async function () {
            await api.file.destroy(file.Path + "?version=" + fileVersion.Version).then(async () => {
                //TODO: Figure out why Kendo is being a fussy shit with removing items from grid...
                d.events.close();
            }).catch((err) => { error(err); });
        };
        d.init();
    },

    deleteFile: async function (e, grid, version, file) {
        e.preventDefault();
        var d = new ConfirmDialog({
            title: "[resource_displayname[areyousure]]",
            question: "[resource_displayname[areyousure]]",
            close: "[resource_displayname[close]]",
            confirm: "[resource_displayname[confirm]]"
        });
        d.events.confirm = async function () {
            await api.file.destroy(file.Path + "?version=" + version).then(() => {
                grid.refresh();
                d.events.close();
            }).catch((err) => { error(err); });
        };
        d.init();
    },

    fileDrop: function (e, grid, folder) {
        e.preventDefault();
        e.stopPropagation();
        var files = e.target.files;
        if (files.length === 0) {
            files = e.originalEvent.dataTransfer.files;
        }
        if (folder !== null) {
            for (var i = 0; i < files.length; i++) {
                var file = files[i];
                api.file.upload(folder.Path + "/" + file.name, file, () => grid.refresh());
            }
        }
        $("input[type=file]", grid.gridElement).remove();
    }
};	"}

