{"AppId":11,"ResourceKey":"DMS","Content":"","Script":"FolderRoles = {
	init: async function (app, container, folder) {
		app = app || session.app;
		container = $(".component[name=FolderRoles]");
		if(!folder) { return; }
		var rolesInApp = await api.get("Core/Role?$filter=AppId eq " + app.Id);
		FolderRoles.setup(container, folder, rolesInApp.value);
	},

	setup: async function (container, folder, rolesInApp) {
		var grid = new GridWidget(container, {data: rolesInApp, sort: {field: "Name", dir: "asc"}});
		grid.toolbar = "<button name='applyRecursively'><span class='k-icon k-i-arrow-rotate-cw'></span>[resource_displayname[applyrecursively]]</button>";
		grid.columns = [
			{ selectable: true, width: "50px"},
			{ field: "Name", title: "[resource_displayname[name]]"}
		];
		grid.groupable = false;
		grid.pageable = false;
		grid.filterable =  false;
		grid.dataBound = function() {
			$("input[type=checkbox]", grid.gridElement).on("click", async function () {
				var checked = $(this).is(":checked");
				var uid = $(this).closest("tr").attr("data-uid");
				var dataItem = grid.dataSource().getByUid(uid);
				if(checked) {
					await api.post("Core/FolderRole", { FolderId: folder.Id, RoleId: dataItem.Id }).then(() => {
						notification.success("[resource_displayname[saved]]");
					}).catch((err) => error(err));
				} else {
					await api.destroy("Core/FolderRole(FolderId=" + folder.Id + ",RoleId=" + dataItem.Id + ")").then(() => {
						notification.success("[resource_displayname[saved]]");
					}).catch((err) => error(err));
				}
			});
		};
		await grid.init();

		$("[name=applyRecursively]", grid.gridElement).on("click", (e) => FolderRoles.applyRecursively(e, folder, grid));
		var folderRoleIds = (await api.get("Core/FolderRole?$filter=FolderId eq " + folder.Id)).value.map(c => c.RoleId);
		$("tbody > tr", grid.gridElement).each(function() {
			var uid = $(this).attr("data-uid");
			var dataItem = grid.dataSource().getByUid(uid);
			if(folderRoleIds.includes(dataItem.Id)) { grid.kendoObject.select($(this)); }
		});
	},

	applyRecursively: async function(e, folder, grid) {
		e.preventDefault();
		$("[name=applyRecursively]", grid.gridElement).html("<span class='k-icon k-i-loading'></span>[resource_displayname[applyrecursively]]");
		$("[name=applyRecursively]", grid.gridElement).off("click");
		var baseSet = (await api.get("Core/FolderRole?$filter=FolderId eq " + folder.Id)).value.map(r => r.RoleId);
		await FolderRoles.applyRecursiveInternal(folder, baseSet);
		notification.success("[resource_displayname[applied]]");
		$("[name=applyRecursively]", grid.gridElement).html("[resource_displayname[applyrecursively]]");
		$("[name=applyRecursively]", grid.gridElement).on("click", (e) => FolderRoles.applyRecursively(e, folder, grid));
	},

	applyRecursiveInternal: async function(folder, roleIds) {
		notification.info("[resource_displayname[applyroles]]: " + folder.Path);
		var currentFolder = await api.get("Core/Folder(" + folder.Id + ")?$expand=SubFolders,Roles");
		var existingFolderRoleIds = currentFolder.Roles.filter(r => roleIds.includes(r.RoleId)).map(r => r.RoleId);
		var newFolderRoleIds = roleIds.filter(r => !existingFolderRoleIds.includes(r));
		for(let i = 0; i < newFolderRoleIds.length; i++) {
			await api.post("Core/FolderRole", { FolderId: folder.Id, RoleId: newFolderRoleIds[i] });
		}
		for(let i = 0; i < currentFolder.SubFolders.length; i++) {
			await FolderRoles.applyRecursiveInternal(currentFolder.SubFolders[i], roleIds);
		}
	}


}
