    init: function (app, container, observable) {
        app = app || session.app;
        container = container || $(".component[name=Font]");
        if (!observable)
            return;

        $("[name=font-size-slider]", container).kendoSlider({ 
            min: 6,
            max: 72,
            smallStep: 2,
            largeStep: 8,
            value: parseFloat((observable.get("font.size") || "4px").replaceAll("px", "")),
            change: function(e) {
                e.preventDefault();
                observable.set("font.size", this.value() + "px");
                $('[name=font-preview]', container).css('font-size', this.value());
            }
        });

        queryLocalFonts()
            .then((fonts) => {
                if(fonts.length == 0)
                    return;

                var fontFamilies = [... new Set(fonts.map(f => f.family))];

                $("[name=font-dropdown]", container).kendoDropDownList({
                    dataSource: fontFamilies,
                    change: function(e) {
                        observable.set('font.family', this.value());
                        $('[name=font-preview]', container).css('font-family', this.value());
                    }
                }).data("kendoDropDownList");
            });
    }
}"}

