		.execConsole > .console > .message .level	{ display: inline-block; margin-right: 12px; min-width: 64px; }
		.execConsole > .console > .message .time	{ display: inline-block; margin-right: 12px; } 
		.execConsole > .console > .message.success	{ color: green; }
