		.component[name=LogStream] {height: calc(100% - 24px) !important; width: calc(100% - 8px) !important; }
</style>","Script":"var FullLogStream = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=FullLogStream]");
        await FullLogStream.connectToLogHub(app, container);

        container.find('.dropdown-select').on('click', function () {
            $('.dropdown-content').toggle();
        });

        container.find('.dropdown-content input[type="checkbox"]').on('change', function () {
            FullLogStream.handleLogLevelSelection(container);
        });
    },

    connectToLogHub: async function (app, container) {
        var domains = (await api.get('Core/App?$select=Domain')).value;

        await FullLogStream.connectToHub(container, (connection) => {
            for(var i = 0; i < domains.length; i++) {
                var domain = domains[i].Domain;
                connection.invoke("join", domain);
                connection.invoke("ConsoleSend", "info", "Client Connected to Log Stream ", domain);
            }
        });
    },

    connectToHub: async function (container, callback) {
        var connection = new signalR.HubConnectionBuilder().withUrl(session.apiRoot + "Hubs/Logs").build();
        connection.on("ConsoleReceive", (level, message) => FullLogStream.receiveMessage(container, level, message));
        await connection.start();
        callback(connection);
    },

    receiveMessage: function (container, level, message) {
        console.log(message);
        var d = new Date();
        var time = d.getHours() + ":" + d.getMinutes() + ":" + d.getSeconds();
        var entry = { Level: level.toLowerCase(), Timestamp: new Date(), Message: message };

        if (entry.Level == "information") { entry.Level = "info"; }
        if (entry.Level == "warning") { entry.Level = "warn"; }

        // Filter messages based on selected log levels
        var selectedLevels = FullLogStream.getSelectedLogLevels(container);
        if (selectedLevels.includes(entry.Level)) {
            container.find(".execConsole > [name=logConsole]").append(FullLogStream.buildMessage(entry));
        }

        if($('[name=autoScroll]', container).is(':checked')) {
            var logConsole = $('[name=logConsole]', container);
            console.log('autoscrolling', logConsole.prop('scrollHeight'));
            logConsole.scrollTop(logConsole.prop('scrollHeight'));
        }
    },

    buildMessage: function (logEntry) {
        var time = new Date(logEntry.Timestamp);
        return "<div class='message " + logEntry.Level.toLowerCase() + "'>" +
            "<div class='level'>" + logEntry.Level.toUpperCase() + "</div>" +
            "<div class='time'>" + time.getHours() + ":" + time.getMinutes() + ":" + time.getSeconds() + "</div>" +
            "<pre class='message'>" + html.encode(logEntry.Message) + "</pre>" +
            "</div>";
    },

    handleLogLevelSelection: function (container) {
        var selectedLevels = FullLogStream.getSelectedLogLevels(container);
        console.log("Selected log levels: ", selectedLevels);
    },

    getSelectedLogLevels: function (container) {
        var selectedOptions = [];
        var selectedLevels = container.find('.dropdown-content input[type="checkbox"]:checked');

        selectedLevels.each(function () {
            selectedOptions.push($(this).val());
        });

        return selectedOptions;
    }
};
