<div name="analysis"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"FundingAnalysis","ResourceKey":"B2B","Script":"FundingAnalysis = {
    init: async function(app, container) { 
        app = app || session.app;
        container = container || $(".component[name=FundingAnalysis]");
		await FundingAnalysis.initCurrencies(app, container);
    },

    initCurrencies: async function(app, container) {
		
		var defaultCurrency = app.Config.B2B.DefaultCurrency 
			? app.Config.B2B.DefaultCurrency 
			: "EUR";

        $("[name=currencyDropdown]", container).kendoDropDownList({
            dataSource: app.Config.B2B.Currencies 
				? app.Config.B2B.Currencies 
				: ["USD", "EUR", "GBP"],
            change: async function (e) {
                var value = this.value();
                await FundingAnalysis.initForCurrency(app, container, value);
            }
        }).data("kendoDropDownList");
		
		$("[name=currencyDropdown]", container)
			.data("kendoDropDownList")
			.value(defaultCurrency);
			
		await FundingAnalysis.initForCurrency(app, container, defaultCurrency);
    },
	
	initForCurrency: async function(app, container, currency) {
		var data = await FundingAnalysis.getData(app, currency);
        await FundingAnalysis.initGrid(FundingAnalysis.formatData(data.funderPaymentDate, data.invoices), currency, container);
	},
	
	getData: async function(app, currency) {
		var source = app.Config.B2B.SourceSystem;
        var calendar = app.Config.Calendars.primary;
        var eventName = app.Config.Calendars.CutoffEventName;
        var today = FundingAnalysis.formatDate();
        var tFilter = `$filter=FundingState ne 'Paid' and DebtorState ne 'Paid' and CurrencyId eq '${currency}'`;
        var ceFilter = `$filter=CalendarId eq ${calendar} and Name eq '${eventName}' and Start gt ${today}`;
        var select = "$select=CreditorName,DebtorPaymentDate,Value";

        var data = (await api.get(`B2B/Invoice/FromSystem(SystemId='${source}')?${tFilter}&${select}`))
            .value;

		var nextCutoffDate = (await api.get(`Core/CalendarEvent?${ceFilter}&$select=Start&$top=1`))
            .value[0]
			.Start;
			
		ceFilter = ceFilter
			.replace(app.Config.Calendars.CutoffEventName, app.Config.Calendars.CutoffEventName)
			.replace(today, FundingAnalysis.formatDate(new Date(nextCutoffDate)));
			
        var nextFunderPaymentDate = (await api.get(`Core/CalendarEvent?${ceFilter}&$select=Start&$top=1`))
            .value[0]
			.Start;
			
		return { 
			invoices: data, 
			funderPaymentDate: new Date(nextFunderPaymentDate) 
		};
	},

    formatData: function(nextFunderPaymentDate, data) {
        var results = {
            suppliers: Object.values(
                data.reduce((acc, item) => {
                    const key = item.CreditorName;

                    if (!acc[key]) {

                        acc[key] = { 
                            supplier: item.CreditorName, 
                            items: [],
                            totalValue: 0 
                        };
                    }

                    acc[key].totalValue += item.Value;
					acc[key].totalValue = FundingAnalysis.formatNumber(acc[key].totalValue);
					
                    acc[key].items.push({ 
						paymentDate: item.DebtorPaymentDate, 
						value: FundingAnalysis.formatNumber(item.Value) 
					});
					
                    return acc;
                }, {}))
        };

        for(var i in results.suppliers) {
            var supplier = results.suppliers[i];

            supplier.buyerPayments = Object.values(supplier.items.reduce((acc, item) => {
                const key = item.paymentDate.split('T')[0];

                if (!acc[key]) {
                    acc[key] = { paymentDate: key, totalValue: 0 };
                }

                acc[key].totalValue += item.value;
				acc[key].totalValue = FundingAnalysis.formatNumber(acc[key].totalValue);
                return acc;
            }, {}));

            var total = supplier.items.reduce((acc, item) => acc + item.value, 0);

            supplier.funderPaymentDate = FundingAnalysis.formatDate(nextFunderPaymentDate);
            supplier.fundingCost = FundingAnalysis.formatNumber((total / 100) + ((total / 1000) * 2));
			supplier.dateSpread = FundingAnalysis.getDaysBetweenDates(
				supplier.buyerPayments.map(i => i.paymentDate))
					.reduce((acc, item) => acc + item, 0);
        }

        return results;
    },

    initGrid: async function(data, currency, container) {
		var gridElement = $("[name=analysis]", container);
		gridElement.empty();
        var g = new GridWidget(gridElement, data.suppliers);
		g.editable = false;
		g.groupable = false;
		g.pageable = {
			pageSize: 10
		};
		g.columns = [
			{
				field: "supplier",
				width: 200,
				title: "Supplier Name",
				description: "Supplier Name",
				filterable: {multi: true, search: true}
			},
			{
				field: "totalValue",
				format: "{0:" + type.moneyFormat + "}",
				title: "Value (Incl Tax)",
				width: 150,
				description: "Total Value (Incl Tax) of all unpaid transactions for currency " + currency,
				attributes:{style:"text-align:right;"}
			},
			{
				field: "fundingCost",
				format: "{0:" + type.moneyFormat + "}",
				title: "Cost (Incl Tax)",
				width: 150,
				description: "Estimed cost of funding all unpaid transactions for currency " + currency,
				attributes:{style:"text-align:right;"}
			},
			{
				field: "",
				title: "Analysis Overview",
				template: function(dataItem) {
					return kendo.template(
						`#=kendo.format("{0:" + type.moneyFormat + "}", FundingAnalysis.formatNumber(totalValue))# ${currency} paid on #=funderPaymentDate# instead of being spread over a period of #=dateSpread# days.`
					)(dataItem)
				},
				description: "Gross impact if all unpaid transactions for currency " + currency + " were funded on ${data[0].funderPaymentDate}."
			}
		];
		
		/*
		g.detailTemplate = "<div name='container'></div>";
		g.detailExpand = function (e) {
			var transaction = this.dataItem(e.masterRow);
			var transactionType = "Invoice";
			var transactionId = transaction.Id;
			var container = $(e.detailRow).find("div[name=container]");
			container.html("");
			loadComponent(container[0], transactionType, (component) => {
				component.id = transactionId;
				component.backButton = false;
				component.init(session.app, container[0]);
				container.find("button").hide();
				$(container).css("overflow-y", "hidden");
			});
		};
		*/
		await g.init();
    },

    formatDate: function(date) {
        if(date === undefined) {
			date = new Date();
		}
		
        const year = date.getFullYear();
        const month = date.getMonth() + 1; // Month is zero-indexed, add 1 to make it 1-indexed
        const day = date.getDate();

        // Pad the month and day with leading zeros if necessary
        const formattedMonth = month < 10 ? `0${month}` : month;
        const formattedDay = day < 10 ? `0${day}` : day;

        return `${year}-${formattedMonth}-${formattedDay}`;
    },
	
	getDaysBetweenDates: function(dates) {
		// Ensure the dates are sorted
		dates.sort((a, b) => new Date(a) - new Date(b));

		const msPerDay = 24 * 60 * 60 * 1000; // Number of milliseconds in a day
		const differences = [];

		for (let i = 1; i < dates.length; i++) {
			const previousDate = new Date(dates[i - 1]);
			const currentDate = new Date(dates[i]);
			const timeDifference = currentDate - previousDate;
			const dayDifference = timeDifference / msPerDay;
			differences.push(dayDifference);
		}

		return differences;
	},
	
	formatNumber: function(number) {
		return Math.round(number * 100) /100;
	}
}
"}

