","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"FundingDetails","ResourceKey":"B2B","Script":"FundingDetails = {
    init: function (app, container, bucketId) {
        app = app || session.app;
        container = container || $(".component[Name=FundingDetails]");
        if (!bucketId) { return; }
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/FundingDetail]]
                ]
            }
        ]);
        FundingDetails.setupGrid(app, container, bucketId);
    },

    setupGrid: async function (app, container, bucketId) {
        var ds = await model.getDatasource({ endpoint: "B2B/FundingDetail", odataAppend: "?$filter=FundingTypeBucketId eq " + bucketId });
        var grid = new GridWidget(container, ds);
        grid.toolbar = "<button class='btn btn-sm btn-primary float-end' name='add'><span class='k-icon k-i-plus'></span>[resource_displayname[AddDetails]]</button>";
        grid.groupable = false;
        grid.pageable = false;
        grid.columns = [
            { field: "Name", title: "[resource_shortdisplayname[name]]", width: 250},
            { field: "Description", title: "[resource_shortdisplayname[description]]", width: 250},
            { field: "Formula", title: "[resource_shortdisplayname[formula]]", editable:()=>true },
            { field: "CurrentLimit", type: "number", title: "[resource_shortdisplayname[currentlimit]]", width: 250, format: "{0:" + type.moneyFormat + "}", editable:()=>true },
            { field: "Limit", type: "number", title: "[resource_shortdisplayname[limit]]", width: 250, format: "{0:" + type.moneyFormat + "}", editable:()=>true },
            { field: "CurrencyId", title: "[resource_displayname[currencyId]]" },
            { field: "IsSystematic", type: "boolean", title: "[resource_shortdisplayname[issystematic]]", width: 80, template: "<input type='checkbox' data-bind='value: IsSystematic' class='k-checkbox k-checkbox-md k-rounded-md' name='isSystematic' #=(IsSystematic) ? 'checked' : ''# />"},
        ];
        grid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" });
        grid.commands.push({ name: "remove", icon: "k-i-trash", text: "[resource_displayname[delete]]" });
        grid.dataBound = function () {
            $("button[name=remove]", grid.gridElement).off("click").on("click", (e) => FundingDetails.remove(e, grid));
            $("button[name=save]", grid.gridElement).off("click").on("click", (e) => FundingDetails.save(e, grid));
            $("input[name=isSystematic]", grid.gridElement).off("click").on("click", (e) => FundingDetails.markSystematic(e, grid));
        };
        await grid.init();
        $("button[name=add]", grid.gridElement).off("click").on("click", (e) => FundingDetails.add(e, app, grid, bucketId));
    },

    markSystematic: function(e, grid) {
        var row = $(e.currentTarget).closest("tr");
        grid.dataItem(row).IsSystematic = !grid.dataItem(row).IsSystematic;
    },

    add: async function (e, app, grid, bucketId) {
        e.preventDefault();
        var m = {
            FundingTypeBucketId: bucketId,
            SystemId: app.Config.B2B.SourceSystem.split(",")[0],
            CurrencyId: app.Config.B2B.Currencies[0],
            IsSystematic: false,
            Limit: 0,
            Name: "",
            Description: "",
            Formula: "fundablevalue"
        };
        var viewModel = kendo.observable(m);
        var d = new Dialog({
            title: "[resource_displayname[AddFundingDetail]]",
            height: "auto",
            width: 1000
        });
        d.template = $("[name=addDetailDialog]").html();
        d.events.create = async function () {
            delete d.viewModel.uid;
            await api.post("B2B/FundingDetail", d.viewModel).then(() => {
                grid.refresh();
                d.events.close();
                notification.success("[resource_displayname[added]]");
            }).catch((e) => { notification.error(e); });
        };
        d.init();
        kendo.bind(d.element, viewModel);
        d.viewModel = viewModel;
        var currencies = (await api.get("B2B/Currency")).value.filter(c => app.Config.B2B.Currencies.find(i => i == c.Id));
        $("input[name=currencyId]", d.element).kendoDropDownList({
            dataSource: { data: currencies, sort: [{ field: "Name", dir: "asc" }] },
            dataValueField: "Id",
            dataTextField: "Id"
    });
    var appSystems = app.Config.B2B.SourceSystem.split(",");
        var systems = (await api.get("B2B/System")).value.filter(s =>appSystems.find(i => i == s.Id));
        $("input[name=systemId]", d.element).kendoDropDownList({
            dataSource: { data: systems, sort: [{ field: "Name", dir: "asc" }] },
            dataValueField: "Id",
            dataTextField: "Name"
        });
    },

    save: async function (e, grid, ) {
        e.preventDefault();
        try {
            var tr = $(e.currentTarget).closest("tr");
            var fundingDetail = grid.dataItem(tr);
            if (typeof (fundingDetail.Limit) === "string") {
                fundingDetail.Limit = parseFloat(fundingDetail.Limit);
            }
            fundingDetail.save().then(() => {
            notification.success("[resource_displayname[updated]]");
            grid.refresh();
            }).catch((err) => error(err));

        }
        catch(err) {
            error(err);
        }
    },

    remove: async function (e, grid, ) {
        e.preventDefault();
        var tr = $(e.currentTarget).closest("tr");
        var fundingDetail = grid.dataItem(tr);
        await api.destroy("B2B/FundingDetail(" + fundingDetail.Id + ")").then(() => {
            notification.success("[resource_displayname[removed]]");
            grid.refresh();
        }).catch((err) => error(err));
    }
}"}

