","Script":"GenerateOffersResults = {
    init: async function (app, container) {
        const allInstances = await api.get(`Core/FlowInstanceData?$orderby=Start desc`);
        const allDates = [...new Set(allInstances.value.map(i => i.Start.slice(0, 10)))];

        const $dropdown = $("#generationDateDropdown").empty();
        $dropdown.append(`<option value="">[resource_displayname[selectdate]]</option>`);
        allDates.forEach(date => $dropdown.append(`<option value="${date}">${date}</option>`));

        const defaultDate = allDates[0];
        $dropdown.val(defaultDate);

        try {
            this.showSpinner();
            if (defaultDate) {
                await this.loadDataForDate(app, container, defaultDate);
            }
        } finally {
            this.hideSpinner();
        }

        $dropdown.off("change").on("change", async function () {
            const selectedDate = $(this).val();
            if (selectedDate) {
                try {
                    GenerateOffersResults.showSpinner();
                    await GenerateOffersResults.loadDataForDate(app, container, selectedDate);
                } finally {
                    GenerateOffersResults.hideSpinner();
                }
            }
        });
    },

    loadDataForDate: async function (app, container, day) {
        const startOfDay = `${day}T00:00:00Z`;
        const nextDay = new Date(day);
        nextDay.setDate(nextDay.getDate() + 1);
        const endOfDay = nextDay.toISOString().slice(0, 19) + "Z";

        const systems = app.Config?.B2B?.SourceSystem?.split(',') || [];
        const systemFilter = systems.map(id => `'${id}'`).join(',');
        const baseFilter = `SourceSystemId in (${systemFilter})`;

        const offerEndpoint = `B2B/Offer?$expand=AuditTrail&$filter=${encodeURIComponent(baseFilter)}`;
        const offers = (await api.get(offerEndpoint)).value || [];

        let newOffers = 0;
        let updatedOffers = 0;

        offers.forEach(o => {
            const createdToday = o.CreationDate >= startOfDay && o.CreationDate < endOfDay;
            const auditedToday = o.AuditTrail?.some(a => a.CreatedOn >= startOfDay && a.CreatedOn < endOfDay);

            if (createdToday) newOffers++;
            else if (auditedToday) updatedOffers++;
        });

        $("[name=totalNewOffers]", container).text(newOffers);
        $("[name=totalUpdatedOffers]", container).text(updatedOffers);
        $("[name=totalOffersProcessed]", container).text(newOffers + updatedOffers);
    },

    showSpinner: function () {
        $("#loadingSpinner").show();
    },

    hideSpinner: function () {
        $("#loadingSpinner").hide();
    }
};
