</div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B Admin","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"InviteUsers","ResourceKey":"B2B","Script":"InviteUsers = {
    init: async function (app, container) {
		app = app || session.app;
        
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Company]]
                ]
            }
        ]);

		container = container || $(".component[name=InviteUsers]");
        var companiesGridContainer = $('[name=companiesGridContainer', container);
        var companiesGrid;

        $('button[name=submitUserInvites]', container).click(async () => await InviteUsers.sendUserInvites(app, container, companiesGrid));

        $('select[name=perspective]', container).change(async(event) => {
            var selected = $(event.target).val();
            companiesGrid = await this.initCompaniesGrid(app, companiesGridContainer, selected);
        });
    },

    initCompaniesGrid: async function(app, gridContainer, perspective) {
        $(gridContainer).html('');
        var perspectives = {
            buyer: 'Debtor',
            supplier: 'Creditor',
            funder: 'Funder'
        };

        var companiesDatasource = await model.getDatasource({
            endpoint: "B2B/Company",
            odataAppend: `?$filter=Buckets/any(b: startsWith(b/Bucket/Path, '${app.Config.Deployment.TenantId}/') and b/Bucket/Key eq '${perspectives[perspective]}')&$expand=Address,References,Buckets($expand=Bucket)`,
            sort: { field: "Name", dir: "asc"}
        });

        var grid = new GridWidget(gridContainer, companiesDatasource);
        grid.selectable = true;
        grid.editable = false;
        grid.searchable = true;
        grid.groupable = false;

        grid.search = {
            fields: ['Name']
        };

        grid.columns = [
		    { selectable: true, width: [theme[columns.checkbox]] },
            { field: "Name", title: "[resource_displayname[name]]" },
        ];

        await grid.init();

        return grid;
    },

    sendUserInvites: async function(app, container, companiesGrid) {
        var emails = this.getEmailAddresses(container);
        var perspective = this.getPerspective(container);
        var companies = this.getSelectedCompanies(companiesGrid);

        var formIsValid = this.validateForm(emails, perspective, companies);

        if(!formIsValid) {
            notification.error('[resource_displayname[fixerrorstryagain]]');
            return;
        }

        var perspectives = {
            buyer: 'Debtor',
            supplier: 'Creditor',
            funder: 'Funder'
        };

        var rolesToAdd = [];

        for(var i in companies) {
            var company = companies[i];
            var companyBuckets = company.Buckets.filter(cb => cb.Bucket.Path != null && cb.Bucket.Path.startsWith(app.Config.Deployment.TenantId) && cb.Bucket.Key == perspectives[perspective]);

            if(companyBuckets.length == 0) {
                notification.error(`[resource_displayname[companybucketnotfound]]: ${company.Name}`);
                return;
            }

            if(companyBuckets.length > 1) {
                notification.error(`[resource_displayname[multiple${perspective}bucketsfound]]: ${company.Name}, ${perspective}`);
                return;
            }

            var companyBucket = companyBuckets[0].Bucket;

            var bucketRoles = (await api.get(`B2B/BucketRole?$filter=BucketId eq ${companyBucket.Id}&$expand=Role`)).value;
            var perspectiveRole = bucketRoles.filter(br => br.Role.Name.toLowerCase() == perspective)[0];

            if(perspectiveRole == null) {
                notification.error(`[resource_displayname[${perspective}rolenotfound]]`);
                return;
            }

            rolesToAdd.push(perspectiveRole.RoleId);
        }

        for(var i in emails) {
            var email = emails[i];
            var user = await this.ensureUserIsRegistered(app, email);

            var userRoles = (await api.get(`B2B/B2BUserRole?$filter=UserId eq '${user.Id}'`)).value;

            for(var j in rolesToAdd) {
                var roleId = rolesToAdd[j];

                var existing = (userRoles.filter(ur => ur.RoleId == roleId)).length == 1;

                if(!existing) {
                    try {
                        await api.post('B2B/B2BUserRole', {
                            UserId: user.Id,
                            RoleId: roleId
                        });
                    } catch (error) {
                        notification.warning('An error occurred while adding the role: ' + error.error);
                    }

                    notification.info(`Added role: ${roleId} to user: ${user.Id}`);
                    notification.success(`Sent invite to user: ${user.Id}`);
                } else {
                    notification.info(`User: ${user.Id} already has role: ${roleId}`);
                }
            }
        }
    },

    getEmailAddresses: function(container) {
        var emailsString = $("[name=emails]", container).val();

        return emailsString.split('\n').filter(e => e != '');
    },

    getPerspective: function(container) {
        return $("[name=perspective]", container).val();
    },

    getSelectedCompanies: function(grid) {
        return grid.select();
    },

    validateForm: function(emails, perspective, companies) {
        if(emails.length == 0) {
            notification.error('[resource_displayname[oneormoreemailsrequired]]');
            return false;
        }

        var invalidEmails = emails.filter(e => e.indexOf('@') == -1 || e.indexOf('.', e.indexOf('@')) == -1);

        if(invalidEmails.length > 0) {
            notification.error('[resource_displayname[invalidemail]]: ' + invalidEmails.join(', '));
            return false;
        }

        if(perspective == null) {
            notification.error('[resource_displayname[selectaperspective]]');
            return false;
        }

        if(companies.length == 0) {
            notification.error('[resource_displayname[selectatleastonecompany]]');
            return false;
        }
        
        return true;
    },

    ensureUserIsRegistered: async function(app, email) {
        var user = (await api.get(`B2B/B2BUser?$filter=EmailAddress eq '${email}'&$expand=Roles`)).value[0];

        if(user == null) {
            notification.warning('[resource_displayname[usernotfound]]: [resource_displayname[creatinguser]]');
            
            user = await this.registerNewUser(app, email);
        }

        return user;
    },

    registerNewUser: async function(app, email) {
        var username = email.split('@')[0];
        var password = this.randomString(32);

        var user = (await api.post('Account/Invite', {
            "DisplayName": username,
            "Email": email,
            "Password": password,
            "ConfirmPassword": password,
            "AppId": app.Id,
            "Culture": app.DefaultCultureId,
            "PhoneNumber": null,
            "DPP": "false",
            "TAC": "false"
        }));

        await this.addToInvitedRole(app, user.id);

        return {
            "Id": user.id,
            "DisplayName": user.displayName,
            "EmailAddress": user.email
        }
    },

    addToInvitedRole: async function(app, userId) {
        var invitedRole = (await api.get(`Core/Role?$filter=AppId eq ${app.Id} and Name eq 'Invited Users'`)).value[0];

        if(invitedRole) {
            var alreadyInRole = (await api.get(`Core/UserRole?$filter=UserId eq '${userId} and RoleId eq ${invitedRole.Id}'`)).value.length > 0;

            if(!alreadyInRole) {
                try {
                    await api.post('Core/UserRole', {
                        UserId: userId,
                        RoleId: invitedRole.Id
                    });
                } catch (error) {
                    notification.error('[resource_displayname[failedToAddRole]]', error);
                }
            }
        }
    },

    randomString: function(length) {
        let result = '';
        const characters = 'ABC6!D01EFGHI"JKLMN25£O96P76QRS74$TUVWX%YZabc^def786gh&ijklm*nopqr(stuvw)xyz01-2345_678=9+';
        const charactersLength = characters.length;
        
        while (result.length < length)
            result += characters.charAt(Math.floor(Math.random() * charactersLength));
        
        return result;
    }
}"}

