</style>","Script":"Invoice = {
    //TODO: populate this from the server
    types: [
        { id: 1, name: "[resource_displayname[SalesInvoice]]" },
        { id: 2, name: "[resource_displayname[CopyInvoice]]" },
        { id: 3, name: "[resource_displayname[Replacement]]" },
        { id: 4, name: "[resource_displayname[SelfBillingInvoice]]" },
        { id: 5, name: "[resource_displayname[ProFormaInv]]" }
    ],
    id: null,
    backButton: true,
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=Invoice]");
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Invoice]],
                    [meta[B2B/InvoiceLine]],
                    [meta[B2B/Company]]
                ]
            }
        ]);

        $(".component[name=Invoice]").addClass("details");

        if (this.id === null) {
            this.id = getQueryParameter("Id");
        }
        var invoiceDetails =[script[InvoiceDetails]];
        var variables = {
            element: $("[name=invoiceDetails]", container)
        };

        invoiceDetails(variables);
        var details = variables.InvoiceDetails;
        if (!this.backButton) {
            details.toolbar = "";
        }
        details.config.odataAppend = "(" + this.id + ")?$expand=References($expand=Credits($expand=Lines),OfferLines($expand=Offer),RemittanceAdviceLines),AuditTrail,Companies";
        await details.init();
            var invoice = details.data;

            await ([script[ReferenceGrid]]({ element: $("[name=referencesGrid]", container), references: invoice.References })).init();
            (await ([script[InvoiceLineGrid]]({ element: $("[name=linesGrid]", container), invoiceId: invoice.Id }))).init();
            var credits = [];
            var offers = []
            var payments = [];
            for (var i = 0; i < invoice.References.length; i = i + 1) {
                if (invoice.References[i].Credits.length > 0) {
                    for (var j = 0; j < invoice.References[i].Credits.length; j = j + 1) {
                        var credit = invoice.References[i].Credits[j];
                        credit.FundableValue = credit.Lines.filter(l=>l.IsFundable).map(l=>l.LinePrice).reduce((a,b) => a+b);
                        credits.push(credit);
                    }
                }
                if (invoice.References[i].OfferLines.length > 0) {
                    for (var j = 0; j < invoice.References[i].OfferLines.length; j = j + 1) {
                        invoice.References[i].OfferLines[j].Id = invoice.References[i].OfferLines[j].OfferId;
                        invoice.References[i].OfferLines[j].Offer.EarliestRelatedTaxPoint = kendo.toString(new Date(invoice.References[i].OfferLines[j].Offer.EarliestRelatedTaxPoint), type.dateFormat);
                        offers.push(invoice.References[i].OfferLines[j]);
                    }
                }
                if (invoice.References[i].RemittanceAdviceLines.length > 0) {
                    for (var j = 0; j < invoice.References[i].RemittanceAdviceLines.length; j = j + 1) {
                        payments.push(invoice.References[i].RemittanceAdviceLines[j]);
                    }
                }
            }

            if (credits.length > 0) {
                var relatedCreditsGridInit = [script[RelatedCreditsGrid]];
                var relatedCreditsVariables = {
                    element: $("[name=creditsGrid]", container),
                    credits: credits
                };
                relatedCreditsGridInit(relatedCreditsVariables);
                relatedCreditsVariables.RelatedCreditsGrid.init();
            }
            else { $("[name=credits]", container).remove(); }

            if (payments.length > 0) {
                var relatedPaymentGridInit = [script[RelatedPaymentsGrid]];
                var relatedPaymentGridVariables = {
                    element: $("[name=paymentsGrid]", container),
                    payments: payments
                };
                relatedPaymentGridInit(relatedPaymentGridVariables);
                relatedPaymentGridVariables.RelatedPaymentsGrid.init();
            }
            else { $("[name=payments]", container).remove(); }


            if (offers.length > 0) {
                var relatedOffersGridInit =[script[RelatedOffersGrid]];
                var relatedOffersGridVariables = {
                    element: $("[name=offersGrid]", container),
                    offers: offers
                };
                relatedOffersGridInit(relatedOffersGridVariables);
                relatedOffersGridVariables.RelatedOffersGrid.init();
            }
            else { $("[name=offers]", container).remove(); }
            audit = [];
            for (var i = 0; i < invoice.AuditTrail.length; i = i + 1) {
                audit.push(invoice.AuditTrail[i]);
            }

            var historyGridInit = [script[HistoryGrid]];
            var variables = {
                element: $("[name=historyGrid", container),
                history: audit
            };
            historyGridInit(variables);
            if (invoice.AuditTrail.length > 0) {
                await variables.HistoryGrid.init();
                variables.HistoryGrid.dataSource().sort({ field: "CreatedOn", dir: "asc" });
            }
            else { $("[name=history]", container).remove(); }
            var companyInfo =(await api.get("B2B/Company?$filter=References/any(r: r/InvoiceReferences/any(j: j/InvoiceId eq " + this.id + "))&$expand=References,Address")).value;
            var transactionCompanyInfo = [];
            for(let i = 0; i < invoice.Companies.length; i++) {
                var transactionCompany = invoice.Companies[i];
                var matchedCompanyInfo = companyInfo.filter(ci => ci.References.filter(cir => cir.Id == transactionCompany.CompanyReferenceId).length > 0)[0];
                transactionCompany.Name = matchedCompanyInfo.Name;
                transactionCompany.DebtorReference = matchedCompanyInfo.References.filter(r => r.SystemId !== "GlobalTax").map(r => r.Value).join();
                transactionCompany.DebtorVATReference = (matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax").length > 0 ? matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax")[0].Value : "N/A");
                transactionCompany.Id = matchedCompanyInfo.Id;
                if(transactionCompanyInfo.filter(r => r.Perspective == transactionCompany.Perspective && r.DebtorReference == transactionCompany.DebtorReference).length === 0) {
                    transactionCompanyInfo.push(transactionCompany);
                }
            }
            var companyGridInit = [script[CompanyGrid]];
            (await companyGridInit({
                element: $("[name=companyDetails]", container),
                dataSource: transactionCompanyInfo
            })).init();
    }
};","Name":"Invoice","Description":null,"Key":"B2B"}

