</style>","Script":"InvoiceCreator = {
  init: async function (app, container) {
    app = app || session.app;
    container = container || $(".component[name=InvoiceCreator]");
    api.addToMetaCache([
      {
        "Name": "B2B",
        "Types": [
          [meta[B2B/System]],
          [meta[B2B/Company]],
          [meta[B2B/Currency]]
        ]
      }
    ]);
    var states = ["[resource_displayname[approved]]", "[resource_displayname[ForApproval]]", "[resource_displayname[Held]]", "[resource_displayname[received]]"];
    $("input[name=buyerState]", container).kendoDropDownList({ dataSource: { data: states, sort: [{ field: "Name", dir: "asc" }] }, });
    var sourceSystems = [app.Config.B2B.SourceSystem];
    $("input[name=Systems]", container).kendoDropDownList({ dataSource: { data: sourceSystems }, });
    var currencies = await model.getDatasource({ endpoint: "B2B/Currency" });
    $("input[name=currency]", container).kendoDropDownList({ dataSource: currencies, dataTextField: "Id", dataValueField: "Id" });
    $("input[name=dueDate]", container).kendoDatePicker({ format: "yyyy-MM-dd" });
    $("input[name=buyerPaymentDate]", container).kendoDatePicker({ format: "yyyy-MM-dd" });
    $("input[name=taxPoint]", container).kendoDatePicker({ format: "yyyy-MM-dd" });
    var companies = await model.getDatasource({ endpoint: "B2B/Company", odataAppend: "/FromSystem(SystemId='" + app.Config.B2B.SourceSystem + "')?$expand=References" });
    $("input[name= buyerReference]", container).kendoDropDownList({ dataSource: companies, dataTextField: "Name", dataValueField: "Id" });
    $("input[name= supplierReference]", container).kendoDropDownList({ dataSource: companies, dataTextField: "Name", dataValueField: "Id" });
    var validator = container.kendoValidator().data("kendoValidator");
    var linesGrid = await InvoiceCreator.setupLineGrid(container);
    $("[name=create]", container).on("click", e => InvoiceCreator.createInvoice(e, container, validator, linesGrid));
  },
  
  setupLineGrid: async function (container) {
    var linesGrid = new GridWidget($("[name=linesGrid]", container), { data: [] });
    linesGrid.columns = [
      { field: "Value", title: "[resource_displayname[value]]", type: "number", format:"{0: " + type.moneyFormat + "}" },
      { field: "GrossValue", title: "[resource_displayname[grossvalue]]", type: "number", format:"{0: " + type.moneyFormat + "}" },
      { field: "TaxValue", title: "[resource_displayname[taxvalue]]", type: "number", format:"{0: " + type.moneyFormat + "}" },
      { title: "[resource_displayname[isfundable]]", template: '<input type="checkbox" class = "k-checkbox" />' }
    ];
    linesGrid.commands.push({ name: "remove", icon: "k-i-delete", text: "[resource_displayname[remove]]" });
    linesGrid.dataBound = function (e) {
      $("input[type=checkbox]", linesGrid.gridElement).off("click").on("click", (e) => {
        var row = $(e.currentTarget).closest("tr");
        var item = linesGrid.dataItem(row);
        item.IsFundable = $(e.currentTarget).is(":checked");
      });
      $("[name=remove]", linesGrid.gridElement).off("click").on("click", (e) => InvoiceCreator.removeLine(e, linesGrid));
    };
    linesGrid.toolbar = "<button name='add'><span class='k-icon k-i-plus'></span>[resource_displayname[add]]</button>";
    linesGrid.groupable = false;
    linesGrid.filterable = false;
    linesGrid.pageable = false;
    linesGrid.scrollable = false;
    await linesGrid.init();

    $("[name=add]", linesGrid.gridElement).off("click").on("click", (e) => InvoiceCreator.newLine(e, linesGrid));

    return linesGrid;
  },

  createInvoice: async function (e, container, validator, linesGrid) {
    e.preventDefault();
      if (!validator.validate()) {
        return;
      }
      var lineData = linesGrid.dataSource().data();
      var transactionLines = [];
      var buyerCompany = await api.get("B2B/Company(" + $("[name=buyerReference]", container).val() + " )?$expand=References");
      var supplierCompany = await api.get("B2B/Company(" + $("[name=supplierReference]", container).val() + " )?$expand=References");
      for (let i = 0; i < lineData.length; i++) {
        var newTransaction = {
          Type: "Invoice",
          State: $("[name=buyerState]", container).val(),
          Reference: $("[name=transactionReference]", container).val(),
          CreditorTransactionRef: $("[name=supplierTransactionReference]", container).val(),
          DebtorRef: buyerCompany.References[0].Value,
          CreditorRef: supplierCompany.References[0].Value,
          VATRef: $("[name=vatReference]", container).val(),
          Currency: $("[name=currency]", container).val(),
          DocDate: $("[name=taxPoint]", container).val(),
          DueDate: $("[name=dueDate]", container).val(),
          PaymentDate: $("[name=buyerPaymentDate]", container).val(),
          Value: lineData[i].Value,
          GrossValue: lineData[i].GrossValue,
          TaxValue: lineData[i].TaxValue,
          IsFundable: lineData[i].IsFundable ? true : false
        };
        transactionLines.push(newTransaction);
      }
      var lines = transactionLines.map(tLine => tLine.Type + ";" + tLine.State + ";" + tLine.Reference + ";" + tLine.CreditorTransactionRef + ";" + tLine.DebtorRef + ";" + tLine.CreditorRef + ";" + tLine.VATRef + ";" + tLine.Currency + ";" + tLine.DocDate
        + ";" + tLine.DueDate + ";" + tLine.PaymentDate + ";" + tLine.Value + ";" + tLine.GrossValue + ";" + tLine.TaxValue + ";" + tLine.IsFundable);
      lines.splice(0, 0, "Type;State;Reference;CreditorTransactionRef;DebtorRef;CreditorRef;VATRef;Currency;DocDate;DueDate;PaymentDate;Value;GrossValue;TaxValue;IsFundable");
      var data = lines.join("\n");
      await api.sendRaw("POST", "DMS/Data/Transactions/Received/" + $("[name=Systems]", container).val() + "_Transactions_" + (new Date()).toISOString() + ".csv", data, "text/plain").then(async () => {
        notification.success("[resource_displayname[addedtodms]]");
      }).catch((err) => error(err));
  },
  
  newLine: async function (e, linesGrid) {
    e.preventDefault();
    linesGrid.dataSource().add({ Value: "", GrossValue: "", TaxValue: "", IsFundable: "" });
  },

      removeLine: async function (e, linesGrid) {
      var item = linesGrid.dataItem($(e.currentTarget).closest("tr"));
      linesGrid.dataSource().remove(item);
  },
}","CreatedOn":"2022-04-29T11:02:33.105Z","LastUpdated":"2022-04-29T11:02:33.105Z"}

