    getDistinctCurrenciesFromTransactions: function (transactions) {
        var currencies = [];

        var ungroupedCurrencies = [];
        transactions.map(function (tra) {
            ungroupedCurrencies.push(tra.CurrencyId);
        });

        var distinctCurrencies = InvoicesByStateChart.distinct(ungroupedCurrencies);
        distinctCurrencies.forEach(function (c) {
            if (currencies.indexOf(c) == -1) {
                currencies.push(c);
