        var distinctTypes = InvoicesByStateChart.distinct(ungroupedTypes);
        distinctTypes.forEach(function (it) {
            if (transactionTypes.indexOf(it) == -1) {
                transactionTypes.push(it);
            }
        });

        return transactionTypes;
    },
    createNonFundedDataSourceForPie: function (viewModel) {
        // Clear out the invoices from the state definitions to avoid duplication
        InvoicesByStateChart.pieNonFundedStates.forEach(function (nfs) {
            nfs.Transactions = [];
        });

        viewModel.Invoices.forEach(function (inv) {
            InvoicesByStateChart.pieNonFundedStates.forEach(function (nfs) {
                if (nfs.DebtorState === inv.DebtorState) {
                    nfs.Transactions.push(inv);
                }
            });
        });

        viewModel.Credits.forEach(function (cre) {
            InvoicesByStateChart.pieNonFundedStates.forEach(function (nfs) {
                if (nfs.DebtorState === cre.DebtorState) {
                    nfs.Transactions.push(cre);
                }
            });
        });

        return InvoicesByStateChart.pieNonFundedStates.map(function (nfs) {
            var sumOfGroup = nfs.Transactions.map(function (tra) {
                    return tra.Value;
                }).reduce(InvoicesByStateChart.getSum, 0);
            return {
                category: nfs.Name,
                value: nfs.Transactions.length,
                color: nfs.Colour,
                sum: kendo.toString(sumOfGroup)
            };
        });
    },
    createFundedDataSourceForPie: function (viewModel) {
        // Clear out the invoices from the state definitions to avoid duplication
        InvoicesByStateChart.pieFundedStates.forEach(function (nfs) {
            nfs.Transactions = [];
        });

        viewModel.Invoices.forEach(function (inv) {
            InvoicesByStateChart.pieFundedStates.forEach(function (nfs) {
                if (nfs.DebtorState === inv.DebtorState && nfs.FundingState === inv.FundingState && inv.FactorCompanyId !== null) {
                    nfs.Transactions.push(inv);
                }
            });
        });

        viewModel.Credits.forEach(function (cre) {
            InvoicesByStateChart.pieFundedStates.forEach(function (nfs) {
                if (nfs.DebtorState === cre.DebtorState && nfs.FundingState === cre.FundingState && cre.FactorCompanyId !== null) {
                    nfs.Transactions.push(cre);
                }
            });
        });

        return InvoicesByStateChart.pieFundedStates.map(function (nfs) {
            var sumOfGroup = nfs.Transactions.map(function (inv) {
                    return inv.Value;
                }).reduce(InvoicesByStateChart.getSum, 0);
            return {
                category: nfs.Name,
                value: nfs.Transactions.length,
                color: nfs.Colour,
                sum: kendo.toString(sumOfGroup)
            };
        });
    },
    createGridDataSourceFromStates: function (states, viewModel) {
        var currencies = InvoicesByStateChart.getDistinctCurrenciesFromTransactions(viewModel.Transactions);
        return states.map(function (nfs) {
            return {
                State: nfs.Name,
                Count: nfs.Transactions.length,
                Total: nfs.Transactions.map(function (tra) {
                    return tra.Value;
                }).reduce(InvoicesByStateChart.getSum, 0),
                CurrencyGroups: currencies.map(function (cur) {
                    var matchingTransactionsOnCurrency = nfs.Transactions.filter(function (tra) {
                            return tra.CurrencyId == cur;
                        });
                    return {
                        Currency: cur,
                        Count: matchingTransactionsOnCurrency.length,
                        Total: matchingTransactionsOnCurrency.map(function (tra) {
                            return tra.Value;
                        }).reduce(InvoicesByStateChart.getSum, 0),
                        TransactionTypeGroups: InvoicesByStateChart.getDistinctTypesFromTransactions(matchingTransactionsOnCurrency).map(function (tt) {
                            var matchingInvoicesOnInvoiceType = matchingTransactionsOnCurrency.filter(function (tra) {
                                    if (tra.InvoiceTypeId != null)
                                        return tra.InvoiceTypeId == tt;
                                    else if (tra.CreditTypeId != null)
                                        return tra.CreditTypeId == (tt - 50);
                                });
                            return {
                                TransactionTypeId: tt,
                                Count: matchingInvoicesOnInvoiceType.length,
                                Total: matchingInvoicesOnInvoiceType.map(function (tra) {
                                    return tra.Value;
                                }).reduce(InvoicesByStateChart.getSum, 0),
                            };
                        })
                    };
                })
            };
        });
    },
    createNonFundedDataSourceForGrid: function (viewModel) {
        InvoicesByStateChart.gridNonFundedStates.forEach(function (nfs) {
            nfs.Transactions = [];
        });
        viewModel.Invoices.forEach(function (inv) {
            InvoicesByStateChart.gridNonFundedStates.forEach(function (nfs) {
                if (nfs.DebtorState === inv.DebtorState) {
                    nfs.Transactions.push(inv);
                }
            });
        });
        viewModel.Credits.forEach(function (cre) {
            InvoicesByStateChart.gridNonFundedStates.forEach(function (nfs) {
                if (nfs.DebtorState === cre.DebtorState) {
                    nfs.Transactions.push(cre);
                }
            });
        });

        return InvoicesByStateChart.createGridDataSourceFromStates(InvoicesByStateChart.gridNonFundedStates, viewModel);
    },
    createFundedDataSourceForGrid: function (viewModel) {
        InvoicesByStateChart.gridFundedStates.forEach(function (nfs) {
            nfs.Transactions = [];
        });
        viewModel.Invoices.forEach(function (inv) {
            InvoicesByStateChart.gridFundedStates.forEach(function (nfs) {
                if (nfs.DebtorState === inv.DebtorState && nfs.FundingState === inv.FundingState && inv.FactorCompanyId !== null) {
                    nfs.Transactions.push(inv);
                }
            });
        });
        viewModel.Credits.forEach(function (cre) {
            InvoicesByStateChart.gridFundedStates.forEach(function (nfs) {
                if (nfs.DebtorState === cre.DebtorState && nfs.FundingState === cre.FundingState && cre.FactorCompanyId !== null) {
                    nfs.Transactions.push(cre);
                }
            });
        });
        return InvoicesByStateChart.createGridDataSourceFromStates(InvoicesByStateChart.gridFundedStates, viewModel);
    },
    createDatasourcesForPie: function (viewModel) {
        //Non Funded
        viewModel.set("PieChartNonFinanceDataSource", InvoicesByStateChart.createNonFundedDataSourceForPie(viewModel));
        //Funded
        viewModel.set("PieChartFinanceDataSource", InvoicesByStateChart.createFundedDataSourceForPie(viewModel));
    },
    createDatasourcesForGrid: function (viewModel) {
        //Non Funded
        viewModel.set("GridNonFinanceDataSource", InvoicesByStateChart.createNonFundedDataSourceForGrid(viewModel));
        //Funded
        viewModel.set("GridFinanceDataSource", InvoicesByStateChart.createFundedDataSourceForGrid(viewModel));
    },

    getSum: function (total, num) {
        return total + InvoicesByStateChart.roundToTwo(num);
    },

    roundToTwo: function (num) {
        return  + (Math.round(num + "e+2") + "e-2");
    },

    distinct: function (array) {
        var result = [];

        array.map(function (v) {
            if (result.indexOf(v) === -1) {
                result.push(v)
            }
        });

        return result;
    },

    init: function (app) {
        var app = app || session.app;
        var sourceSystemId = app.Config.B2B.SourceSystemId;

        var el = kendo.fx($("#InvoicesByStatePanel")),
        flip = el.flip("horizontal", $("#InvoicesByStatePanelSide1"), $("#InvoicesByStatePanelSide2"));

        $("#InvoicesByStatePanelSelectorDetails").click(function () {
            flip.stop().play();
        });

        $("#InvoicesByStatePanelSelectorSummary").click(function () {
            flip.stop().reverse();
			// Re-draw the chart to avoid dodgy rendering issue
			 var chart = $('[name=InvoicesByStatePieChart].clx-chart');
             chart.data('kendoChart').refresh();
        });

        var viewModel = new kendo.data.ObservableObject({
			Finance: true,
			SelectedState: null,
			PieChartDataSource: [],
			PieChartNonFinanceDataSource: null,
			PieChartFinanceDataSource: null,
			GridDataSource: function () {
				return (this.get("Finance")) ? this.get("GridFinanceDataSource") : this.get("GridNonFinanceDataSource");
			},
			GridNonFinanceDataSource: null,
			GridFinanceDataSource: null,
			Invoices: null
		});

		InvoicesByStateChart.buildControlSet(viewModel);
        InvoicesByStateChart.populateData("dueIn30Days", "EUR", false, viewModel, sourceSystemId);

        var root = $('[name=InvoicesByStateChart].component');
        root.data('model', viewModel);
        kendo.bind(root, viewModel);

        $("#InvoicesByStatePanelSide1")[0].style.display = "flex";
        $("#InvoicesByStatePanelSide2")[0].style.display = "flex";

        var target = $("#InvoicesByStatePanel");
        $('.clx-loader', target).remove();
    },

    populateData: function (query, currency, finance, viewModel, sourceSystemId) {
        var date = new Date();

        var matchingQuery = InvoicesByStateChart.getQueriesForChart(sourceSystemId).filter(function (q) {
			return q.id == query;
		})[0];
        date.setDate(date.getDate() + matchingQuery.offsetDays);
        var currencyAppend = (currency != null) ? " and CurrencyId eq '" + currency + "'" : "";
        var invoiceQueryString = matchingQuery.invoiceQueryString + kendo.toString(date, 'yyyy-MM-dd') + currencyAppend + ")";
        var creditQueryString = matchingQuery.creditQueryString + kendo.toString(date, 'yyyy-MM-dd') + currencyAppend + ")";

        api.get(invoiceQueryString).then(function (invoices) {
            api.get(creditQueryString).then(function (credits) {

                viewModel.Invoices = invoices.value;
                viewModel.Credits = credits.value;
                viewModel.Transactions = invoices.value.concat(credits.value);
                InvoicesByStateChart.createDatasourcesForPie(viewModel);
                InvoicesByStateChart.createDatasourcesForGrid(viewModel);
                viewModel.datasource = (finance) ? viewModel.get('PieChartFinanceDataSource') : viewModel.get('PieChartNonFinanceDataSource');
                InvoicesByStateChart.buildInvoicesByStatePie(viewModel.datasource);
                InvoicesByStateChart.buildInvoicesByStateGrid((finance) ? viewModel.GridFinanceDataSource : viewModel.GridNonFinanceDataSource);
            });
        });
    },
    buildControlSet: function (viewModel) {
        var root = $('[name=InvoicesByStateChart].component');
        $('#durationFilterPlaceholder', root).kendoDropDownList({
            dataSource: [{
                    id: 'dueIn30Days',
                    name: "[resource_displayname[DueIn30Days]]"
                }, {
                    id: 'dueOver30Days',
                    name: "[resource_displayname[DueOver30Days]]"
                }, {
                    id: 'overdue',
                    name: "[resource_displayname[Overdue]]"
                }
            ],
            dataTextField: 'name',
            dataValueField: 'id',
            value: 'dueIn30Days',
            change: function (e) {
                var currencyFilterValue = $('#currencyFilterPlaceholder')[0].value;
                var durationFilterValue = $('#durationFilterPlaceholder')[0].value;
                $('#durationFilter2Placeholder').data("kendoDropDownList").value(durationFilterValue);
                var financeFilterValue = $('#financeFilterPlaceholder')[0].value;
                InvoicesByStateChart.populateData(durationFilterValue, currencyFilterValue, (financeFilterValue == "nonfinance") ? false : true, viewModel);
            }
        });
        $('#durationFilter2Placeholder', root).kendoDropDownList({
            dataSource: [{
                    id: 'dueIn30Days',
                    name: "[resource_displayname[DueIn30Days]]"
                }, {
                    id: 'dueOver30Days',
                    name: "[resource_displayname[DueOver30Days]]"
                }, {
                    id: 'overdue',
                    name: "[resource_displayname[Overdue]]"
                }
            ],
            dataTextField: 'name',
            dataValueField: 'id',
            value: 'dueIn30Days',
            change: function (e) {
                var durationFilterValue = $('#durationFilter2Placeholder')[0].value;
                $('#durationFilterPlaceholder').data("kendoDropDownList").value(durationFilterValue);
                var financeFilterValue = $('#financeFilter2Placeholder')[0].value;
                InvoicesByStateChart.populateData(durationFilterValue, null, (financeFilterValue == "nonfinance") ? false : true, viewModel);
            }
        });
        //Currency DropDowns
        $('#currencyFilterPlaceholder', root).kendoDropDownList({
            dataSource: ["EUR", "USD", "GBP"],
            change: function (e) {
                var currencyFilterValue = $('#currencyFilterPlaceholder')[0].value;
                var durationFilterValue = $('#durationFilterPlaceholder')[0].value;
                var financeFilterValue = $('#financeFilterPlaceholder')[0].value;
                InvoicesByStateChart.populateData(durationFilterValue, currencyFilterValue, (financeFilterValue == "nonfinance") ? false : true, viewModel);
            }
        });

        // If user is a finance-supplier or a buyer, add finance option to dropdown
        api.get('Core/User/Me()?$expand=Roles($expand=Role;$filter=Role/AppId eq [app[id]])').then(function (userData) {
            var financeDropDownDataSource = [{
                    id: 'nonfinance',
                    name: "[resource_displayname[DebtorState]]"
                }
            ];

            // function to determine whether the user has EP role
            function hasRoleWithFinance(role) {
                return (role.Role.Name.toLowerCase().indexOf('finance suppliers') > -1) || (role.Role.Name.toLowerCase().indexOf('buyers') > -1) || (role.Role.Name.toLowerCase().indexOf('administrators') > -1);
            }

            if (userData && userData.Roles.some(hasRoleWithFinance)) {
                financeDropDownDataSource.push({
                    id: 'finance',
                    name: "[resource_displayname[FundingState]]"
                });
            }
            $('#financeFilterPlaceholder', root).kendoDropDownList({
                dataSource: financeDropDownDataSource,
                dataTextField: 'name',
                dataValueField: 'id',
                value: 'nonfinance',
                change: function (e) {
                    var currencyFilterValue = $('#currencyFilterPlaceholder')[0].value;
                    var durationFilterValue = $('#durationFilterPlaceholder')[0].value;
                    var financeFilterValue = $('#financeFilterPlaceholder')[0].value;
                    $('#financeFilter2Placeholder').data("kendoDropDownList").value(financeFilterValue);
                    InvoicesByStateChart.populateData(durationFilterValue, currencyFilterValue, (this.value() == "nonfinance") ? false : true, viewModel);
                }
            });
            $('#financeFilter2Placeholder', root).kendoDropDownList({
                dataSource: financeDropDownDataSource,
                dataTextField: 'name',
                dataValueField: 'id',
                value: 'nonfinance',
                change: function (e) {
                    var durationFilterValue = $('#durationFilter2Placeholder')[0].value;
                    var financeFilterValue = $('#financeFilter2Placeholder')[0].value;
                    $('#financeFilterPlaceholder').data("kendoDropDownList").value(financeFilterValue);
                    $('#currencyFilterPlaceholder').data("kendoDropDownList").value("EUR");
                    InvoicesByStateChart.populateData(durationFilterValue, null, (this.value() == "nonfinance") ? false : true, viewModel);
                }
            });
        });
    },

    buildInvoicesByStatePie: function (data) {
        var target = $('[name=invoicesByStatePieChart]')[0];
        $('.clx-loader', target).remove();
        $('[name=InvoicesByStatePieChart].clx-chart').remove() // lets remove any existing charts that occupy this space!
        $('<div name="InvoicesByStatePieChart" class="clx-chart InvoicesByStatePieChart"></div>').appendTo($('#InvoicesByStatePiePlaceholder')[0]).kendoChart({
            series: [{
                    name: "Invoices By State",
                    type: "pie",
                    overlay: {
                        gradient: "none"
                    },
                    startAngle: 0,
                    data: data,
                    labels: {
                        visible: true,
                        align: "column",
                        template: '#=value# #= category #\n #= kendo.toString(dataItem.sum, "n")#',
                        font: "14px Verdana",
                        position: "outsideEnd",
                        background: function (e) {
                            return e.series.color;
                        },
                        opacity: 1,
                        color: "#FFFFFF"
                    },
                    padding: 70,
                    explodeField: "explode",
                }
            ],
            tooltip: {
                visible: false,
            },
            legend: {
                visible: false
            },
            seriesClick: function (e) {
                var alreadyExploded = e.dataItem.explode;

                var grid = $('[name=invoicesByStateGrid]');
                var dataItem = grid.data('kendoGrid').dataSource.data().filter(function (x) {
                        return x.State === e.dataItem.category;
                    })[0];
                Array.from($('[data-uid]', grid)).forEach(function (r) {
                    grid.data('kendoGrid').collapseRow(r);
                });

                if (dataItem && !alreadyExploded) {
                    var row = $('tbody tr[data-uid=' + dataItem.uid + ']', grid);
                    grid.data('kendoGrid').expandRow(row);
                }

                // Disable animations
                e.sender.options.transitions = false;

                // Explode the current slice
                e.dataItem.explode = !alreadyExploded;
                e.sender.refresh();

            }
        });
    },
    buildInvoicesByStateGrid: function (data) {
        var target = $('[name=invoicesByStateGrid]');
        $('.clx-loader', target).remove();

        if (target.length && target.data('kendoGrid')) {
            // lets check if this exists and if it does destroy it
            target.data('kendoGrid').destroy();
        }

        target.kendoGrid({
            theme: 'ChartTheme',
            dataSource: {
                data: data
            },
            columns: [{
                    field: 'State',
                    title: '[resource_displayname[State]]',
                }, {
                    field: 'Count',
                    title: '[resource_displayname[Count]]',
                }
            ],
            detailInit: InvoicesByStateChart.currencyDetailInit,
            detailExpand: function (e) {
                var grid = this.element;
                var dataItem = e.sender.dataItem(e.masterRow);
                Array.from($('[data-uid]:not([data-uid=' + dataItem.uid + '])', grid)).forEach(function (r) {
                    grid.data('kendoGrid').collapseRow(r);
                });

                var chart = $('[name=InvoicesByStatePieChart].clx-chart');
                chart.data('kendoChart')
                .options
                .series[0]
                .data.forEach(function (d) {
                    // Clean up exploded state
                    if (d.category === dataItem.State) {
                        d.explode = true;
                    }
                });
                chart.data('kendoChart').refresh();
            },
            detailCollapse: function (e) {
                var chart = $('[name=InvoicesByStatePieChart].clx-chart');
                chart.data('kendoChart')
                .options
                .series[0]
                .data.forEach(function (d) {
                    // Clean up exploded state
                    d.explode = false;
                });
                chart.data('kendoChart').refresh();
            }
        });
    },
    currencyDetailInit: function (e) {
        var rowData = this.dataItem(e.masterRow);
        $("<div/>").appendTo(e.detailCell).kendoGrid({
            dataSource: {
                data: rowData.CurrencyGroups
            },
            columns: [{
                    field: 'Currency',
                    title: '[resource_displayname[Currency]]',
                }, {
                    field: 'Count',
                    title: '[resource_displayname[Count]]',
                }, {
                    field: 'Total',
                    title: '[resource_displayname[Total]]',
                    template: '#= kendo.toString(Total, "n")#'
                },
            ],
            detailInit: InvoicesByStateChart.typeDetailInit,
        });
    },
    typeDetailInit: function (e) {
        var rowData = this.dataItem(e.masterRow);
        $("<div/>").appendTo(e.detailCell).kendoGrid({
            dataSource: {
                data: rowData.TransactionTypeGroups
            },
            columns: [{
                    field: 'TransactionTypeId',
                    title: '[resource_displayname[TransactionType]]',
                    template: "#= InvoicesByStateChart.getTypeString(TransactionTypeId)#"
                }, {
                    field: 'Count',
                    title: '[resource_displayname[Count]]',
                }, {
                    field: 'Total',
                    title: '[resource_displayname[Total]]',
                    template: '#= kendo.toString(Total, "n")#'
                },
            ],
        });
    },
    getTypeString: function (id) {
        var type = InvoicesByStateChart.types.filter(function (s) { return s.id == id; });

        if (type.length > 0) { return type[0].name; }
        return '';
    }
}

$(function () {
    InvoicesByStateChart.init();
});
