<p name="nodata" class="alert alert-warning text-center m-2">[resource_displayname[nodatatodisplay]]</p>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Charts","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"InvoiceValueByMonth","ResourceKey":"B2B","Script":"InvoiceValueByMonth = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=InvoiceValueByMonth]");

		var defaultCurrency = app.Config.B2B.DefaultCurrency
			? app.Config.B2B.DefaultCurrency
			: "EUR";

		$("[name=currencyDropdown]", container).kendoDropDownList({
			dataSource: app.Config.B2B.Currencies
				? app.Config.B2B.Currencies
				: ["USD", "EUR", "GBP"],
			change: async function (e) {
				var value = this.value();
				var data = await InvoiceValueByMonth.getData(app, value);

				chart.kendoObject.options.series[0].name = `[resource_displayname[GrossValue]] (${value})`;
				chart.kendoObject.options.categoryAxis.categories = data.months;
				chart.kendoObject.options.valueAxis.max = Math.max(...data.totals) * 1.1;
				chart.kendoObject.options.series[0].data = data.totals;
				chart.kendoObject.refresh();

				if(data.totals.flat().filter(d => d != 0).length == 0) {
					$('[name=nodata]', container).show();
					$('[name=chart]', container).hide();
				} else {
					$('[name=nodata]', container).hide();
					$('[name=chart]', container).show();
				}
			}
		});

		$("[name=currencyDropdown]", container).data("kendoDropDownList").value(defaultCurrency);

		var data = await this.getData(app, defaultCurrency);
		var chart = this.initChart(container, data, defaultCurrency);
		chart.init();

		if(data.totals.flat().filter(d => d != 0).length == 0) {
			$('[name=nodata]', container).show();
			$('[name=chart]', container).hide();
		} else {
			$('[name=nodata]', container).hide();
			$('[name=chart]', container).show();
		}

		$(window).resize(function () {
			chart.kendoObject.refresh();
		});
	},

	initChart: function (container, data, currency) {
		var args = {
			showLegend: true,
			valueTemplate: "#: kendo.toString(value, type.moneyFormat)#",
			tooltipTemplate: "#= series.name #: #= kendo.toString(value, type.moneyFormat) #",
			series: [{
				name: `[resource_displayname[GrossValue]] (${currency})`,
				data: data.totals
			}],
			categories: data.months,
			max: Math.max(...data.totals) * 1.1,
			type: "column"
		};

		return (new Chart($("[name=chart]", container), args));
	},

	getData: async function(app, currency) {
		var sourceSystem = app.Config.B2B.SourceSystem;

		var filter = `$filter=Currency eq '${currency}'`;
		var invoiceQuery = `B2B/Invoice/StatsByCalendarMonth(SystemId='${sourceSystem}')?${filter}`;

		var invoices = (await api.get(invoiceQuery)).value;
		var transactions = invoices
			.map(t => {
				var split = t.CalendarMonth.split('-');
				var year = split[0];
				var month = split[1].padStart(2, '0');
				t.month = new Date(`${year}-${month}-01`);
				t.formatted = kendo.toString(t.month, 'MM-yyyy');
				return t;
			})
			.sort((a, b) => a.month - b.month);

		var categories = [... new Set(transactions.map(t => t.formatted))];

		return {
			months: categories,
			totals: categories.map(m => transactions
				.filter(t => t.formatted == m)
				.map(t => t.Sum)
				.reduce((accumulator, current) => accumulator + current, 0))
		};
	}
}"}

