    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=InvoiceYearToDate]");

        const defaultCurrency = app.Config.B2B.DefaultCurrency || "EUR";

        const currencyDropdown = $("[name=currencyDropdown]", container).kendoDropDownList({
            dataSource: app.Config.B2B.Currencies || ["USD", "EUR", "GBP"],
            change: async function () {
                const selectedCurrency = this.value();
                await InvoiceYearToDate.updateInvoiceData(app, container, selectedCurrency);
            }
        }).data("kendoDropDownList");

        currencyDropdown.value(defaultCurrency);
        await InvoiceYearToDate.updateInvoiceData(app, container, defaultCurrency);

        $(".comparison-icon").kendoTooltip({
            content: function (e) {
                return "[resource_displayname[comparisontext]]"
            },
            position: "right"
        });
    },

    updateInvoiceData: async function (app, container, currency) {
        const { total, invoiceCount, totalComparisonResult, countComparisonResult } = await InvoiceYearToDate.getData(app, currency);
        InvoiceYearToDate.displayTotalInvoice(total, invoiceCount, totalComparisonResult, countComparisonResult, container);
    },

    getData: async function (app, currency) {
        const sourceSystem = app.Config.B2B.SourceSystem;
        const invoiceQuery = `B2B/Invoice?$filter=SourceSystemId eq '${sourceSystem}' and CurrencyId eq '${currency}'`;

        const invoices = (await api.get(invoiceQuery)).value;

        const currentDate = new Date();
        const currentYear = currentDate.getFullYear().toString();
        const previousYear = (currentDate.getFullYear() - 1).toString();
        const currentMonth = currentDate.getMonth() + 1; // numeric month (1–12)

        const filterInvoicesYearToDate = (year) =>
            invoices.filter(({ TaxPoint }) => {
                const [invoiceYear, invoiceMonth] = TaxPoint.split("-");
                return (
                    invoiceYear === year &&
                    parseInt(invoiceMonth, 10) <= currentMonth
                );
            });

        const currentYearInvoices = filterInvoicesYearToDate(currentYear);
        const previousYearInvoices = filterInvoicesYearToDate(previousYear);

        const calculateTotal = (invoiceList) =>
            invoiceList.reduce((sum, { Value }) => sum + Value, 0);

        const totalForCurrentYear = calculateTotal(currentYearInvoices);
        const totalForPreviousYear = calculateTotal(previousYearInvoices);

        const compare = (current, previous) =>
            current > previous ? "up" : current < previous ? "down" : "same";

        return {
            total: totalForCurrentYear,
            invoiceCount: currentYearInvoices.length,
            totalComparisonResult: compare(totalForCurrentYear, totalForPreviousYear),
            countComparisonResult: compare(currentYearInvoices.length, previousYearInvoices.length)
        };
    },


    displayTotalInvoice: function (total, invoiceCount, totalComparisonResult, countComparisonResult, container) {
        const invoiceValueDisplay = $("div.invoiceValueDisplay", container);

        const getComparisonIcon = (result) => ({
            up: '<span class="comparison-icon up-arrow">↑</span>',
            down: '<span class="comparison-icon down-arrow">↓</span>',
            same: '<span class="comparison-icon same-icon">→</span>'
        })[result];

        const countComparisonIcon = getComparisonIcon(countComparisonResult);
        const valueComparisonIcon = getComparisonIcon(totalComparisonResult);

        invoiceValueDisplay.html(`
            <h4>[resource_displayname[totalinvoicecountthisyear]]</h4>
            <h2 class="yearToDate">${invoiceCount} ${countComparisonIcon}</h2>
            <h4>[resource_displayname[totalinvoicevaluethisyear]]</h4>
            <h2 class="yearToDate">${kendo.toString(total, type.moneyFormat)} ${valueComparisonIcon}</h2>
        `);
    }
};
"}

