    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=LayoutManagement]");
        api.addToMetaCache([
            {
                "Name": "Core",
                "Types": [
                    [meta[Core/Layout]]
                ]
            }
        ]);
        var config = {
            endpoint: "Core/Layout",
            odataAppend: "?$filter=AppId eq " + app.Id
        };
        let ds = await model.getDatasource(config);
        await LayoutManagement.initGrid(app, container, ds);

        await loadComponent($('[name=layoutMigrationComponent]', container), 'LayoutMigration');
        await LayoutMigration.init(app, $(`.component[name=LayoutMigration]`, container));
    },

    initGrid: async function(app, container, dataSource) {
        var grid = new GridWidget(container, dataSource);
        grid.groupable = false;
        grid.toolbar = [
        {
            template: "<div class='btn-group btn-group-sm'> \
                <button class='btn btn-primary' name='create'> \
                    <span class='k-icon k-i-plus'></span>[resource_displayname[new]] \
                </button> \
                <button class='btn btn-primary' name='migrate'> \
                    <span class='k-icon k-i-arrow-up'></span>[resource_displayname[migrate]] \
                </button> \
            </div>"
        }];

        grid.columns = [
            { 
                field: "Name", 
                title: '[resource_displayname[name]]' 
            },
			{ 
                field: "LastUpdated", 
                title: "[resource_displayname[lastupdated]]", 
                type: "date", 
                format: "{0: " + type.dateFormat + " HH:mm}",
                width: "[theme[columns.small]]" 
            },
            { 
                field: "LastUpdatedBy", 
                title: "[resource_displayname[lastupdated]]",
                width: "[theme[columns.small]]"
            }
        ];
        grid.commands.push({name: "save", icon: "k-i-save", text: "[resource_displayname[save]]"});
        grid.commands.push({name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]"});
        grid.detailTemplate = kendo.template($("[name=layoutDetails]", container).html());
        grid.detailExpand = async function(e) {
            var item = grid.kendoObject.dataItem(e.masterRow);
            var expandContainer = $(e.detailRow);
            var replaced = expandContainer.html().replaceAll('{ID}', Guid());

            expandContainer.html(replaced);

            if ($(e.detailRow).find(".monaco-editor").length === 0) {
                await LayoutManagement.layoutExpand(item, expandContainer);
            };
        };
        grid.dataBound = function(e) {
            $("button[name=save]", grid.gridElement).on("click", (e) => LayoutManagement.save(e, grid));
            $("button[name=delete]", grid.gridElement).on("click", (e) => LayoutManagement.destroy(e, grid));
        };
        grid.resizable = {
            rows: true
        };
        await grid.init();
        $("button[name=migrate]", grid.gridElement).on("click",  (e) => LayoutManagement.migrate(e, app, container));
        $("button[name=create]", grid.gridElement).on("click", (e) => LayoutManagement.create(e, app, grid));
        return grid;
    },

    layoutExpand: async function(item, container) {
        var headerEditor = new HTMLMonacoEditor($("div[name=header] > div[name=editorContainer]", container)[0], {
            code: item.HeaderHtml
        });
        var bodyEditor = new HTMLMonacoEditor($("div[name=body] > div[name=editorContainer]", container)[0], {
            code: item.Html
        });
        headerEditor.onChange = () => item.HeaderHtml = headerEditor.getValue();
        bodyEditor.onChange = () => item.Html = bodyEditor.getValue();
        headerEditor.init();
        bodyEditor.init();

        $('[name=header-tab-button]', container).on('click', () => {
            headerEditor.editor.layout();
        });

        $('[name=body-tab-button]', container).on('click', () => {
            bodyEditor.editor.layout();
        });
    },

    migrate: async function (e, app, container) {
        e.preventDefault();
        var migrateDialog = new Dialog({
            width: 620,
            height: "auto",
            title: "[resource_displayname[migrateLayouts]]"
        });

        migrateDialog.template = $("[name=layoutMigrationComponent]", container).first().html();
        await migrateDialog.init();

        await LayoutMigration.initDropdown($('[name=LayoutMigration]', migrateDialog.element));
    },

    create: async function (e, app, grid) {
        e.preventDefault();
        var createLayoutDialog = new Dialog({
            width: 600,
            height: "auto",
            title: "[resource_displayname[newlayout]]"
        });
        createLayoutDialog.template = $("[name=newLayoutDialog]").first().html();
        createLayoutDialog.events.create = async function (e) {
            await api.add("Core/Layout", {
                Id: 0,
                AppId: app.Id,
                Name: $("[name=name]", createLayoutDialog.element).val(),
                HeaderHtml: "", 
                Html: ""
            }).then(() => {
                notification.success('[resource_displayname[layoutcreated]]');
                createLayoutDialog.events.close();
                grid.refresh();
            }).catch((e) => notification.error(e));
        };
        await createLayoutDialog.init();
    },

    save: async function (e, grid) {
        e.preventDefault();
        var layout = grid.dataItem($(e.currentTarget).closest("tr"));
        await layout.save(e);
        notification.success("[resource_description[saved]]");
    },

    destroy: async function (e, grid) {
        e.preventDefault();
        var layout = grid.dataItem($(e.currentTarget).closest("tr"));
        await layout.destroy(e);
        notification.success("[resource_description[LayoutDeleted]]");
        grid.refresh();
    }
}"}

