</style>","Script":"Login = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $("[name=Login].component");
		var loginContainer =$("[name=loginContents]", container);
		loginContainer.html(loginContainer.html().replace("[LOGINFORM]", $("script[name=loginForm]").html()));

		if(session.app.Config.Themes.Default.paintLoginMid) {
			$(".midContent").css("background-color", session.app.Config.Themes.Default.colours.secondary);
		}
		if(session.app.Config.Themes.Default.paintLoginBottom) {
			$(".bottomContent").css("background-color", session.app.Config.Themes.Default.colours.secondary);
		}
		$(".value[name=pass] > span").css("color", session.app.Config.Themes.Default.colours.secondary);

		var confirmation = {
			SSOUserId: getQueryParameter("u"),
			Token: getQueryParameter("t")
		};

		if (confirmation.SSOUserId && confirmation.Token) {
			var r = await api.post("Account/ConfirmEmail", confirmation);
			if (r === true) { notification.success("[resource_description[TokenVerificationSuccess]]"); }
			else { notification.warning("[resource_description[TokenVerificationFailed]]"); }
		}
		if (window.location.href.indexOf("AccessDenied") != -1) {
			$("[name=error]", container).text("Access Denied!");
		}

		var login = async function (e) {
			notification.info("[resource_displayname[loggingin]]");
			var result = await api.login(
				$("[name=user] input").val(),
				$("[name=pass] input").val()
			);

			if(result.id) {	await Login.success(e);	}
		};

		$("button[name=login]", container).on("click", login);
		$("[name=pass] > .value > input").on("keyup", async function (e) {
			if (event.keyCode === 13) {	await login(e);	}
		});

		$("[name=buttons] [name=forgotPass]", container).off().on("click", Login.forgotPassword);
		$("[name=register]", container).on("click", function (e) {
			Login.register(e, app);
		});

		$("[name=pass] .k-icon.k-i-preview").on("click", function () {
			$("[name=pass] > .value > input").attr("type", ($("[name=pass] > .value > input").attr("type") == "password" ? "text" : "password"));
		});
	},

	register: function(e, app) {
		e.preventDefault();
		var d = new Dialog({ title: "[resource_displayname[register]]", width: 620, height: "auto" });
		d.template = $("[name=registerComponent]").first().html();
		d.init(() => Register.init(app, $(".component[name=Register]", d.element), d));
	},

	forgotPassword: function (e) {
		e.preventDefault();
		var d = new Dialog({
			title: "[resource_description[PasswordResetEmailTitle]]"
		});
		d.template = $("script[name=ForgotPass]").html();
		d.events.submit = async function (e) {
			if($("[name=forgotPasswordForm]", d.element).getKendoValidator().validate()) {
				var request = {
					Email: $("input[name=email]", d.element).val(),
					AppId: session.app.Id,
					Culture: session.culture
				};
				var e = await api.post("Account/ForgotPassword", request);
				notification.success("[resource_description[ForgotPasswordRequesrSubmitted]]");
				d.events.close();
			}
		};
		d.init(() => {
			$("[name=forgotPasswordForm]", d.element).kendoValidator();
		});
	},

	success: async function (e) {
		var user = await api.get("Core/User/Me()");
		var newLocation = getQueryParameter("returnUrl") || window.location.href.replace("Login", "");
		if(window.location.toString().indexOf("culture=") === -1) {
			if (newLocation.indexOf("?") !==-1) {
				window.location.href = newLocation+"&culture="+ user.DefaultCultureId;
			}
			else {
				window.location.href = newLocation+"?culture="+ user.DefaultCultureId;
			}
		}
		else { window.location.href = newLocation; }
	},

	failed: function (e) {
		var root = $("[name=Login].component");
		$("[name=Login].component #btn-submit").attr("disabled", false);
		$("[name=error]", root).text("[resource_description[AccessDenied]]");
	}
