</style>","Script":"var LogStream = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=LogStream]");
        await LogStream.connectToLogHub(app, container);

        container.find('.logLevelOptions input[type="checkbox"]').on('change', function () {
            LogStream.handleLogLevelSelection(container);
        });
    },


    connectToLogHub: async function (app, container) {
        var host = app.Domain;
        await LogStream.connectToHub(container, (connection) => {
            connection.invoke("join", host);
            connection.invoke("ConsoleSend", "info", "Client Connected to Log Stream ", host);
        });
    },

    connectToHub: async function (container, callback) {
        var connection = new signalR.HubConnectionBuilder().withUrl(session.apiRoot + "Hubs/Logs").build();
        connection.on("ConsoleReceive", (level, message) => LogStream.receiveMessage(container, level, message));
        await connection.start();
        callback(connection);
    },

    receiveMessage: function (container, level, message) {
        var entry = { Level: level.toLowerCase(), Timestamp: new Date(), Message: message };

        if (entry.Level === "information") entry.Level = "info";
        if (entry.Level === "warning") entry.Level = "warn";

        var $logConsole = container.find(".execConsole > [name=logConsole]");

        $logConsole.append(LogStream.buildMessage(entry));

        LogStream.handleLogLevelSelection(container);

        if (container.find("input[name=autoScroll]").is(":checked")) {
            $logConsole.scrollTop($logConsole.prop("scrollHeight"));
        }
    },

    buildMessage: function (logEntry) {
        var time = new Date(logEntry.Timestamp);
        var level = logEntry.Level.toLowerCase().trim();

        return "<div class='message " + level + "' data-level='" + level + "'>" +
            "<div class='level'>" + level.toUpperCase() + "</div>" +
            "<div class='time'>" + time.getHours() + ":" + time.getMinutes() + ":" + time.getSeconds() + "</div>" +
            "<pre class='message'>" + html.encode(logEntry.Message) + "</pre>" +
            "</div>";
    },

    handleLogLevelSelection: function (container) {
        var selectedLevels = LogStream.getSelectedLogLevels(container);

        container
            .find(".execConsole > [name=logConsole] > .message")
            .each(function () {
                var messageLevel = $(this).attr("data-level");

                if (selectedLevels.includes(messageLevel)) {
                    $(this).css("display", "flex");
                    $(this).find("pre").css("display", "inline");
                } else {
                    $(this).css("display", "none");
                }
            });
    },

    getSelectedLogLevels: function (container) {
        var selectedOptions = [];
        container.find('.logLevelOptions input[type="checkbox"]:checked').each(function () {
            selectedOptions.push($(this).val());
        });
        return selectedOptions;
    }
};
