","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Content Management","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"MailManagement","ResourceKey":"CMS","Script":"MailManagement = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=MailManagement]");
        api.addToMetaCache([
            {
                "Name": "Core",
                "Types": [
                    [meta[Core/QueuedEmail]],
                    [meta[Core/SentEmail]],
                    [meta[Core/MailServer]]
                ]
            }
        ]);

        MailManagement.setupMailSentGrid(app, container);
        MailManagement.setupMailServerGrid(app, container);
        MailManagement.setupMailQueueGrid(app, container);
    },

    save: async function (e, grid) {
        e.preventDefault();
        var item = grid.dataItem($(e.currentTarget).closest("tr"));
        await item.save().then(notification.success("[resource_displayname[saved]]"));
        grid.refresh();
    },

    setupMailSentGrid: async function (app, container) {
        var mailSent = await model.getDatasource({ endpoint: "Core/SentEmail", odataAppend: "?$filter=AppId eq " + app.Id, sort: { field: "SentOn", dir: "desc" } });

        var mailSentGrid = new GridWidget($("[name=history]", container), mailSent);
        mailSentGrid.filterable = true;

        mailSentGrid.detailTemplate = "<iframe class='mail-content-frame'></iframe>"
        mailSentGrid.detailExpand = function (e) {
            var item = mailSentGrid.dataItem($(e.masterRow));
            var element = $("iframe", $(e.detailRow))[0];
            var document = element.contentDocument || element.contentWindow.document;
            document.write(item.Content);
            document.close();
        };
        mailSentGrid.columns = [
            { field: "Subject", title: "[resource_displayname[subject]]" },
            { field: "From", title: "[resource_displayname[from]]" },
            { field: "SentByUserId", title: "[resource_displayname[sentbyuserid]]" },
            { field: "To", title: "[resource_displayname[to]]" },
            { field: "CC", title: "[resource_displayname[cc]]" },
            { field: "SentOn", title: "[resource_displayname[senton]]", type: "date", format: "{0: " + type.dateFormat + " HH:mm}" }
        ];
        mailSentGrid.init();
    },

    setupMailServerGrid: async function (app, container) {
        var mailServer = await model.getDatasource({ endpoint: "Core/MailServer", odataAppend: "?$filter=AppId eq " + app.Id });

        var mailServerGrid = new GridWidget($("[name=mailServer]", container), mailServer);
        mailServerGrid.filterable = true;
        mailServerGrid.editable = true;
        mailServerGrid.groupable = false;
        mailServerGrid.toolbar = "<div class='btn-group btn-group-sm'> <button class='btn btn-primary' name='create'> <span class='k-icon k-i-plus'></span>[resource_displayname[new]] </button> </div>";
        mailServerGrid.columns = [
            { field: "Name", title: "[resource_displayname[name]]" },
            { field: "FromEmail", title: "[resource_displayname[fromEmail]]" },
            { field: "User", title: "[resource_displayname[user]]" },
            { field: "Password", title: "[resource_displayname[password]]", template: "#='*'.repeat(Password.length)#" },
            { field: "Host", title: "[resource_displayname[host]]" },
            { field: "Port", title: "[resource_displayname[port]]" },
            { field: "EnableSSL", title: "[resource_displayname[enablessl]]" },
        ];
        mailServerGrid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" });
        mailServerGrid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });
        mailServerGrid.dataBound = function (e) {
            $("[name=save]", mailServerGrid.gridElement).off("click").on("click", (e) => MailManagement.save(e, mailServerGrid));
            $("[name=delete]", mailServerGrid.gridElement).off("click").on("click", (e) => MailManagement.remove(e, mailServerGrid));
            $("button[name=create]", mailServerGrid.gridElement).on("click", (e) => MailManagement.newMailServer(e, mailServerGrid, app));
        };
        mailServerGrid.init();
    },

    setupMailQueueGrid: async function (app, container) {
        var mailQueue = await model.getDatasource({ endpoint: "Core/QueuedEmail", odataAppend: "?$filter=AppId eq " + app.Id + "&$expand=FailedSends" });

        var mailQueueGrid = new GridWidget($("[name=queue]", container), mailQueue);
        mailQueueGrid.filterable = true;
        mailQueueGrid.detailTemplate = $("[name=mailQueueExpand]").first().html();
        mailQueueGrid.detailExpand = function (e) {
            var item = mailQueueGrid.dataItem($(e.masterRow));
            $("[name=mailTabs]", $(e.detailRow)).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });

            var element = $("iframe", $(e.detailRow))[0];
            var document = element.contentDocument || element.contentWindow.document;
            document.write(item.Content);
            document.close();

            var grid = new GridWidget($("[name=failuresTab]", $(e.detailRow)), { data: item.FailedSends, pageSize: 50, sort: { field: "AttemptedOn", dir: "desc" } });
            grid.filterable = false;
            grid.groupable = false;
            grid.columns = [
                { field: "AttemptedOn", type: "date", format: "{0: " + type.dateFormat + "  HH:mm}", title: "[resource_displayname[attemptedon]]" },
                { field: "FailureReason", title: "[resource_displayname[failurereason]]" },
            ];
            grid.init();
        };

        mailQueueGrid.dataBound = function () {
            $("[name=delete]", mailQueueGrid.gridElement).on("click", async (e) => {
                var item = mailQueueGrid.dataItem($(e.currentTarget).closest("tr"));
                await api.destroy("Core/QueuedEmail(" + item.Id + ")").then(() => {
                    notification.success("[resource_displayname[queuedemaildeleted]]");
                    mailQueueGrid.refresh();
                }).catch((err) => error(err));
            });
        };

        mailQueueGrid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });
        mailQueueGrid.columns = [
            { field: "Subject", title: "[resource_displayname[subject]]" },
            { field: "SentByUserId", title: "[resource_displayname[sentbyuserid]]" },
            { field: "To", title: "[resource_displayname[to]]" },
            { field: "CC", title: "[resource_displayname[cc]]" },
        ];
        mailQueueGrid.init();
    },

    remove: async function (e, grid) {
        e.preventDefault();
        var item = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
        await api.destroy("Core/MailServer(" + item.Id + ")").then(async () => {
            notification.success("[resource_displayname[mailserverdeleted]]");
            grid.refresh();
        }).catch((err) => error(err));
    },

    newMailServer: async function (e, grid, app) {
        e.preventDefault();

        var newMailServer = {
            Id: 0,
            AppId: app.Id,
            Name: "",
            User: "",
            Password: "",
            Host: "",
            Port: "",
            EnableSSL: true
        };

        var d = new Dialog({
            title: "[resource_displayname[createnewmailserver]]",
            width: 500
        });

        d.template = $("[name=newMailServerDialog]").html();

        d.events.create = async function (e) {
            e.preventDefault();

            newMailServer.Name = $("input[name=Name]", d.element).val();
            newMailServer.User = $("input[name=User]", d.element).val();
            newMailServer.Password = $("input[name=Password]", d.element).val();
            newMailServer.Host = $("input[name=Host]", d.element).val();
            newMailServer.Port = parseInt($("input[name=Port]", d.element).val()) || 0;
            newMailServer.EnableSSL = $("input[name=EnableSSL]", d.element).is(":checked");

            await api.add("Core/MailServer", newMailServer)
                .then(() => {
                    notification.success("[resource_displayname[mailservercreated]]");
                    d.events.close();
                    grid.refresh();
                })
                .catch(err => error(err));
        };

        d.init(() => {
            $("[name=create]", d.element).off("click").on("click", d.events.create);
        });
    },
}"}

