    init: async function (app, container, instance) {
        const tenantId = app.TenantId;

        const allInstances = await api.get(`Core/FlowInstanceData?$orderby=Start desc`);
        const allDates = [...new Set(allInstances.value.map(i => i.Start.slice(0, 10)))];

        const allCsvLines = await api.get(`B2B/CompanyCSVLine?$filter=SourceSystemId eq '${tenantId}'&$select=CreatedOn`);

        const datesWithDataSet = new Set(
            allCsvLines.value
                .filter(l => l.CreatedOn)
                .map(l => l.CreatedOn.slice(0, 10))
        );

        const datesWithData = allDates.filter(date => datesWithDataSet.has(date));

        const $dropdown = $(container).find("#importDateDropdown");
        $dropdown.empty();
        $dropdown.append(`<option value="">[resource_displayname[selectimportdate]]</option>`);
        datesWithData.forEach(date => {
            $dropdown.append(`<option value="${date}">${date}</option>`);
        });

        const defaultDate = instance?.Start?.slice(0, 10) ?? datesWithData[0];
        $dropdown.val(defaultDate);

        await (async () => {
            try {
                MasterdataImportResults.showSpinner();
                await MasterdataImportResults.loadDataForDate(app, container, defaultDate, tenantId);
            } finally {
                MasterdataImportResults.hideSpinner();
            }
        })();

        $dropdown.off("change").on("change", async function () {
            const selectedDate = $(this).val();
            console.log("Dropdown changed to:", selectedDate);
            if (selectedDate) {
                try {
                    MasterdataImportResults.showSpinner();
                    await MasterdataImportResults.loadDataForDate(app, container, selectedDate, tenantId);
                } finally {
                    MasterdataImportResults.hideSpinner();
                }
            }
        });
    },

    loadDataForDate: async function (app, container, day, tenantId) {
        const startOfDay = `${day}T00:00:00Z`;
        const nextDay = new Date(day);
        nextDay.setDate(nextDay.getDate() + 1);
        const endOfDay = nextDay.toISOString().slice(0, 19) + "Z";

        const csvLineFilter = `SourceSystemId eq '${tenantId}' and CreatedOn ge ${startOfDay} and CreatedOn lt ${endOfDay}`;
        const csvLines = await api.get(
            `B2B/CompanyCSVLine?$filter=${csvLineFilter}&$select=CreatedOn,FileName,CompanyId,ProcessingState`
        );

        const companyFilter = `(CreatedOn ge ${startOfDay} and CreatedOn lt ${endOfDay}) or (LastUpdated ge ${startOfDay} and LastUpdated lt ${endOfDay})`;
        const companies = await api.get(`B2B/Company?$filter=${companyFilter}&$expand=Buckets`);

        $("[name=files]", container).html(this.getFiles(csvLines.value, day));
        $("[name=failures]", container).html(this.getFailedLines(csvLines.value));
        $("[name=invalidLines]", container).html(this.getInvalidLines(csvLines.value));

        const companyStats = this.getCompanyImportStats(csvLines.value, day, companies.value);
        $("[name=newCompanies]", container).html(companyStats.newCompanies);

        const bucketStats = await this.getBucketImportStats(day, tenantId);
        $("[name=debtorBuckets]", container).html(bucketStats.debtorCount);
        $("[name=creditorBuckets]", container).html(bucketStats.creditorCount);
        $("[name=funderBuckets]", container).html(bucketStats.funderCount);
    },

    getFiles: function (csvLines, day) {
        const uniqueNames = [...new Set(
            csvLines
                .filter(line => line.CreatedOn && line.CreatedOn.slice(0, 10) === day)
                .map(line => line.FileName)
        )];

        const yearPath = day.slice(0, 4);
        const monthPath = day.slice(0, 7);
        const dayPath = day;

        return uniqueNames.map(name =>
            `<a download='${name}' href='${session.apiRoot}DMS/Data/Masterdata/Processed/${yearPath}/${monthPath}/${dayPath}/${name}'>${name}</a><br>`
        ).join("");
    },

    getFailedLines: function (csvLines) {
        return csvLines.filter(line => line.ProcessingState === "Failed").length;
    },

    getInvalidLines: function (csvLines) {
        return csvLines.filter(line => line.ProcessingState === "Invalid").length;
    },

    getCompanyImportStats: function (csvLines, day, companies) {
        const companyMap = new Map(companies.map(c => [String(c.Id), c]));
        let newCount = 0;

        csvLines.forEach(line => {
            if (!line.CompanyId) return;
            const company = companyMap.get(String(line.CompanyId));
            if (!company || !company.CreatedOn) return;

            const created = company.CreatedOn.slice(0, 10);
            if (created === day) {
                newCount++;
            }
        });

        return { newCompanies: newCount };
    },

    getBucketImportStats: async function (day, tenantId) {
        const startOfDay = `${day}T00:00:00Z`;
        const nextDay = new Date(day);
        nextDay.setDate(nextDay.getDate() + 1);
        const endOfDay = nextDay.toISOString().slice(0, 19) + "Z";

        const filter = `CreatedOn ge ${startOfDay} and CreatedOn lt ${endOfDay} and startswith(Path,'${tenantId}')`;
        const query = `B2B/Bucket?$filter=${filter}&$select=Key`;

        const buckets = await api.get(query);

        let debtorCount = 0, creditorCount = 0, funderCount = 0;
        for (const b of buckets.value) {
            if (b.Key === 'debtor') debtorCount++;
            else if (b.Key === 'creditor') creditorCount++;
            else if (b.Key === 'funder') funderCount++;
        }

        return { debtorCount, creditorCount, funderCount };
    },

    showSpinner: function () {
        $("#loadingSpinner").show();
    },

    hideSpinner: function () {
        $("#loadingSpinner").hide();
    }
};
"}

{"Key":"B2B","Name":"MigrateFunderData","ResourceKey":"B2B","Content":"<form class="form" name="MigrateForm">

	<div class="input-group input-group-sm mb-1">
