        <span class="k-icon k-i-arrow-up"></span>[resource_displayname[Migrate]]
    </button>

</form>","Script":"MigrateFunderData = {
    init: async function (app, container, dialog) {
        app = app || session.app;
        container = container || $(".component[name=MigrateFunderData]");

        const ddl = $("select[name=api]", container);
        ddl.empty().append(`<option value="">[resource_displayname[selecttarget]]</option>`);

        app.Config.Deployment.Targets.forEach(t => {
            ddl.append(`<option value="${t.Api}">${t.EnvironmentName}</option>`);
        });

        $("button[name=migrate]", container).off().on("click", async () => {
            notification.info('Importing funder data...');
            await MigrateFunderData.migrateFunderData(app, container, dialog);
        });
    },

    migrateFunderData: async function(app, container, dialog) {
        const selectedApi = $("[name=api]", container).val();
        const target = app.Config.Deployment.Targets.find(r => r.Api === selectedApi);

        if (!target) {
            notification.error("[resource_displayname[selecttarget]]");
            return;
        }

        const vars = {
            Domain: target.Domain,
            TenantId: app.Config.Deployment.TenantId,
            RemoteAuth: {
                User: session.user,
                Pass: $("[name=pass]", container).val(),
                Api: target.Api,
            },
            Dialog: dialog,
            SourceSystemId: $('[name=system_id]', container).val(),
            DestinationSystemId: app.Config.B2B.SourceSystem,
            RootBucketId: null,
            DestinationApp: null,
        };

        notification.info('Logged into external API...');
        await MigrateFunderData.loginExternalApi(vars);

        const appResponse = await vars.ExternalApi.get(`Core/App?$filter=Domain eq '${vars.Domain}'`);
        vars.DestinationApp = appResponse.value[0];
        vars.RootBucketId = JSON.parse(vars.DestinationApp.ConfigJson).B2B.RootBucket;

        await MigrateFunderData.doMigrateMasterData(vars);

        const interval = setInterval(async () => {
            const pendingCount = await MigrateFunderData.getPendingCompanyCount(vars);

            if (pendingCount > 0) {
                notification.info(`Waiting for ${pendingCount} companies to be processed...`);
            } else {
                clearInterval(interval);
                notification.info('All companies imported');
                await MigrateFunderData.doMigrateFunderData(vars);
            }
        }, 2500);
    },

    getPendingCompanyCount: async function(vars) {
        const result = await vars.ExternalApi.get(
            `B2B/CompanyCSVLine?$filter=SourceSystemId eq '${vars.DestinationSystemId}' and ProcessingState eq 'New'&$select=Id`
        );
        return result.value.length;
    },

    loginExternalApi: async function(vars) {
        vars.ExternalApi = new Api({
            apiRoot: vars.RemoteAuth.Api
        });

        vars.RemoteAuth.token = await vars.ExternalApi.login(
            vars.RemoteAuth.User,
            vars.RemoteAuth.Pass,
            true
        );
    },

    doMigrateMasterData: async function(vars) {
        notification.info('Importing masterdata...');

        let masterdataCsv = await api.get(
            `B2B/Company/FromTenantSystem()?tenantId=${vars.TenantId}&systemId=${vars.SourceSystemId}&$format=csv&delimiter=;`
        );

        masterdataCsv = masterdataCsv
            .replace('AddressLine1', 'Address.Line1')
            .replace('AddressLine2', 'Address.Line2')
            .replace('AddressZipOrPostalCode', 'Address.PostCode')
            .replace('AddressTownOrCity', 'Address.City')
            .replace('AddressRegion', 'Address.StateOrProvince')
            .replace('AddressCountryId', 'Address.Country')
            .replaceAll(`;${vars.SourceSystemId};`, `;${vars.DestinationSystemId};`)
            .replaceAll(`;${vars.SourceSystemId}|`, `;${vars.DestinationSystemId}|`)
            .replaceAll(`,${vars.SourceSystemId}|`, `,${vars.DestinationSystemId}|`);

        const now = new Date().toISOString().replace(/[:T.]/g, '-');
        const fileName = `migrate-funder-data-${now}.csv`;

        await vars.ExternalApi.sendRaw(
            'post',
            `B2B/Import/Companies?fileName=${fileName}&sourceSystemId=${vars.DestinationSystemId}&rootBucketId=${vars.RootBucketId}&separator=;&referenceSeparator=,`,
            masterdataCsv
        );

        notification.success('Imported masterdata.');
    },

    doMigrateFunderData: async function(vars) {
        notification.info('Migrating funder data...');

        const destinationSystemId = vars.DestinationSystemId;
        const filter = `$filter=startswith(Path, '${vars.TenantId}') and Key eq 'Funder'`;
        const include = "$expand=Companies($expand=Company($expand=References)),Buckets($expand=FundingDetails,Companies($expand=Company($expand=References)))";

        const funderGroupBucketId = (await vars.ExternalApi.get(
            `B2B/Bucket?$filter=startswith(Path, '${vars.DestinationApp.TenantId}') and Key eq 'FunderGroup'`
        )).value[0].Id;

        const funders = await api.get(`B2B/Bucket?${filter}&${include}`);

        const mappedFunders = funders.value.map(f => ({
            Key: f.Key,
            Name: f.Name,
            Description: f.Description,
            ParentId: funderGroupBucketId,
            Companies: f.Companies.map(c => c.Company.References.filter(r => r.SystemId !== 'GlobalTax')[0]?.Value),
            Buckets: f.Buckets.map(b => ({
                Key: b.Key,
                Name: b.Name,
                Description: b.Description,
                Companies: b.Companies.map(c => c.Company.References.filter(r => r.SystemId !== 'GlobalTax')[0]?.Value),
                FundingDetails: b.FundingDetails.map(d => ({
                    SystemId: destinationSystemId,
                    Name: d.Name,
                    Description: d.Description,
                    CurrencyId: d.CurrencyId,
                    Limit: d.Limit,
                    IsSystematic: d.IsSystematic,
                    Formula: d.Formula,
                    BuyerReferenceId: d.BuyerReferenceId,
                    SupplierReferenceId: d.SupplierReferenceId,
                    FunderReferenceId: d.FunderReferenceId
                }))
            }))
        }));

        await vars.ExternalApi.post(
            `B2B/Import/FundingConfiguration?sourceSystemId=${destinationSystemId}`,
            mappedFunders
        );

        notification.success('Imported funding configuration.');
        vars.Dialog.events.close();
    }
};
