</div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"NextCutoffDetails","ResourceKey":"Home","Script":"NextCutoffDetails = {
		months: {
		1: "[resource_displayname[month-1]]",
		2: "[resource_displayname[month-2]]",
		3: "[resource_displayname[month-3]]",
		4: "[resource_displayname[month-4]]",
		5: "[resource_displayname[month-5]]",
		6: "[resource_displayname[month-6]]",
		7: "[resource_displayname[month-7]]",
		8: "[resource_displayname[month-8]]",
		9: "[resource_displayname[month-9]]",
		10: "[resource_displayname[month-10]]",
		11: "[resource_displayname[month-11]]",
		12: "[resource_displayname[month-12]]"
	},
	init: async function (app, container) {
		app = app || session.app;
		container = container || $("[component[Name=NextCuttoffDetails]]");
		app = await api.get("Core/App(" + app.Id + ")");
		app.Config = JSON.parse(app.ConfigJson);
		var calendarId = app.Config.Calendars.primary;
		var cutoffEvent = app.Config.Calendars.CutoffEventName;
		var expiryTime = app.Config.B2B.ExpiryTime || "23:59";
		let date = new Date();
		date.setHours(0, 0, 0, 0);
		var events = (await api.get("Core/CalendarEvent?$filter=CalendarId eq " + calendarId + " and Name eq '" + cutoffEvent + "' and Start ge " + date.toISOString().split("T")[0] + "&$top=3&$orderby=Start asc")).value;
		var scheduledTasks = (await api.get("Core/ScheduledTask?$filter=AppId eq " + app.Id + " and NextExecution ne null")).value;

		var scheduledTaskEvents = scheduledTasks.map(s => {
			return [
				{ Id: 0, Name: s.Name, Start: s.NextExecution, End: s.NextExecution },
				{ Id: 0, Name: s.Name, Start: s.LastExecuted, End: s.LastExecuted },
			];
		}).flat();

		var calendarDataSource = events.concat(scheduledTaskEvents).map(r => {
			r.Start = new Date(r.Start);
			r.End = new Date(r.End);
			return r;
		});


		NextCutoffDetails.displayTimeUntilNextCutoff(app, events, expiryTime, container, calendarDataSource);

		var defaultCurrency = app.Config.B2B.DefaultCurrency
			? app.Config.B2B.DefaultCurrency
			: "EUR";

		var currencyDropDown = $("[name=currencyDropdown]", container).kendoDropDownList({
			dataSource: app.Config.B2B.Currencies
				? app.Config.B2B.Currencies
				: ["USD", "EUR", "GBP"],
			change: async function (e) {
				var value = this.value();
				NextCutoffDetails.displayOfferStats(app, container, value);
			}
		}).getKendoDropDownList();

		$("[name=currencyDropdown]", container)
			.data("kendoDropDownList")
			.value(defaultCurrency);

		currencyDropDown.trigger("change");
	},

	displayOfferStats: async function (app, container, currency) {
		var endpoint = "B2B/Offer/FromSystem(SystemId='" + app.Config.B2B.TransactionSource + "')";
		var select = "$select=Value,CurrencyId";

		var proposedFilter = "$filter=(FunderState eq 'Proposed' or DebtorState eq 'Proposed') and CreditorState ne 'FundingAccepted' and FunderState ne 'FundingAccepted'";
		var acceptedfilter = "$filter=(FunderState eq 'FundingAccepted' or CreditorState eq 'FundingAccepted') and (DebtorState eq 'Proposed' or FunderState eq 'Proposed' or DebtorState eq 'Approved')";
		var rejectedfilter = "$filter=FunderState eq 'RejectedCancelled' or CreditorState eq 'RejectedCancelled' or DebtorState eq 'RejectedCancelled'";

		var statsContainer = $("[name=offerStats]", container);

		var proposed = await NextCutoffDetails.getValueSumAndCount(`${endpoint}?${proposedFilter}&${select}`, currency);
		$("a[name=proposed] > [name=value]", statsContainer)
			.text(B2B.transactionStates["Proposed"] + " " + proposed.sum + " (" + proposed.count + ")");

		var accepted = await NextCutoffDetails.getValueSumAndCount(`${endpoint}?${acceptedfilter}&${select}`, currency);
		$("a[name=accepted] > [name=value]", statsContainer)
			.text(window.B2B.transactionStates["FundingAccepted"] + " " + accepted.sum + " (" + accepted.count + ")");

		var rejected = await NextCutoffDetails.getValueSumAndCount(`${endpoint}?${rejectedfilter}&${select}`, currency);
		$("a[name=rejected] > [name=value]", statsContainer)
			.text(window.B2B.transactionStates["RejectedCancelled"] + " " + rejected.sum + " (" + rejected.count + ")");
	},

	getValueSumAndCount: async function (query, currency) {
		var data = (await api.get(query)).value || [];
		var relevant = data.filter(i => i.CurrencyId == currency);

		return {
			count: relevant.length,
			sum: kendo.toString(relevant.reduce((total, i) => total + i.Value, 0), type.moneyFormat)
		};
	},

	getTimeUntilNextCutoff: function (event, expiryTime) {
		var eventStart = new Date(event.Start).toISOString().split("T")[0] + "T" + expiryTime + ":00Z";
		var dateDifference = new Date(eventStart) - new Date();
		var day = Math.floor(dateDifference / (1000 * 60 * 60 * 24));
		var hour = Math.floor((dateDifference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
		var minutes = Math.floor((dateDifference % (1000 * 60 * 60)) / (1000 * 60));
		var seconds = Math.floor((dateDifference % (1000 * 60)) / 1000);
		return {
			days: day,
			hours: hour,
			minutes: minutes,
			seconds: seconds
		};
	},

	displayTimeUntilNextCutoff: function (app, events, expiryTime, container, calendarDataSource) {
		setInterval(function () {
			var timeLeft = NextCutoffDetails.getTimeUntilNextCutoff(events[0], expiryTime);

			if (timeLeft.seconds < 0) {
				timeLeft = NextCutoffDetails.getTimeUntilNextCutoff(events[1], expiryTime);
			}

			$("[name=timeLeft]", container).html("<p class=countdown> [resource_description[nextcutoff]]: " + timeLeft.days + " [resource_displayname[days]] " + timeLeft.hours + " [resource_displayname[hours]] " + timeLeft.minutes + " [resource_displayname[minutes]] " + timeLeft.seconds + " [resource_displayname[seconds]] " + "</p>");
			$("[name=timeLeft]", container).off("click").on("click", (e) => NextCutoffDetails.showCalendar(e, app, calendarDataSource));
			$(".countdown", container).css("color", session.app.Config.Themes.Default.colours.text);
		}, 1000)
	},

	showCalendar(e, app, event, calendarDataSource) {
		e.preventDefault();

		const currentDate = new Date();
		const currentMonthNumber = currentDate.getMonth() + 1;

		const calendarTitle = NextCutoffDetails.months[currentMonthNumber];
		const dialogTitle = `[resource_displayname[calendar]] - ${calendarTitle}`;

		const d = new Dialog({ title: dialogTitle, width: 1800, height: 900 });

		d.init(async () => {
			const calendar = await loadComponent($(d.element), "CalendarManagement");

			const firstDayOfMonth = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1);
			const lastDayOfMonth = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0);

			await calendar.init(app, $(".component[name=CalendarManagement]"), {
				fromDate: firstDayOfMonth,
				toDate: lastDayOfMonth,
				eventSource: calendarDataSource
			});
		});
	}

}"}

