</style>","Script":"Offer = {
    states: [script[TransactionStates]],
    id: null,
    backButton: true,

    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=Offer]");
        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Offer]],
                    [meta[B2B/OfferLine]],
                    [meta[B2B/Company]]
                ]
            }
        ]);

        $(container).addClass("details");
        $(".component[name=Offer]").addClass("details");

        var id = this.id || getQueryParameter("Id");
        var backButton = this.backButton || false;

        var details = await [script[OfferDetails]]({ element: $("[name=offerDetails]", container) });
        if (!backButton) { details.toolbar = ""; }
        details.config.odataAppend = "(" + id + ")?$expand=AuditTrail,References($expand=RemittanceAdviceLines),Companies";
        await details.init();

        var offer = details.data;
        $.each(offer.Lines, function (i, L) { L.LastUpdated = new Date(L.LastUpdated); });
        $.each(offer.AuditTrail, function (i, L) { L.CreatedOn = new Date(L.CreatedOn); });

        await (await [script[ReferenceGrid]]({
            element: $("[name=references]", container),
            references: offer.References
        })).init();
        await (await [script[OfferLineGrid]]({
            element: $("[name=lines]", container),
            offerId: offer.Id
        })).init();

        var remittances = [];

        for (var i = 0; i < offer.References.length; i++) {
            var offerReference = offer.References[i];
            for (var j = 0; j < offerReference.RemittanceAdviceLines.length; j++) {
                var raLine = offerReference.RemittanceAdviceLines[j];
                remittances.push(raLine);
            }
        }

        var config = {
            element: $("[name=payments]", container),
            payments: remittances
        };

        if (remittances.length > 0) {
            await (await [script[RelatedPaymentsGrid]](config));
            config.RelatedPaymentsGrid.init();
        } else {
            $("[name=paymentDetails]", container).remove();
        }


        if (offer.AuditTrail.length > 0) {
            var historyGrid = await [script[HistoryGrid]]({ element: $("[name=history]", container), history: { data: offer.AuditTrail, sort: { field: "CreatedOn", dir: "asc" } } });
            await historyGrid.init();
        } else { $("[name=history]", container).remove(); }

        var companyInfo = (await api.get("B2B/Company?$filter=References/any(r: r/OfferReferences/any(j: j/OfferId eq " + id + "))&$expand=References,Address")).value;
        var transactionCompanyInfo = [];
        for (let i = 0; i < offer.Companies.length; i++) {
            var transactionCompany = offer.Companies[i];
            var matchedCompanyInfo = companyInfo.filter(ci => ci.References.filter(cir => cir.Id == transactionCompany.CompanyReferenceId).length > 0)[0];
            transactionCompany.Name = matchedCompanyInfo.Name;
            transactionCompany.DebtorReference = matchedCompanyInfo.References.filter(r => r.SystemId !== "GlobalTax").map(r => r.Value).join();
            transactionCompany.DebtorVATReference = (matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax").length > 0 ? matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax")[0].Value : "N/A");
            transactionCompany.Id = matchedCompanyInfo.Id;
            if (transactionCompanyInfo.filter(r => r.Perspective == transactionCompany.Perspective && r.DebtorReference == transactionCompany.DebtorReference).length === 0) {
                transactionCompanyInfo.push(transactionCompany);
            }
        }
        var companyGridInit = [script[CompanyGrid]];
        (await companyGridInit({
            element: $("[name=companyDetails]", container),
            dataSource: transactionCompanyInfo
        })).init();
    }
};","Name":"Offer","Description":null,"Key":"B2B"}

{"Key":"B2B","Name":"OfferFundingDetails","ResourceKey":"B2B","Content":"<div class="col left">
</div>
<div class="col right">
    <h3>[resource_displayname[constants]]</h3>
<style scoped>
   .col.left,.col.right { max-width: 49.5%; min-width:400px; display: inline-block; vertical-align: top; }
   .col.right { margin: 0 -2px; }
</style>","Script":"OfferFundingDetails = {
    init: async function(app, container, offer) {
        if(!offer) { return; }
        
        app = app || session.app;
        container = container || $(".component[name=OfferFundingDetails]");

        var constantsData = await OfferFundingDetails.getConstants(offer);

        var fundingDetailsInfo = (await api.get("B2B/FundingDetail?&$filter=FundingTypeBucket/Offers/any(bo: bo/OfferId eq " + offer.Id + ")")).value[0];

        fundingDetailsInfo.NewFormula = fundingDetailsInfo.Formula.toLowerCase();
        Object.keys(constantsData).forEach(cd => fundingDetailsInfo.NewFormula =  fundingDetailsInfo.NewFormula.replaceAll(cd.toLowerCase(), constantsData[cd]));
        fundingDetailsInfo.NewFormula = fundingDetailsInfo.NewFormula.replaceAll("m", "");

        var fundingDetailsGrid = new ReadOnlyDetailView($(".left", container), {data: fundingDetailsInfo});
        fundingDetailsGrid.title = "[resource_displayname[info]]";
        fundingDetailsGrid.toolbar = "";

        if(new Date(fundingDetailsGrid.LastUpdated) > offer.CreationDate) {
            fundingDetailsGrid.toolbar += "[resource_displayname[fundingdetailschanged]]";
        }
        fundingDetailsGrid.groupable = false;
        fundingDetailsGrid.editable = false;
        fundingDetailsGrid.pageable = false;
        fundingDetailsGrid.filterable = false;
        fundingDetailsGrid.fields = [
            {field: "Name", title: "[resource_displayname[name]]", width: 150},
            {field: "Formula", title: "[resource_displayname[formula]]"},
            {field: "NewFormula", title: "[resource_displayname[formula]]"},
            {field: "Evaluated", template:"#=eval(NewFormula)#", title: "[resource_displayname[evaluated]]"},
            { field: "IsSystematic", type: "boolean", title: "[resource_shortdisplayname[issystematic]]", width: 80, template: "<input type='checkbox' disabled class='k-checkbox k-checkbox-md k-rounded-md' name='isSystematic' #=(IsSystematic) ? 'checked' : ''# />"},
        ];
        fundingDetailsGrid.init();

        $("[name=viewConstants]", container).on("click", (e) => OfferFundingDetails.viewConstants(e, constantsData));

        var constantsGrid = new GridWidget($(".right", container), {
            data: Object.keys(constantsData).map(c => ({Key:c, Value: constantsData[c]}))
        });

        constantsGrid.columns = [
            {field: "Key", title: "[resource_displayname[key]]"},
            {field: "Value", title: "[resource_displayname[value]]"}
        ];

        constantsGrid.editable = false;
        constantsGrid.pageable = false;
        constantsGrid.groupable = false;
        constantsGrid.filterable = false;
        constantsGrid.scrollable = false;

        constantsGrid.init();
    },

    getConstants: async function(offer) {
        var constantsData = {
            fundableValue: offer.FundableValue,
            faceValue: offer.TransactionValue,
            days: Math.ceil(Math.abs(new Date(offer.DebtorPaymentDate) - new Date(offer.DueDate)) / (1000 * 60 * 60 * 24))
        };

        var rates = (await api.get("B2B/Rate/Current()")).value;
        rates.forEach((rate) => constantsData[rate.Name] = rate.Value);
        return constantsData;
    }
}","CreatedOn":"2022-10-25T15:17:48.091Z","LastUpdated":"2022-10-25T15:17:48.091Z"}

