{"Content":"<input type="text" name="currencyDropdown" class="currency" />
<div class="offerValueDisplay"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"OfferYearToDate","ResourceKey":"B2B","Script":"OfferYearToDate = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=OfferYearToDate]");

        const defaultCurrency = app.Config.B2B.DefaultCurrency || "EUR";

        const currencyDropdown = $("[name=currencyDropdown]", container).kendoDropDownList({
            dataSource: app.Config.B2B.Currencies || ["USD", "EUR", "GBP"],
            change: async function () {
                const selectedCurrency = this.value();
                await OfferYearToDate.updateOfferData(app, container, selectedCurrency);
            }
        }).data("kendoDropDownList");

        currencyDropdown.value(defaultCurrency);
        await OfferYearToDate.updateOfferData(app, container, defaultCurrency);

        $(".comparison-icon").kendoTooltip({
            content: function (e) {
                return "[resource_displayname[comparisontext]]"
            },
            position: "right"
        });
    },

    updateOfferData: async function (app, container, currency) {
        const { total, offerCount, totalComparisonResult, countComparisonResult } = await OfferYearToDate.getData(app, currency);
        OfferYearToDate.displayTotalOffer(total, offerCount, totalComparisonResult, countComparisonResult, container);
    },

    getData: async function (app, currency) {
        const sourceSystem = app.Config.B2B.SourceSystem;
        const offerQuery = `B2B/Offer?$filter=SourceSystemId eq '${sourceSystem}' and CurrencyId eq '${currency}'`;

        const offers = (await api.get(offerQuery)).value;

        const currentDate = new Date();
        const currentYear = currentDate.getFullYear().toString();
        const previousYear = (currentDate.getFullYear() - 1).toString();
        const currentMonth = currentDate.getMonth() + 1; // numeric month

        const filterOffersYearToDate = (year) =>
            offers.filter(({ DueDate }) => {
                const [offerYear, offerMonth] = DueDate.split("-");
                return (
                    offerYear === year &&
                    parseInt(offerMonth, 10) <= currentMonth
                );
            });

        const currentYearOffers = filterOffersYearToDate(currentYear);
        const previousYearOffers = filterOffersYearToDate(previousYear);

        const calculateTotal = (offerList) =>
            offerList.reduce((sum, { Value }) => sum + Value, 0);

        const totalForCurrentYear = calculateTotal(currentYearOffers);
        const totalForPreviousYear = calculateTotal(previousYearOffers);

        const compare = (current, previous) =>
            current > previous ? "up" : current < previous ? "down" : "same";

        return {
            total: totalForCurrentYear,
            offerCount: currentYearOffers.length,
            totalComparisonResult: compare(totalForCurrentYear, totalForPreviousYear),
            countComparisonResult: compare(currentYearOffers.length, previousYearOffers.length)
        };
    },


    displayTotalOffer: function (total, offerCount, totalComparisonResult, countComparisonResult, container) {
        const offerValueDisplay = $("div.offerValueDisplay", container);

        const getComparisonIcon = (result) => ({
            up: '<span class="comparison-icon up-arrow">↑</span>',
            down: '<span class="comparison-icon down-arrow">↓</span>',
            same: '<span class="comparison-icon same-icon">→</span>'
        })[result];

        const countComparisonIcon = getComparisonIcon(countComparisonResult);
        const valueComparisonIcon = getComparisonIcon(totalComparisonResult);

        offerValueDisplay.html(`
            <h4>[resource_displayname[totaloffercountthisyear]]</h4>
            <h2 class="yearToDate">${offerCount} ${countComparisonIcon}</h2>
            <h4>[resource_displayname[totaloffervaluethisyear]]</h4>
            <h2 class="yearToDate">${kendo.toString(total, type.moneyFormat)} ${valueComparisonIcon}</h2>
        `);
    }
};
"}

{"Key":"Summary","Name":"OfferYearToDateStats","ResourceKey":"B2B","Content":"    <h4 class="smallChartTitle">[resource_displayname[offersgeneratedthisyear]]</h4>
	<div class="offerGrid"></div>

    <style scoped>
        .offerGrid {height: 200px }
    </style>","Script":"OfferYearToDateStats = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=OfferYearToDateStats]");
        container.addClass("small");
        const currentDate = new Date();
        const offset = currentDate.getTimezoneOffset();
        const firstDay = new Date((new Date(currentDate.getFullYear(), 0, 1)).getTime() - (offset * 60 * 1000)).toISOString().split("T")[0];
        const lastDay = new Date((new Date(currentDate.getFullYear(), 11, 31)).getTime() - (offset * 60 * 1000)).toISOString().split("T")[0];
        var offerData = await api.get(`B2B/Offer/FromSystem(SystemId='${app.Config.B2B.SourceSystem}')?$apply=filter(DueDate ge ${firstDay} and DueDate le ${lastDay})/groupby((CurrencyId), aggregate(Value with sum as Total, Id with countdistinct as Count))`);
        OfferYearToDateStats.setupOfferGrid(offerData, $(".offerGrid", container));
    },

    setupOfferGrid: async function (offerData, container) {
        var dataSource = offerData;
        var offerGrid = new GridWidget(container, dataSource);
        offerGrid.pageable = false;
        offerGrid.groupable = false;
        offerGrid.scrollable = true;
        offerGrid.editable = false;
        offerGrid.columns = [
            { field: "CurrencyId", title: "[resource_displayname[currency]]" },
            { field: "Total", title: "[resource_displayname[value]]", format: "{0:" + type.moneyFormat + "}", width: 100 },
            { field: "Count", title: "[resource_displayname[count]]" },
        ];
        await offerGrid.init();
    },
}","CreatedOn":"2023-08-17T21:27:09.876Z","LastUpdated":"2023-08-17T21:27:09.876Z"}

