    init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=OnboardCompany]");

        await OnboardCompany.initCountryDropDown(app, container);
        var referencesGrid = await OnboardCompany.initReferencesGrid(app, container);

        $("[name=addCompany]", container).click(async () => await OnboardCompany.addCompany(app, container, referencesGrid));
    },

    initCountryDropDown: async function (app, container) {
