    initReferencesGrid: async function(app, container) {
        var references = (app.Config.B2B.References?.Systems || [])
            .map((r) => {
            return {
                SystemId: r,
                Value: null
            };
        });
        
        referencesGrid = new GridWidget($("[name=referencesGrid]", container), {
            data: references
        });
        var systemIds = (await api.get("B2B/System?$select=Id")).value.map(r => ({value:r.Id, text:r.Id}));
        referencesGrid.columns = [
            { field: "SystemId", title: "[resource_displayname[systemid]]", values: systemIds},
            { field: "Value", title: "[resource_displayname[value]]" }
        ];
        referencesGrid.groupable = false;
        referencesGrid.filterable = false;
        referencesGrid.pageable = false;
        referencesGrid.scrollable = false;

        await referencesGrid.init();

        return referencesGrid;
    },

    addCompany: async function(app, container, referencesGrid) {
        var company = {
            "Name": $("[name=name]", container).val(),
            "Address": {
                "Line1": $("[name=address_line_1]", container).val(),
                "Line2": $("[name=address_line_2]", container).val(),
                "ZipOrPostalCode": $("[name=postcode]", container).val(),
                "TownOrCity": $("[name=town]", container).val(),
                "StateOrProvince": $("[name=state]", container).val(),
                "CountryId": $("[name=country]", container).val()
            },
            "References": this.getReferencesFromGrid(referencesGrid),
            "is_buyer": $("[name=buyer]", container).is(":checked"),
            "is_supplier": $("[name=supplier]", container).is(":checked"),
            "is_funder": $("[name=funder]", container).is(":checked"),
        };

        if(!company.is_buyer && !company.is_supplier && !company.is_funder) {
            notification.error('[resource_displayname[selectatleastoneperspective]]');
            return;
        }

        var csv = `Perspective;Name;Reference;GlobalTax;Address.Line1;Address.Line2;Address.City;Address.Region;Address.Country;Address.PostCode\n`;
        
        var perspectives = [];

        if(company.is_buyer)
            perspectives.push('Buyer');
        
        if(company.is_supplier)
            perspectives.push('Supplier');
        
        if(company.is_funder)
            perspectives.push('Funder');

        var reference = company.References.filter(r => r.SystemId == app.Config.B2B.SourceSystem)[0]?.Value;
        var globalTax = company.References.filter(r => r.SystemId == 'GlobalTax')[0]?.Value;

        csv += `${perspectives.join(',')};${company.Name};${reference};${globalTax};${company.Address.Line1};${company.Address.Line2};${company.Address.TownOrCity};${company.Address.StateOrProvince};${company.Address.CountryId};${company.Address.ZipOrPostalCode}`;
        
        var now = new Date();
        var date = [
            now.getFullYear(),
            (now.getMonth() < 9) ? '0' + (now.getMonth() + 1) : (now.getMonth() + 1),
            (now.getDate() < 10) ? '0' + now.getDate() : now.getDate(),
            (now.getHours() < 10) ? '0' + now.getHours() : now.getHours(),
            (now.getMinutes() < 10) ? '0' + now.getMinutes() : now.getMinutes(),
            (now.getSeconds() < 10) ? '0' + now.getSeconds() : now.getSeconds()
        ].join('-');

        var fileName = 'onboarding-company-UI-' + date  + '.csv';

        await api.sendRaw('post', 'B2B/Import/Companies?fileName=' + fileName + '&sourceSystemId=' + app.Config.B2B.SourceSystem + '&rootBucketId=' + app.Config.B2B.RootBucket + '&separator=;&referenceSeparator=,', csv)
            .then((response) => {
                notification.success('[resource_displayname[companyimported]]');
            })
            .catch((error) => {
                notification.error('[resource_displayname[failedtoimportcompany]]: ' + error.error);
            });
    },

    getReferencesFromGrid: function(grid) {
        return grid.dataSource().data().toJSON();
    }
}"}

{"Content":"<input type="text" name="currencyDropdown" class="currency" />
<h3 class="chartTitle" name="outstandingHeader">[resource_displayname[outstandingbalancebyduedate]]</h3>
<div class="chart" name="chart"></div>
<p name="nodata" class="alert alert-warning text-center m-2">[resource_displayname[nodatatodisplay]]</p>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Charts","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"OutstandingBalanceByDueDate","ResourceKey":"B2B","Script":"OutstandingBalanceByDueDate = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=OutstandingBalanceByDueDate]");

		var defaultCurrency = app.Config.B2B.DefaultCurrency
			? app.Config.B2B.DefaultCurrency
			: "EUR";

		var originalChartTitle = $('[name=outstandingHeader]', container).html();

		$("[name=currencyDropdown]", container).kendoDropDownList({
			dataSource: app.Config.B2B.Currencies
				? app.Config.B2B.Currencies
				: ["USD", "EUR", "GBP"],
			change: async function (e) {
				var value = this.value();
				var data = await OutstandingBalanceByDueDate.getData(app, value);

				var start = data.dates[0] || kendo.toString(new Date(), 'dd-MM-yyyy');
				var end = data.dates.toReversed()[0] || kendo.toString(new Date(), 'dd-MM-yyyy');

				chart.kendoObject.options.series[0].name = `[resource_displayname[UnpaidValue]] (${value})`;
				chart.kendoObject.options.categoryAxis.categories = data.dates;
				chart.kendoObject.options.valueAxis.max = Math.max(...data.totals, 10) * 1.1;
				chart.kendoObject.options.series[0].data = data.totals;
				chart.kendoObject.refresh();

				$('[name=outstandingHeader]', container).html(`${originalChartTitle} ${start} - ${end}`);

				if(data.totals.flat().filter(d => d != 0).length == 0) {
					$('[name=nodata]', container).show();
					$('[name=chart]', container).hide();
				} else {
					$('[name=nodata]', container).hide();
					$('[name=chart]', container).show();
				}
			}
		});

		$("[name=currencyDropdown]", container).data("kendoDropDownList").value(defaultCurrency);

		var data = await this.getData(app, defaultCurrency);
		var start = data.dates[0] || kendo.toString(new Date(), 'dd-MM-yyyy');
		var end = data.dates.toReversed()[0] || kendo.toString(new Date(), 'dd-MM-yyyy');
		$('[name=outstandingHeader]', container).html(`${originalChartTitle} ${start} - ${end}`);

		var chart = this.initChart(container, data, defaultCurrency);
		chart.init();

		if(data.totals.flat().filter(d => d != 0).length == 0) {
			$('[name=nodata]', container).show();
			$('[name=chart]', container).hide();
		} else {
			$('[name=nodata]', container).hide();
			$('[name=chart]', container).show();
		}

		$(window).resize(function () {
			chart.kendoObject.refresh();
		});
	},

	initChart: function (container, data, currency) {
		var start = data.dates[0] || kendo.toString(new Date(), 'dd-MM-yyyy');

		if(data.dates.length == 0)
			data.dates = [start];

		if(data.totals.length == 0)
			data.totals = [0];

		var args = {
			showLegend: true,
			valueTemplate: "#: kendo.toString(value, type.moneyFormat)#",
			tooltipTemplate: "#= series.name #: #= kendo.toString(value, type.moneyFormat) #",
			series: [{
				name: `[resource_displayname[UnpaidValue]] (${currency})`,
				data: data.totals
			}],
			categories: data.dates,
			max: Math.max(...data.totals, 10) * 1.1,
			type: "column"
		};

		return (new Chart($("[name=chart]", container), args));
	},

	getData: async function(app, currency) {
		var sourceSystem = app.Config.B2B.SourceSystem;
		var start = new Date();
		var end = new Date(start);
		end.setUTCDate(start.getUTCDate() + 75);

		var filter = `filter(CurrencyId eq '${currency}' and DebtorPaymentDate ge ${start.toISOString()} and DebtorPaymentDate le ${end.toISOString()})`;
		var invoiceQuery = `B2B/ActiveTransaction/FromSystem(SystemId='${sourceSystem}')?$apply=${filter}/groupby((DebtorPaymentDate,CurrencyId), aggregate(Value with sum as UnpaidValue))`;

		var invoices = await api.get(invoiceQuery);
		var transactions = invoices
			.map(t => {
				var split = t.DebtorPaymentDate.split('t')[0].split('-');
				var year = split[0];
				var month = split[1];
				var day = split[2];

				t.date = new Date(`${year}-${month}-${day}`);
				t.formatted = kendo.toString(t.date, 'dd-MM-yyyy');
				return t;
			})
			.sort((a, b) => a.date - b.date);

		var categories = [... new Set(transactions.map(t => t.formatted))];

		return {
			dates: categories,
			totals: categories.map(m => transactions
				.filter(t => t.formatted == m)
				.map(t => t.UnpaidValue)
				.reduce((accumulator, current) => accumulator + current, 0))
		};
	}
}"}

