{"Key":"B2B","Name":"PageCurrencyControl","ResourceKey":"B2B","Content":"<input type="text" name="pageCurrencyDropdown" class="currency" />","Script":"PageCurrencyControl = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=PageCurrencyControl]");

        var defaultCurrency = app.Config.B2B.DefaultCurrency 
            ? app.Config.B2B.DefaultCurrency 
            : "EUR";

        var data = app.Config.B2B.Currencies 
            ? app.Config.B2B.Currencies 
            : ["USD", "EUR", "GBP"];

        $("[name=pageCurrencyDropdown]", container).kendoDropDownList({
            dataSource: data,
            index: data.indexOf(defaultCurrency),
            change:PageCurrencyControl.onChange
        }).data("kendoDropDownList");

        $(document).ready(() => {
            var interval = setInterval(() => {
                var dropdowns = $("span.k-picker:not([style='display: none;']) > [name=currencyDropdown]");

                if(dropdowns.length == 0)
                    clearInterval(interval);

                dropdowns.each((dropdown) => {
                    $(dropdowns[dropdown]).closest(".k-picker").hide();
                });
            }, 500);
        });
    },
    onChange: function(e) {
        var value = this.value();
        var dropdowns = $("[name=currencyDropdown]");
        dropdowns.each((i) => {
            var dropdown = $(dropdowns[i]).data("kendoDropDownList");
            dropdown.value(value);
            dropdown.trigger('change');
        });
    }
