</script>","Script":"PageDesigner = {
      getMatchedCulture: function(page) {
            var matchedContents = page.Contents.filter(r => r.CultureId === session.culture);
            return matchedContents.length > 0 ? matchedContents[0].CultureId : "";
      },

    init: function(app, container, page) {
        app = app || session.app;
        container = container || $(".component[name=PageDesigner]");
        if(!page) { return; }
        if(page.Contents.length === 0) {
            page.Contents.push({CultureId: "", Html: "", Script: "", PageId: page.Id, Id: 0, Name: "body" });
        }
		$("[name=splitter]", container).kendoSplitter({
			scrollable: false,
			panes: [
				{ collapsible: false, size: "320px" },
				{ collapsible: false, scrollable: false },
                { collapsible: true, size: "470px" }
			]
		});
        PageDesigner.addComponentOptions(app, $(".flowmenu", container));
        PageDesigner.populateComponentDesigner($("[name=designerContainer]", container), $("[name=propertyContainer]", container), page);
        $("[name=save]", container).off("click").on("click", (e) => PageDesigner.save(e, page, $("[name=designerContainer]", container)));
        $("[name=viewsource]", container).off("click").on("click", (e) => PageDesigner.viewSourceCode(e, page));
    },

    viewSourceCode: async function(e, page) {
        var culture = PageDesigner.getMatchedCulture(page);
        var pageContent = page.Contents.filter(c => c.CultureId === culture)[0];

        e.preventDefault();
        var html = null;
        var d = new Dialog({
            width: 1000,
            height: 638,
            title: "[resource_displayname[viewSource]]",
            template: $("[name=sourceEditor]").first().html()
        });
        d.events.close = async function(e) {
            e.preventDefault();
            PageDesigner.updatePageContents(page, PageDesigner.getMatchedCulture(page), html.getValue());
            delete page.type;
            await api.update("Core/Page(" + page.Id + ")", page).then(() => {
                notification.success("[resource_displayname[updated]]");
            }).catch((err) => error(err));
        };
        d.init(() => {
            html = new HTMLMonacoEditor($("[name=sourceCodeEditor]", d.element)[0], { code: pageContent.Html });
            html.init();
        });
    },

    save: async function(e, page, designerContainer, propertyBox) {
        e.preventDefault();
        var designerHtml = $(designerContainer).html();
        var virtualJQuery = $("<div />", { html: designerHtml });
        var globalStyles = [];

        $(virtualJQuery).find(".component").replaceWith(function() {
            var name = $(this).attr("name");
            var elementStyles = [];
            $("input", propertyBox).each((i, input) => {
                var inputName = $(input).attr("name");
                var inputValue = $(this).css(inputName);
                if(inputValue) { elementStyles.push({name: inputName, value: inputValue}); }
            });
            if(elementStyles.length > 0) {
                globalStyles.push({name: name, type: "component", styles: elementStyles});
            }
            return "[component[" + name + "]]";
        });
        $(virtualJQuery).find("style[name=designerGeneratedStyles]").replaceWith("");
        var styleTag =  "<style name=\"designerGeneratedStyles\">" + globalStyles.map(gs => ".component[name=" + gs.name + "] { " + gs.styles.map(l => l.name + ":" + l.value + ";").join(" ") + " }").join('\n') + "</style>";
        var data = $(virtualJQuery).html() + styleTag;
        PageDesigner.updatePageContents(page, PageDesigner.getMatchedCulture(page), data);
        delete page.type;
        await api.update("Core/Page(" + page.Id + ")", page).then(() => {
            notification.success("[resource_displayname[updated]]");
        }).catch((err) => error(err));
    },

    updatePageContents: function(page, culture, data) {
        page.Contents.filter(r => r.CultureId == culture)[0].Html = data;
    },

    populateComponentDesigner: function(container, propertyBox, page) {
        var culture = PageDesigner.getMatchedCulture(page);
        $(container).html(PageDesigner.getComponentsSwapped(page.Contents.filter(c => c.CultureId === culture)[0].Html));
        $("button[name=removeThisComponent]", container).off("click").on("click", (e) => PageDesigner.removeThisComponent(e));
        $(".editableComponent", container).off("click").on("click", (e) => PageDesigner.populatePropertyBox(e, propertyBox));
    },

    populatePropertyBox: function(e, propertyBox) {
        e.preventDefault();
        var component = $(e.currentTarget).closest(".component");
        $("[name=elementTitle]", propertyBox).html($(component).attr("name") + " [resource_displayname[propeties]]");
        $("input", propertyBox).each((i, input) => {
            var inputName = $(input).attr("name");
            var inputValue = $(component).css(inputName);
            $(input).val(inputValue);
        });
        $("input", propertyBox).off("click").on("keyup", (e) => PageDesigner.setElementCSSValue(e, component));
    },

    setElementCSSValue: function(e, element) {
        e.preventDefault();
        var inputTag = $(e.currentTarget);
        var propertyName = inputTag.attr("name");
        var propertyValue = inputTag.val();
        if(propertyValue.includes("px") || propertyValue.includes("%")) {
            $(element).css(propertyName, propertyValue);
        }
    },

    removeThisComponent: function(e) {
        e.preventDefault();
        var component = $(e.currentTarget).closest(".component");
        $(component).remove();
    },

    getComponentsSwapped: function(contents) {
        var regExp = new RegExp("\\[component\\[[A-Za-z\\d_/. \\-]*\\]\\]");
        var targetText = JSON.parse(JSON.stringify(contents));
        while((m = regExp.exec(targetText)) !== null) {
            var componentName = m[0].replace("[component[", "");
            componentName = componentName.substring(0, componentName.length - 2);
            targetText = targetText.replace(m[0], `
                <section contenteditable="false\" name="${componentName}" class="component editableComponent">
                    <span class="k-icon k-i-source-code"></span>${componentName}
                    <button name="removeThisComponent">
                        <span class="k-icon k-i-close"></span>
                    </button>
                </section>`);
        }
        return targetText;
    },

    addComponentOptions: async function(app, container) {
        var appComponents = (await api.get("Core/Component?$filter=AppId eq " + app.Id + "&$select=Name,Key")).value;
        var commonCacheComponents = (await api.get("Core/CommonObject/Latest()?type=Core/Component&$select=Name,Key")).value;
        var keySet = [...new Set(appComponents.map(ac => ac.Key).concat(commonCacheComponents.map(cc => cc.Key)))];
        var keyToNamesMapping = {};
        for(let i =0 ; i < keySet.length; i++) {
            keyToNamesMapping[keySet[i]] = [...new Set(appComponents.filter(r => r.Key === keySet[i]).map(ac => ac.Name).concat(commonCacheComponents.filter(r => r.Key === keySet[i]).map(cc => cc.Name)))];;
        }

        for(const [key,nameSet] of Object.entries(keyToNamesMapping)) {
            var insertedElement = $(container).append(`
                <ul class="categorytypes" name="typeListing">
                    <li class="header">
                        <span class="k-icon k-i-source-code"></span>[resource_displayname[components]] - ${key}
                    </li>
                    <ul class="subtypes">
                    </ul>
                </ul>
            `).children().last();
            $(".subtypes", insertedElement).append(nameSet.map(n => `
                <li class="ui-draggable ui-draggable-handle">
                    <span class="k-icon k-i-source-code"></span>
                    ${n}
                </li>
            `).join(""));
        }
    },

}","CreatedOn":"2022-05-01T13:02:57.740Z","LastUpdated":"2022-05-01T13:02:57.740Z"}

{"Content":"","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Content Management","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"PageInfo","ResourceKey":"CMS","Script":"PageInfo = {
	init: async function (app, container, page) {
		app = app || session.app;
		container = container || $(".component[name=PageInfo]");

		if(!page) { return; }

        api.addToMetaCache([
        {
            "Name": "Core",
            "Types": [
                [meta[Core/Culture]],
                [meta[Core/PageInfo]],
            ]
        }]);

		var cultures = model.getDatasource({
			endpoint: "Core/Culture",
			sort: { field: "Name", dir: "asc"}
		});

		var pageInfos = await model.getDatasource({
			endpoint: "Core/PageInfo", 
			odataAppend: "?$filter=PageId eq " + page.Id
		});

		var grid = new GridWidget(container, pageInfos);
		grid.groupable = false;
		grid.pageable = false;
		grid.toolbar = `<div class="btn-group btn-group-sm"> <button class="btn btn-primary" name="create"> <span class="k-icon k-i-plus"></span>[resource_displayname[new]] </button> </div>`;
		grid.columns = [
			{ 
				field: "CultureId",
				 title: "[resource_displayname[culture]]", 				
				 editor: (container, options) => $('<input name="' + options.field + '"/>').appendTo(container).kendoDropDownList({ autoBind: false, dataTextField: "Name", dataValueField: "Id", dataSource: cultures })
			},
			{ field: "Title", title: "[resource_shortdisplayname[title]]" },
			{ field: "Description", title: "[resource_shortdisplayname[description]]" },
			{ field: "Keywords", title: "[resource_shortdisplayname[keywords]]" }
		];
		grid.dataBound = function() {
			$("[name=save]", grid.gridElement).off("click").on("click", (e) => PageInfo.save(e, grid));
			$("[name=delete]", grid.gridElement).off("click").on("click", (e) => PageInfo.destroy(e,grid));
		};

		grid.commands.push({name: "save", icon: "k-i-save", text: "[resource_displayname[save]]"});
		grid.commands.push({name: "delete", icon: "k-i-trashIcon", text: "[resource_displayname[delete]]"});

		await grid.init();

		$("[name=create]", grid.gridElement).on("click", (e) => PageInfo.create(e, app, page, grid));
	},

	create: async function (e, app, page, grid) {
		e.preventDefault();

		var defaultCulture = grid.dataSource().data().filter(r => r.CultureId === "");

		var newPI = await model.item.createInstance("Core/PageInfo");
		newPI.PageId = page.Id;
		if(defaultCulture.length > 0) {
			newPI.Title = defaultCulture[0].Title;
			newPI.Keywords = defaultCulture[0].Keywords;
			newPI.Description = defaultCulture[0].Description;
		} else {
			newPI.Title = page.Name;
			newPI.Keywords = page.Name;
			newPI.Description = page.Name;
		}
		await newPI.save().then(() => {
			notification.success("[resource_displayname[added]]");
			grid.refresh();
		}).catch((err) => error(err));
	},

	destroy: async function (e, grid) {
		var dataItem = grid.dataItem($(e.target).closest("tr"));
		await dataItem.destroy(e);

		notification.success("[resource_displayname[deleted]]");
		grid.refresh();
	},

	save: async function (e, grid) {
		e.preventDefault();
		var dataItem = grid.dataItem($(e.target).closest("tr"));
		await dataItem.save();

		notification.success("[resource_displayname[updated]]");
		grid.refresh();
	}
};"}

