","Script":"PageManagement = {
      getMatchedCulture: function(page) {
            var matchedContents = page.Contents.filter(r => r.CultureId === session.culture);
            return matchedContents.length > 0 ? matchedContents[0].CultureId : "";
      },

      init: async function (app, container) {
            app = app || session.app;
            container = container || $(".component[name=PageManagement]");

            api.addToMetaCache([
            {
                  "Name": "Core",
                  "Types": [
                        [meta[Core/Page]]
                  ]
            }]);

            $("[name=pageManagementToolbar]", container).kendoToolBar({
                  items: [
                        {template: "<button class='k-i-icon k-i-page' name='selectpage'>[resource_displayname[selectpage]]</button>"}
                  ]
            });

            $("[name=selectpage]", container).on("click", (e) => PageManagement.selectPage(e, container, app));
      },

      loadPage: async function(app, container, page) {
            if(!page) {
                  return;
            }
            var culture = PageManagement.getMatchedCulture(page);
            var baseUrl = (location.port !== "") 
                  ? "https://" + app.Domain + ":" + location.port + "/"
                  : "https://" + app.Domain + "/";
            var url = baseUrl + page.Path + "?edit=true&culture=" + culture;
            var iframe = $("iframe", container);
            iframe.attr("src", url);

            $(document).off("enablePageEditing").on("enablePageEditing", () => {
                  var iframeContentContainer = iframe[0].contentDocument ? iframe[0].contentDocument : iframe[0].contentWindow.document;
                  $.each($(".content", iframeContentContainer),  (i, area) => {
                        var content = page.Contents.filter(c => c.Name == "body" && c.CultureId === culture)[0];
                        if (!content) {
                              content = { Id: 0, PageId: page.Id, Name: "body", CultureId: "", Html: "", Script: "" };
                              page.Contents.push(content);
                        }
                        $(area).empty();
                        $(area).html(content.Html);
                  });
            });
      },

      selectPage: async function(e, container, app) {
            e.preventDefault();
            var selectPageDialog  = new Dialog({title: "[resource_displayname[selectpage]]", width: 400, height: 800, modal: false });
            selectPageDialog.init(async () => {
                  var cmsComponent = await loadComponent(selectPageDialog.element, "CMS");
                  cmsComponent.init(app, $(".component[name=CMS]", selectPageDialog.element), (page) => { 
                        PageManagement.loadPage(app, container, page);
                        selectPageDialog.events.close();
                  });
            });
      }
};





