	init: async function (app, container, page, saveAction) {
		app = app || session.app;
		container = container || $(".component[name=PageProperties]");
		saveAction = saveAction || function () { page.save(); };

		if (!page)
			return;

		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/Layout]]
				]
			}]);

		var layouts = await model.getDatasource({
			endpoint: "Core/Layout",
			odataAppend: "?$filter=AppId eq " + app.Id + "&$select=Name"
		});

		$("input[name=layout]", container).kendoDropDownList({
			dataTextField: "Name",
			dataValueField: "Name",
			dataSource: layouts,
			value: page.Layout || "Default",
			change: function (e) {
				page.Layout = this.value();
				saveAction(e);
				notification.success("[resource_displayname[layoutchanged]]");
			}
		});

		$(container).css("width", "100%");

		$("input[name=showOnMenus]", container).prop("checked", page.ShowOnMenus);
		$("input[name=resourceKey]", container).val(page.ResourceKey);

		$("input[name=showOnMenus]", container).on("click", (e) => {
			page.ShowOnMenus = $("input[name=showOnMenus]", container).is(":checked");
			saveAction(e);
			notification.success("[resource_displayname[changesaved]]");
		});
		$("input[name=resourceKey]", container).on("change", (e) => {
			page.ResourceKey = $("input[name=resourceKey]", container).val();
			saveAction(e);
			notification.success("[resource_displayname[changesaved]]");
		});

		$("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });

		PageInfo.init(app, $(".component[name=PageInfo]", $(".tab[name=information]", container)), page);
		PageRoles.init(app, $(".component[name=PageRoles]", $(".tab[name=roles]", container)), page);
	}
};"}

{"AppId":11,"ResourceKey":"CMS","Content":"","Script":"PageRoles = {
	init: async function (app, container, page) {
		app = app || session.app;
		container = container || $(".component[name=PageRoles]");
		if(!page) { return; }
		var rolesInApp = await api.get("Core/Role?$filter=AppId eq " + app.Id);
		PageRoles.setup(container, page, rolesInApp.value);
	},

	setup: async function (container, page, rolesInApp) {
		var grid = new GridWidget(container, {data: rolesInApp, sort: {field: "Name", dir: "asc"}});
		grid.columns = [
			{ selectable: true, width: "50px"},
			{ field: "Name", title: "[resource_displayname[name]]"}
		];
		grid.groupable = false;
		grid.pageable = false;
		grid.filterable =  false;
		grid.dataBound = function() {
			$("input[type=checkbox]", grid.gridElement).on("click", async function () {
				var checked = $(this).is(":checked");
				var uid = $(this).closest("tr").attr("data-uid");
				var dataItem = grid.dataSource().getByUid(uid);
				if(checked) {
					await api.post("Core/PageRole", { PageId: page.Id, RoleId: dataItem.Id }).then(() => {
						notification.success("[resource_displayname[saved]]");
					}).catch((err) => error(err));
				} else {
					await api.destroy("Core/PageRole(PageId=" + page.Id + ",RoleId=" + dataItem.Id + ")").then(() => {
						notification.success("[resource_displayname[saved]]");
					}).catch((err) => error(err));
				}
			});
		};
		await grid.init();

		var pageRoleIds = (await api.get("Core/PageRole?$filter=PageId eq " + page.Id)).value.map(c => c.RoleId);
		$("tbody > tr", grid.gridElement).each(function() {
			var uid = $(this).attr("data-uid");
			var dataItem = grid.dataSource().getByUid(uid);
			if(pageRoleIds.includes(dataItem.Id)) { grid.kendoObject.select($(this)); }
		});
	}
}
