","Script":"PasswordReset = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=PasswordReset]");

		$('input', container).on('click', function (e) {
			$(this).attr('type') == 'password' ? 'text' : 'password';
		});
		$('button[name=submitReset]', container).on('click', async function (e) {
			await PasswordReset.confirm(e, app, container)
		});
	},

	confirm: async function (e, app, container) {
		var url = new URL(window.location.href);
		var resetRequest = {
			UserId: url.searchParams.get("uid"),
			NewPassword: $('input[name=pass]', container).val(),
			ConfirmPassword: $('input[name=confirm]', container).val(),
			Token: url.searchParams.get("token"),
			SourceAppId: app.Id
		};
		await api.post("Account/ConfirmForgotPassword", resetRequest).then((resSuccess) => {
			if (resSuccess || resSuccess == '')
			{
				notification.success("[resource_description[ResetSuccess]]");
				window.location.href = "/Login";
			}
			else
				notification.error("[resource_description[ResetFailed]]");
		});


	}
}

$(function () {
	PasswordReset.init();
});
