</style>","Script":"Payment = {
    //TODO: populate this from the server
    types: [
        { id: 1, name: "[resource_displayname[Statement]]" },
        { id: 2, name: "[resource_displayname[PayerPaymentAdvice]]" },
        { id: 3, name: "[resource_displayname[PayeePaymentAdvice]]" }
    ],
    id: null,
    backButton: true,
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=Payment]");

        $(container).addClass("details");
        $(".component[name=Payment]").addClass("details");

        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/RemittanceAdvice]],
                    [meta[B2B/RemittanceAdviceLine]],
                    [meta[B2B/Company]]
                ]
            }
        ]);


        var children = $(".col > div", container)
        children.css("margin", app.Config.Themes[session.theme].margins);
        children.css("border", app.Config.Themes[session.theme].border.style);
        children.css("box-shadow", app.Config.Themes[session.theme].shadows);
        if (this.id === null) {
            this.id = getQueryParameter("Id");
        }
        var paymentDetails = [script[PaymentDetails]];
        var variables = {
            element: $("[name=paymentDetails]", container)
        };
        paymentDetails(variables);
        var details = variables.PaymentDetails;
        if (!this.backButton) {
            details.toolbar = "";
        }
        details.config.odataAppend = "(" + this.id + ")?$expand=References,AuditTrail,Companies";
        await details.init();
        var payment = details.data;

        var referenceGridInit = [script[ReferenceGrid]];
        var referenceVariables = {
            element: $("[name=referencesGrid]", container),
            references: payment.References
        };
        referenceGridInit(referenceVariables);
        referenceVariables.ReferenceGrid.init();
        var lineGridInit = [script[PaymentLineGrid]];
        var variablesLines = {
            element: $("[name=linesGrid]", container),
            paymentId: payment.Id
        };
        (await lineGridInit(variablesLines)).init();
        audit = [];
        for (var i = 0; i < payment.AuditTrail.length; i = i + 1) {
            audit.push(payment.AuditTrail[i]);
        }
        if (payment.AuditTrail.length > 0) {
            var historyGrid = [script[HistoryGrid]];
            var variables = {
                element: $("[name=historyGrid]", container),
                history: audit
            };
            historyGrid(variables);
            var h = variables.HistoryGrid;
            h.init(() => {
                h.kendoObject.dataSource.sort({ field: "CreatedOn", dir: "desc" });
            });
        } else { $("[name=history]", container).remove(); }
        var companyInfo = (await api.get("B2B/Company?$filter=References/any(r: r/RemittanceAdviceReferences/any(j: j/RemittanceAdviceId eq " + this.id + "))&$expand=References,Address")).value;
        var transactionCompanyInfo = [];
        for (let i = 0; i < payment.Companies.length; i++) {
            var transactionCompany = payment.Companies[i];
            var matchedCompanyInfo = companyInfo.filter(ci => ci.References.filter(cir => cir.Id == transactionCompany.CompanyReferenceId).length > 0)[0];
            transactionCompany.Name = matchedCompanyInfo.Name;
            transactionCompany.DebtorReference = matchedCompanyInfo.References.filter(r => r.SystemId == payment.SourceSystemId).map(r => r.Value).join();
            transactionCompany.DebtorVATReference = (matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax").length > 0 ? matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax")[0].Value : "N/A");
            transactionCompany.Id = matchedCompanyInfo.Id;
            if (transactionCompanyInfo.filter(r => r.Perspective == transactionCompany.Perspective && r.DebtorReference == transactionCompany.DebtorReference).length === 0) {
                transactionCompanyInfo.push(transactionCompany);
            }
        }
        var companyGridInit = [script[CompanyGrid]];
        (await companyGridInit({
            element: $("[name=companyDetails]", container),
            dataSource: transactionCompanyInfo
        })).init();
    },
    transactionLink: function (raLine) {
        if (raLine.InvoiceReference) return "/Transactions/Invoice?Id=" + raLine.InvoiceReference.InvoiceId;
        if (raLine.CreditReference) return "/Transactions/Credit?Id=" + raLine.CreditReference.CreditId;
        // ??
        //if(raLine.OfferReference) return "/Finance/Offer?Id=" + raLine.OfferReference.OfferId;
        return "";
