<div class="paymentValueDisplay"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"PaymentYearToDate","ResourceKey":"B2B","Script":"PaymentYearToDate = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=PaymentYearToDate]");

        const defaultCurrency = app.Config.B2B.DefaultCurrency || "EUR";

        const currencyDropdown = $("[name=currencyDropdown]", container).kendoDropDownList({
            dataSource: app.Config.B2B.Currencies || ["USD", "EUR", "GBP"],
            change: async function () {
                const selectedCurrency = this.value();
                await PaymentYearToDate.updatePaymentData(app, container, selectedCurrency);
            }
        }).data("kendoDropDownList");

        currencyDropdown.value(defaultCurrency);
        await PaymentYearToDate.updatePaymentData(app, container, defaultCurrency);

        $(".comparison-icon").kendoTooltip({
            content: function (e) {
                return "[resource_displayname[comparisontext]]"
            },
            position: "right"
        });
    },

    updatePaymentData: async function (app, container, currency) {
        const { total, paymentCount, totalComparisonResult, countComparisonResult } = await PaymentYearToDate.getData(app, currency);
        PaymentYearToDate.displayTotalPayment(total, paymentCount, totalComparisonResult, countComparisonResult, container);
    },

    getData: async function (app, currency) {
        const sourceSystem = app.Config.B2B.SourceSystem;
        const paymentQuery = `B2B/RemittanceAdvice?$filter=SourceSystemId eq '${sourceSystem}' and CurrencyId eq '${currency}'`;

        const payments = (await api.get(paymentQuery)).value;

        const currentDate = new Date();
        const currentYear = currentDate.getFullYear().toString();
        const previousYear = (currentDate.getFullYear() - 1).toString();
        const currentMonth = currentDate.getMonth() + 1; 

        const filterPaymentsYearToDate = (year) =>
            payments.filter(({ DueDate }) => {
                const [paymentYear, paymentMonth] = DueDate.split("-");
                return (
                    paymentYear === year &&
                    parseInt(paymentMonth, 10) <= currentMonth
                );
            });

        const currentYearPayments = filterPaymentsYearToDate(currentYear);
        const previousYearPayments = filterPaymentsYearToDate(previousYear);

        const calculateTotal = (paymentList) =>
            paymentList.reduce((sum, { Value }) => sum + Value, 0);

        const totalForCurrentYear = calculateTotal(currentYearPayments);
        const totalForPreviousYear = calculateTotal(previousYearPayments);

        const compare = (current, previous) =>
            current > previous ? "up" : current < previous ? "down" : "same";

        return {
            total: totalForCurrentYear,
            paymentCount: currentYearPayments.length,
            totalComparisonResult: compare(totalForCurrentYear, totalForPreviousYear),
            countComparisonResult: compare(currentYearPayments.length, previousYearPayments.length)
        };
    },


    displayTotalPayment: function (total, paymentCount, totalComparisonResult, countComparisonResult, container) {
        const paymentValueDisplay = $("div.paymentValueDisplay", container);

        const getComparisonIcon = (result) => ({
            up: '<span class="comparison-icon up-arrow">↑</span>',
            down: '<span class="comparison-icon down-arrow">↓</span>',
            same: '<span class="comparison-icon same-icon">→</span>'
        })[result];

        const countComparisonIcon = getComparisonIcon(countComparisonResult);
        const valueComparisonIcon = getComparisonIcon(totalComparisonResult);

        paymentValueDisplay.html(`
            <h4>[resource_displayname[totalpaymentcountthisyear]]</h4>
            <h2 class="yearToDate">${paymentCount} ${countComparisonIcon}</h2>
            <h4>[resource_displayname[totalpaymentvaluethisyear]]</h4>
            <h2 class="yearToDate">${kendo.toString(total, type.moneyFormat)} ${valueComparisonIcon}</h2>
        `);
    }
};
"}

