        container = container || $(".component[name=PaymentYearToDateStats]");
        container.addClass("small");
        const currentDate = new Date();
        const offset = currentDate.getTimezoneOffset();
        const firstDay = new Date((new Date(currentDate.getFullYear(), 0, 1)).getTime() - (offset * 60 * 1000)).toISOString().split("T")[0];
        const lastDay = new Date((new Date(currentDate.getFullYear(), 11, 31)).getTime() - (offset * 60 * 1000)).toISOString().split("T")[0];
        var paymentData = await api.get(`B2B/RemittanceAdvice/FromSystem(SystemId='${app.Config.B2B.SourceSystem}')?$apply=filter(DueDate ge ${firstDay} and DueDate le ${lastDay})/groupby((CurrencyId), aggregate(Value with sum as Total, Id with countdistinct as Count))`);
        PaymentYearToDateStats.setupPaymentGrid(paymentData, $(".paymentGrid", container));
