</script>","Script":"PendingRequests = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=PendingRequests]");
        var dataSource = new kendo.data.DataSource({
            transport: {
                read: async (options) => {
                    try {
                        var result = await api.get(`B2B/AccessRequest?$filter=Status eq 'pending' and TenantId eq '${app.TenantId}'`);
                        options.success(result.value);
                    } catch (err) {
                        options.error(err);
                    }
                }
            },
            pageSize: 20,
            schema: {
                model: { id: "Id" }
            },
            serverPaging: true,
            serverSorting: true,
            serverFiltering: true
        });

        var grid = new GridWidget($("[name=pendingRequestsGrid]", container), dataSource);

        grid.columns = [
            { field: "UserEmailAddress", type: "string", title: "[resource_shortdisplayname[userEmail]]" },
            { field: "CompanyName", type: "string", title: "[resource_shortdisplayname[companyName]]" },
            { field: "Perspective", title: "[resource_shortdisplayname[perspective]]" },
            { field: "CreatedOn", type: "date", title: "[resource_shortdisplayname[requestDate]]", format: "{0:" + type.dateFormat + "}" }
        ];

        grid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });

        grid.editable = false;
        grid.sortable = true;
        grid.filterable = true;
        grid.groupable = false;
        grid.pageable = { refresh: true, pageSizes: [10, 20, 50, 100], numeric: true, serverPaging: true };

        grid.detailTemplate = kendo.template($("[name=pendingRequestDetailTemplate]").html());

        grid.detailExpand = function (e) {
            var detailRow = $(e.detailRow);
            if (detailRow.data("initialized")) return;
            detailRow.data("initialized", true);

            var dataItem = grid.kendoObject.dataItem(e.masterRow);

            var loadDetail = (selector, componentName) => {
                loadComponent($(selector, detailRow), componentName, c => {
                    c.init(app, $(selector, detailRow), dataItem);
                    $(selector, detailRow).data("model", $(selector, detailRow).find(":first").data("kendoBindingTarget"));
                });
            };

            loadDetail(".component[name=PersonalDetailsContainer]", "RegistrationPersonalDetails");
            loadDetail(".component[name=CompanyDetailsContainer]", "RegistrationCompanyDetails");
            loadDetail(".component[name=AdminDetailsContainer]", "RegistrationAdminDetails");

            $("button[name=save]", detailRow).off("click").on("click", async e => {
                e.preventDefault();
                var personalModel = $(".component[name=PersonalDetailsContainer]", detailRow).data("model");
                var companyModel = $(".component[name=CompanyDetailsContainer]", detailRow).data("model");
                var adminModel = $(".component[name=AdminDetailsContainer]", detailRow).data("model");

                if (!personalModel || !adminModel) {
                    notification.error("[resource_displayname[savefailed]]");
                    return;
                }

                await PendingRequests.saveRequest(grid, dataItem, personalModel, companyModel, adminModel);
                dataItem.set("AdminComments", adminModel.get("AdminComments"));

                grid.kendoObject.collapseRow($(e.currentTarget).closest("tr"));
            });

            $("button[name=reject]", detailRow).off("click").on("click", e => {
                e.preventDefault();
                PendingRequests.reject(e, grid, dataItem);
            });

            $("button[name=approve]", detailRow).off("click").on("click", e => {
                e.preventDefault();
                PendingRequests.approve(e, grid, dataItem);
            });
        };

        grid.dataBound = function () {
            $("button[name=delete]", grid.gridElement).off("click").on("click", e => PendingRequests.destroy(e, grid));
        };

        await grid.init();
    },

    destroy: async function (e, grid) {
        e.preventDefault();
        var d = new ConfirmDialog({
            title: "[resource_displayname[deleterequest]]",
            question: "[resource_displayname[doyouwantodeletetherequest]]",
            confirm: `<span class='k-icon k-i-trash'></span>[resource_displayname[delete]]`,
        });

        d.events.confirm = async function () {
            var request = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
            await api.destroy(`B2B/AccessRequest(${request.Id})`);
            notification.success("[resource_displayname[accessrequestdeleted]]");
            grid.kendoObject.dataSource.read();
            d.events.close();
        };

        d.init();
    },

    saveRequest: async function (grid, dataItem, personalModel, companyModel, adminModel) {
        var updatedItem = Object.assign({}, dataItem.toJSON ? dataItem.toJSON() : dataItem, {
            UserName: `${personalModel.get("FirstName")}.${personalModel.get("LastName")}`.toLowerCase(),
            UserEmailAddress: personalModel.get("UserEmailAddress"),
            UserPhoneNumber: personalModel.get("UserPhoneNumber"),
            UserJobRole: personalModel.get("UserJobRole"),
            ManagerName: personalModel.get("ManagerName"),
            ManagerEmailAddress: personalModel.get("ManagerEmailAddress"),
            AdminComments: adminModel.get("AdminComments"),
            FundingTypeBucketId: adminModel.get("FundingTypeBucketId") || null
        });

        if (companyModel) {
            var companyId = adminModel.get("CompanyId");
            if (companyId) {
                updatedItem.CompanyId = companyId;
            }

            updatedItem.CompanyName = companyModel.get("CompanyName") || dataItem.CompanyName;
            updatedItem.CompanyTaxReference = companyModel.get("CompanyTaxReference");
            updatedItem.CompanyClientReference = companyModel.get("CompanyClientReference") || "";
            updatedItem.CompanyAddressLine1 = companyModel.get("CompanyAddressLine1");
            updatedItem.CompanyAddressLine2 = companyModel.get("CompanyAddressLine2");
            updatedItem.CompanyRegion = companyModel.get("CompanyRegion") || "";
            updatedItem.CompanyPostcode = companyModel.get("CompanyPostcode");
            updatedItem.CompanyCountryCode = companyModel.get("CompanyCountryCode");
            updatedItem.Perspective = companyModel.get("Perspective");
            updatedItem.RequestedFundingType = companyModel.get("RequestedFundingType") || "";
        }

        await api.put(`B2B/AccessRequest(${dataItem.Id})`, updatedItem);
        notification.success("[resource_displayname[accessrequestupdated]]");

        grid.kendoObject.dataSource.read();
    },

    approve: async function (e, grid, dataItem) {
        e.preventDefault();

        var updatedItem = Object.assign({}, dataItem.toJSON(), {
            Status: "approved"
        });

        await api.put(`B2B/AccessRequest(${dataItem.Id})`, updatedItem);
        notification.success("[resource_displayname[accessrequestapproved]]");

        grid.kendoObject.dataSource.read();

        const detailRow = $(e.currentTarget).closest(".k-detail-row");
        const masterRow = detailRow.prev("tr.k-master-row");
        grid.kendoObject.collapseRow(masterRow);
    },

    reject: async function (e, grid, dataItem) {
        e.preventDefault();
        var rejectDialog = new Dialog({ title: "[resource_displayname[rejectRequest]]", width: 600 });
        rejectDialog.template = $("[name=rejectrequestdialog]").first().html();

        rejectDialog.init(() => {
            $("[name=rejectSave]", rejectDialog.element).off("click").on("click", async () => {
                var comment = $("[name=adminComment]", rejectDialog.element).val().trim();

                var updatedItem = Object.assign({}, dataItem.toJSON ? dataItem.toJSON() : dataItem, {
                    Status: "denied",
                    AdminComments: comment
                });

                await api.put(`B2B/AccessRequest(${dataItem.Id})`, updatedItem);
                notification.success("[resource_displayname[accessrequestrejected]]");

                grid.kendoObject.dataSource.read();
                grid.kendoObject.collapseRow($(rejectDialog.element).closest("tr"));
                rejectDialog.events.close();
            });
        });
    }
};
