{"Content":"<div name="pendingGridContainer"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"B2B Admin","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"PendingUserInvites","ResourceKey":"B2B","Script":"PendingUserInvites = {
