        var pendingGrid = await this.initPendingGrid(app, pendingGridContainer);
    },

    initPendingGrid: async function(app, gridContainer) {
        $(gridContainer).html('');

        var pendingDatasource = await model.getDatasource({
            endpoint: "Core/User",
            odataAppend: `?$filter=Roles/any(r: r/Role/Name eq 'Invited Users')`,
            sort: {
                field: "Id",
                dir: "asc"
            }
        });

        var grid = new GridWidget(gridContainer, pendingDatasource);
