                'DisplayName',
                'Email'
            ]
        };

        grid.columns = [
            { field: "Id", title: "[resource_displayname[id]]" },
            { field: "DisplayName", title: "[resource_displayname[displayname]]" },
            { field: "Email", title: "[resource_displayname[email]]" },
        ];

        grid.commands.push({
            name: "resend-invite",
            icon: 'k-i-paper-plane',
