            text: "[resource_displayname[delete]]"
        }
        );
        
        grid.dataBound = function() {
            $("[name=resend-invite]", grid.gridElement).on("click", async function(e) {
		        var item = grid.dataItem($(e.currentTarget).closest("tr"));
                await PendingUserInvites.resendInvite(app, item).then(() => {
                notification.success('[resource_displayname[invitationresent]]')
                }).catch((err) => error(err));
            });
            $("button[name=delete-invite]", grid.gridElement).on("click", (e) => PendingUserInvites.deleteInvite(e, grid));
        };

        await grid.init();

        return grid;
    },

    	deleteInvite: async function (e, grid) {
		e.preventDefault();
		var d = new ConfirmDialog({
			title: "[resource_displayname[areyousure]]",
			question: "[resource_displayname[areyousure]]",
			confirm: "[resource_displayname[confirm]]",
			close: "[resource_displayname[close]]"
		});
