<script type="text/template" name="b2bReportDetails">
<div name="tabs">
    <ul>
        <li class="k-active">[resource_displayname[buyers]]</li>
        <li>[resource_displayname[suppliers]]</li>
        <li>[resource_displayname[funders]]</li>
