</script>","Script":"PlatformUsage = {
    init: async function(app, container) {
        app = app || session.app;
		container = container || $(".component[name=PlatformUsage]");
        $("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });

        api.addToMetaCache([
            {
                "Name": "Security",
                "Types": [
                    [meta[Security/TenantAnalysis]]
                ]
            },
            {
                "Name": "Security",
                "Types": [
                    [meta[Security/Tenant]]
                ]
            },
        ]);

        await PlatformUsage.initCore(app, container);
        await PlatformUsage.initB2B(app, container);
    },

    initCore: async function(app, container) { 
        var gridElement = $(".core", container);
        var config = { 
            endpoint: "Security/TenantAnalysis", 
            odataAppend: `?$filter=TenantId eq '${app.TenantId}' and Name eq 'User Activity (Daily)' `,  
            sort: { field: "CreatedOn", dir: "desc" } 
        };
        var dataSource = await model.getDatasource(config);
        var args = { element: gridElement, dataSource: dataSource, buildDetails: PlatformUsage.buildCoreDetails };
        var grid = PlatformUsage.setupCoreDailyUsageGrid(args);
        await grid.init();
    },

    initB2B: async function(app, container) { 
        var gridElement = $(".b2b", container);
        var dataSource = await model.getDatasource({ endpoint: "Security/TenantAnalysis", odataAppend: `?$filter=TenantId eq  '${app.TenantId}' and Name eq 'B2B Consumption (Daily)' `});
        var args = { element: gridElement, dataSource: dataSource, buildDetails: PlatformUsage.buildB2BDetails };
        var grid = PlatformUsage.setupB2BDailyUsageGrid(args);
        await grid.init();
    },

    buildCoreDetails: async function(container, report) {
        Object.keys(report).forEach(async key => {
			container.append(
				$("[name=reportPart]")
					.html()
					.replace('[PARTNAME]', key)
					.replace('[PARTNAME]', key.replace("Call", " Call"))
			);

			await PlatformUsage.reportItemsFor(key, $(`[name=${key}] > [name=grid]`, container), report[key]);
        });
    },

    reportItemsFor: async function(key, element, data) {
        var args = { element: element, dataSource: data };

        switch(key) {
            case "Users":
                await PlatformUsage.setupCoreDailyUsageUserDetailsGrid(args).init();
                break;
            case "Pages":
                await PlatformUsage.setupCoreDailyUsagePageDetailsGrid(args).init();
                break;
            case "ApiCalls":
                await PlatformUsage.setupCoreDailyUsageApiDetailsGrid(args).init();
                break;
            default:
                args.buildDetails = PlatformUsage.buildTransactionDetails;
                await PlatformUsage.setupB2BDailyUsageDetailsGrid(args).init();
        }
    },

    buildB2BDetails: function(container, report) {
        container.append($("[name=b2bReportDetails]").html());
        $("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });

        Object.keys(report).forEach(async key => {
                await PlatformUsage.reportItemsFor(key, $(`.reportTab[name=${key}]`, container), report[key]);
        });
    },

    buildTransactionDetails: async function(container, data) { 
        var childData = [];
        data.ActiveTransactions.forEach(t => { t.Type = "Active Transactions";	childData.push(t);	});
        data.Invoices.forEach(t =>                  { t.Type = "Invoices"; childData.push(t); });
        data.Credits.forEach(t =>                    { t.Type = "Credits"; childData.push(t); });
        data.Offers.forEach(t =>                     { t.Type = "Offers"; childData.push(t); });
        data.Payments.forEach(t =>               { t.Type = "Payments"; childData.push(t); });
        await PlatformUsage.setupB2BDailyUsageTransactionDetailsGrid({ element: container, dataSource: childData }).init(); 
    },

    setupCoreDailyUsageGrid: [script[CoreDailyUsageGrid]],
    setupB2BDailyUsageGrid: [script[B2BDailyUsageGrid]],
	
	setupCoreDailyUsageUserDetailsGrid: [script[CoreDailyUsageUserDetailsGrid]],
    setupCoreDailyUsagePageDetailsGrid: [script[CoreDailyUsagePageDetailsGrid]],
    setupCoreDailyUsageApiDetailsGrid: [script[CoreDailyUsageApiDetailsGrid]],
    setupB2BDailyUsageDetailsGrid: [script[B2BDailyUsageDetailsGrid]],
    setupB2BDailyUsageTransactionDetailsGrid: [script[B2BDailyUsageTransactionDetailsGrid]]
}
