</style>","Script":"ProgrammeManagement = {
		init: function(app, container) {
        		 app = app|| session.app; 
        		 container = container || $(".component[name=ProgrammeManagement]"); 
                 ProgrammeManagement.setupGrid(app, container, app.Config.B2B.RootBucket);
        },

        setupGrid: function(app, container, rootBucket) {

			var config = {
                     endpoint: "B2B/Bucket",
               		 odataAppend: "?$filter=ParentId eq " + rootBucket + " and Key eq 'Programme'"
             };

			 model.getDatasource(config, function (ds) {
                   var grid = $("[name=grid]", container).kendoGrid({
                          dataSource: ds,
                          editable: true,
                          sortable: true,
                          filterable: true,
                          scrollable: true,
                          pageable: {
                              refresh: true,
                              pageSizes: true,
                              buttonCount: 5
                          },
                          toolbar: "<button name='create'><span class='k-icon k-i-plus'></span>[resource_displayname[New]]</button>",
                          columns: [
                              { field: "Name", title: "[resource_shortdisplayname[Name]]", width: 200 },
                              { field: "Description", title: "[resource_shortdisplayname[Description]]" },
                              { width: 270, template: 
                               		  "<a href='/Funding/Products?programmeId=#=Id#'><span class='k-icon k-i-folder-open'></span>[resource_displayname[Products]]</a>" + 
                                      "<a name='save'><span class='k-icon k-i-save'></span>[resource_displayname[Save]]</a>" + 
                                      "<a name='destroy'><span class='k-icon k-i-delete'></span>[resource_displayname[Delete]]</a>"
                              }
                          ],
                          detailTemplate: kendo.template($("script[name=programmeDetails]").html()),
                		  detailExpand: function(e) { ProgrammeManagement.expand(app, $(e.detailRow), this.dataItem(e.masterRow)); },
                          dataBound: function () {
                              $("a[name=save]", grid).on("click", function(e) { ProgrammeManagement.save(e, container); });
                              $("a[name=destroy]", grid).on("click", function(e) { ProgrammeManagement.destroy(e, container); });
                          }
                    });

                    $("button[name=create]", grid).on("click", function (e) { ProgrammeManagement.newBucket(e, container, rootBucket); });
			  });
        },

   		expand: function(app, container, bucket) {
               var tabs = $("[name=tabs]", container).kendoTabStrip({ animation: { open: { effects: "fadeIn" } } });
               loadComponent($(".tab[name=summary]", container), "ProgrammeSummary", function(c) { ProgrammeSummary.init(app, $(".tab[name=summary]", container), bucket); });
               loadComponent($(".tab[name=companies]", container), "BucketedCompanyManagement", function(c) { BucketedCompanyManagement.init(app, $("[name=companies]", container), bucket); });
               loadComponent($(".tab[name=roles]", container), "BucketedRoleManagement", function(c) { BucketedRoleManagement.init(app, $("[name=roles]", container), bucket); });
       },

   		save: function (e, container) {
           e.preventDefault();
           var grid = $("[name=grid]", container).data("kendoGrid");
           var bucket = grid.dataItem($(e.currentTarget).closest("tr"));
           bucket.save(e, function () { notification.success("[resource_displayname[BucketSaved]]"); });
       },

       destroy: function (e, container) {
           e.preventDefault();

		   var d = new ConfirmDialog({
			   question:[[resource_displayname[confirmdelete]],
			   confirm: [resource_displayname[confirm]],
		   close: [resource_displayname[close]]});

		   d.events.confirm= function()
		   {

               var grid = $("[name=grid]", container).data("kendoGrid");
               var bucket = grid.dataItem($(e.currentTarget).closest("tr"));
               bucket.destroy(e, function () {
                   	notification.success("[resource_description[BucketDeleted]]");
                   	var grid = $("[name=grid]", container).data("kendoGrid");
                   	grid.dataSource.read();
                   	grid.refresh();
               });
		   }

		   d.init();
        },

   		newBucket: function(e, container, parentId) {
        		e.preventDefault();
                var newBucket = {
                        ParentId: parentId,
                		Name: "New Programme",
                    	Key: "Programme",
                   		Description: "New Programme"
                };

        		api.add("B2B/Bucket", newBucket, function(res) { 
                    notification.success("[resource_description[BucketCreated]]"); 
                    var grid = $("[name=grid]", container).data("kendoGrid");
                   	grid.dataSource.read();
                   	grid.refresh();
                });
        }
};

