{"Content":"","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Funding","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"ProposedOffers","ResourceKey":"B2B","Script":"ProposedOffers = {
    invoiceTypes: [
        { id: 1, name: "[resource_displayname[SalesInvoice]]" },
        { id: 2, name: "[resource_displayname[CopyInvoice]]" },
        { id: 3, name: "[resource_displayname[Replacement]]" },
        { id: 4, name: "[resource_displayname[SelfBillingInvoice]]" },
        { id: 5, name: "[resource_displayname[ProFormaInv]]" }
    ],

    creditTypes: [
        { id: 1, name: "[resource_displayname[CreditNote]]" },
        { id: 2, name: "[resource_displayname[Replacement]]" },
        { id: 3, name: "[resource_displayname[DebitNote]]" },
        { id: 4, name: "[resource_displayname[SelfBillingCredit]]" }
    ],

    paymentTypes: [
        { id: 1, name: "[resource_displayname[Statement]]" },
        { id: 2, name: "[resource_displayname[PayerPaymentAdvice]]" },
        { id: 3, name: "[resource_displayname[PayeePaymentAdvice]]" }
    ],

    states: [script[TransactionStates]],

    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=ProposedOffers]");

        api.addToMetaCache([
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/Offer]]
                ]
            }
        ]);

        var fields = "Id,ExpiryDate,CreditorName,DebtorName,Number,FundableValue,Value,Cost,Rate,CurrencyId,EarliestRelatedTaxPoint,DueDate,DebtorPaymentDate";
        var filter = "(FunderState eq 'Proposed' or DebtorState eq 'Proposed') and CreditorState ne 'FundingAccepted' and FunderState ne 'FundingAccepted'";

        var fundingTypeBuckets = (await api.get(
            "B2B/Bucket?$filter=Parent/Parent/ParentId eq "
            + app.Config.B2B.RootBucket
            + " and Key eq 'FundingType' and Parent/Companies/any() and FundingDetails/any(r:r/isSystematic eq false)&$expand=FundingDetails"
        )).value;

        var config = {
            endpoint: "B2B/Offer",
            odataAppend: "/FromSystem(SystemId='"
                + app.Config.B2B.TransactionSource
                + "')?$filter=" + filter + "&$expand=References&$select=" + fields,
            sort: [
                { field: "EarliestRelatedTaxPoint", dir: "asc" }
            ],
            pageSize: 1000
        };

        var dataSource = await model.getDatasource(config);

        var grid = (await [script[ProposedOffersGrid]]({
            element: container,
            dataSource: dataSource,
            app: app
        }));

        await grid.init();

        // FIX: computeTotals uses correct datasource path
        grid.computeTotals();

        $("[name=acceptAll]", grid.gridElement).on("click", (_) => ProposedOffers.acceptAll(grid));
        $("[name=acceptSelected]", grid.gridElement).on("click", (_) => ProposedOffers.acceptSelected(grid));
        $("[name=applyRecommendations]", grid.gridElement).on("click", (_) => ProposedOffers.applyRecommodations(grid));

        $("[name=fundingLimitDropdown]", grid.gridElement).hide();

        if (fundingTypeBuckets.length === 0) {
            $("[name=fundingTypeBucketsDropdown]", grid.gridElement).remove();

        } else {
            if (fundingTypeBuckets.length > 1) {
                $("[name=fundingTypeBucketsDropdown]", grid.gridElement).kendoDropDownList({
                    dataTextField: "Name",
                    dataValueField: "Id",
                    dataSource: fundingTypeBuckets,
                    change: async function (e) {
                        e.preventDefault();
                        var bucketId = this.value();
                        ProposedOffers.applyFundingTypeBucketFilter(
                            app, bucketId, grid, filter, fields
                        );
                    }
                }).data("kendoDropDownList").value(fundingTypeBuckets[0].Id);

            } else {
                $("[name=fundingTypeBucketsDropdown]", grid.gridElement).remove();
            }

            ProposedOffers.applyFundingTypeBucketFilter(
                app, fundingTypeBuckets[0].Id, grid, filter, fields
            );
        }
    },

    applyFundingTypeBucketFilter: async function (app, bucketId, grid, filter, fields) {
        var odataAppend = (bucketId == "")
            ? "/FromSystem(SystemId='" + app.Config.B2B.TransactionSource
              + "')?$filter=" + filter + "&$expand=References&$select=" + fields

            : "/FromSystem(SystemId='" + app.Config.B2B.TransactionSource
              + "')?$filter=" + filter
              + " and Buckets/any(r: r/BucketId eq " + bucketId + ")"
              + "&$expand=References&$select=" + fields;

        var config = {
            endpoint: "B2B/Offer",
            odataAppend: odataAppend,
            sort: [
                { field: "EarliestRelatedTaxPoint", dir: "asc" }
            ],
            pageSize: 1000
        };

        var dataSource = await model.getDatasource(config);
        grid.kendoObject.setDataSource(dataSource);

        if (bucketId !== "") {

            $("[name=fundingLimitDropdown]", grid.gridElement).hide();

            let fundingDetailsBucket = await api.get(
                "B2B/Bucket(" + bucketId + ")?$expand=FundingDetails"
            );

            let applicableLimits = fundingDetailsBucket.FundingDetails
                .filter(r => r.Limit !== 0)
                .map((v, i) => {
                    v.Index = i;
                    v.DisplayName =
                        v.Name
                        + " ("
                        + kendo.toString(v.Limit - v.CurrentLimit, type.moneyFormat)
                        + " "
                        + v.CurrencyId
                        + ")";
                    return v;
                });

            if (applicableLimits.length !== 0) {
                $("[name=fundingLimitDropdown]", grid.gridElement).show();

                $("[name=fundingLimitDropdown]", grid.gridElement).kendoDropDownList({
                    dataSource: applicableLimits,
                    dataTextField: "DisplayName",
                    dataValueField: "Index",
                    change: async function (e) {
                        e.preventDefault();

                        ProposedOffers.applyFundingLimit(
                            app,
                            grid,
                            this.value() !== "" ? applicableLimits[this.value()] : null,
                            filter + " and Buckets/any(r: r/BucketId eq " + bucketId + ")",
                            fields
                        );
                    }
                }).data("kendoDropDownList").value(applicableLimits[0].Index);

                ProposedOffers.applyFundingLimit(
                    app,
                    grid,
                    applicableLimits[0],
                    filter + " and Buckets/any(r: r/BucketId eq " + bucketId + ")",
                    fields
                );
            }
        } else {
            $("[name=fundingLimitDropdown]", grid.gridElement).hide();
        }
    },

    applyFundingLimit: async function (app, grid, fundingDetail, filter, fields) {
        let odataAppend = (fundingDetail)
            ? "/FromSystem(SystemId='" + app.Config.B2B.TransactionSource
              + "')?$filter=" + filter
              + " and CurrencyId eq '" + fundingDetail.CurrencyId
              + "'&$expand=References&$select=" + fields

            : "/FromSystem(SystemId='" + app.Config.B2B.TransactionSource
              + "')?$filter=" + filter
              + "&$expand=References&$select=" + fields;

        var config = {
            endpoint: "B2B/Offer",
            odataAppend: odataAppend,
            sort: [
                { field: "EarliestRelatedTaxPoint", dir: "asc" }
            ],
            pageSize: 1000
        };

        var dataSource = await model.getDatasource(config);
        grid.kendoObject.setDataSource(dataSource);
    },

    applyRecommodations: async function (grid) {

        var limitValue = parseFloat($("[name=limitValue]", grid.gridElement).val());

        // FIX: Correct datasource path
        var offers = grid.kendoObject.dataSource.data();

        var culmativeOfferSum = 0;

        for (let i = 0; i < offers.length; i++) {
            offers[i].ticked = false;
        }

        for (let i = 0; i < offers.length; i++) {
            var offer = offers[i];
            if (culmativeOfferSum + offer.Value <= limitValue) {
                culmativeOfferSum += offer.Value;
                offer.ticked = true;
            }
        }

        ProposedOffers.populateTicks(
            grid,
            offers.filter(r => r.ticked).map(o => o.Id)
        );

        grid.computeTotals();
    },

    populateTicks: function (grid, selectedOffers) {
        var items = grid.kendoObject.items();

        $("tr", grid.gridElement).each(function () {
            $(this).removeClass("k-selected");
            $("input[type=checkbox]", $(this)).prop("checked", false);
        });

        for (let i = 0; i < items.length; i++) {
            var offer = grid.dataItem(items[i]);
            if (selectedOffers.includes(offer.Id)) {
                grid.kendoObject.select(items[i]);
            }
        }
    },

    acceptSelected: async function (grid) {
        var offers = grid.select();
        ProposedOffers.acceptThese(offers);
    },

    acceptAll: async function (grid) {

        // FIX: Correct datasource path
        var offers = grid.kendoObject.dataSource.data();

        var d = new ConfirmDialog({
            title: "[resource_displayname[areyousure]]",
            close: "[resource_displayname[close]]",
            confirm: "[resource_displayname[confirm]]"
        });

        d.events.confirm = async function () {
            ProposedOffers.acceptThese(offers);
            d.events.close();
        };

        d.init();
    },

    acceptThese: async function (offers) {
        kendo.ui.progress($("body"), true);

        for (var i in offers) {
            var offer = offers[i];

            await api.post(`B2B/Offer(${offer.Id})/Accept`)
                .then(async (result) => {
                    kendo.ui.progress($("body"), false);

                    var failure = result.value == "false";

                    if (failure) {
                        notification.error("[resource_displayname[offeracceptancefail]]");
                    } else {
                        notification.success("[resource_displayname[offeraccepted]]");
                    }
                })
                .catch((err) => error(err));
        }

        window.location.reload();
    }
};
"}

