</style>","Script":"PurchaseOrder = {
    states: [script[TransactionStates]],

    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=PurchaseOrder]");
                var meta = [
            {
                "Name": "B2B",
                "Types": [
                    [meta[B2B/PurchaseOrder]],
                    [meta[B2B/PurchaseOrderLine]],
                    [meta[B2B/Company]]
                ]
            }
        ];

        container.addClass("large");

        api.addToMetaCache(meta);
             var children = $(".col > div", container)
            children.css("margin", app.Config.Themes[session.theme].margins);
            children.css("border", app.Config.Themes[session.theme].border.style);
            children.css("box-shadow", app.Config.Themes[session.theme].shadows);
        if (this.id === null) {
            this.id = getQueryParameter("Id");
        }
        var purchaseOrderDetailsInit = [script[PurchaseOrderDetails]];
        var variables = {
            element: $("[name=purchaseOrderDetails", container)
        };
        await purchaseOrderDetailsInit(variables);
        var resources = await api.get("Core/Resource?$filter=AppId eq " + app.Id + " and key eq 'B2B'");
        var details = variables.PurchaseOrderDetails;
        if (!this.backButton) {
            details.toolbar = "";
        }
        details.config.odataAppend = "(" + this.id + ")?$expand=References($expand=RemittanceAdviceLines),AuditTrail,Companies";
        details.init(null, resources.value, function () {
            var purchaseorder = details.data;
            var referenceGridInit = [script[ReferenceGrid]];
            var referenceVariables = {
                element: $("[name=references]", container),
                references: purchaseorder.References
            };
            referenceGridInit(referenceVariables);
            referenceVariables.ReferenceGrid.init();
            var lineGrid = [script[PurchaseOrderLineGrid]];
            var lineVariables = {
                element: $("[name=lines]", container),
                lines: purchaseorder.Lines
            };
            lineGrid(lineVariables);
            lineVariables.PurchaseOrderLineGrid.init();
            var payments = [];
            for(var i = 0; i < purchaseorder.References.length; i = i + 1) {
                for(var j = 0; j < purchaseorder.References[i].RemittanceAdviceLines.length; j = j + 1) {
                    payments.push(purchaseorder.References[i].RemittanceAdviceLines[j]);
                }
            }
            if (payments.length > 0) {
                var relatedPaymentGridInit = [script[RelatedPaymentsGrid]];
                var relatedPaymentGridVariables = {
                    element: $("[name=payments]", container),
                    payments: payments
                };
                relatedPaymentGridInit(relatedPaymentGridVariables);
                relatedPaymentGridVariables.RelatedPaymentsGrid.init();
            }
            else { $("[name=payments]", container).remove(); }
            if (purchaseorder.AuditTrail.length > 0) {
                var historyGrid = [script[HistoryGrid]];
                var variables = {
                    element: $("[name=history]", container),
                    history: purchaseorder.AuditTrail
                };
                historyGrid(variables);
                var h = variables.HistoryGrid;
                h.init(() => {
                    h.kendoObject.dataSource.sort({ field: "CreatedOn", dir: "desc" });
                });
            }
            else { $("[name=history]", container).remove(); }
        });
        var companyInfo = (await api.get("B2B/Company?$filter=References/any(r: r/PurchaseOrderReferences/any(j: j/PurchaseOrderId eq " + this.id + "))&$expand=References,Address")).value;
        var purchaseOrderCompanyInfo = purchaseorder.Companies.map(function (company) {
            var matchedCompanyInfo = companyInfo.filter(ci => ci.References.filter(cir => cir.Id == company.CompanyReferenceId).length > 0)[0];
            company.Name = matchedCompanyInfo.Name;
            company.DebtorReference = matchedCompanyInfo.References.filter(r => r.SystemId !== "GlobalTax").map(r => r.Value).join();
            company.DebtorVATReference = (matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax").length > 0 ? matchedCompanyInfo.References.filter(r => r.SystemId == "GlobalTax")[0].Value : "N/A");
            company.Id = matchedCompanyInfo.Id;
            return company;
        });
        var companyGridInit = [script[CompanyGrid]];
        (await companyGridInit({
            element: $("[name=companyDetails]", container),
            dataSource: purchaseOrderCompanyInfo
        })).init();
    }
