","Script":"RegistrationAdminDetails = {
    companiesGrid: null,
    fundingGrid: null,

    init: async function (app, container, data) {
        app = app || session.app;
        container = container || $(".component[name=RegistrationAdminDetails]")[0];
        data = data || {};

        kendo.unbind($(container));
        api.addToMetaCache([{
            Name: "B2B",
            Types: [
                [meta[B2B/Company]]
            ]
        }]);

        const viewModel = kendo.observable({
            AdminComments: data.AdminComments || "",
            CompanyName: data.CompanyName || "",
            CompanyId: data.CompanyId || "",
            FundingTypeName: "",
            FundingTypeBucketId: data.FundingTypeBucketId || ""
        });

        if (data.CompanyId) {
            try {
                const company = await api.get(`B2B/Company(${data.CompanyId})`);
                viewModel.set("CompanyName", company.Name || "");
            } catch (err) {
                console.error("Error fetching company name:", err);
            }
        }

        if (data.FundingTypeBucketId) {
            try {
                const fundingBucket = await api.get(`B2B/Bucket(${data.FundingTypeBucketId})`);
                viewModel.set("FundingTypeName", fundingBucket.Name || "");
            } catch (err) {
                console.error("Error fetching funding type name:", err);
            }
        }

        kendo.bind($(container), viewModel);
        $(container).data("model", viewModel);

        $("button[name=selectCompany]", container).off("click").on("click", async () => {
            const perspective = data.Perspective;
            await RegistrationAdminDetails.openCompanySelectionDialog(app, container, viewModel, perspective);
        });

        $("button[name=selectFundingType]", container).off("click").on("click", async () => {
            await RegistrationAdminDetails.openFundingSelectionDialog(app, container, viewModel);
        });
    },

    openCompanySelectionDialog: async function (app, container, viewModel, perspective) {
        const dialog = new Dialog({
            title: "[resource_displayname[selectcompany]]",
            width: 800,
            height: 700,
            template: `
                <div name="companiesGridContainer"></div>
                <div class="text-end"> <div class="btn-group btn-group-sm">
                <button class="btn btn-primary mt-2" name="confirmSelect"><span class="k-icon k-i-check"></span>[resource_displayname[select]]</button>
                </div></div>`
        });

        dialog.init(async () => {
            const gridContainer = $('[name=companiesGridContainer]', dialog.element);
            RegistrationAdminDetails.companiesGrid = await RegistrationAdminDetails.initCompaniesGrid(app, gridContainer, perspective);

            $('[name=confirmSelect]', dialog.element).off("click").on("click", async () => {
                const selected = RegistrationAdminDetails.companiesGrid.select();
                if (!selected?.length) { notification.error("[resource_displayname[selectcompanyfirst]]"); return; }
                const selectedItem = selected[0];

                viewModel.set("CompanyId", selectedItem.Id);
                viewModel.set("CompanyName", selectedItem.Name);

                $(container).data("model", viewModel);
                dialog.events.close();
            });
        });
    },

    openFundingSelectionDialog: async function (app, container, viewModel) {
        const dialog = new Dialog({
            title: "[resource_displayname[selectfundingtype]]",
            width: 800,
            height: 360,
            template: `<div name="fundingGridContainer"></div>
                <div class="text-end"> <div class="btn-group btn-group-sm">
                <button class="btn btn-primary mt-2" name="confirmSelect"><span class="k-icon k-i-check"></span>[resource_displayname[select]]</button>
                </div></div>`
        });

        dialog.init(async () => {
            const gridContainer = $('[name=fundingGridContainer]', dialog.element);
            RegistrationAdminDetails.fundingGrid = await RegistrationAdminDetails.initFundingGrid(app, gridContainer);

            $('[name=confirmSelect]', dialog.element).off("click").on("click", async () => {
                const selected = RegistrationAdminDetails.fundingGrid.select();
                if (!selected?.length) { notification.error("[resource_displayname[selectfundingtypefirst]]"); return; }
                const selectedItem = selected[0];

                viewModel.set("FundingTypeBucketId", selectedItem.Id);
                viewModel.set("FundingTypeName", selectedItem.Name);

                $(container).data("model", viewModel);
                dialog.events.close();
            });
        });
    },

    initCompaniesGrid: async function (app, gridContainer, perspective) {
        $(gridContainer).empty();
        const perspectivesMap = { buyer: 'Debtor', supplier: 'Creditor', funder: 'Funder' };
        const filterPerspective = perspectivesMap[perspective];

        const companiesDatasource = await model.getDatasource({
            endpoint: "B2B/Company",
            odataAppend: `?$filter=Buckets/any(b: startsWith(b/Bucket/Path, '${app.TenantId}/') and b/Bucket/Key eq '${filterPerspective}')&$expand=Address,References,Buckets($expand=Bucket)`,
            sort: { field: "Name", dir: "asc" }
        });

        const grid = new GridWidget(gridContainer, companiesDatasource);
        grid.selectable = true;
        grid.editable = false;
        grid.searchable = true;
        grid.groupable = false;
        grid.search = { fields: ['Name'] };
        grid.columns = [
            { selectable: true, width: [theme[columns.checkbox]] },
            { field: "Name", title: "[resource_displayname[name]]" }
        ];

        await grid.init();
        return grid;
    },

    initFundingGrid: async function (app, gridContainer) {
        $(gridContainer).empty();

        const res = await api.get(`B2B/Bucket?$filter=Key eq 'FundingType' and startsWith(Path, '${app.TenantId}/')&$format=json&$top=50`);
        const items = (res && res.value) || [];

        const fundingDataSource = new kendo.data.DataSource({
            data: items,
            sort: { field: "Name", dir: "asc" }
        });

        const grid = new GridWidget(gridContainer, fundingDataSource);
        grid.selectable = true;
        grid.editable = false;
        grid.searchable = true;
        grid.groupable = false;
        grid.search = { fields: ['Name'] };
        grid.columns = [
            { selectable: true, width: [theme[columns.checkbox]] },
            { field: "Name", title: "[resource_displayname[name]]" }
        ];

        await grid.init();
        return grid;
    }
};
