</script>","Script":"RejectedRequests = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=RejectedRequests]");

        var data = (await api.get(`B2B/AccessRequest?$filter=Status eq 'denied' and TenantId eq '${app.TenantId}'`)).value;

        var dataSource = new kendo.data.DataSource({
            data: data,
            pageSize: 20,
            schema: { model: { id: "Id" } }
        });

        var grid = new GridWidget($("[name=rejectedRequestsGrid]", container), dataSource);

        grid.columns = [
            { field: "UserEmailAddress", type: "string", title: "[resource_shortdisplayname[userEmail]]" },
            { field: "CompanyName", type: "string", title: "[resource_shortdisplayname[companyName]]" },
            { field: "Perspective", title: "[resource_shortdisplayname[perspective]]" },
            { field: "CreatedOn", type: "date", title: "[resource_shortdisplayname[requestDate]]", format: "{0:" + type.dateFormat + "}" },
            { field: "AdminComments", title: "[resource_shortdisplayname[admincomment]]" }
        ];

        grid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });

        grid.editable = false;
        grid.sortable = true;
        grid.filterable = true;
        grid.groupable = false;
        grid.pageable = { refresh: true, pageSizes: [10, 20, 50, 100], numeric: true };

        grid.detailTemplate = kendo.template($("[name=rejectedRequestDetailTemplate]").html());

        grid.detailExpand = function (e) {
            var detailRow = $(e.detailRow);
            if (detailRow.data("initialized")) return;
            detailRow.data("initialized", true);

            var dataItem = grid.kendoObject.dataItem(e.masterRow);

            var loadDetail = (selector, componentName) => {
                loadComponent($(selector, detailRow), componentName, c => {
                    c.init(app, $(selector, detailRow), dataItem);
                    $(selector, detailRow).data("model", $(selector, detailRow).find(":first").data("kendoBindingTarget"));
                    $(selector, detailRow).find("input, select, textarea, button").prop("disabled", true);
                });
            };

            loadDetail(".component[name=PersonalDetailsContainer]", "RegistrationPersonalDetails");
            loadDetail(".component[name=CompanyDetailsContainer]", "RegistrationCompanyDetails");
            loadDetail(".component[name=AdminDetailsContainer]", "RegistrationAdminDetails");
        };

        grid.dataBound = function () {
            $("button[name=delete]", grid.gridElement).off("click").on("click", e => RejectedRequests.destroy(e, grid));
        };

        await grid.init();
    },

    destroy: function (e, grid) {
        e.preventDefault();
        var d = new ConfirmDialog({
            title: "[resource_displayname[deleterequest]]",
            question: "[resource_displayname[doyouwantodeletetherequest]]",
            confirm: `<span class='k-icon k-i-trash'></span>[resource_displayname[delete]]`,
        });

        d.events.confirm = async function () {
            var request = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
            await api.destroy(`B2B/AccessRequest(${request.Id})`);
            notification.success("[resource_displayname[accessrequestdeleted]]");

            grid.kendoObject.dataSource.remove(request);

            d.events.close();
        };

        d.init();
    }
};
