<div name="resourceMigrationComponent" style="display: none;"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Content Management","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"ResourceManagement","ResourceKey":"CMS","Script":"ResourceManagement = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=Resourcing]");
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/Resource]]
				]
			}]);
		var config = {
			endpoint: "Core/Resource",
			odataAppend: "?$filter=AppId eq " + app.Id + " and Culture eq ''",
			group: { field: "Key" }
		};
		let cultures = await api.get("Core/Culture");
		let resourceDataSource = await model.getDatasource(config);
		let typeInfo = await api.getType("Core/Resource");
		await ResourceManagement.setupGrid(app, container, resourceDataSource, cultures, typeInfo);

		await loadComponent($('[name=resourceMigrationComponent]', container), 'ResourceMigration', async (c) => {
			await c.init(app, $('[name=ResourceMigration]', container));
		});
	},

	setupGrid: async function (app, container, resourceDataSource, cultures, typeInfo) {
		var grid = new GridWidget(container, resourceDataSource);
		grid.toolbar = [
			{
				template: "<div class='btn-group btn-group-sm'> \
	<button class='btn btn-primary' name='create'> \
		<span class='k-icon k-i-plus'></span>[resource_displayname[new]] \
	</button> \
	<button class='btn btn-primary' name='migrate'> \
		<span class='k-icon k-i-arrow-up'></span>[resource_displayname[migrate]] \
	</button> \
</div>"
			}
		];
		grid.filterable = true;
		grid.searchable = true;
		grid.search = {
			fields: ["Key", "Name", "DisplayName", "ShortDisplayName", "Description", "LastUpdatedBy"]
		};

		grid.columns = [
			{
				field: "Key",
				editable: false,
				title: "[resource_shortdisplayname[key]]",
				width: "[theme[columns.small]]"
			},
			{
				field: "Name",
				editable: false,
				title: "[resource_shortdisplayname[name]]"
			},
			{
				field: "DisplayName",
				title: "[resource_shortdisplayname[displayname]]",
				template: "#=(DisplayName && DisplayName.length > 80) ? ResourceManagement.escapeHtml(DisplayName.substring(0, 80)) + '...' : ResourceManagement.escapeHtml(DisplayName)#",
				encoded: true
			},
			{
				field: "ShortDisplayName",
				title: "[resource_shortdisplayname[shortdisplayname]]",
				template: "#=(ShortDisplayName && ShortDisplayName.length > 80) ? ResourceManagement.escapeHtml(ShortDisplayName.substring(0, 80)) + '...' : ResourceManagement.escapeHtml(ShortDisplayName)#",
				encoded: true,
				width: "[theme[columns.small]]"
			},
			{
				field: "Description",
				title: "[resource_shortdisplayname[description]]",
				template: "#=(Description && Description.length > 80) ? ResourceManagement.escapeHtml(Description.substring(0, 80)) + '...' : ResourceManagement.escapeHtml(Description)#",
				encoded: true
			},
			{
				field: "LastUpdated",
				title: "[resource_displayname[lastupdated]]",
				type: "date",
				format: "{0: " + type.dateFormat + " HH:mm}",
				width: "[theme[columns.small]]"
			},
			{
				field: "LastUpdatedBy",
				title: "[resource_displayname[lastupdated]]",
				width: "[theme[columns.small]]"
			}
		];

		grid.commands.push({ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" });
		grid.commands.push({ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" });
		grid.detailTemplate = "<div name='translations'></div>";
		grid.detailExpand = (e) => ResourceManagement.expandResource(e, app, grid, cultures.value, typeInfo);

		grid.dataBound = () => {
			$("button[name=save]", grid.gridElement).on("click", (e) => ResourceManagement.save(e, grid));
			$("button[name=delete]", grid.gridElement).on("click", (e) => ResourceManagement.destroy(e, grid));
		};

		await grid.init();
		$("button[name=migrate]", grid.gridElement).on("click", (e) => ResourceManagement.migrate(app));
		$("button[name=create]", grid.gridElement).on("click", (e) => ResourceManagement.newResource(e, app, grid));
		$("input[name='searchResourcing']", grid.gridElement).off("keyup").keyup(ResourceManagement.delay((e) => ResourceManagement.search(e, grid, container, app, typeInfo), 500));
	},

	delay: function (callback, ms) {
		var timer = 0;
		return function () {
			var context = this, args = arguments;
			clearTimeout(timer);
			timer = setTimeout(function () {
				callback.apply(context, args);
			}, ms || 0);
		};
	},

	search: async function (grid, app, typeInfo) {
		var searchTerm = $("input[name='searchResourcing']", grid.gridElement).val();
		let data = await api.get("Core/Resource?$filter=AppId eq " + app.Id + " and Culture eq '' and (contains(Name, '" + searchTerm + "') or contains(DisplayName, '" + searchTerm + "') or contains(Description, '" + searchTerm + "') or contains(ShortDisplayName, '" + searchTerm + "') or contains(Key, '" + searchTerm + "'))");
		$.each(data.value, function (idx, item) {
			model.prepareItem(item, typeInfo);
		});
		grid.dataSource().data(data.value);
		grid.refresh();
	},

	expandResource: async function (e, app, grid, cultures, typeInfo) {
		var resource = grid.dataItem(e.masterRow);
		var container = $(e.detailRow);
		if ($("[name=translationsGrid]", container).length === 0) {
			await ResourceManagement.setupTranslationsGrid(app, $("[name=translations]", container), resource, cultures, typeInfo);
		}
	},

	escapeHtml: function (html) {
		return html.replaceAll('&', '&amp;').replaceAll('<', '&lt;').replaceAll('>', '&gt;').replaceAll('"', '&quot;').replaceAll("'", '&#039;');
	},

	setupTranslationsGrid: async function (app, container, resource, cultures, typeInfo) {
		var config = {
			endpoint: "Core/Resource",
			odataAppend: "?$filter=AppId eq " + app.Id + " and Key eq '" + resource.Key + "' and Name eq '" + resource.Name + "' and Culture ne ''",
		};

		let datasource = await model.getDatasource(config);

		var translationsGrid = new GridWidget(container, datasource);
		translationsGrid.groupable = false;
		translationsGrid.pageable = false;
		translationsGrid.filterable = false;
		translationsGrid.toolbar = kendo.template("<div class='btn-group btn-group-sm'> \
	<button class='btn btn-primary' name='createTranslation'> \
		<span class='k-icon k-i-plus'></span>[resource_displayname[newtranslation]] \
	</button> \
</div>");
		translationsGrid.columns = [
			{ field: "Culture", editable: false, title: "[resource_shortdisplayname[culture]]" },
			{ field: "DisplayName", title: "[resource_shortdisplayname[displayname]]", template: "#=(DisplayName && DisplayName.length > 80) ? ResourceManagement.escapeHtml(DisplayName.substring(0, 80)) + '...' : ResourceManagement.escapeHtml(DisplayName)#", encoded: true },
			{ field: "ShortDisplayName", title: "[resource_shortdisplayname[shortdisplayname]]", template: "#=(ShortDisplayName && ShortDisplayName.length > 80) ? ResourceManagement.escapeHtml(ShortDisplayName.substring(0, 80)) + '...' : ResourceManagement.escapeHtml(ShortDisplayName)#", encoded: true },
			{ field: "Description", title: "[resource_shortdisplayname[description]]", template: "#=(Description && Description.length > 80) ? ResourceManagement.escapeHtml(Description.substring(0, 80)) + '...' : ResourceManagement.escapeHtml(Description)#", encoded: true },
			{ field: "LastUpdated", title: "[resource_displayname[lastupdated]]", type: "date", format: "{0: " + type.dateFormat + " HH:mm}" },
			{ field: "LastUpdatedBy", title: "[resource_displayname[lastupdatedby]]" },
		];
		translationsGrid.commands.push({
			name: "save",
			icon: "k-i-save",
			text: "[resource_displayname[save]]"
		});
		translationsGrid.commands.push({
			name: "delete",
			icon: "k-i-trash",
			text: "[resource_displayname[delete]]"
		});
		translationsGrid.dataBound = function () {
			$("button[name=save]", translationsGrid.gridElement).on("click", (e) => ResourceManagement.save(e, translationsGrid));
			$("button[name=delete]", translationsGrid.gridElement).on("click", (e) => ResourceManagement.destroy(e, translationsGrid));
		};
		await translationsGrid.init();
		$("button[name=createTranslation]", translationsGrid.gridElement).on("click", (e) => ResourceManagement.createTranslation(e, app, resource, translationsGrid, cultures, typeInfo));
	},
	createTranslation: async function (e, app, resource, translationsGrid, cultures, typeInfo) {
		e.preventDefault();

		var options = cultures.filter(c =>
			c.Id !== '' &&
			translationsGrid.dataSource().data().filter(r => r.Culture === c.Id).length === 0
		);

		var d = new Dialog({
			title: "[resource_displayname[newtranslation]]",
			width: 450
		});

		d.template = $("[name=newTranslationDialog]").html();

		d.events.create = async function (e) {
			e.preventDefault();

			var newTranslation = {
				Id: 0,
				AppId: app.Id,
				Culture: $("select[name=culture]", d.element).val(),
				Key: resource.Key,
				Name: resource.Name,
				DisplayName: $("input[name=DisplayName]", d.element).val(),
				ShortDisplayName: $("input[name=ShortDisplayName]", d.element).val(),
				Description: $("input[name=Description]", d.element).val()
			};

			await api.add("Core/Resource", newTranslation)
				.then(r => {
					notification.success("[resource_displayname[translationcreated]]".replace("[culture]", r.Culture));
					model.prepareItem(r, typeInfo);
					translationsGrid.refresh();
					d.events.close();
				})
				.catch(err => error(err));
		};

		d.init(() => {
			$("select[name=culture]", d.element).kendoDropDownList({
				dataTextField: "Name",
				dataValueField: "Id",
				dataSource: options,
				index: 0
			});

			$("[name=create]", d.element)
				.off("click")
				.on("click", d.events.create);
		});
	},


	getCultureFromUser: function (options, callback) {
		var culture = null;
		var d = new Dialog({
			width: 600,
			title: "[resource_displayname[newtranslation]]"
		});
		d.template = $("script[name=newTranslation]").html();
		d.events.confirm = function () {
			callback(culture.val());
			d.events.close();
		};
		d.init(() => {
			culture = $("[name=culture]", d.element)
				.kendoDropDownList({
					dataTextField: "Name",
					dataValueField: "Id",
					dataSource: options,
					index: 0
				});
		});
	},

	migrate: function (app) {
		var d = new Dialog({
			width: 1100,
			height: 'auto',
			title: "[resource_displayname[migrate]]"
		});
		d.template = $("[name=resourceMigrationComponent]").first().html();
		d.init(() => ResourceMigration.initDropdown($(".component[name=ResourceMigration]", d.element)));
	},


	newResource: async function (e, app, grid) {
		e.preventDefault();

		var newResource = {
			Id: 0,
			AppId: app.Id,
			Culture: "",
			Key: "",
			Name: "",
			DisplayName: "",
			ShortDisplayName: "",
			Description: ""
		};

		var d = new Dialog({
			title: "[resource_displayname[newresource]]",
			width: 510
		});

		d.template = $("[name=newResourceDialog]").html();

		d.events.create = async function (e) {
			e.preventDefault();

			newResource.Key = $("input[name=Key]", d.element).val();
			newResource.Name = $("input[name=Name]", d.element).val();
			newResource.DisplayName = $("input[name=DisplayName]", d.element).val();
			newResource.ShortDisplayName = $("input[name=ShortDisplayName]", d.element).val();
			newResource.Description = $("input[name=Description]", d.element).val();

			await api.add("Core/Resource", newResource)
				.then(() => {
					notification.success("[resource_displayname[resourcecreated]]");
					d.events.close();
					grid.refresh();
				})
				.catch(err => error(err));
		};

		d.init(() => {
			$("[name=create]", d.element).off("click").on("click", d.events.create);
		});
	},

	save: async function (e, grid) {
		e.preventDefault();

		var resource = grid.dataItem($(e.currentTarget).closest("tr"));

		let originalResource = await api.get("Core/Resource(" + resource.Id + ")");
		if (!originalResource) {
			console.error("Original resource not found.");
			return;
		}

		var oldKey = originalResource.Key;
		var oldName = originalResource.Name;

		try {
			await resource.save();
			notification.success("[resource_displayname[saved]]");
		} catch (err) {
			console.error("Error saving resource:", err);
			return;
		}

		let translations = await api.get("Core/Resource?$filter=AppId eq " + resource.AppId + " and Key eq '" + oldKey + "' and Name eq '" + oldName + "' and Culture ne ''");

		if (translations && translations.value && translations.value.length > 0) {
			for (let translation of translations.value) {
				translation.Key = resource.Key;
				translation.Name = resource.Name;

				try {

					await api.put(`Core/Resource(${translation.Id})`, translation);
				} catch (err) {
					console.error("Error updating translation:", err);
				}
			}

			await grid.refresh();
		} else {
			console.log("No translations found for this resource.");
		}
	},

	destroy: function (e, grid) {
		e.preventDefault();
		var resource = grid.dataItem($(e.currentTarget).closest("tr"));
		var d = new ConfirmDialog({
			title: "[resource_displayname[areyousure]]",
			question: "[resource_displayname[thiscannotbeundone]]",
			confirm: "[resource_displayname[confirm]]",
			close: "[resource_displayname[close]]"
		});
		d.events.confirm = async function () {
			d.events.close();
			await api.destroy("Core/Resource(" + resource.Id + ")").then(async () => {
				notification.success("[resource_displayname[resourcedeleted]]");
				grid.refresh();
			}).catch((err) => error(err));
		};
		d.init();
	}
};"}

