<div name="rolePrivManagementComponent" style="display:none;"></div>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Account Management","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"RoleManagement","ResourceKey":"Account","Script":"RoleManagement = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=RoleManagement]");

		api.addToMetaCache([
			{
				Name: "Core",
				Types: [
					[meta[Core/Role]]
				]
			}
		]);

		await RoleManagement.setupRoleGrid(app, container);
	},

	setupRoleGrid: async function (app, container) {
		var config = {
			endpoint: "Core/Role",
			odataAppend: "?$filter=AppId eq " + app.Id,
			sort: { field: "Name", dir: "asc" }
		};

		var ds = await model.getDatasource(config);
		var roleGrid = new GridWidget(container, ds);

		roleGrid.groupable = false;
		roleGrid.pageable = false;

		roleGrid.toolbar = [
			{
				template: `
					<div class="btn-group btn-group-sm">
						<button class="btn btn-primary" name="createRole">
							<span class="k-icon k-i-plus"></span>[resource_displayname[NewRole]]
						</button>
					</div>
				`
			}
		];

		roleGrid.columns = [
			{ field: "Name", title: "[resource_shortdisplayname[Name]]" }
		];

		roleGrid.commands.push(
			{ name: "save", icon: "k-i-save", text: "[resource_displayname[save]]" },
			{ name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]" }
		);

		roleGrid.detailTemplate = $("[name=roleDetails]").html();

		roleGrid.detailExpand = function (e) {
			RoleManagement.expandRole(e, app, roleGrid);
		};

		roleGrid.dataBound = function () {
			$("button[name=save]", roleGrid.gridElement)
				.off("click")
				.on("click", async (e) => await RoleManagement.save(e, roleGrid));

			$("button[name=delete]", roleGrid.gridElement)
				.off("click")
				.on("click", async (e) => await RoleManagement.destroy(e, roleGrid));
		};

		await roleGrid.init();

		$("button[name=createRole]", roleGrid.gridElement)
			.off("click")
			.on("click", () => RoleManagement.createRole(app, roleGrid));

		await loadComponent($('[name=roleUserManagementComponent]', container), 'RoleUserManagement');
		await loadComponent($('[name=rolePrivManagementComponent]', container), 'RolePrivManagement');
	},

	save: async function (e, grid) {
		e.preventDefault();
		var role = grid.dataItem($(e.currentTarget).closest("tr"));

		await role.save()
			.then(() => notification.success("[resource_displayname[RoleSaved]]"))
			.catch(err => error(err));
	},

	destroy: async function (e, grid) {
		e.preventDefault();
		var row = $(e.currentTarget).closest("tr");
		var role = grid.dataItem(row);

		grid.dataSource().remove(role);

		await api.destroy("Core/Role(" + role.Id + ")")
			.then(() => notification.success("[resource_displayname[roledeleted]]"))
			.catch(err => error(err));
	},

	expandRole: async function (e, app, grid) {
		var role = grid.dataItem(e.masterRow);
		var container = $(e.detailRow);

		var replaced = container.html().replaceAll("{ID}", Guid());
		container.html(replaced);

		if ($(".component", container).length === 0) {
			$("[name=userGrid]", container).html($("[name=RoleUserManagement]").first().html());
			$("[name=privGrid]", container).html($("[name=RolePrivManagement]").first().html());

			RoleUserManagement.init(app, $("[name=userGrid]", container), role);
			RolePrivManagement.init(app, $("[name=privGrid]", container), role);
		}
	},

	createRole: function (app, grid) {
		var newRole = {
			AppId: app.Id,
			Name: "",
			Privs: ""
		};

		var addRoleDialog = new Dialog({
			title: "[resource_displayname[newRole]]",
			width: 450
		});

		addRoleDialog.template = $("[name=addRoleDialog]").html();

		addRoleDialog.events.confirm = async function () {
			newRole.Name = $("[data-bind='value: Name']", addRoleDialog.element).val();

			await api.add("Core/Role", newRole)
				.then(() => {
					notification.success("[resource_displayname[RoleCreated]]");
					grid.refresh();
					addRoleDialog.events.close();
				})
				.catch(err => error(err));
		};

		addRoleDialog.init();
	}
};
"}

{"Name":"RolePrivManagement","ResourceKey":"Account","Content":"<style scoped>
    .component[name=RolePrivManagement] {max-height: 800px !important; }
    .k-grid-content k-auto-scrollable {max-height: 800px; }
    div[name=privs].k-tabstrip-content {overflow-x: hidden !important; }
    </style>","Script":"RolePrivManagement = {
    init: async function(app, container, role) {
        app = app || session.app;
        container = container || $(".component[name=RolePrivManagement]");
        container.addClass("large");
        if(!role) { return; }
        var privs = (await api.get("Core/Privilege")).value;
        privs.forEach(p => p.Has = (role.Privileges.indexOf(p.Id) !== -1));
        var rolePrivGrid = new GridWidget(container, {data: privs});
        rolePrivGrid.columns=[
            {field: "Has", title: " ", template: "<input class='k-select-checkbox k-checkbox k-checkbox-md k-rounded-md' type='checkbox' #= (Has == true) ? checked ='checked' : '' # class='chkbx k-checkbox'/>", width: 40},
            {field: "Type", title: "[resource_displayname[Type]]" },
            {field: "Operation", title: "[resource_displayname[Operation]]"},
            {field: "Description", title: "[resource_displayname[PrivExplanation]]"}
        ];
        rolePrivGrid.groupable = false;
        rolePrivGrid.editable = false;
        rolePrivGrid.filterable = false;
        rolePrivGrid.pageable = false;
        rolePrivGrid.sortable = false;
        rolePrivGrid.dataBound = function() {
            $("input[type=checkbox]", rolePrivGrid.gridElement).off("click").on("click", async function(e) {
                e.preventDefault();
                var dataItem = rolePrivGrid.dataItem($(e.target).closest("tr"));
                dataItem.set("Has", this.checked);
                role.Privileges = rolePrivGrid.dataSource().data().filter(p => p.Has).map(p => p.Id);
                await role.save().then(() => { notification.success("[resource_displayname[rolesaved]]"); })
                .catch((err) => { error(err); });
            });
        };
        await rolePrivGrid.init();
        rolePrivGrid.dataSource().group({field: "Type"});
    }
}","CreatedOn":"2021-08-25T16:52:03.690Z","LastUpdated":"2021-08-25T16:52:03.690Z","Key":"Account Management"}

