        });
        userDialog.template = $("[name=selectusersdialog]").first().html();
        userDialog.events.select = async function(e) {
            e.preventDefault();
			var selected = userGrid.select();
            for(let i = 0; i < selected.length; i++) {
				await api.post("Core/UserRole", {
                    RoleId: role.Id,
                    UserId: selected[i].Id
                }).then(() => {
            notification.success("[resource_displayname[useradded]]");
					grid.refresh();
				}).catch((e) => error(e));
			}
			userDialog.events.close();
        };
        userDialog.init(async () => {
            var userData = await model.getDatasource({
                endpoint: "Core/User",
                odataAppend: "?$filter=IsActive eq true",
                pageSize: 10
            });
            userGrid = new GridWidget($("[name=selectUsersGrid]", userDialog.element), userData);
			userGrid.filterable = true;
			userGrid.groupable = false;
            userGrid.pageable = true;
            userGrid.editable = false;
            userGrid.columns = [
                {selectable: true, width: 50},
                { field: "Id", title: "[resource_displayname[userid]]" },
                { field: "DisplayName", title: "[resource_displayname[displayname]]" },
                { field: "Email", title: "[resource_displayname[email]]" }
            ];
            userGrid.init();
        });
    },

    deleteUser: async function(roleUser, usersGrid) {
        await api.destroy("Core/UserRole(RoleId=" + roleUser.RoleId + ",UserId='" + roleUser.UserId + "')").then(() => {
            notification.success("[resource_displayname[userdeleted]]");
            usersGrid.refresh();
        }).catch((err) => error(err));
    },

    addUser: async function (e, role, grid) {
        e.preventDefault();
        var model = kendo.observable({
            RoleId: role.Id,
            UserId: ""
        });
        var addUserDialog = new Dialog({
            title: "[resource_displayname[adduser]]",
            width: 500
        });
        addUserDialog.template = $("[name=addUserDialog]").html();
        addUserDialog.events.confirm = async function (e) {
            await api.add("Core/UserRole", model).then(() => {
                notification.success("[resource_displayname[useradded]]");
                if (role.Users) { role.Users.push({ RoleId: role.Id, UserId:  model.UserId }); }
                addUserDialog.events.close();
                grid.refresh();
            }).catch((err) => error(err));
        };
        addUserDialog.init();
        kendo.bind(addUserDialog.element, model);
    }
}"}

