    </style>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Content Management","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"Scheduling","ResourceKey":"CMS","Script":"Scheduling = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".container[name=Scheduling]");
		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/ScheduledTask]],
					[meta[Core/FlowDefinition]],
					[meta[Core/User]]
				]
			}
		]);
		var scheduledTasks = await model.getDatasource({
			endpoint: "Core/ScheduledTask",
			odataAppend: `?$filter=AppId eq ${app.Id}&$expand=Flow`,
			sort: {
				field: "Name",
				dir: "asc"
			}
		});
		var flowDefinitions = await model.getDatasource({
			endpoint: "Core/FlowDefinition",
			odataAppend: `?$filter=AppId eq ${app.Id}&$orderBy=Name asc`
		});
		var users = await model.getDatasource({
			endpoint: "Core/User",
			odataAppend: `?$filter=Roles/any(r: r/Role/AppId eq ${app.Id})`,
			pageSize: 1000
		});

		await Scheduling.initGrid(app, container, scheduledTasks, flowDefinitions, users);

		await loadComponent($('[name=flowInstanceManagementComponent]', container), 'FlowInstanceManagement');
	},

	secondInTicks: 10000000,

	ticksToFriendly: function (value) {
		if (value === 0) { return "[resource_displayname[notimeperiod]]" }
		var seconds = value / Scheduling.secondInTicks;
		var days = Math.floor((seconds % 31536000) / 86400);
		var hours = Math.floor(((seconds % 31536000) % 86400) / 3600);
		var minutes = Math.floor((((seconds % 31536000) % 86400) % 3600) / 60);
		var seconds = (((seconds % 31536000) % 86400) % 3600) % 60;
		var string = "";

		if (days > 1)
			string += days + " [resource_displayname[days]] ";
		else if (days === 1)
			string += days + " [resource_displayname[day]] ";

		if (hours > 1)
			string += hours + " [resource_displayname[hours]] ";
		else if (hours === 1)
			string += hours + " [resource_displayname[hour]] ";

		if (minutes > 1)
			string += minutes + " [resource_displayname[minutes]] ";
		else if (minutes === 1)
			string += minutes + " [resource_displayname[minute]] ";

		if (seconds > 1)
			string += seconds + " [resource_displayname[seconds]] ";
		else if (seconds === 1)
			string += seconds + " [resource_displayname[second]] ";

		return string;
	},

	initGrid: async function (app, container, scheduledTasks, flowDefinitions, users) {
		var grid = new GridWidget(container, scheduledTasks);
		grid.groupable = false;
		grid.toolbar = [
			{
				template: `<div class='btn-group btn-group-sm'>
					<button class='btn btn-primary' name='create'>
						<span class='k-icon k-i-plus'></span>[resource_displayname[new]]
					</button>
				</div>`
			}
		];
		grid.columns = [
			{ field: "Name", title: "[resource_shortdisplayname[Name]]" },
			{ field: "Description", title: "[resource_shortdisplayname[Description]]" },
			{
				field: "FlowId",
				title: "[resource_shortdisplayname[Flow]]",
				template: "#=Flow.Name#",
				editor: function (container, options) {
					$('<input required name="' + options.field + '"/>')
						.appendTo(container)
						.kendoDropDownList({ autoBind: false, dataTextField: "Name", dataValueField: "Id", dataSource: flowDefinitions });
				}
			},
			{
				field: "LastExecuted",
				title: "[resource_shortdisplayname[lastexecuted]]",
				type: "date",
				format: "{0:" + type.dateFormat + " HH:mm}",
				width: "[theme[columns.small]]",
				editable: () => false
			},
			{
				field: "NextExecution",
				title: "[resource_shortdisplayname[nextexecution]]",
				type: "date",
				format: "{0:" + type.dateFormat + " HH:mm}",
				width: "[theme[columns.small]]",
				editor: function (container, options) {
					$('<input required name="' + options.field + '"/>')
						.appendTo(container)
						.kendoDateTimePicker({
							autoBind: false,
							value: new Date(),
							dateInput: true,
							format: type.dateFormat + " HH:mm"
						});
				}
			},
		];

		grid.commands.push({ name: "execute", text: "[resource_displayname[execute]]", icon: "k-i-play-sm" });
		grid.commands.push({ name: "delete", text: "[resource_displayname[delete]]", icon: "k-i-trash" });

		grid.dataBound = function () {
			$("button[name=delete]", grid.gridElement).on("click", (e) => Scheduling.destroy(e, grid));
			$("button[name=execute]", grid.gridElement).on("click", async (e) => await Scheduling.execute(e, grid));
		};

		grid.detailTemplate = `<div class="scheduled-task-detail-grid"></div>`;
		grid.detailExpand = async (e) => {
			var item = grid.dataItem($(e.masterRow));
			var detailRow = $("div", e.detailRow);
			var uid = item.uid;

			var draft = {
				ScheduleInTicks: item.ScheduleInTicks,
				NextExecution: item.NextExecution,
				ExecuteAs: item.ExecuteAs,
				ExecutionArgs: item.ExecutionArgs
			};

			var html = $("script[name=scheduledTaskTabs]")
				.html()
				.replace(/{UID}/g, uid);

			detailRow.html(html);

			detailRow.find('.nav-tabs button').each(function () {
				new bootstrap.Tab(this);
			});

			bootstrap.Tab.getOrCreateInstance(
				detailRow.find('.nav-tabs button:first')[0]
			).show();

			var flowTab = detailRow.find('[name=FlowInstanceManagement]');

			setTimeout(() => {
				FlowInstanceManagement.init(
					session.app,
					flowTab,
					item.FlowId,
					item.Flow?.InstanceReportingComponentName
				);
			}, 0);

			var detailsTab = detailRow.find(`#taskDetailsTab-${uid}`);
			var formHtml = $("script[name=scheduledTaskDetailForm]").html();

			detailsTab.find(".nested-grid-container").html(formHtml);

			var form = detailsTab.find(".scheduled-task-form");

			form.find("[name=ScheduleInTicks]").kendoSlider({
				min: 0,
				max: 86400 * Scheduling.secondInTicks * 14,
				smallStep: Scheduling.secondInTicks * 3600,
				largeStep: Scheduling.secondInTicks * 3600 * 24,
				value: draft.ScheduleInTicks || 0,
				tickPlacement: "none",
				tooltip: { template: "#=Scheduling.ticksToFriendly(value)#" },
				change: (e) => {
					draft.ScheduleInTicks = e.value;
					form.find("[name=schedulePreview]").text(Scheduling.ticksToFriendly(e.value));
				}
			});

			form.find("[name=schedulePreview]")
				.text(Scheduling.ticksToFriendly(draft.ScheduleInTicks));

			form.find("[name=NextExecution]").kendoDateTimePicker({
				value: draft.NextExecution,
				dateInput: true,
				format: type.dateFormat + " HH:mm",
				change: (e) => draft.NextExecution = e.sender.value()
			});

			form.find("[name=ExecuteAs]").kendoDropDownList({
				autoBind: false,
				dataTextField: "Id",
				dataValueField: "Id",
				dataSource: users,
				value: draft.ExecuteAs,
				change: (e) => draft.ExecuteAs = e.sender.value()
			});

			var argsEditor = new MonacoEditor(
				form.find("[name=ExecutionArgs]")[0],
				{
					code: draft.ExecutionArgs,
					language: "json",
					automaticLayout: true
				}
			);

			argsEditor.onChange = () => {
				draft.ExecutionArgs = argsEditor.getValue();
			};

			argsEditor.init();


			form.find("button[name=saveDetail]").on("click", async () => {

				item.set("ScheduleInTicks", draft.ScheduleInTicks);
				item.set("NextExecution", draft.NextExecution);
				item.set("ExecuteAs", draft.ExecuteAs);
				item.ExecutionArgs = draft.ExecutionArgs;

				var payload = {
					Id: item.Id,
					AppId: item.AppId,
					Name: item.Name,
					Description: item.Description,
					FlowId: item.FlowId,
					ExecuteAs: item.ExecuteAs,
					NextExecution: item.NextExecution,
					ExecutionArgs: item.ExecutionArgs,
					ScheduleInTicks: item.ScheduleInTicks
				};

				try {
					await api.put(`Core/ScheduledTask(${item.Id})`, payload);
					notification.success("[resource_displayname[saved]]");

				} catch (err) {
					error(err);
				}
			});
		};



		await grid.init();
		$("button[name=create]", grid.gridElement).on("click", () => Scheduling.newScheduledTask(app, grid, flowDefinitions));
	},

	editArgs: async function (e, grid) {
		e.preventDefault();
		var task = grid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
		var argsEditor = null;
		var d = new Dialog({
			title: "[resource_displayname[editArgs]]",
			width: 800
		});
		d.template = $("script[name=editArgs]").html();
		d.events.save = async function (e) {
			task.save(e, function () { notification.success("[resource_displayname[ScheduledTaskSaved]]"); d.events.close(); });
		};
		d.init(() => {
			argsEditor = new MonacoEditor($("[name=executionArgs]", d.element)[0], { code: task.ExecutionArgs, language: "json", automaticLayout: true });
			argsEditor.onChange = (e) => task.ExecutionArgs = argsEditor.getValue();
			argsEditor.init();
			argsEditor.editor.layout();
		});
	},

	newScheduledTask: async function (app, grid, flowDefinitions) {
		var d = new Dialog({ title: "[resource_displayname[newscheduledtask]]", width: 620, height: 660 });
		d.template = $("[name=newScheduledTask]").html();
		var appRoles = (await api.get("Core/Role?$expand=Users&$filter=AppId eq " + app.Id)).value;
		var userIds = appRoles.map(r => r.Users).flat().map(r => r.UserId);
		var argsEditor = null;
		d.events.create = async function (e) {
			var newScheduledTask = {
				Name: $("[name=name]", d.element).val(),
				Description: $("[name=description]", d.element).val(),
				FlowId: $("[name=flowDefinition]", d.element).val(),
				AppId: app.Id,
				ExecuteAs: $("[name=executeas]", d.element).val(),
				NextExecution: (new Date($("[name=nextexecution]", d.element).val())).toISOString(),
				ExecutionArgs: argsEditor.getValue(),
				ScheduleInTicks: parseInt($("[name=scheduleInTicks]", d.element).val()) || 0
			};
			d.events.close();
			await api.add("Core/ScheduledTask", newScheduledTask).then(() => {
				notification.success("[resource_displayname[schedulecreated]]");
				grid.refresh();
			}).catch((err) => error(err));
		};

		d.init(async () => {
			$("[name=scheduleInTicks]", d.element).kendoSlider({
				min: 0,
				max: 86400 * Scheduling.secondInTicks * 14, // 0 to 14 days
				smallStep: Scheduling.secondInTicks * 3600, // 1 hour
				largeStep: Scheduling.secondInTicks * 3600 * 24, // 1 day
				tooltip: {
					template: "#=Scheduling.ticksToFriendly(value)#"
				}
			});

			$("[name=flowDefinition]", d.element).kendoDropDownList({ dataTextField: "Name", dataValueField: "Id", dataSource: flowDefinitions });
			$("[name=nextexecution]", d.element).kendoDateTimePicker({ value: new Date(), dateInput: true });
			$("[name=executeas]").kendoDropDownList({
				dataSource: { data: userIds }
			});
			argsEditor = new MonacoEditor($("[name=executionArgs]", d.element)[0], { code: "", language: "json", automaticLayout: true });
			argsEditor.init();
			grid.refresh();
		});
	},

	execute: async function (e, grid) {
		e.preventDefault();
		var task = grid.dataItem($(e.currentTarget).closest("tr"));
		await api.post("Core/ScheduledTask(" + task.Id + ")/Execute?incrementNextExecution=false").then(() => {
			notification.success("[resource_displayname[executed]]");
		}).catch((err) => error(err));
	},

	saveChild: async function (e, nestedGrid, parentGrid) {
		e && e.preventDefault();

		var kendoGrid = nestedGrid.kendoObject || nestedGrid.grid;
		if (!kendoGrid) return;

		var row = $(e.currentTarget).closest("tr");
		var childItem = kendoGrid.dataItem(row);
		if (!childItem) return;

		row.find("input, select, textarea").each(function () {
			var field = $(this).attr("name");
			if (!field) return;

			let value = $(this).data("kendoDropDownList")?.value()
				|| $(this).data("kendoDateTimePicker")?.value()
				|| $(this).val();

			if (field === "ScheduleInTicks") value = parseInt(value) || 0;

			childItem.set(field, value);
		});

		var payload = {
			Id: childItem.Id,
			AppId: childItem.AppId,
			Name: childItem.Name,
			Description: childItem.Description,
			FlowId: childItem.FlowId,
			ExecuteAs: childItem.ExecuteAs,
			NextExecution: childItem.NextExecution,
			ExecutionArgs: childItem.ExecutionArgs,
			ScheduleInTicks: childItem.ScheduleInTicks
		};

		try {
			await api.put("Core/ScheduledTask(" + payload.Id + ")", payload);
			childItem.dirty = false;
			notification.success("[resource_displayname[saved]]");

			if (parentGrid) parentGrid.refresh();

		} catch (err) {
			error(err);
		}

		kendoGrid.refresh();
	},

	destroy: function (e, grid) {
		e.preventDefault();
		var task = grid.dataItem($(e.currentTarget).closest("tr"));
		task.destroy(e).then(() => {
			notification.success("[resource_displayname[scheduledeleted]]");
			grid.refresh();
		}).catch((err) => error(err));
	}
}"}

{"AppId":11,"ResourceKey":"CMS","Content":"<div class='execConsole' name='execConsole'>
   <style>
      [name=flowConsole] { padding: 5px; }
