      [name=flowConsole] > .message > * { vertical-align: top; }
      [name=flowConsole] > .message > .message { display: inline-block; border: none; max-width: 90%; word-wrap: break-word; }
      [name=flowConsole] > .message .time { margin-right: 10px; }
      [name=flowConsole] > .message.success > .message { color: green; }
      [name=flowConsole] > .message.info > .message { color: green; }
      [name=flowConsole] > .message.debug > .message { color: blue; }
      [name=flowConsole] > .message.warning > .message { color: #D8A700; }
      [name=flowConsole] > .message.error > .message { color: red; }
      [name=flowConsole] > .message.fatal > .message { color: red; }
   </style>
   <div name='flowConsole'></div>
</div>","Script":"ScriptRunner = {
  init: function (app, container, variables, functionSet, requestDialog) {
    app = app || session.app;
    container = container || $(".component[name=ScriptRunner]");
    if(!variables) { return; }
    ScriptRunner.execute(container, variables, functionSet, requestDialog);
  },

  execute: function (container, variables, functionSet, dialog) {
    var logBackup = console.log;
    var htmlConsole = $("[name=flowConsole]", container);
    console.log(dialog);
    console.log = function (e) {
      var d = new Date();
      var time = d.getHours() + ":" + d.getMinutes() + ":" + d.getSeconds();
      htmlConsole.append(
        $("<div class='message " + "info" + "'>" +
          "<span class='time'>" + time + "</span>" +
          "<pre class='message'>" + html.encode(e) + "</pre>" +
          "</div>")
      );

      dialog.element.scrollTop(dialog.element.prop("scrollHeight"));

      logBackup(e);
    };
    var apiSendBackup = api.send;
    api.send = async function (type, query, data) {
      var d = new Date();
      var htmlConsole = $("[name=flowConsole]", container);
      var time = d.getHours() + ":" + d.getMinutes() + ":" + d.getSeconds();
      var message = type + "-" + query;
      if (data !== null && !query.includes("ImportThis()")) {
        var json = JSON.stringify(data, null, 2);
        message = message + "<br>" + json; // spacing level = 2
      }
      htmlConsole.append(
        $("<div class='message " + "debug" + "'>" +
          "<span class='time'>" + time + "</span>" +
          "<pre class='message'>" + message + "</pre>" +
          "</div>")
      );

      $("[name=execConsole]", container).scrollTop(htmlConsole.prop("scrollHeight"));

      return apiSendBackup.apply(api, [type, query, data]);
    };
    try {
      var execute = [script[Execute]];
      execute(variables, functionSet);
    }
    catch (err) {
      var d = new Date();
      var htmlConsole = $("[name=flowConsole]", container);
      var time = d.getHours() + ":" + d.getMinutes() + ":" + d.getSeconds();
      htmlConsole.append(
        $("<div class='message " + "debug" + "'>" +
          "<span class='time'>" + time + "</span>" +
          "<pre class='message'>" + err.message + "</pre>" +
          "</div>")
      );

      $("[name=execConsole]", container).scrollTop(htmlConsole.prop("scrollHeight"));

      error(err);
    }
  }
