","Script":"SessionsReport = {
  allAnalytics: [],
  filteredAnalytics: [],

  init: async function (app, container) {
    const tenantId = app.TenantId;

    const rawData = await api.get(`Security/TenantAnalysis?$filter=TenantId eq '${tenantId}' and Name eq 'User Activity (Daily)'&$orderby=CreatedOn asc&$format=json`);
    SessionsReport.allAnalytics = rawData.value.map(e => ({
      date: e.CreatedOn.slice(0, 10),
      data: JSON.parse(e.Value)
    }));

    const availableDates = SessionsReport.allAnalytics.map(e => e.date);
    const minDate = availableDates[0];
    const maxDate = availableDates[availableDates.length - 1];

    $("#startDate").val(minDate);
    $("#endDate").val(maxDate);

    await SessionsReport.loadAndRender(container, minDate, maxDate);

    $("#applyDateRange").off("click").on("click", async () => {
      const start = $("#startDate").val();
      const end = $("#endDate").val();
      if (start && end) {
        await SessionsReport.loadAndRender(container, start, end);
      }
    });

    $("#downloadCsvBtn").off("click").on("click", () => {
      const csvRows = ['Date;User ID;User Name;Email;Sessions;Page Hits;API Calls'];
      for (const entry of SessionsReport.filteredAnalytics) {
        const date = entry.date;
        for (const user of entry.data.Users || []) {
          csvRows.push([
            date,
            user.User.Id,
            user.User.UserDisplayName,
            user.User.UserEmail,
            user.Sessions,
            user.PageRequests,
            user.ApiRequests
          ].join(';'));
        }
      }
      downloadCsv(csvRows, `user-activity-${$("#startDate").val()}-to-${$("#endDate").val()}.csv`);
    });
  },

  loadAndRender: async function (container, startDate, endDate) {
    const entries = SessionsReport.allAnalytics.filter(e => e.date >= startDate && e.date <= endDate);
    SessionsReport.filteredAnalytics = entries;

    const totalUsers = new Set();
    let totalPageHits = 0;
    let totalApiCalls = 0;

    for (const entry of entries) {
      for (const user of entry.data.Users || []) {
        totalUsers.add(user.User.Id);
      }
      totalPageHits += (entry.data.Pages || []).reduce((sum, p) => sum + p.Hits, 0);
      totalApiCalls += (entry.data.ApiCalls || []).reduce((sum, a) => sum + a.Hits, 0);
    }

    $("[name=totalUsers]", container).text(totalUsers.size);
    $("[name=totalPageHits]", container).text(totalPageHits);
    $("[name=totalApiCalls]", container).text(totalApiCalls);
  }
};

function downloadCsv(rows, filename = 'activity.csv') {
  const csvContent = 'data:text/csv;charset=utf-8,' + rows.join('\n');
  const encodedUri = encodeURI(csvContent);
  const link = document.createElement('a');
  link.setAttribute('href', encodedUri);
  link.setAttribute('download', filename);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
}
