{"Key":"Menus","Name":"SideNav","ResourceKey":"Nav","Content":"<ul name="menu" class="menu"></ul>
<style>
   .component[name=SideNav] > .menu { padding: 10px;}
   .component[name=SideNav] > .menu li.item { margin: 12px 10px; padding: 4px; line-height: 130%; border-left: 4px solid #f7c580; font-size: 12px; font-weight: 500;}
   .component[name=SideNav] > .menu li.item.selected { border-left: 4px solid #ee8a00; font-weight: bold; }
</style>","Script":"SideNav = {
	init: async function(app, container) {
        app = app || session.app;
        container = container || $(".component[name=SideNav]");
        var page = session.page;
		var query = "core/Page?$filter=AppId eq " + session.app.Id + " and ParentId eq "  + page.ParentId + "&$expand=PageInfo,Pages($expand=PageInfo,Pages($expand=PageInfo))";		
        var pages = await api.get(query); 
		var menu = $("ul[name=menu]", container);

		for(var i in pages.value.sort(function(i) { return i.Order; })) {
			if(pages.value[i].ShowOnMenus) {
				SideNav.createItem(pages.value[i], menu); 
			}
		}
	},
   
	getCurrentPageInfoTitle: function(page, culture)
	{
		// Find Matching Culture PageInfo and sort by them
		var matchingPageInfos = page.PageInfo.filter(function(pi){ return pi.CultureId == culture;});
		if(matchingPageInfos.length > 0)
		{
			return matchingPageInfos[0].Title;
		}
		// Or if there are no matching, use the default page info
		return page.PageInfo.filter(function(pi){ return pi.CultureId == "";})[0].Title;
	},
	createItem: function(page, parentElement) {
		if(page.Path === null) { page.Path = ""; }
	
		var children = $("<ul class='submenu'></ul>");
		
		var culture = ($("html").attr("lang")) ? $("html").attr("lang") : "";
		var selectedPageInfos = page.Pages.map(function (p){ return SideNav.getCurrentPageInfoTitle(p, culture); });
		var sortedPagesInfos = selectedPageInfos.sort();
		
		var sortedPages = sortedPagesInfos.map(function (spi){ 
			var firstMatchingPage = page.Pages.filter(function (p){ 
				var pageHasMatchingPageInfo = p.PageInfo.filter(function (pi){ 
					return pi.Title == spi;
				}).length > 0;
				return pageHasMatchingPageInfo;
			})[0];
			return firstMatchingPage;
		});
		
		for(var i in sortedPages) {
			if(sortedPages[i].ShowOnMenus) {
				SideNav.createItem(sortedPages[i], children); 
			}
		}
       
	   var itemClass = SideNav.itemClass(page);
		parentElement.append($("<li data-id='" + page.Id + "' class='" + itemClass + "'></li>"));
		var thisNode = $("li[data-id=" + page.Id + "]", parentElement);
		thisNode.append("<a href='/" + page.Path + "'>" + SideNav.titleOf(page) + "</a>");
		
		if($("li", children).length > 0) {
			thisNode.append(children);
		}
	},
	
	itemClass: function(page) {
		if(session.page.PageId == page.Id || session.page.ParentId == page.Id) { return "item selected"; }
		return "item";
	},
	
	titleOf: function(page) {
		var culture = $("html").attr("lang");
		for(var i in page.PageInfo) {  
			if(page.PageInfo[i].CultureId === culture)
				return page.PageInfo[i].Title;
		}
		
		for(var i in page.PageInfo) {  
			if(page.PageInfo[i].CultureId === "")
				return page.PageInfo[i].Title;
		}
		
		return "unknown";
	}
};","CreatedOn":"2023-04-03T09:04:18.323Z","LastUpdated":"2023-04-03T09:04:18.323Z"}

