.slides {
    position: relative;
    overflow: hidden;
    height: 100%;
    border-radius: [theme[border.radius]];
}

/* Hide the images by default */
.slide {
    opacity: 0;
    vertical-align: center;
    min-height: 210px;
    max-width: 100%;
    border-radius: [theme[border.radius]];
}

/* Fading animation */
.fade {
    -webkit-animation-name: fade;
    -webkit-animation-duration: 2s;
    animation-name: fade;
    animation-duration: 2s;
}

.hide {
    display: none;
}

.show {
    display: block;
    opacity: 1;
}

@-webkit-keyframes fade { from {opacity: 0}  to {opacity: 1} }
@keyframes fade { from {opacity: 0} to {opacity: 1} }
</style>","Script":"Slideshow = {
	slideIndex: 0,
	init: async function(app, container) {
		app = app || session.app;
		container = container || $(".component[name=Slideshow]");
		var folder = await api.get("Core/Folder?$filter=AppId eq " + app.Id + " and Path eq 'Content/Slideshow'&$expand=Files($select=Path)&$select=Files&$top=1");
		var slides = $("[name=slides]", container);
		var images = folder.value[0].Files;

		for(var i = 0; i < images.length; i++) {
			var item = images[i];
			var src = session.apiRoot + "DMS/" + item.Path;
			slides.append(`<img class="slide fade hide" loading="lazy" src="${src}" />`);
		}

		Slideshow.showSlides(Slideshow.slideIndex);
		setTimeout(Slideshow.autoSlide, 5000);
	},

	plusSlides: function(n) {
		Slideshow.showSlides(Slideshow.slideIndex + n);
	},

	showSlides: function(n) {
		var slides = $(".slide");
		var currentIndex = Slideshow.slideIndex;

		Slideshow.slideIndex = n >= slides.length
			? 0
			: n;

		$(slides[currentIndex]).addClass('hide');
		$(slides[currentIndex]).removeClass('show');

		$(slides[Slideshow.slideIndex]).removeClass('hide');
		$(slides[Slideshow.slideIndex]).addClass('show');
	},

	autoSlide: function() { 
		Slideshow.plusSlides(1); 
		setTimeout(Slideshow.autoSlide, 5000);
	}
}","Name":"Slideshow","Description":null,"Key":"Marketing"}

