<div name="financeSupplierSummaryPage" style="display: none">
	[component[FinanceSupplierSummaryPage]]
</div>","Script":"SummaryHome = {
	init: function (app) {
		var root = $('[name=SummaryHome].component');
		app = app || session.app;
		if (!app.Config.RoleSummaryPages) {
			app.Config.RoleSummaryPages = {};
		}
		var homeSummaryConfig = app.Config.RoleSummaryPages;

		if (homeSummaryConfig.length > 0) {
			// Get the current user
			api.get('Core/User/Me()?$expand=Roles($expand=Role;$filter=Role/AppId eq [app[id]])', function (user) {
				var matchingRoles = [];
				for (i = 0; i < homeSummaryConfig.length; i++) {
					if (user.Roles.filter(function (ur) {
							return ur.Role.Name == homeSummaryConfig[i].RoleName;
						}).length > 0)
						matchingRoles.push(homeSummaryConfig[i]);
				}
				if (matchingRoles.length > 0) {
					//Temp to grant Admins the non-admin summary page
					//matchingRoles = matchingRoles.reverse();
					switch (matchingRoles[0].SummaryPage) {
					case "AdminSummaryPage":
						$('[name=defaultSummaryPage]', root).remove();
						$('[name=buyerSummaryPage], root').remove();
						$('[name=nonFinanceSupplierSummaryPage], root').remove();
						$('[name=financeSupplierSummaryPage], root').remove();
						$('[name=adminSummaryPage], root')[0].style.display = "block";
						break;
					case "BuyerSummaryPage":
						$('[name=defaultSummaryPage]', root).remove();
						$('[name=buyerSummaryPage], root')[0].style.display = "block";
						$('[name=nonFinanceSupplierSummaryPage], root').remove();
						$('[name=financeSupplierSummaryPage], root').remove();
						$('[name=adminSummaryPage], root').remove();
						break;
					case "NonFinanceSupplierSummaryPage":
						$('[name=defaultSummaryPage]', root).remove();
						$('[name=buyerSummaryPage], root').remove();
						$('[name=nonFinanceSupplierSummaryPage], root')[0].style.display = "block";
						$('[name=financeSupplierSummaryPage], root').remove();
						$('[name=adminSummaryPage], root').remove();
						break;
					case "FinanceSupplierSummaryPage":
						$('[name=defaultSummaryPage]', root)[0].remove();
						$('[name=buyerSummaryPage], root').remove();
						$('[name=nonFinanceSupplierSummaryPage], root').remove();
						$('[name=financeSupplierSummaryPage], root')[0].style.display = "block";
						$('[name=adminSummaryPage], root').remove();
						break;
					default:
						$('[name=defaultSummaryPage]', root)[0].style.display = "block";
						$('[name=buyerSummaryPage], root').remove();
						$('[name=nonFinanceSupplierSummaryPage], root').remove();
						$('[name=financeSupplierSummaryPage], root').remove();
						$('[name=adminSummaryPage], root').remove();
						if (window["DefaultSummaryPage"] && typeof window["DefaultSummaryPage"].init === 'function') {
							window["DefaultSummaryPage"].init();
						}
						break;
					}
					if (window[matchingRoles[0].SummaryPage] && typeof window[matchingRoles[0].SummaryPage].init === 'function') {
						window[matchingRoles[0].SummaryPage].init();
					}
				}
			});
		}
	}
};
$(function () {
	SummaryHome.init(session.app);
});
