</h4>
</div>","Script":"SuppliersCount = {
	init: function (app, bucketId) {
		app = app || session.app;
		bucketId = bucketId || app.Config.B2B.RootBucket;

		if(bucketId != null)
		{
			var query = "B2B/Company?$filter=Buckets/any(b: b/Bucket/Name eq 'Suppliers' and b/Bucket/ParentId eq " + bucketId + ")";

			api.get(query).then(function (companiesResult) {
				var data = companiesResult.value;

				var ds = SuppliersCount.createDatasourceForNumberOfVendors(data);
				SuppliersCount.buildSuppliersCountGraph(ds);
			});	
		}
	},
	createDatasourceForNumberOfVendors: function(data)
	{
		if(data != null && data.length > 0)
		{
			data = data.sort(SuppliersCount.sortCompaniesByDateTradingEnabled);
			dataSource = data.map(function(d, i) { 
				d.Pos = i + 1;
				return d;
			});
			if(dataSource.length > 0)
				dataSource.unshift({ Pos: 0, DateTradingEnabled: dataSource[0].DateTradingEnabled });

			return dataSource;
		}
		else
			return [];
	},
	buildSuppliersCountGraph: function(ds)
	{
		var root = $('[name=SuppliersCount].component');
		var target = $('[data-graph="SuppliersCount"]', root);
		var dataSeries = ds.map(function (sup) {
			var position = sup.Pos;
			var onboardedDate = new Date(sup.DateTradingEnabled);
			return [onboardedDate, position];
		});

		$('.clx-loader', target).remove();

		$('<div class="clx-chart"></div>').appendTo(target).kendoChart({
			legend: {
				visible: false
			},
			dataSource: dataSeries,
			seriesDefaults: {
				type: "scatterLine",
				dashType: "solid",
				style: "smooth",
				markers: {
					size: 0.5
				},
			},
			series: [{
					color: "#BED600",
					xField: "date",
					yField: "close",
					width: 5
				}
			],
			yAxis: {
				labels: {
					step: 2
				}
			}
		});
	},
	sortCompaniesByDateTradingEnabled(com1, com2)
	{
		return (com1.DateTradingEnabled < com2.DateTradingEnabled)
			? -1
			: (com1.DateTradingEnabled > com2.DateTradingEnabled)
				? 1
				: 0;
	}
}","Name":"SuppliersCount","Description":null,"Key":"Summary"}

