    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=TemplateManagement]");
		api.addToMetaCache([
		{
				"Name": "Core",
				"Types": [
					[meta[Core/Template]]
				]
		}]);
        var config = { endpoint: "Core/Template", odataAppend: "?$filter=AppId eq " + app.Id };
        let ds = await model.getDatasource(config);
        await TemplateManagement.initGrid(app, container, ds);
    },

    initGrid: async function(app, container, dataSource) {
        var grid = new GridWidget(container, dataSource);
        grid.groupable = false;
        grid.columns = [
            { 
                field: "ResourceKey", 
                title: "[resource_displayname[resourcekey]]",
                width: "[theme[columns.small]]"  
            },
            { 
                field: "Name", 
                title: '[resource_displayname[Name]]'
            },
            { 
                field: "LastUpdated", 
                title: "[resource_displayname[lastupdated]]", 
                type: "date", 
                format: "{0: " + type.dateFormat + " HH:mm}",
                width: "[theme[columns.small]]" 
            },
            { 
                field: "LastUpdatedBy", 
                title: "[resource_displayname[lastupdated]]",
                width: "[theme[columns.small]]"
            }
        ];
        grid.detailTemplate = kendo.template($("[name=templateDetails]", container).html());
        grid.commands.push({name: "save", icon: "k-i-save", text: "[resource_displayname[save]]"});
        grid.commands.push({name: "delete", icon: "k-i-trash", text: "[resource_displayname[delete]]"});
        grid.toolbar = [
        {
            template: `<div class='btn-group btn-group-sm'>
                <button class='btn btn-primary' name='create'>
                    <span class='k-icon k-i-plus'></span>[resource_displayname[new]]
                </button>
                <button class='btn btn-primary' name='migrate'>
                    <span class='k-icon k-i-arrow-up'></span>[resource_displayname[migrate]]
                </button>
            </div>`
        }];
        grid.detailExpand = async function(e) {
                var item = grid.kendoObject.dataItem(e.masterRow);
                var expandContainer = $("[name=editorContainer]", e.detailRow);
                if($(".monaco-editor", expandContainer).length == 0) {
                    await TemplateManagement.templateExpand(item, expandContainer);
                }
        };
        grid.dataBound = (e) => {
            $("button[name=save]", grid.gridElement).on("click", (e) => TemplateManagement.save(e, grid));
            $("button[name=delete]", grid.gridElement).on("click", (e) => TemplateManagement.destroy(e, grid));
        };
        grid.resizable = {
            rows: true
        };
        await grid.init();
        grid.rowResize = function(e) {
            console.log('resizing');
            $('.monaco-editor', e.detailRow).data('monacoEditor').layout();
        };
        $("button[name=migrate]", grid.gridElement).on("click", function (e) { TemplateManagement.migrate(e, app); });
        $("button[name=create]", grid.gridElement).on("click", function (e) { TemplateManagement.create(e, app, grid); });
        return grid;
    },

    templateExpand: async function(item, container) {
        var htmlEditor = new HTMLMonacoEditor(container[0], { code: item.RawString });
        htmlEditor.onChange = (e) => { item.RawString = htmlEditor.getValue(); };
        htmlEditor.init();
    },

    migrate: function (e, app) {
        e.preventDefault();
        var d = new Dialog({ width: 610, height: "auto", title: "[resource_displayname[migrateTemplates]]" });
        d.template = $("[name=templateMigrationComponent]").first().html();
        d.init(() => TemplateMigration.init(app, $(".component[name=TemplateMigration]", d.element)));
    },

    create: async function (e, app, grid) {
        var createTemplateDialog = new Dialog({width: 600, height: "auto", title: "[resource_displayname[newtemplate]]"});
        createTemplateDialog.template = $("[name=newTemplateDialog]").first().html();
        createTemplateDialog.events.create = async function (e) {
            var template = { 
                Id: 0, 
                AppId: app.Id, 
                Name: $("[name=name]", createTemplateDialog.element).val(), 
                RawString: "", 
                ResourceKey: $("[name=resourcekey]",createTemplateDialog.element).val()
            };
            await api.add("Core/Template", template).then(() => {
                notification.success("[resource_displayname[templatecreated]]");
                grid.refresh();
                createTemplateDialog.events.close();
            }).catch((e) => error(e));
        };
        await createTemplateDialog.init();
    },

    save: async function (e, grid) {
        e.preventDefault();
        var template = grid.dataItem($(e.currentTarget).closest("tr"));
        await template.save(e).then(() => {
            notification.success("[resource_description[saved]]");
        }).catch((err) => error(err));
    },

    destroy: async function (e, grid) {
        e.preventDefault();
        var template = grid.dataItem($(e.currentTarget).closest("tr"));
        await template.destroy(e).then(() => {
            notification.success("[resource_description[templatedeleted]]");
            grid.refresh();
        }).catch((err) => error(err));
    }
}
"}

