    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=TemplateMigration]");
		api.addToMetaCache([
		{
				"Name": "Core",
				"Types": [
					[meta[Core/Template]],
                    [meta[Core/App]]
				]
		}]);
        let ds = await model.getDatasource({ endpoint: "Core/App" });
        $("[name=app]", container).kendoDropDownList({
            autoBind: false,
            optionLabel: "[resource_displayname[selectapp]]",
            dataTextField: "Name",
            dataValueField: "Id",
            dataSource: ds
        });
        var templates = (await api.get("Core/Template?$filter=AppId eq " + app.Id + "&$select=Name")).value;
        var grid = new GridWidget($("[name=templateGrid]", container), templates);
        grid.columns = [
            { selectable: true, width: 40 },
            { field: "Name", title: "[resource_shortdisplayname[name]]" }
        ];
        grid.pageable = false;
        grid.groupable = false;
        grid.init(() => {
            grid.kendoObject.dataSource.sort({ field: "Category", dir: "asc" });
            grid.kendoObject.select(grid.kendoObject.tbody.find(">tr"));
        });
        $("[name=migrate]", container).on("click", async function (e) {
            var appId = $("[name=app]", container).val();
            if($("[name=overwrite]", container).is(":checked")) {
                var names = grid.select().map(r => "'" + r.Name + "'");

                var templateIds = await api.get("Core/Template?$filter=AppId eq " + appId + " and Name in (" + names.join() + ")&$select=Id");
                await api.post("Core/Template/DeleteAll", { value: templateIds.value.map(t => t.Id) })
                    .catch((err) => error(err));
            }
            var packages = await TemplateMigration.getPackages(app, grid);
            await api.add("Core/Package/ImportThis?appId=" + appId, packages);
            notification.success("[resource_displayname[migrated]]");
        });
    },

    getPackages: async function (app, grid) {
        var packages = [{
            Id: "00000000-0000-0000-0000-000000000000",
            Name: "Templates",
            Description: "Generated by TemplateMigration",
            Category: "Dynamic",
            SourceApi: session.apiRoot,
            Items: [
                await TemplateMigration.getPackage(app, grid)
            ]
        }];
        return packages;
    },

    getPackage: async function (app, grid) {
        var names = grid.select().map(r => "'" + r.Name + "'");
        var data = await api.get("Core/Template?$filter=AppId eq " + app.Id + " and Name in (" + names.join() + ")");
        for (var i = 0; i < data.value.length; i = i + 1) {
            delete data.value[i].Id;
        }
        return {
            Id: "00000000-0000-0000-0000-000000000000",
            PackageId: "00000000-0000-0000-0000-000000000000",
            Type: "Core/Template",
            Data: JSON.stringify(data.value)
        };
    }
};"}

