    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=TestimonialManagement]");
        container.addClass("large");
        $("[name=testimonialToolbar]").kendoToolBar({
            items: [
                {
                    text: "[resource_displayname[newtestimony]]",
                    type: "button",
                    template: `<div class="btn-group btn-group-sm">
                        <button class="btn btn-primary" name="addTestimonial">
                            <span class="k-icon k-i-plus"></span>[resource_displayname[new]]
                        </button>
                    </div>`
                },
            ]
        });
        //Gets the html files and inits the foldermanagement component
        var testimonialFiles = (await api.get("Core/Folder?$filter=AppId eq " + app.Id + " and Path eq 'content/testimonials/html'&$expand=Files")).value[0];
        FolderManagement.init(app, $(".component[name=FolderManagement]", $("[name=testimonialsFolder]", container)), testimonialFiles, false, true);

        $("[name=addTestimonial]", container).off("click").on("click", async (e) => await TestimonialManagement.addTestimonial(e, container));
    },

    addTestimonial: async function (e) {
        e.preventDefault();
        var newTestimonyDialog = new Dialog({ width: 600, height: "auto", title: "[resource_displayname[newtestimony]]" });
        newTestimonyDialog.template = $("[name=newTestimonyDialog]").html();

        newTestimonyDialog.events.create = async function (e) {
            e.preventDefault();
            var companyName = $("[name=companyName]").val();
            var contactName = $("[name=contactName]").val();
            var jobTitle = $("[name=jobTitle]").val();
            var content = $("[name=content]").val();

            var htmlContent = `<img src="[api[root]]DMS/content/testimonials/images/${companyName}logo.png" style="margin: 15px 0 -5px 0; max-height: 70px;"> <br>`;

            if (contactName) {
                htmlContent += `<p> ${contactName}</p>`;
            }

            if (jobTitle) {
                htmlContent += `<p> ${jobTitle}</p>`;
            }

            htmlContent += `<p style="padding-top: 15px; font-size: 14px; font-weight: normal;">"${content}"</p>`;

            var companyLogoFile = $("[name=companyLogo]", newTestimonyDialog.element).prop("files")[0];

            if (companyLogoFile) {
                try {

                    await api.file.upload("Content/Testimonials/Images/" + companyName + "Logo.png", companyLogoFile)

                    await api.sendRaw(
                        "POST",
                        "DMS/Content/Testimonials/html/" + companyName + "Testimonial.html",
                        htmlContent,
                        "text/plain" 
                    );

                    notification.success("[resource_displayname[testimonialsubmitted]]");
                } catch (err) {
                    notification.error("[resource_displayname[uploadfailed]]");
                    console.error(err);
                }
            } else {
                notification.error("[resource_displayname[noimageuploaded]]");
            }

            newTestimonyDialog.events.close();
        };

        newTestimonyDialog.init(() => {
            TestimonialManagement.initCompanyLogoFileUpload(newTestimonyDialog.element);
        });
    },


};"}

