","Script":"Testimonials = {
    testimonialIndex: 1,
    autoSlideInterval: 5000,

    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=Testimonials]");
        container.addClass("furtherInfoComponent");

        try {
            var folder = await api.get("Core/Folder?$filter=AppId eq " + app.Id + " and Path eq 'Content/Testimonials/html'&$expand=Files($select=Path)&$select=Files&$top=1");
            var htmlFiles = folder.value[0].Files;

            if (!htmlFiles || htmlFiles.length === 0) {
                $(".component[name=Testimonials]").remove();
                return;
            }

            var fetchPromises = htmlFiles.map(async (item) => {
                var src = session.apiRoot + "DMS/" + item.Path;
                return $.get(src);
            });

            var htmlContentArray = await Promise.all(fetchPromises);

            var testimonialsContainer = $("[name=testimonials]", container);
            htmlContentArray.forEach((htmlContent) => {
                testimonialsContainer.append("<div class='testimonial' style='flex: 0 0 auto;'>" + htmlContent + "</div>");
            });

            // Ensure there are at least two testimonials to create a continuous marquee effect
            if ($(".testimonial").length >= 2) {
                testimonialsContainer.append(testimonialsContainer.html()); // Duplicate the testimonials for continuous scrolling

                this.startMarquee();
            } else {
                // Handle the case when there are not enough testimonials for a marquee
                console.warn("Insufficient testimonials for a marquee effect.");
            }
        } catch (error) {
            console.error("An error occurred:", error);
        }
    },

    startMarquee: function () {
        var testimonialsContainer = $("[name=testimonials]");

        testimonialsContainer.css("display", "flex");
        testimonialsContainer.css("overflow", "hidden");

        var containerWidth = testimonialsContainer.width();
        var testimonialsWidth = $(".testimonial").length * containerWidth;

        testimonialsContainer.css("width", testimonialsWidth + "px");

        setInterval(function () {
            var scrollAmount = containerWidth;

            testimonialsContainer.animate(
                { scrollLeft: testimonialsContainer.scrollLeft() + scrollAmount },
                1000, // You can adjust the speed of the marquee effect here
                "linear",
                function () {
                    if (testimonialsContainer.scrollLeft() + containerWidth >= testimonialsWidth) {
                        testimonialsContainer.scrollLeft(0);
                    }
                }
            );
        }, this.autoSlideInterval);
    }
};
