    init: async function(app, container, theme) {
        app = app || session.app;
        container = container || $(".component[name=ThemeBuilder]");
        if(!theme)
            return;

        if(!theme.colours.charts) {
            theme.colours.charts = [
                "#000000",
                "#000000",
                "#000000",
                "#000000",
                "#000000",
                "#000000"
            ];
        }

        if(!theme.cultureFlagLayout) {
            theme.cultureFlagLayout = "text";
        }

        ThemeBuilder.initNavTabIds(app, container);

        var coloursComponent = await loadComponent($('[name=colours]', container), 'Colours');

        var model = new kendo.observable(theme);
        kendo.bind(container, model);
        $(container).data("model", model);
        
        await ThemeBuilder.addClickListenerForComponents(app, container, model);
        
        await coloursComponent.init(app, $('[name=colours]', container), model);
    },

    initNavTabIds: function(app, container) {
        var id = Guid();
        var template = $('script[name=edit-theme]', container).html();
        template = template.replaceAll('{ID}', id);

        container.append(template);
    },

    addClickListenerForComponents: async function(app, container, model) {
        var buttons = $('button[role=tab]', container);
        buttons.each((button) => {
            var button = $(buttons[button], container);
            var target = $(button.attr('data-bs-target'));
            var component = target.attr('data-component');

            if(component != null) {
                button.click(async () => {
                    var existing = $(`.component[name=${component}]`, $(target, container));

                    if(existing.length == 0) {
                        await loadComponent($(target, container), component, async (c) => {
