<div name="themeBuilderComponent" style="display:none;">[component[ThemeBuilder]]</div>","Script":"ThemeList = {
    init: async function(app, container, themesDMSPath, clientEntry) {
        app = app || session.app;
        container = container || $(".component[name=ThemeList]");
        if(!themesDMSPath) { return; }
        var themeGrid = new GridWidget(container, ThemeList.getDataSource(themesDMSPath));
        themeGrid.toolbar ="<button name='add'><span class='k-icon k-i-add'></span>[resource_displayname[add]]</button><button name='save'><span class='k-icon k-i-save'></span>[resource_displayname[save]]</button><button name='editFiles'><span class='k-icon k-i-edit'></span>[resource_displayname[editfiles]]</button>";
        themeGrid.groupable = false;
        themeGrid.pageable = false;
        themeGrid.sortable = true;
        themeGrid.columns = [{ field: "name", title: "[resource_displayname[name]]" }];
        themeGrid.commands.push({ name: "edit", icon: "k-i-edit", text: "[resource_displayname[edit]]" });
        themeGrid.commands.push({ name: "remove", icon: "k-i-delete", text: "[resource_displayname[delete]]" });
        themeGrid.dataBound = function () {
            $("[name=remove]", themeGrid.gridElement).on("click", async function (e) {
                var item = themeGrid.kendoObject.dataItem($(e.currentTarget).closest("tr"));
                await ThemeList.removeTheme(e, themeGrid, item) 
            });
            $("[name=edit]", themeGrid.gridElement).on("click", async (e) => await ThemeList.editTheme(e, app, themesDMSPath, themeGrid));
        }
        await themeGrid.init();
        $("button[name=add]", themeGrid.gridElement).on("click", () => ThemeList.addTheme(themeGrid, themesDMSPath));
        $("button[name=editFiles]", themeGrid.gridElement).on("click", (e) => ThemeList.editFiles(e, app, clientEntry));
        $("button[name=save]", themeGrid.gridElement).on("click", () =>  ThemeList.save(themeGrid, themesDMSPath));
    },

    getDataSource(url) {
        return new kendo.data.DataSource({
            transport: {
                read: { 
                    url: api.apiRoot + url, 
                    dataType: "json",
                    type: "GET",
                    beforeSend: function(req) {
                        req.setRequestHeader("Authorization", "bearer " + api.token);
                    }
                }
            },
            pageSize: 50,
            schema: {
                data: (response) => response,
                total: (response) => response.length
            }
        });;
    },

    save: async function(themeGrid, themesDMSPath) {
        await api.put(themesDMSPath, themeGrid.dataSource().data()).then(() => {
            notification.success("[resource_displayname[saved]]");
            themeGrid.refresh();
        }).catch((err) => error(err));
    },
    
    addTheme: function (themeGrid, themesDMSPath) {
        var model = kendo.observable({ name: "", theme: JSON.parse(JSON.stringify(session.app.Config.Themes.Default)) });
        var addThemeDialog = new Dialog({ title: "[resource_displayname[addtheme]]" });
        addThemeDialog.template = $("[name=addThemeDialog]").html();
        addThemeDialog.events.confirm = async function () {
            themeGrid.dataSource().insert(0, model);
            await ThemeList.save(themeGrid, themesDMSPath);
            addThemeDialog.events.close();
        };
        addThemeDialog.init(() => {  
            kendo.bind(addThemeDialog.element, model);  
        });
    },

    editFiles: async function (e, app, clientEntry) {
        e.preventDefault();
        var editFileDialog = new Dialog({ title: "[resource_displayname[edittheme]]"});
        editFileDialog.init(() => {
            ClientFiles.init(app, $(".component[name=ClientFiles]", editFileDialog.element), clientEntry);
            $("[name=confirm]", editFileDialog.element).on("click", (e) => { e.preventDefault();  editFileDialog.events.close(); });
        });
    },

    editTheme: async function (e, app, themesDMSPath, themeGrid) {
        var themeEntry = themeGrid.dataItem($(e.currentTarget).closest("tr"));
        var editThemeDialog = new Dialog({ title: "[resource_displayname[edittheme]]", width: "auto", height: 600 });
        editThemeDialog.template = $("[name=editThemeDialog]").html();
        editThemeDialog.events.save = async function() {
            themeEntry.theme = ThemeBuilder.build($(".component[name=ThemeBuilder]", editThemeDialog.element));
            await ThemeList.save(themeGrid, themesDMSPath);
            editThemeDialog.events.close();
        };
        editThemeDialog.init(() => {
            $("[name=themeContent]", editThemeDialog.element).html($("[name=themeBuilderComponent]").first().html());
            ThemeBuilder.init(app, $(".component[name=ThemeBuilder]", editThemeDialog.element), themeEntry.theme);
        });
    },

    removeTheme: async function (e, themeGrid, themeEntry) {
        themeGrid.kendoObject.dataSource.remove(themeEntry);
    }
}","CreatedOn":"2021-11-19T18:58:03.321Z","LastUpdated":"2021-11-19T18:58:03.321Z"}

