","Script":"TopCompaniesByInvoiceCount = {
    init: async function (app, container) {
        app = app || session.app;
        container = container || $(".component[name=TopCompaniesByInvoiceCount]");

        var defaultCurrency = app.Config.B2B.DefaultCurrency
            ? app.Config.B2B.DefaultCurrency
            : "EUR";

        $("[name=currencyDropdown]", container).kendoDropDownList({
            dataSource: app.Config.B2B.Currencies
                ? app.Config.B2B.Currencies
                : ["USD", "EUR", "GBP"],
            change: async function (e) {
                var value = this.value();
                var data = await TopCompaniesByInvoiceCount.getData(app, value);
                TopCompaniesByInvoiceCount.buildLeaderboard({ data: data }, container);
            }
        });

        $("[name=currencyDropdown]", container).data("kendoDropDownList").value(defaultCurrency);

        var data = await this.getData(app, defaultCurrency);
        this.buildLeaderboard({ data: data }, container);
    },

    getData: async function (app, currency) {
        var sourceSystem = app.Config.B2B.SourceSystem;
        var endpoint = `B2B/Invoice/FromSystem(SystemId='${sourceSystem}')`;
        var filter = `?$apply=filter(CurrencyId eq '${currency}')/groupby((CreditorName), aggregate(Id with countdistinct as Total))`;

        var chartData = await api.get(endpoint + filter);
        return chartData.sort((a, b) => b.Total - a.Total).slice(0, 10);
    },

    buildLeaderboard: function (data, container) {
        $('[name=leaderboardTarget]', container).empty();

        var maxValue = data.data.length > 0 ? data.data[0].Total : 0;
        var itemTemplate = $('[name=TopCompaniesByInvoiceCount].template').first().html().replace("[MAX]", maxValue);

        $('[name=leaderboardTarget]', container).kendoListView({
            dataSource: data,
            template: kendo.template(itemTemplate),
            selectable: true,
            dataBound: function (e) {
                var percentiles = $('.percentage', e.sender.element);
                percentiles.map(function (index, element) {
                    var val = $(element).attr('data-percentage');
                    var percent = parseFloat(val.split('/')[0]) / (parseFloat(val.split('/')[1]) / 100);
                    $(element).css('width', percent + '%');
                });
            },
        });
    }
}
