<div class="chart" name="topCreditorsByCount"></div>","Script":"TopCreditorsByTransactionCount = {
	init: async function (app, container) { 
		var currentDate =  new Date();
		currentDate.setMonth(currentDate.getMonth() + 2);
		var targetDate = new Date().setMonth(currentDate.getMonth()-6);
		var requests = [];
		while(currentDate > targetDate) {
			var calendarMonth = currentDate.getFullYear() + "-" + currentDate.getMonth();
		    var query = "B2B/Company/TopCreditors()?$top=10&$orderby=Count desc&systemId=" + app.Config.B2B.SourceSystem + "&calendarMonth=" + calendarMonth;
			currentDate.setMonth(currentDate.getMonth() -1);
			requests.push(api.get(query));
		}
		var data = await Promise.all(requests);
		TopCreditorsByTransactionCount.initCreditorsByCount(container, data);
	},

	initChart: function(args, element) {
		var chart = new Chart(element, args);
		chart.init();
		return chart;
	},

	initCreditorsByCount: function(container, data) {
        console.log({ component: "TopCreditorsByTransactionCount", data: data });
        var args = {
            showLegend: true,
            series: new Array(),
            categories: new Array(),
            max: data.map(i => i.Count).sort(function(a,b){return b - a})[0],
            type: "line"
        };

        data.map(function(i)  { args.categories.push(i.value[0].CalendarMonth); });
        var length = 0;
        for(var i in data) {
            for(var c in data[i].value) {
                var company = data[i].value[c];
                var name = company.Name + " (" + company.Ref.split("|")[1] + ")";
                var series = args.series.filter(s => s.name == name)[0];
                if(!series) {
                    series = { name: name, data: [] };
                    args.series.push(series);
                }
                series.data.push(company.Count);
            }
            length++;
            for(var s in args.series) { 
                args.series[s].length = length; 
                for(var x = 0; x < length; x++) { args.series[s].data[x] = args.series[s].data[x] || null; }
            }
        }
        args.series.length = 10;
        for(var i in args.series) { args.series[i].data.reverse(); }
        args.categories.reverse();
        return TopCreditorsByTransactionCount.initChart(args, $("[name=topCreditorsByCount]", container));
	}
};","Name":"TopCreditorsByTransactionCount","Description":null,"Key":"Summary"}

