","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"CMS","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"TopNav","ResourceKey":"CMS","Script":"TopNav = {
	init: function(app, container, page) {
        app = app || session.app;
        container = container || $(".component[name=TopNav]");
        page = page || session.page;
		var query = "core/Page?$filter=AppId eq " + session.app.Id + " and ParentId eq null&$orderBy=Order asc&$expand=PageInfo,Pages($orderBy=Order asc;$expand=PageInfo,Pages($orderBy=Order asc;$expand=PageInfo))";
		api.get(query)
			.then(function(pages) {
				var menu = $("ul[name=menu]", container);
				var filteredPages = pages.value.filter(page => page.ShowOnMenus == true);
				TopNav.generateNavMenu(menu, filteredPages);
			});
	},

	generateNavMenu: function(nav, pages) {
		for(var i = 0; i < pages.length; i++) {
			var page = pages[i];
			var visibleChildren = TopNav.getVisibleChildPages(page);

			if(visibleChildren.length > 0)
				TopNav.generateNavDropdown(nav, page, visibleChildren)
			else
				TopNav.generateNavItem(nav, page);
		}
	},

	generateNavItem: function(nav, page) {
		var navItem = $('<li class="' + TopNav.itemClass(page, false) + '"></li>');
		navItem.append($('<a href="/' + page.Path + '" class="' + TopNav.linkClass(page, false) + '">' + TopNav.titleOf(page) + '</a>'));
		nav.append(navItem);
	},

	generateNavDropdown: function(nav, page, children) {
		var navItem = $('<li class="' + TopNav.itemClass(page, true) + '"></li>');
		navItem.append($('<a href="/' + page.Path + '" class="nav-link dropdown-toggle ' + (TopNav.isCurrentPage(page, true) ? 'active' : '') +'" aria-expanded="false">' + TopNav.titleOf(page) + '</a>'));
		var dropdown = $('<ul class="dropdown-menu"></ul>');
		for(var i = 0; i < children.length; i++) {
			var item = children[i];
			TopNav.generateNavDropdownItem(dropdown, item);
		}
		navItem.append(dropdown);
		nav.append(navItem);
	},

	generateNavDropdownItem: function(dropdown, page) {
		var navItem = $('<li></li>');
		navItem.append($('<a href="/' + page.Path + '" class="' + TopNav.linkClass(page, true) + '">' + TopNav.titleOf(page) + '</a>'));
		dropdown.append(navItem);
	},

	getVisibleChildPages: function(page) {
		var culture = ($("html").attr("lang")) ? $("html").attr("lang") : "";
		// if(Object.keys(page).indexOf('Pages') === -1)
			// return [];

		var selectedPageInfos = page.Pages.map(p => TopNav.getCurrentPageInfoTitle(p, culture));
		// var sortedPagesInfos = selectedPageInfos.sort();

		var sortedPages = selectedPageInfos.map(function (spi){ 
			var firstMatchingPage = page.Pages.filter(function (p){ 
				var pageHasMatchingPageInfo = p.PageInfo.filter(function (pi){ 
					return pi.Title == spi;
				}).length > 0;
				return pageHasMatchingPageInfo;
			})[0];
			return firstMatchingPage;
		});

		return sortedPages.filter(function(child) {
			return child.ShowOnMenus == true;
		});
	},

	getCurrentPageInfoTitle: function(page, culture) {
		// Find Matching Culture PageInfo and sort by them
		var matchingPageInfos = page.PageInfo.filter(function(pi){
			return pi.CultureId == culture;
		});

		if(matchingPageInfos.length > 0)
			return matchingPageInfos[0].Title;

		// Or if there are no matching, use the default page info
		return page.PageInfo.filter(function(pi){
			return pi.CultureId == "";
		})[0].Title;
	},

	createItem: function(page, parentElement, dropdown = false) {
		if(page.Path === null)
			page.Path = "";

		var dropdownNode = $("<ul class='dropdown-menu'></ul>");

		var culture = ($("html").attr("lang")) ? $("html").attr("lang") : "";
		var selectedPageInfos = page.Pages.map(p => TopNav.getCurrentPageInfoTitle(p, culture));
		// var sortedPagesInfos = selectedPageInfos.sort();

		var sortedPages = selectedPageInfos.map(function (spi){ 
			var firstMatchingPage = page.Pages.filter(function (p){ 
				var pageHasMatchingPageInfo = p.PageInfo.filter(function (pi){ 
					return pi.Title == spi;
				}).length > 0;
				return pageHasMatchingPageInfo;
			})[0];
			return firstMatchingPage;
		});

		for(var i in sortedPages) {
			if(sortedPages[i].ShowOnMenus) {
				TopNav.createItem(sortedPages[i], dropdownNode, (sortedPages.length > 1)); 
			}
		}

		parentElement.append($("<li data-id='" + page.Id + "' class='" + '' + "'></li>"));
		var thisNode = $("li[data-id=" + page.Id + "]", parentElement);

		thisNode.append("<a href='/" + page.Path + "'>" + TopNav.titleOf(page) + "</a>");

		if($("li", dropdownNode).length > 0) {
			thisNode.append(dropdownNode);
		}
	},

	itemClass: function(page, dropdown = false) {
		var isCurrentPage = TopNav.isCurrentPage(page, false);

		if(dropdown == true)
			return isCurrentPage
				? 'dropdown-item active'
				: 'dropdown-item';
		return isCurrentPage
			? 'nav-item active'
			: 'nav-item';
	},

	linkClass: function(page, dropdown) {
		var isCurrentPage = TopNav.isCurrentPage(page, false);
		if(dropdown == true)
			return isCurrentPage ? 'dropdown-item active' : 'dropdown-item';
		return isCurrentPage ? 'nav-link active' : 'nav-link';
	},

	isCurrentPage: function(page, isParent = false) {
		if(isParent == true)
			return session.page.ParentId == page.Id;

		return session.page.PageId == page.Id;
	},

	titleOf: function(page) {
		var culture = $("html").attr("lang");
		for(var i in page.PageInfo)
			if(page.PageInfo[i].CultureId.split('-')[0] === culture)
				return page.PageInfo[i].Title;

		for(var i in page.PageInfo)
			if(page.PageInfo[i].CultureId.split('-')[0] === "")
				return page.PageInfo[i].Title;

		return "unknown";
	}
};"}

