<div name="chart" class = "chart"></div>","Script":"TotalDiscountedAmountOverTime = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=TotalDiscountedAmountOverTime]");
		container.addClass("dashboardComponent")

		var data = [];
		for(let i = 0; i < 12; i++) {
			let date = new Date();
			date.setMonth(date.getMonth() - 11);
			const offset = date.getTimezoneOffset()
			const firstDay = new Date((new Date(date.getFullYear(), date.getMonth() + i, 1)).getTime() - (offset*60*1000)).toISOString().split("T")[0];
			const lastDay = new Date((new Date(date.getFullYear(), date.getMonth() + (i + 1), 0)).getTime() - (offset*60*1000)).toISOString().split("T")[0];
			data.push(api.get(`B2B/Offer/FromSystem(SystemId='${app.Config.B2B.SourceSystem}')?$apply=filter(DueDate ge ${firstDay} and DueDate le ${lastDay} and (FunderState eq 'FundingAccepted' or CreditorState eq 'FundingAccepted' or FunderState eq 'Paid' or CreditorState eq 'FundingAccepted'))/groupby((CurrencyId), aggregate(Id with countdistinct as Total, Cost with sum as Cost))`).then((chartData) => {
				if(chartData.length > 0) {
					for(let c in app.Config.B2B.Currencies) {
						var matchingCurrency = chartData.filter(r => r.CurrencyId === app.Config.B2B.Currencies[c]);
						if(matchingCurrency.length > 0) {
							return matchingCurrency.map(r => { r.CalendarMonth = firstDay.split("-")[0] + "-" + firstDay.split("-")[1]; return r; });
						} else {
							return { CalendarMonth:  firstDay.split("-")[0] + "-" + firstDay.split("-")[1], Cost: 0, Total: 0, CurrencyId: app.Config.B2B.Currencies[c] };
						}
					}
				} else {
					for(let c in app.Config.B2B.Currencies) {
						return { CalendarMonth:  firstDay.split("-")[0] + "-" + firstDay.split("-")[1], Cost: 0, Total: 0, CurrencyId: app.Config.B2B.Currencies[c] };
					}
				}
			}));
		}
		data = (await Promise.all(data)).flat();
		TotalDiscountedAmountOverTime.initChart(container, data, app.Config.B2B.Currencies);
	},

	initChart: function (container, data, currencies) {
		var categories = data.map(i => i.CalendarMonth).filter((value, index, self) => self.indexOf(value) === index);
		console.log({ component: "TotalDiscountedAmountOverTime", data: data });
		var args = {
			showLegend: true,
			valueTemplate: "#: kendo.toString(value, type.aggregateMoneyFormat)#",
			tooltipTemplate: "#= series.name #: #= kendo.toString(value, type.aggregateMoneyFormat) #",
			series: currencies.map(cur => ({
				name: "[resource_displayname[Cost]] (" + cur + ")",
				data: categories.map(c => data.filter(r => r.CalendarMonth === c && r.CurrencyId === cur).map(i => i.Cost))
			})),
			categories: categories,
			max: data.map(i => i.Cost).sort((a, b) => b - a)[0],
			type: "column"
		};
		(new Chart($("[name=chart]", container), args)).init();
	}
}","Name":"TotalDiscountedAmountOverTime","Description":null,"Key":"Summary"}

{"AppId":11,"ResourceKey":"B2B","Content":"<div data-graph="TotalDiscountsOverTime">
<h4>
	<span>[resource_displayname[TotalDiscountsOverTime]]</span>
</h4>","Script":"TotalDiscountsOverTime = {
	init: function (app, bucketId, startOfRange, endOfRange, grouping) {
		app = app || session.app;
		bucketId = bucketId || app.Config.B2B.RootBucket;
		startOfRange = startOfRange || -30;
		endOfRange = endOfRange || 0;
		grouping = grouping || "month";
		if(startOfRange <= endOfRange && bucketId != null)
		{
			var tempStartDate = new Date();
			var tempEndDate = new Date();
			var startOfRange = new Date(tempStartDate.setDate(tempStartDate.getDate() + startOfRange));
			var endOfRange = new Date(tempEndDate.setDate(tempEndDate.getDate() + endOfRange));
			var query = "B2B/Offer?$filter=Buckets/any(b: b/Bucket/Name eq 'All Offers' and b/Bucket/ParentId eq " + bucketId + ") and AuditTrail/any(at: at/Message eq 'Accepted' and at/CreatedOn ge " + kendo.toString(startOfRange, 'yyyy-MM-dd') + " and at/CreatedOn le " + kendo.toString(endOfRange, 'yyyy-MM-dd') + ")&$expand=AuditTrail";

			api.get(query).then(function (offersResult) {
				var data = offersResult.value;
				var ds = TotalDiscountsOverTime.createDatasourceOffersOverTime(data);
				TotalDiscountsOverTime.buildTotalDiscountsOverTimeGraph(ds);
			});	
		}
	},
	createDatasourceOffersOverTime: function(data)
	{
		if(data != null && data.length > 0)
		{
			data = data.map(function(d){ 
				if(d.AuditTrail != null && d.AuditTrail.length > 0)
				{
					var offerAcceptedAuditTrails = d.AuditTrail.filter(function(at){ return at.Message == "Accepted";});
					if(offerAcceptedAuditTrails != null && offerAcceptedAuditTrails.length > 0)
					{
						var sortedAcceptedAuditTrails = TotalDiscountsOverTime.sortAuditTrailEventsByCreatedOn(offerAcceptedAuditTrails);
						d.AcceptedDate = kendo.toString(new Date(sortedAcceptedAuditTrails[sortedAcceptedAuditTrails.length -1].CreatedOn), 'yyyy-MM-dd');
					}
				}
				return d;
			});
			var groupedOffers = TotalDiscountsOverTime.groupByArray(data, 'AcceptedDate')
			var dataSource = groupedOffers.map(function(g){ return { date: g.key, count: g.values.length}});
			return dataSource;
		}
		else
			return [];
	},
	buildTotalDiscountsOverTimeGraph: function(ds)
	{
		var root = $('[name=TotalDiscountsOverTime].component');
		var target = $('[data-graph="TotalDiscountsOverTime"]', root);

		$('.clx-loader', target).remove();

		$('<div class="clx-chart"></div>').appendTo(target).kendoChart({
			dataSource: ds,
			series:[{
				type: 'column',
				field: 'count',
				overlay:{
					gradient:'none'
				},
				color: "#BED600"
			}],
			categoryAxis: {
				field: 'date',
				type: "date",
				baseUnit: "days",
				labels: {
					step: 4
				},
				majorGridLines: {
					visible: false
				}
			},
		});
	},
	groupByArray: function(xs, key) { 
		return xs.reduce(function (rv, x) { 
			let v = key instanceof Function ? key(x) : x[key]; 
			let el = rv.find((r) => r && r.key === v); 
			if (el) { el.values.push(x); } 
			else { rv.push({ key: v, values: [x] }); } 
			return rv;
		}, []); 
	},
	sortAuditTrailEventsByCreatedOn: function(at1, at2)
	{
		return (at1.CreatedOn < at2.CreatedOn )
			? -1
			: (at1.CreatedOn  > at2.CreatedOn )
				? 1
				: 0;
	}
}","Name":"TotalDiscountsOverTime","Description":null,"Key":"Summary"}

