			var dataSource = groupedOffers.map(function(g){ return { date: g.key, totalValue: g.values.map(function(d){ return d.FundableValue; }).reduce(TotalValueOfDiscountedInvoices.getSum,0)}});
			return dataSource;
		}
		else
			return [];
	},
	buildTotalValueOfDiscountedInvoicesGraph: function(ds)
	{
		var root = $('[name=TotalValueOfDiscountedInvoices].component');
		var target = $('[data-graph="TotalValueOfDiscountedInvoices"]', root);

		$('.clx-loader', target).remove();

		$('<div class="clx-chart"></div>').appendTo(target).kendoChart({
			dataSource: ds,
			series:[{
				type: 'column',
				field: 'totalValue',
				overlay:{
					gradient:'none'
				},
				color: "#BED600"
			}],
			categoryAxis: {
				field: 'date',
				type: "date",
				baseUnit: "days",
				labels: {
					step: 4
				},
				majorGridLines: {
					visible: false
				}
			},
		});
	},
	groupByArray: function(xs, key) { 
		return xs.reduce(function (rv, x) { 
			let v = key instanceof Function ? key(x) : x[key]; 
			let el = rv.find((r) => r && r.key === v); 
			if (el) { el.values.push(x); } 
			else { rv.push({ key: v, values: [x] }); } 
			return rv;
		}, []); 
	},
	sortAuditTrailEventsByCreatedOn: function(at1, at2)
	{
		return (at1.CreatedOn < at2.CreatedOn )
			? -1
			: (at1.CreatedOn  > at2.CreatedOn )
				? 1
				: 0;
	},
	getSum: function (total, num) {
		return total + num;
	},
}","Name":"TotalValueOfDiscountedInvoices","Description":null,"Key":"Summary"}

