				console.log(data, chart);
				chart.kendoObject.options.series[0].name = "[resource_displayname[transactioncount]] (" + value + ")";
				chart.kendoObject.options.categoryAxis.categories = data.months;
				chart.kendoObject.options.valueAxis.max = Math.max(...data.counts) * 1.1;
				chart.kendoObject.options.series[0].data = data.counts;
				chart.kendoObject.refresh();

				if(data.counts.flat().filter(d => d != 0).length == 0) {
					$('[name=nodata]', container).show();
					$('[name=chart]', container).hide();
				} else {
