                title: "[resource_shortdisplayname[processedon]]",
                description: "[resource_description[processedon]]"
            }
        ];

        g.dataBound = function (e) {
            $("[name=reimport]", g.gridElement).off("click").on("click", (e) => TransactionImportCSVLines.reimport(e, g));
        };

        if(g.expandView) {
            g.detailTemplate = "<div name='container'></div>";
            g.detailExpand = function (e) {
                var transaction = this.dataItem(e.masterRow);
                var container = $(e.detailRow).find("div[name=container]");
