    reimport: async function (event, grid) {
        notification.info('Reimporting line...');
        var item = grid.dataItem($(event.currentTarget).closest("tr"));
        var items = [
            'SourceSystemId;Type;State;Reference;CreditorTransactionRef;DebtorRef;CreditorRef;VATRef;Currency;DocDate;DueDate;PaymentDate;RelatedTransactionRef;PayRef;Value;GrossValue;TaxValue;IsFundable;IsRaLine;AlsoPayOffer;Description'
        ];
        items.push([
            item.SourceSystemId,
            item.TransactionType,
            item.State,
            item.Reference,
            item.CreditorTransactionRef,
            item.DebtorRef,
            item.CreditorRef,
            item.VATRef,
            item.Currency,
            item.DocDate,
            item.DueDate,
            item.PaymentDate,
            item.RelatedTransactionRef,
            item.PayRef,
            item.Value,
            item.GrossValue,
            item.TaxValue,
            item.IsFundable,
            item.IsRaLine,
            item.AlsoPayOffer,
            item.Description
        ].join(';'));
        var requestBody = items.join(`
`);
        console.log(requestBody);
        await api.sendRaw('post', 'B2B/Import/Transactions?rootBucketId=' + item.RootBucketId + '&sourceSystemId=' + item.SourceSystemId + '&fileName=UI-Reimport-' + item.FileName, requestBody)
            .then(async () => {
                notification.success("[resource_displayname[reimported]]");
            })
            .catch((err) => error(err));
    }
};"}

