","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Workflow","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"TransactionImportResults","ResourceKey":"Workflow","Script":"TransactionImportResults = {
  init: async function (app, container) {
    const allInstances = await api.get(`Core/FlowInstanceData?$orderby=Start desc`);
    const allDates = [...new Set(allInstances.value.map(i => i.Start.slice(0, 10)))];

    const $dropdown = $("[name=importDateDropdown]", container).empty();
    $dropdown.append(`<option value="">[resource_displayname[selectimportdate]]</option>`);
    allDates.forEach(date => $dropdown.append(`<option value="${date}">${date}</option>`));

    const defaultDate = allDates[0];
    if (defaultDate) {
      $dropdown.val(defaultDate);

      try {
        this.showSpinner(container);
        await this.loadDataForDate(app, container, defaultDate);
      } finally {
        this.hideSpinner(container);
      }
    }

    $dropdown.off("change").on("change", async function () {
      const selectedDate = $(this).val();
      if (selectedDate) {
        try {
          TransactionImportResults.showSpinner(container);
          await TransactionImportResults.loadDataForDate(app, container, selectedDate);
        } finally {
          TransactionImportResults.hideSpinner(container);
        }
      }
    });
  },

  loadDataForDate: async function (app, container, day) {
    if (!day) return;

    const startOfDay = `${day}T00:00:00Z`;
    const nextDay = new Date(day);
    nextDay.setDate(nextDay.getDate() + 1);
    const endOfDay = nextDay.toISOString().slice(0, 19) + "Z";

    const systems = app.Config.B2B.SourceSystem.split(',');
    const systemFilter = systems.map(id => `'${id}'`).join(',');
    const filter = `SourceSystemId in (${systemFilter}) and CreatedOn ge ${startOfDay} and CreatedOn lt ${endOfDay}`;
    const endpoint = `B2B/TransactionCSVLine?$filter=${encodeURIComponent(filter)}`;

    const csvLines = (await api.get(endpoint)).value || [];

    const failedLines = csvLines.filter(line => line.State === "Failed").length;
    const invalidLines = csvLines.filter(line => line.State === "Invalid").length;

    $("[name=files]", container).html(this.getFiles(csvLines, day));

    const transactionStats = await this.getTransactionImportStats(day, app.Config.B2B.SourceSystem);
    const paymentStats = await this.getPaymentImportStats(csvLines, day, app.Config.B2B.SourceSystem);

    $("[name=totalNewTransactions]", container).html(transactionStats.totalNew);
    $("[name=totalUpdatedTransactions]", container).html(transactionStats.totalUpdated);
    $("[name=totalFailedLines]", container).html(failedLines);
    $("[name=totalInvalidLines]", container).html(invalidLines);
    $("[name=totalLinesImported]", container).html(csvLines.length);
    $("[name=totalNewInvoices]", container).html(transactionStats.newInvoices);
    $("[name=totalUpdatedInvoices]", container).html(transactionStats.updatedInvoices);
    $("[name=totalNewCredits]", container).html(transactionStats.newCredits);
    $("[name=totalUpdatedCredits]", container).html(transactionStats.updatedCredits);
    $("[name=totalNewPayments]", container).html(paymentStats.newPayments);
    $("[name=totalUpdatedPayments]", container).html(paymentStats.updatedPayments);
  },

  getFiles: function (csvLines, targetDate) {
    const fileNames = [...new Set(csvLines.map(line => line.FileName))];
    const path = targetDate.split('-'); // [yyyy, mm, dd]
    return fileNames.map(name =>
      `<a download='${name}' href='${session.apiRoot}DMS/Data/Transactions/Processed/${path[0]}/${path[0]}-${path[1]}/${targetDate}/${name}'>${name}</a><br>`
    ).join("");
  },

  getTransactionImportStats: async function (day, systemIdParam) {
    const startOfDay = `${day}T00:00:00Z`;
    const nextDay = new Date(day);
    nextDay.setDate(nextDay.getDate() + 1);
    const endOfDay = nextDay.toISOString().slice(0, 19) + "Z";

    const systemFilter = systemIdParam.split(',').map(id => `'${id}'`).join(',');
    const filter = `(SourceSystemId in (${systemFilter})) and ((CreationDate ge ${startOfDay} and CreationDate lt ${endOfDay}) or AuditTrail/any(a: a/CreatedOn ge ${startOfDay} and a/CreatedOn lt ${endOfDay}))`;

    const [invoices, credits] = await Promise.all([
      api.get(`B2B/Invoice?$select=Id,CreationDate&$expand=AuditTrail($select=CreatedOn)&$filter=${encodeURIComponent(filter)}`).then(res => res.value || []),
      api.get(`B2B/Credit?$select=Id,CreationDate&$expand=AuditTrail($select=CreatedOn)&$filter=${encodeURIComponent(filter)}`).then(res => res.value || [])
    ]);

    let newInvoices = 0, updatedInvoices = 0, newCredits = 0, updatedCredits = 0;

    invoices.forEach(t => {
      const createdToday = new Date(t.CreationDate) >= new Date(startOfDay) && new Date(t.CreationDate) < new Date(endOfDay);
      const auditedToday = t.AuditTrail?.some(a => new Date(a.CreatedOn) >= new Date(startOfDay) && new Date(a.CreatedOn) < new Date(endOfDay));
      if (createdToday) newInvoices++;
      else if (auditedToday) updatedInvoices++;
    });

    credits.forEach(t => {
      const createdToday = new Date(t.CreationDate) >= new Date(startOfDay) && new Date(t.CreationDate) < new Date(endOfDay);
      const auditedToday = t.AuditTrail?.some(a => new Date(a.CreatedOn) >= new Date(startOfDay) && new Date(a.CreatedOn) < new Date(endOfDay));
      if (createdToday) newCredits++;
      else if (auditedToday) updatedCredits++;
    });

    return {
      newInvoices,
      updatedInvoices,
      newCredits,
      updatedCredits,
      totalNew: newInvoices + newCredits,
      totalUpdated: updatedInvoices + updatedCredits
    };
  },

  getPaymentImportStats: async function (csvLines, day, systemIdParam) {
    const startOfDay = `${day}T00:00:00Z`;
    const nextDay = new Date(day);
    nextDay.setDate(nextDay.getDate() + 1);
    const endOfDay = nextDay.toISOString().slice(0, 19) + "Z";

    const paymentRefs = new Set(
      csvLines
        .filter(line => (line.TransactionType === "Invoice" || line.TransactionType === "Credit") && line.State === "Paid" && line.PayRef)
        .map(line => line.PayRef)
    );

    if (paymentRefs.size === 0) return { newPayments: 0, updatedPayments: 0 };

    const systemFilter = systemIdParam.split(',').map(id => `'${id}'`).join(',');
    const filter = `(SourceSystemId in (${systemFilter})) and ((CreationDate ge ${startOfDay} and CreationDate lt ${endOfDay}) or AuditTrail/any(a: a/CreatedOn ge ${startOfDay} and a/CreatedOn lt ${endOfDay}))`;

    const remittances = (await api.get(`B2B/RemittanceAdvice?$select=Id,CreationDate&$expand=AuditTrail($select=CreatedOn),References($select=Id)&$filter=${encodeURIComponent(filter)}`)).value || [];

    let newPayments = 0, updatedPayments = 0;

    remittances.forEach(ra => {
      const hasMatch = ra.References?.some(ref => paymentRefs.has(ref.Id?.split('|')[1]));
      if (!hasMatch) return;

      const created = new Date(ra.CreationDate);
      const auditedToday = ra.AuditTrail?.some(a => new Date(a.CreatedOn) >= new Date(startOfDay) && new Date(a.CreatedOn) < new Date(endOfDay));

      if (created >= new Date(startOfDay) && created < new Date(endOfDay)) newPayments++;
      else if (auditedToday) updatedPayments++;
    });

    return { newPayments, updatedPayments };
  },

  showSpinner: function (container) {
    $("[name=loadingSpinner]", container).show();
  },

  hideSpinner: function (container) {
    $("[name=loadingSpinner]", container).hide();
  }
};
"}

