","Script":"UsageReport = {
	allAnalytics: [],
	filteredAnalytics: [],

	init: async function (app = session.app, container = $(".component[name=UsageReport]")[0]) {
		var tenantId = app.TenantId;
		UsageReport.allAnalytics = await UsageReport.fetchAnalyticsData(tenantId);

		var dates = UsageReport.allAnalytics.map(e => e.date);
		var now = new Date();
		var currentYear = now.getFullYear();
		var currentMonth = String(now.getMonth() + 1).padStart(2, '0');
		var today = String(now.getDate()).padStart(2, '0');
		var thisYearStart = `${currentYear}-01-01`;
		var thisYearEnd = `${currentYear}-${currentMonth}-${today}`;

		$("[name='startDate']").val(dates.find(d => d >= thisYearStart) || dates[0]);
		$("[name='endDate']").val(dates[dates.length - 1]);

		var thisYearData = await UsageReport.filterAnalyticsByDate(thisYearStart, thisYearEnd);
		await UsageReport.thisYearSummary(thisYearData, currentYear);

		UsageReport.setupEventHandlers(container);

		var years = [...new Set(UsageReport.allAnalytics.map(e => new Date(e.date).getFullYear()))].sort((a, b) => b - a);
		var yearSelector = $("[name='yearSelector']").empty();
		years.forEach(y => yearSelector.append(`<option value="${y}">${y}</option>`));
		yearSelector.val(years[0]).trigger("change");
	},

	fetchAnalyticsData: async function (tenantId) {
		var res = await api.get(`Security/TenantAnalysis?$filter=TenantId eq '${tenantId}' and Name eq 'User Activity (Daily)'&$orderby=CreatedOn asc&$format=json`);
		return res.value.map(e => ({ date: e.CreatedOn.slice(0, 10), data: JSON.parse(e.Value) }));
	},

	setupEventHandlers: function () {
		$("[name='applyDateRange']").off().on("click", async () => {
			var start = $("[name='startDate']").val();
			var end = $("[name='endDate']").val();
			if (start && end) {
				UsageReport.filteredAnalytics = UsageReport.filterAnalyticsByDate(start, end);
				await UsageReport.thisYearSummary(UsageReport.filteredAnalytics, new Date(start).getFullYear());
				notification.info("[resource_displayname[datefilterapplied]]");
			}
		});

		$("[name='yearSelector']").off().on("change", async function () {
			var year = $(this).val();
			var data = UsageReport.filterAnalyticsByDate(`${year}-01-01`, `${year}-12-31`);
			var { userMonthlySessions, allMonths } = await UsageReport.calculateSummary(data);
			await UsageReport.groupedUserTable(userMonthlySessions, allMonths);

			var { counts, sortedMonths } = UsageReport.calculateUniqueUsersPerMonth(data);
			UsageReport.renderUniqueUsersTable(counts, sortedMonths);

			await UsageReport.renderTopUsersTable(userMonthlySessions);
		});

		$("[name='downloadCsvBtn']").off().on("click", () => {
			var start = $("[name='startDate']").val();
			var end = $("[name='endDate']").val();
			var data = UsageReport.filteredAnalytics.length ? UsageReport.filteredAnalytics : UsageReport.filterAnalyticsByDate(start, end);
			UsageReport.downloadCsv(UsageReport.generateCsvRows(data), `user-activity-${start}-to-${end}.csv`);
			notification.info("[resource_displayname[filedownloadstarted]]");
		});

		$("[name='downloadPdfBtn']").off().on("click", async () => {
			const { jsPDF } = window.jspdf;
			const pdf = new jsPDF('p', 'pt', 'a4');

			const reportElement = document.querySelector(".component[name='UsageReport']");
			const originalOverflow = reportElement.style.overflow;
			const originalHeight = reportElement.style.height;

			const start = $("[name='startDate']").val();
			const end = $("[name='endDate']").val();

			const headerRow = reportElement.querySelector(".row.align-items-center.ps-2.pe-2.pt-2");
			if (headerRow) headerRow.style.display = "none";

			const header = document.createElement("div");
			header.style.textAlign = "center";
			header.style.margin = "0 0 20px 0";
			header.innerHTML = `
    <h2 style="margin:0;">[resource_displayname[portalusagesummary]]</h2>
    <div style="font-size:12pt; color:#555;">
      ${start || "–"} → ${end || "–"}
    </div>
  `;
			reportElement.prepend(header);

			reportElement.style.overflow = "visible";
			reportElement.style.height = "auto";

			await new Promise(r => setTimeout(r, 100)); // Let layout settle

			const canvas = await html2canvas(reportElement, {
				scale: 2,
				useCORS: true,
				windowWidth: reportElement.scrollWidth,
				windowHeight: reportElement.scrollHeight
			});

			const imgData = canvas.toDataURL("image/png");
			const pageWidth = pdf.internal.pageSize.getWidth();
			const pageHeight = pdf.internal.pageSize.getHeight();
			const imgWidth = pageWidth;
			const imgHeight = (canvas.height * imgWidth) / canvas.width;

			let position = 0;
			let heightLeft = imgHeight;

			pdf.addImage(imgData, "PNG", 0, position, imgWidth, imgHeight);
			heightLeft -= pageHeight;

			while (heightLeft > 0) {
				position = heightLeft - imgHeight;
				pdf.addPage();
				pdf.addImage(imgData, "PNG", 0, position, imgWidth, imgHeight);
				heightLeft -= pageHeight;
			}

			pdf.save(`UsageReport-${start || "start"}-to-${end || "end"}.pdf`);

			header.remove();
			if (headerRow) headerRow.style.display = "";
			reportElement.style.overflow = originalOverflow;
			reportElement.style.height = originalHeight;

			notification.info("[resource_displayname[filedownloadstarted]]");
		});
	},

	filterAnalyticsByDate: (start, end) => UsageReport.allAnalytics.filter(e => e.date >= start && e.date <= end),

	generateCsvRows: function (entries) {
		var rows = ['Date;User ID;User Name;Email;Sessions;Page Hits;API Calls'];
		entries.forEach(entry => {
			(entry.data.Users || []).forEach(user => {
				var u = user.User || {};
				rows.push([
					entry.date,
					u.Id || '',
					u.UserDisplayName || '',
					u.UserEmail || '',
					user.Sessions || 0,
					user.PageRequests || 0,
					user.ApiRequests || 0
				].join(';'));
			});
		});
		return rows;
	},

	downloadPdf: async function (entries, filename = 'activity.pdf') {
		const { jsPDF } = window.jspdf;
		const doc = new jsPDF();
		let y = 10;
		doc.setFontSize(14);
		doc.text("User Activity Report", 10, y);
		y += 10;
		entries.forEach(entry => {
			doc.setFontSize(12);
			doc.text(`Date: ${entry.date}`, 10, y);
			y += 6;
			(entry.data.Users || []).forEach(user => {
				if (y > 270) { doc.addPage(); y = 10; }
				var u = user.User || {};
				doc.setFontSize(10);
				doc.text(
					`${u.UserDisplayName || 'Unknown'} (${u.UserEmail || 'No Email'}) | Sessions: ${user.Sessions || 0}, Pages: ${user.PageRequests || 0}, API: ${user.ApiRequests || 0}`,
					10, y
				);
				y += 5;
			});
			y += 3;
		});
		doc.save(filename);
	},

	thisYearSummary: async function (data, year) {
		var { monthlySummary, userMonthlySessions, allMonths } = await UsageReport.calculateSummary(data);
		if (allMonths.length) {
			UsageReport.monthlyTable("[name='monthlySummaryTable']", monthlySummary, {
				sessionsId: "[name='grandTotalSessions']",
				pageHitsId: "[name='grandTotalPageHits']",
				apiHitsId: "[name='grandTotalApiHits']"
			}, allMonths);
		} else {
			$("[name='monthlySummaryTable']").find("thead, tbody").empty();
			$("[name='grandTotalSessions'], [name='grandTotalPageHits'], [name='grandTotalApiHits']").text(0);
		}
		await UsageReport.groupedUserTable(userMonthlySessions, allMonths);
		var { counts, sortedMonths } = UsageReport.calculateUniqueUsersPerMonth(data);
		UsageReport.renderUniqueUsersTable(counts, sortedMonths);
		await UsageReport.renderTopUsersTable(userMonthlySessions);
	},

	calculateSummary: async function (entries) {
		var monthlySummary = {}, userMonthlySessions = {}, months = new Set();
		var appId = session.app.Id;
		var [userRolesRes, allRolesRes] = await Promise.all([
			api.get("Core/UserRole"),
			api.get("Core/Role")
		]);
		var userRoles = userRolesRes.value;
		var allRoles = allRolesRes.value;
		var ignoredRoles = ["Guests", "Users", "Administrators"];
		var roles = allRoles.filter(r => r.AppId === appId && !ignoredRoles.includes(r.Name));
		var roleMap = Object.fromEntries(roles.map(r => [r.Id, r.Name]));
		var allowedUsers = new Set();
		userRoles.forEach(({ UserId, RoleId }) => {
			if (roleMap[RoleId]) allowedUsers.add(UserId);
		});
		entries.forEach(({ date, data }) => {
			var d = new Date(date);
			var month = `${String(d.getMonth() + 1).padStart(2, '0')}-${d.getFullYear()}`;
			months.add(month);
			if (!monthlySummary[month]) monthlySummary[month] = { sessions: 0, pageHits: 0, apiHits: 0 };
			(data.Users || []).forEach(({ User = {}, Sessions = 0, ApiRequests = 0 }) => {
				if (!User.Id || !allowedUsers.has(User.Id)) return;
				monthlySummary[month].sessions += Sessions;
				monthlySummary[month].apiHits += ApiRequests;
				userMonthlySessions[User.Id] ??= { name: User.UserDisplayName || '', email: User.UserEmail || '', monthly: { } };
				userMonthlySessions[User.Id].monthly[month] = (userMonthlySessions[User.Id].monthly[month] || 0) + Sessions;
			});
			monthlySummary[month].pageHits += (data.Pages || []).reduce((sum, p) => sum + (p.Hits || 0), 0);
		});
		return {
			monthlySummary,
			userMonthlySessions,
			allMonths: [...months].sort((a, b) => {
				var [ma, ya] = a.split('-').map(Number);
				var [mb, yb] = b.split('-').map(Number);
				return ya - yb || ma - mb;
			})
		};
	},

	calculateUniqueUsersPerMonth: function (entries) {
		var uniqueUsersByMonth = {};
		entries.forEach(({ date, data }) => {
			var d = new Date(date);
			var month = `${String(d.getMonth() + 1).padStart(2, '0')}-${d.getFullYear()}`;
			uniqueUsersByMonth[month] ??= new Set();
			(data.Users || []).forEach(({ User = {} }) => {
				if (User.Id) uniqueUsersByMonth[month].add(User.Id);
			});
		});
		var counts = {};
		Object.keys(uniqueUsersByMonth).forEach(m => counts[m] = uniqueUsersByMonth[m].size);
		var sortedMonths = Object.keys(counts).sort((a, b) => {
			var [ma, ya] = a.split('-').map(Number);
			var [mb, yb] = b.split('-').map(Number);
			return ya - yb || ma - mb;
		});
		return { counts, sortedMonths };
	},

	renderUniqueUsersTable: function (counts, months) {
		var table = $("[name='uniqueUsersTable']");
		var thead = table.find("thead").empty();
		var tbody = table.find("tbody").empty();
		var headerRow = $("<tr></tr>");
		headerRow.append(`<th class="text-start">[resource_displayname[metric]]</th>`);
		months.forEach(month => headerRow.append(`<th>${month}</th>`));
		headerRow.append(`<th>Total</th>`);
		thead.append(headerRow);
		var dataRow = $("<tr></tr>");
		dataRow.append(`<td class="text-start">[resource_displayname[uniqueusers]]</td>`);
		let total = 0;
		months.forEach(month => {
			var val = counts[month] || 0;
			dataRow.append(`<td>${val}</td>`);
			total += val;
		});
		dataRow.append(`<td>${total}</td>`);
		tbody.append(dataRow);
	},

	monthlyTable: function (selector, summary, totals, months) {
		var table = $(selector);
		var thead = table.find("thead").empty();
		var tbody = table.find("tbody").empty();
		if (!months || !months.length) return;
		var headerRow = $("<tr></tr>");
		headerRow.append(`<th class="text-start">[resource_displayname[metric]]</th>`);
		months.forEach(month => headerRow.append(`<th>${month}</th>`));
		headerRow.append(`<th>[resource_displayname[total]]</th>`);
		thead.append(headerRow);
		function buildRow(label, key) {
			var row = $(`<tr><td class="text-start">${label}</td></tr>`);
			let total = 0;
			months.forEach(month => {
				var val = summary[month]?.[key] || 0;
				row.append(`<td>${val}</td>`);
				total += val;
			});
			row.append(`<td>${total}</td>`);
			return { row, total };
		}
		var sessions = buildRow("[resource_displayname[totalsessions]]", "sessions");
		var pageHits = buildRow("[resource_displayname[totalpagehits]]", "pageHits");
		var apiHits = buildRow("[resource_displayname[totalapihits]]", "apiHits");
		tbody.append(sessions.row, pageHits.row, apiHits.row);
