	groupedUserTable: async function (userMonthlySessions, months) {
		var appId = session.app.Id;
		var [userRolesRes, allRolesRes] = await Promise.all([
			api.get("Core/UserRole"),
			api.get("Core/Role")
		]);
		var userRoles = userRolesRes.value;
		var allRoles = allRolesRes.value;
		var ignoredRoles = ["Guests", "Users", "Administrators"];
		var roles = allRoles.filter(r => r.AppId === appId && !ignoredRoles.includes(r.Name));
		var roleMap = Object.fromEntries(roles.map(r => [r.Id, r.Name]));
		var userToRoles = {};
		userRoles.forEach(({ UserId, RoleId }) => {
			var roleName = roleMap[RoleId];
			if (!roleName) return;
			userToRoles[UserId] = userToRoles[UserId] || [];
			userToRoles[UserId].push(roleName);
		});
		var grouped = {};
		Object.entries(userMonthlySessions).forEach(([userId, userData]) => {
			var roles = userToRoles[userId];
			if (!roles || roles.length === 0) return;
			roles.forEach(role => {
				grouped[role] = grouped[role] || [];
				grouped[role].push(userData);
			});
		});
		var table = $("[name='userMonthlyTable']");
		var thead = table.find("thead").empty();
		var tbody = table.find("tbody").empty();
		var tfoot = table.find("tfoot").empty();
		var head = $("<tr><th class='text-start'>[resource_displayname[user]]</th></tr>");
		months.forEach(m => head.append(`<th>${m}</th>`));
		head.append(`<th>[resource_displayname[total]]</th>`);
		thead.append(head);
		var totals = {}, grandTotal = { all: 0 };
		months.forEach(m => totals[m] = 0);
		Object.entries(grouped).forEach(([role, users]) => {
			var groupRow = $(`<tr class="bg-light"><td class="text-start table-light" colspan="${months.length + 2}"><strong>${role}</strong></td></tr>`);
			tbody.append(groupRow);
			users.forEach(user => {
				var row = $(`<tr><td class="text-start">${user.name || user.email}</td></tr>`);
				let userTotal = 0;
				months.forEach(m => {
					var val = user.monthly[m] || 0;
					row.append(`<td>${val}</td>`);
					userTotal += val;
					totals[m] += val;
				});
				row.append(`<td>${userTotal}</td>`);
				grandTotal.all += userTotal;
				tbody.append(row);
			});
		});
		var foot = $("<tr><td class='text-start'>[resource_displayname[total]]</td></tr>");
		months.forEach(m => foot.append(`<td>${totals[m]}</td>`));
		foot.append(`<td>${grandTotal.all}</td>`);
		tfoot.append(foot);
	},

	renderTopUsersTable: async function (userMonthlySessions) {
		var appId = session.app.Id;
		var [userRolesRes, allRolesRes] = await Promise.all([
			api.get("Core/UserRole"),
			api.get("Core/Role")
		]);
		var userRoles = userRolesRes.value;
		var allRoles = allRolesRes.value;
		var ignoredRoles = ["Guests", "Users", "Administrators"];
		var roles = allRoles.filter(r => r.AppId === appId && !ignoredRoles.includes(r.Name));
		var roleMap = Object.fromEntries(roles.map(r => [r.Id, r.Name]));
		var allowedUsers = new Set();
		userRoles.forEach(({ UserId, RoleId }) => {
			if (roleMap[RoleId]) allowedUsers.add(UserId);
		});
		var filteredUsers = Object.entries(userMonthlySessions)
			.filter(([userId]) => allowedUsers.has(userId))
			.map(([_, u]) => ({
				name: u.name || u.email || "Unknown",
				total: Object.values(u.monthly).reduce((a, b) => a + b, 0)
			}));
		var top10 = filteredUsers.sort((a, b) => b.total - a.total).slice(0, 10);
		var table = $("[name='topUsersTable']");
		var thead = table.find("thead").empty();
		var tbody = table.find("tbody").empty();
		thead.append(`
      <tr>
        <th class="text-start">[resource_displayname[user]]</th>
        <th>[resource_displayname[totalsessions]]</th>
      </tr>
    `);
		top10.forEach(u => {
			tbody.append(`
        <tr>
          <td class="text-start">${u.name}</td>
          <td>${u.total}</td>
        </tr>
      `);
		});
	},

	downloadCsv: function (rows, filename = 'activity.csv') {
		var blob = new Blob([rows.join('\n')], { type: 'text/csv;charset=utf-8;' });
		var link = document.createElement('a');
		link.href = URL.createObjectURL(blob);
		link.download = filename;
		document.body.appendChild(link);
		link.click();
		document.body.removeChild(link);
	}
};
