</style>","Script":"UserOnboardingAcceptWizard = {
    init: async function (app, container, onboardingGrid, submission, dialog) {
        app = app || session.app;
        container = container || $(".component[name=UserOnboardingAcceptWizard]");
        api.addToMetaCache([
			{
				"Name": "B2B",
				"Types": [
					[meta[B2B/Bucket]],
                    [meta[B2B/Company]]
				]
			},
            {
                "Name": "Core",
                "Types": [
                    [meta[Core/Role]]
                ]
            }
		]);
        var variables = { SelectedCoreRoles: [], SelectedB2BRoles: [], companies: [], submission: submission };
        var ds = await model.getDatasource({ endpoint: "Core/Role", odataAppend: "?$filter=AppId eq " + app.Id + "&$orderby=Name" });
        await UserOnboardingAcceptWizard.setupRoleGrid($("div[name=roles]", container), ds, variables);
        var stepIndex = 0;
        $("button[name=next]", container).on("click", function (e) { e.preventDefault(); UserOnboardingAcceptWizard.nextStep(app, container, variables, stepIndex, onboardingGrid, dialog) });
    },

    nextStep: async function (app, container, variables, stepIndex, onboardingGrid, dialog) {
        if (stepIndex == 0 && variables.SelectedCoreRoles.length === 0) { notification.error("[resource_displayname[selectonerole]]"); return; }
        if (stepIndex === 1 && variables.companies.length === 0) { notification.error("[resource_displayname[selectonecompany]]"); return; }
        if (stepIndex === 2 && variables.SelectedB2BRoles.length === 0) { notification.error("[resource_displayname[selectonerole]]"); return; }
        if (stepIndex === 3) { await UserOnboardingAcceptWizard.approveOnboardingRequest(app, variables, onboardingGrid, dialog); return; }
        $("[step]", container).hide();
        $("[stepPart]", container).removeClass("selected");
        stepIndex++;
        $("button[name=next]", container).off("click").on("click", function (e) { e.preventDefault(); UserOnboardingAcceptWizard.nextStep(app, container, variables, stepIndex, onboardingGrid, dialog) });
        $("[step=" + stepIndex + "]", container).show();
        $("[stepPart=" + stepIndex + "]", container).addClass("selected");
        if (stepIndex === 1) { UserOnboardingAcceptWizard.setupCompanyGrid($("div[name=companies]", container), variables); }
        if (stepIndex === 2) {
            var selectedCompanies =  []
            var companyReferences = []
            for (let i = 0; i < variables.companies.length; i = i +1){
                company = await api.get("B2B/Company(" + variables.companies[i].Id + ")?$expand=References");
                companyReference = company.References[0].Id;
                companyReferences.push("'" + companyReference + "'")
                selectedCompanies.push(company);
            }
            var rootBucketId = session.app.Config.B2B.RootBucket;
            var systems = session.app.Config.B2B.SourceSystem.split(",");
            
            var companies = (await api.get("B2B/Company?$expand=References&$filter=References/any(ref: ref/Id in (" + companyReferences + "))&$expand=Buckets($expand=Bucket($expand=Roles))")).value;
            var buckets = [];
            var allRoles = [];
            companies.map((company) => {
                for(var i = 0; i < company.Buckets.length; i++) {
                    var bucket = company.Buckets[i].Bucket;
                    if(bucket.Path != null && bucket.Path.startsWith(app.Config.Deployment.TenantId)) {
                        buckets.push({
                            CompanyName: company.Name,
                            CompanyRef: company.References.filter((ref) => ref.SystemId == app.Config.B2B.SourceSystem)[0].Id,
                            Description: bucket.Description,
                            Id: bucket.Id,
                            Key: bucket.Key,
                            Name: bucket.Name,
                            ParentId: bucket.ParentId,
                            RolesJson: null,
                            Roles: bucket.Roles.map((role) => role.RoleId)
                        });
                        bucket.Roles.map((role) => allRoles.push(role.RoleId));
                    }
                }
            });
            var uniqueRoles = [... new Set(allRoles)];
            var roleData = (await api.get("B2B/B2BRole?$filter=Id in (" + (uniqueRoles.map((role) => "'" + role + "'")).join(',') + ")")).value;
            for(var i = 0; i < buckets.length; i++) {
                var bucket = buckets[i];
                bucket.RolesJson = JSON.stringify(bucket.Roles.map((r) => roleData.filter((role) => role.Id == r)[0]));
            }
            var ds = buckets;

            await UserOnboardingAcceptWizard.setupB2BGrid($("div[name=b2broles]", container), ds, variables);
        }
        if (stepIndex === 3) {
            await UserOnboardingAcceptWizard.setupRoleGrid($("div[name=selectedCoreRoles]", container), variables.SelectedCoreRoles, variables, null, true);
            await UserOnboardingAcceptWizard.setupB2BGrid($("div[name=selectedB2BRoles]", container), variables.SelectedB2BRoles, variables, null, true);
            $("button[name=next]", container).html("[resource_displayname[approve]]");
        }
    },

    approveOnboardingRequest: async function(app, variables, onboardingGrid, dialog) {
        var submission = variables.submission;
        submission.State = "Accepted";
        var fields = JSON.parse(submission.DataJson).fields;
        delete submission.type;
        var workflowData = {
            SelectedCoreRoles: variables.SelectedCoreRoles,
            SelectedB2BRoles: variables.SelectedB2BRoles,
            companies: variables.companies,
            submission: variables.submission
        };
        var acceptWorkflow = await api.get("Core/FlowDefinition?$filter=Name eq 'OnboardingApprove' and AppId eq " + app.Id);
        if(acceptWorkflow.value.length > 0) {
            await api.add("Core/FlowDefinition(" + acceptWorkflow.value[0].Id + ")/Execute", workflowData).then(()=> {
                notification.success("Executed");
            });
        }
        if (onboardingGrid)
            onboardingGrid.kendoObject.dataSource.read();
        
        if (dialog)
            dialog.events.close();
        
        for (let i = 0; i < variables.SelectedCoreRoles.length; i = i + 1) {
            var userExists = (await api.get("Core/UserRole?$filter=RoleId eq " + variables.SelectedCoreRoles[i].Id + " and UserId eq '" + fields[0].username + "'")).value.length > 0;
            if (!userExists) {
                await api.add("Core/UserRole", {
                    RoleId: variables.SelectedCoreRoles[i].Id,
                    UserId: fields[0].username
                });
            }
        }
        var b2bRoles = variables.SelectedB2BRoles.map(r=>r.Roles).flat();
        for (let i = 0; i < b2bRoles.length; i = i + 1) {
            let userExists = (await api.get("B2B/B2BUserRole?$filter=RoleId eq " + b2bRoles[i].Id + " and UserId eq '" + fields[0].username + "'")).value.length > 0;
            if (!userExists) {
                await api.add("B2B/B2BUserRole", {
                    UserId: fields[0].username,
                    RoleId: b2bRoles[i].Id
                });
            }
        }
        await api.update("Core/Submission(" + submission.Id + ")", submission);
        notification.success("Approved");
    },

	setupB2BGrid: async function (grid, dataSource, variables, callback, readonly = false) {
		var b2bGrid = new GridWidget(grid, dataSource);
		b2bGrid.groupable = false;
		b2bGrid.editable = false;
        b2bGrid.pageable = !readonly;
		b2bGrid.columns = [ { field: "Name", title: "[resource_shortdisplayname[Name]]" }, { field: "Key", title: "[resource_shortdisplayname[Key]]" } ];
		b2bGrid.detailTemplate = "<div name='bucketRoles' style='height:200px'></div>";
		b2bGrid.detailExpand = async function (e) {
			var bucket = b2bGrid.kendoObject.dataItem(e.masterRow);
			var expandTag = $(e.detailRow);
			if ($(e.detailRow).find(".k-grid").length === 0) {
				var b2bGridDefinition = [script[BucketRoleGrid]];
				variables.element = $("[name=bucketRoles]", expandTag);
				variables.dataSource = { data: JSON.parse(bucket.RolesJson) };
                await b2bGridDefinition(variables);
                variables.BucketRoleGrid.pageable = !readonly;
				variables.BucketRoleGrid.init();
			}
		};
		b2bGrid.init(callback);
	},

	setupCompanyGrid: async function (grid, variables) {
		var companies = await model.getDatasource({ endpoint: "B2B/Company", odataAppend: "/FromSystem(SystemId='" + session.app.Config.B2B.SourceSystem + "')" });
		var companyGrid = new GridWidget(grid, companies);
		companyGrid.groupable = false;
		companyGrid.editable = false;
        companyGrid.scrollable = true;
		companyGrid.searchable = true;
        companyGrid.pageable = true;
		companyGrid.columns = [
            { selectable: true, width: "50px" }, 
            { field: "Name", title: "[resource_shortdisplayname[name]]" } 
        ];
		companyGrid.change = function (e) {
			var selectedRows = this.select();
			variables.companies = [];
			for (var i = 0; i < selectedRows.length; i++) {
				var dataItem = this.dataItem(selectedRows[i]);
				variables.companies.push(dataItem);
			}

		};
		await companyGrid.init();
	},

	setupRoleGrid: async function (grid, dataSource, variables, callback, readonly = false) {
		var roleGridDefinition = [script[CoreRoleGrid]];
		variables.element = grid;
		variables.dataSource = dataSource;
		variables.readonly = readonly;
		await roleGridDefinition(variables);
		variables.CoreRoleGrid.dataBound = callback;
		variables.CoreRoleGrid.init();
	},
