</style>","Script":"UserOnboardingNewRequestWizard = {
	init: async function (app, container, onboardingGrid, dialog) {
		app = app || session.app;
		container = container || $(".component[name=UserOnboardingNewRequestWizard]");
		if (!onboardingGrid) { return; }

		api.addToMetaCache([
			{
				"Name": "Core",
				"Types": [
					[meta[Core/User]]
				]
			}
		]);

		var validator = container.kendoValidator().data("kendoValidator");
		var disclaimer = await api.get("Core/File?$filter=Folder/AppId eq " + app.Id + " and Path eq 'content/useronboardingdisclaimer-[[lang]].html'");
		var maxStepIndex = (disclaimer.value.length > 0) ? 3 : 2;

		if (disclaimer.value.length == 0) {
			$("[name=disclaimerStep]", container).hide();
		}

		$("button[name=previous]", container).hide();
		var userDetails = await api.get("B2B/B2BUser/Me()");
		var currentUser = await api.get("Core/User/Me()?$expand=Roles($expand=Role)");

		if (currentUser.Roles.filter(r => r.Role.AppId == app.Id && r.Role.Name == "Administrators").length > 0) {
			var users = await model.getDatasource({ endpoint: "Core/User", odataAppend: "?$filter=Roles/any(r: r/Role/AppId eq " + app.Id + ")" });
			$("[name=username]", container).kendoComboBox({
				dataTextField: "Id",
				dataValueField: "Id",
				dataSource: users,
				filter: "contains",
				suggest: true,
				index: 3
			});
		} else {
			$("[name=username]", container).attr('disabled', true);
		}

		var fullName = userDetails.DisplayName;
		var nameParts = fullName == null ? [] : fullName.split(" ");
		var firstName = nameParts[0];
		var lastName = (nameParts.length > 1) ? nameParts[1] : "";

		var onboardingModel = new kendo.observable({
			0: { firstname: firstName, surname: lastName, username: userDetails.Id, email: userDetails.EmailAddress, phone: userDetails.MobilePhone, jobtitle: userDetails.JobTitle },
			1: { companyName: null, vatNo: null, addressLine1: null, addressLine2: null, city: null, stateProvince: null, zipOrPostalCode: null, country: null },
			2: { requestType: null, fundingType: null, reference: null, contactName: null, contactEmail: null, contactPhone: null }
		});

		kendo.bind(container, onboardingModel);
		container.data("model", onboardingModel);

		await api.get("B2B/Country").then((countries) => {
			$("input[name=country]", container).kendoDropDownList({ dataSource: { data: countries.value, sort: [{ field: "Name", dir: "asc" }] }, dataValueField: "Id", dataTextField: "Name" });
		});

		$("select", container).kendoDropDownList();

		$("[name=requestType]", container).on("change", function () {
			var selectedType = $(this).val();
			if (selectedType === "supplier") {
				$("[name=fundingType]", container).closest("li").show();
			} else {
				$("[name=fundingType]", container).closest("li").hide();
			}
		});

		$("[name=fundingType]", container).closest("li").hide();

		container.getKendoValidator().validate();
		$(".sectionContainer", container).hide();
		$(".sectionContainer[name=" + $(".partsList > ul > li.selected", container).attr("data-container") + "]").show();

		var stepIndex = 0;
		var variables = {};

		$("button[name=next]", container).on("click", (e) => UserOnboardingNewRequestWizard.nextStep(e, app, container, variables, stepIndex, onboardingGrid, dialog, onboardingModel, validator, maxStepIndex));
	},

	submitRequest: async function (e, app, grid, dialog, model) {
		e.preventDefault();

		var submission = {
			SourceComponent: "UserOnboarding",
			State: "New",
			DataJson: JSON.stringify({ "fields": JSON.parse(JSON.stringify(model)) }),
			AppId: app.Id
		};

		console.log("Final Submission Object:", submission);

		await api.add("Core/Submission", submission)
			.then(() => {
				notification.success("[resource_displayname[submitted]]");
				grid.refresh();
				dialog.events.close();
			})
			.catch((err) => {
				console.error("API Submission Error:", err);
			});
	},


	nextStep: async function (e, app, container, variables, stepIndex, onboardingGrid, dialog, model, validator, maxStepIndex) {
		e.preventDefault();
		if (!validator.validate()) {
			return;
		}
		if (stepIndex === maxStepIndex) { await UserOnboardingNewRequestWizard.submitRequest(e, app, onboardingGrid, dialog, model); return; }
		$("[step]", container).hide();
		$("[stepPart]", container).removeClass("selected");
		stepIndex++;
		if (stepIndex > 0) {
			$("button[name=previous]", container).show();
			$("button[name=previous]", container).off("click").on("click", (e) => UserOnboardingNewRequestWizard.nextStep(e, app, container, variables, stepIndex - 2, onboardingGrid, dialog, model, validator, maxStepIndex))
		}
		if (stepIndex == 0) { $("button[name=previous]", container).hide(); }
		$("button[name=next]", container).off("click").on("click", (e) => UserOnboardingNewRequestWizard.nextStep(e, app, container, variables, stepIndex, onboardingGrid, dialog, model, validator, maxStepIndex));
		$("[step=" + stepIndex + "]", container).show();
		$("[stepPart=" + stepIndex + "]", container).addClass("selected");
		if (stepIndex === maxStepIndex) {
			$("button[name=next]", container).html("[resource_displayname[create]]");
		}
		else {
			$("button[name=next]", container).html("[resource_displayname[next]]");
		}
		
	},
}","CreatedOn":"2022-03-02T10:55:06.321Z","LastUpdated":"2022-03-02T10:55:06.321Z"}

