<div name="chart" class= "chart"></div>
<p name="nodata" class="alert alert-warning text-center m-2">[resource_displayname[nodatatodisplay]]</p>","CreatedOn":"2025-05-30T18:44:57.6789397Z","CreatedBy":"ashley.upson","Key":"Charts","LastUpdated":"2025-05-30T18:44:57.6789397Z","LastUpdatedBy":"ashley.upson","Name":"ValueOfEarlyPaidInvoices","ResourceKey":"B2B","Script":"ValueOfEarlyPaidInvoices = {
	init: async function (app, container) {
		app = app || session.app;
		container = container || $(".component[name=ValueOfEarlyPaidInvoices]");

		var defaultCurrency = app.Config.B2B.DefaultCurrency
			? app.Config.B2B.DefaultCurrency
			: "EUR";

		var end = new Date();
		var start = new Date();
		start.setUTCFullYear(start.getUTCFullYear() - 1);
		var months = getMonthlyDateRange(start, end, 'MM-yyyy');

		$("[name=currencyDropdown]", container).kendoDropDownList({
			dataSource: app.Config.B2B.Currencies
				? app.Config.B2B.Currencies
				: ["USD", "EUR", "GBP"],
			change: async function (e) {
				var value = this.value();
				var data = await ValueOfEarlyPaidInvoices.getData(app, months, value);
				chart.kendoObject.options.series[0].data = data;
				chart.kendoObject.options.series[0].name = `[resource_displayname[Total]] (${value})`;
				chart.kendoObject.options.valueAxis.max = Math.max(...data) * 1.1;
				chart.kendoObject.refresh();

				if(data.flat().filter(d => d != 0).length == 0) {
					$('[name=nodata]', container).show();
					$('[name=chart]', container).hide();
				} else {
					$('[name=nodata]', container).hide();
					$('[name=chart]', container).show();
				}
			}
		});

		$("[name=currencyDropdown]", container).data("kendoDropDownList").value(defaultCurrency);

		var data = await this.getData(app, months, defaultCurrency);

		var chart = this.initChart(container, months, data, defaultCurrency);
		chart.init();

		if(data.flat().filter(d => d != 0).length == 0) {
			$('[name=nodata]', container).show();
			$('[name=chart]', container).hide();
		} else {
			$('[name=nodata]', container).hide();
			$('[name=chart]', container).show();
		}

		$(window).resize(function () {
			$(chart.chartElement).data('kendoChart').refresh();
		});
	},

	initChart: function (container, months, data, currency) {
		var categories = months.map(m => m.formatted);

		var args = {
			showLegend: true,
			valueTemplate: "#: kendo.toString(value, type.aggregateMoneyFormat)#",
			tooltipTemplate: "#= series.name #: #= kendo.toString(value, type.aggregateMoneyFormat) #",
			series: [{
				name: `[resource_displayname[Total]] (${currency})`,
				data: data
			}],
			categories: categories,
			max: Math.max(...data) * 1.1,
			type: "column"
		};

		return (new Chart($("[name=chart]", container), args));
	},

	getData: async function(app, months, currency) {
		var results = [];
		var sourceSystem = app.Config.B2B.SourceSystem;
		var data = [];

		for(var i = 0; i < months.length; i++) {
			(function(month) { // IIFE to capture the current month
				var endpoint = `B2B/Invoice/FromSystem(SystemId='${sourceSystem}')`;
				var filter = `filter(CurrencyId eq '${currency}' and TaxPoint ge ${month.from} and TaxPoint le ${month.to} and (FundingState eq 'FundingAccepted' or FundingState eq 'Paid'))`;
				data.push(api.get(`${endpoint}?$apply=${filter}/groupby((CurrencyId), aggregate(Value with sum as Total))`).then((r) => {
					if(r[0] == undefined) {
						r[0] = {
							CurrencyId: currency,
							Total: 0
						};
					}
					r[0].CalendarMonth = month.formatted;
					r[0].SortingDate = month.formatted.split('-').reverse().join('-');

					results.push(r[0]);
				}));
			})(months[i]); // Pass the current month to the IIFE
		}

		await Promise.all(data);

		var categories = months.map(m => m.formatted);

		return categories.map(c => results.filter(d => d.CalendarMonth == c)[0].Total);
	}
}"}

